// ─────────────────────────────────────────────────────
// @termuijs/widgets — Breadcrumbs widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, stringWidth, caps, styleToCellAttrs, truncate } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface BreadcrumbsOptions {
    /** Separator drawn between segments. Default: caps.unicode ? '❯' : '>' */
    separator?: string;
    /** Color of the last (current) segment. Default: cyan */
    activeColor?: Color;
}

/**
 * Breadcrumbs — renders a non-interactive path trail of segments with separators and truncation.
 *
 * Example output:
 *   Home ❯ Docs ❯ API
 */
export class Breadcrumbs extends Widget {
    private _segments: string[];
    private _separator?: string;
    private _activeColor?: Color;

    constructor(segments: string[], style: Partial<Style> = {}, opts: BreadcrumbsOptions = {}) {
        super(style);
        this._segments = segments;
        this._separator = opts.separator;
        this._activeColor = opts.activeColor;
    }

    /** Update the trail of segments. */
    setSegments(segments: string[]): void {
        if (
            this._segments.length === segments.length &&
            this._segments.every((segment, index) => segment === segments[index])
        ) {
            return;
        }
        this._segments = segments;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._getContentRect();
        if (width <= 0 || height <= 0 || this._segments.length === 0) return;

        const attrs = styleToCellAttrs(this._style);
        const activeColor: Color = this._activeColor ?? { type: 'named', name: 'cyan' };
        const separatorChar = this._separator ?? (caps.unicode ? '❯' : '>');
        const ellipsis = caps.unicode ? '…' : '...';
        const sep = ` ${separatorChar} `;

        let visibleSegments = [...this._segments];
        let text = visibleSegments.join(sep);
        let tw = stringWidth(text);

        // Truncate from the left if it exceeds width
        while (tw > width && visibleSegments.length > 1) {
            visibleSegments.shift();
            text = ellipsis + sep + visibleSegments.join(sep);
            tw = stringWidth(text);
        }

        const hasTruncated = visibleSegments.length < this._segments.length;
        let showEllipsis = hasTruncated;

        // If width is so narrow that ellipsis + separator consumes all space,
        // hide them so at least part of the final segment stays visible.
        if (showEllipsis && visibleSegments.length === 1) {
            if (stringWidth(ellipsis + sep) >= width) {
                showEllipsis = false;
            }
        }

        let currentX = x;
        const renderList: Array<{ type: 'normal' | 'separator' | 'active', text: string }> = [];

        if (showEllipsis) {
            renderList.push({ type: 'normal', text: ellipsis });
        }

        for (let i = 0; i < visibleSegments.length; i++) {
            if (i > 0 || (showEllipsis && hasTruncated)) {
                renderList.push({ type: 'separator', text: sep });
            }
            const isLast = i === visibleSegments.length - 1;
            renderList.push({ 
                type: isLast ? 'active' : 'normal', 
                text: visibleSegments[i] 
            });
        }

        // Render each part
        for (const item of renderList) {
            const itemWidth = stringWidth(item.text);
            if (currentX - x >= width) break;

            const remainingWidth = width - (currentX - x);
            const str = item.text;

            const itemAttrs = { ...attrs };
            if (item.type === 'active') {
                itemAttrs.fg = activeColor;
            }

            screen.writeString(currentX, y, truncate(str, remainingWidth, ''), itemAttrs);
            currentX += stringWidth(truncate(str, remainingWidth, ''));
        }
    }
}

import { type Screen, type Style } from '@termuijs/core';
import { styleToCellAttrs } from '@termuijs/core';
import type { FrameStats } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export class PerformanceOverlay extends Widget {
    private _stats: FrameStats = {
        cellsChanged: 0,
        bytesWritten: 0,
        durationMs: 0,
    };

    constructor(style: Partial<Style> = {}) {
        super(style);
    }

    updateStats(stats: FrameStats): void {
        this._stats = stats;
        this.markDirty();
    }

    get stats(): FrameStats {
        return this._stats;
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._getContentRect();

        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        const lines = [
            'Performance',
            `Frame: ${this._stats.durationMs.toFixed(1)}ms`,
            `Cells: ${this._stats.cellsChanged}`,
            `Bytes: ${this._stats.bytesWritten}`,
        ];

        for (let i = 0; i < lines.length && i < height; i++) {
            screen.writeString(x, y + i, lines[i]!, attrs);
        }
    }
}

import { type Screen, type Style, styleToCellAttrs, truncate } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface FPSCounterOptions {
    showAverage?: boolean;
    showMinMax?: boolean;
}

export class FPSCounter extends Widget {
    private _fps = 0;
    private _minFps = Infinity;
    private _maxFps = 0;
    private _totalFps = 0;
    private _samples = 0;

    private _showAverage: boolean;
    private _showMinMax: boolean;

    constructor(
        style: Partial<Style> = {},
        opts: FPSCounterOptions = {},
    ) {
        super(style);

        this._showAverage = opts.showAverage ?? true;
        this._showMinMax = opts.showMinMax ?? true;
    }

    updateFPS(fps: number): void {
        if (fps < 0) return;

        this._fps = fps;
        this._minFps = Math.min(this._minFps, fps);
        this._maxFps = Math.max(this._maxFps, fps);

        this._totalFps += fps;
        this._samples++;

        this.markDirty();
    }

    getFPS(): number {
        return this._fps;
    }

    getAverageFPS(): number {
        return this._samples === 0
            ? 0
            : this._totalFps / this._samples;
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._getContentRect();

        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        let row = 0;

        screen.writeString(
            x,
            y + row++,
            truncate(`FPS: ${this._fps}`, width),
            attrs,
        );

        if (this._showAverage && row < height) {
            screen.writeString(
                x,
                y + row++,
                truncate(`Avg: ${this.getAverageFPS().toFixed(1)}`, width),
                attrs,
            );
        }

        if (this._showMinMax && row < height) {
            screen.writeString(
                x,
                y + row++,
                truncate(`Min: ${this._minFps === Infinity ? 0 : this._minFps}`, width),
                attrs,
            );
        }

        if (this._showMinMax && row < height) {
            screen.writeString(
                x,
                y + row,
                truncate(`Max: ${this._maxFps}`, width),
                attrs,
            );
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Tag widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, stringWidth, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export type TagVariant = 'info' | 'success' | 'warning' | 'error' | 'neutral';

export interface TagOptions {
    /** Variant determines border and text color. Default: 'neutral'. */
    variant?: TagVariant;
}

/** Foreground colors for each variant (used for border + text). */
const FG_COLORS: Record<TagVariant, Color> = {
    info:    { type: 'named', name: 'cyan' },
    success: { type: 'named', name: 'green' },
    warning: { type: 'named', name: 'yellow' },
    error:   { type: 'named', name: 'red' },
    neutral: { type: 'named', name: 'white' },
};

/**
 * Tag — a short inline label with a colored border and no background fill.
 *
 * Used for categorical labels such as "typescript", "react", "v2.0".
 * Renders a bordered box with the text colored by variant but no background.
 * Uses `caps.unicode` to choose between Unicode box-drawing and ASCII fallback.
 *
 * CONSTRUCTOR: (text, style?, opts?)
 */
export class Tag extends Widget {
    private _text: string;
    private _variant: TagVariant;

    constructor(text: string, style?: Partial<Style>, opts?: TagOptions) {
        super(style ?? {});
        this._text = text;
        this._variant = opts?.variant ?? 'neutral';
    }

    /** Update the tag text. */
    setText(text: string): void {
        if (text === this._text) return;

        this._text = text;
        this.markDirty();
    }

    /** Get the current tag text. */
    getText(): string {
        return this._text;
    }

    /** Update the tag variant. */
    setVariant(variant: TagVariant): void {
        if (variant === this._variant) return;

        this._variant = variant;
        this.markDirty();
    }

    /** Get the current tag variant. */
    getVariant(): TagVariant {
        return this._variant;
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        const fg = FG_COLORS[this._variant];

        // Choose border characters based on unicode support
        const tl = caps.unicode ? '┌' : '+';
        const tr = caps.unicode ? '┐' : '+';
        const bl = caps.unicode ? '└' : '+';
        const br = caps.unicode ? '┘' : '+';
        const hz = caps.unicode ? '─' : '-';
        const vt = caps.unicode ? '│' : '|';

        const borderAttrs = { fg };
        const textAttrs = { fg };

        // Padded text: " text "
        const padded = ` ${this._text} `;
        const textWidth = stringWidth(padded);

        // Inner width is the area between left and right border
        const innerWidth = Math.min(textWidth, Math.max(0, width - 2));

        // ── Row 0: top border ──
        if (height >= 1) {
            screen.setCell(x, y, { char: tl, ...borderAttrs });
            for (let c = 1; c <= innerWidth; c++) {
                screen.setCell(x + c, y, { char: hz, ...borderAttrs });
            }
            if (innerWidth + 1 < width) {
                screen.setCell(x + innerWidth + 1, y, { char: tr, ...borderAttrs });
            }
        }

        // ── Row 1: content row (no background fill) ──
        if (height >= 2) {
            screen.setCell(x, y + 1, { char: vt, ...borderAttrs });

            // Write padded text with variant foreground, no background
            const visibleText = padded.slice(0, innerWidth);
            screen.writeString(x + 1, y + 1, visibleText, textAttrs);

            if (innerWidth + 1 < width) {
                screen.setCell(x + innerWidth + 1, y + 1, { char: vt, ...borderAttrs });
            }
        }

        // ── Row 2: bottom border ──
        if (height >= 3) {
            screen.setCell(x, y + 2, { char: bl, ...borderAttrs });
            for (let c = 1; c <= innerWidth; c++) {
                screen.setCell(x + c, y + 2, { char: hz, ...borderAttrs });
            }
            if (innerWidth + 1 < width) {
                screen.setCell(x + innerWidth + 1, y + 2, { char: br, ...borderAttrs });
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Canvas widget
// ─────────────────────────────────────────────────────

import type { Screen, Style, Color } from '@termuijs/core';
import { styleToCellAttrs, BRAILLE_OFFSET, BRAILLE_DOTS } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

/**
 * A raw Canvas widget providing a HTML5-like 2D drawing context for custom rendering.
 * Mapped to Braille characters for 2x4 sub-cell pixel resolution.
 */
export class Canvas extends Widget {
    private _pixels: Uint8Array;
    private _canvasWidth: number = 0;
    private _canvasHeight: number = 0;
    private _color: Color | undefined;

    constructor(style: Partial<Style> = {}) {
        super(style);
        this._pixels = new Uint8Array(0);
    }

    /**
     * Sets the active drawing color. If not set, the foreground color from style is used.
     */
    public setColor(color: Color): void {
        this._color = color;
    }

    /**
     * Clears the entire canvas.
     */
    public clear(): void {
        if (this._pixels.length > 0) {
            this._pixels.fill(0);
            this.markDirty();
        }
    }

    /**
     * Sets a single sub-cell pixel.
     */
    public setPixel(x: number, y: number, value: boolean = true): void {
        x = Math.floor(x);
        y = Math.floor(y);
        if (x < 0 || x >= this._canvasWidth || y < 0 || y >= this._canvasHeight) return;

        const idx = y * this._canvasWidth + x;
        const current = this._pixels[idx];
        const next = value ? 1 : 0;

        if (current !== next) {
            this._pixels[idx] = next;
            this.markDirty();
        }
    }

    /**
     * Fills a rectangle with the current drawing state.
     */
    public fillRect(x: number, y: number, w: number, h: number): void {
        x = Math.floor(x);
        y = Math.floor(y);
        w = Math.floor(w);
        h = Math.floor(h);

        let dirty = false;
        for (let r = Math.max(0, y); r < Math.min(this._canvasHeight, y + h); r++) {
            for (let c = Math.max(0, x); c < Math.min(this._canvasWidth, x + w); c++) {
                const idx = r * this._canvasWidth + c;
                if (this._pixels[idx] !== 1) {
                    this._pixels[idx] = 1;
                    dirty = true;
                }
            }
        }
        if (dirty) {
            this.markDirty();
        }
    }

    /**
     * Draws an unfilled circle.
     */
    public drawCircle(cx: number, cy: number, r: number): void {
        cx = Math.floor(cx);
        cy = Math.floor(cy);
        r = Math.floor(r);

        // Bresenham's circle algorithm
        let x = 0;
        let y = r;
        let d = 3 - 2 * r;

        const drawCirclePixels = (xc: number, yc: number, x: number, y: number) => {
            this.setPixel(xc + x, yc + y);
            this.setPixel(xc - x, yc + y);
            this.setPixel(xc + x, yc - y);
            this.setPixel(xc - x, yc - y);
            this.setPixel(xc + y, yc + x);
            this.setPixel(xc - y, yc + x);
            this.setPixel(xc + y, yc - x);
            this.setPixel(xc - y, yc - x);
        };

        drawCirclePixels(cx, cy, x, y);
        while (y >= x) {
            x++;
            if (d > 0) {
                y--;
                d = d + 4 * (x - y) + 10;
            } else {
                d = d + 4 * x + 6;
            }
            drawCirclePixels(cx, cy, x, y);
        }
    }

    /**
     * Draws a line from (x0, y0) to (x1, y1).
     */
    public lineTo(x0: number, y0: number, x1: number, y1: number): void {
        x0 = Math.floor(x0);
        y0 = Math.floor(y0);
        x1 = Math.floor(x1);
        y1 = Math.floor(y1);

        const dx = Math.abs(x1 - x0);
        const dy = -Math.abs(y1 - y0);
        const sx = x0 < x1 ? 1 : -1;
        const sy = y0 < y1 ? 1 : -1;
        let err = dx + dy;

        while (true) {
            this.setPixel(x0, y0);
            if (x0 === x1 && y0 === y1) break;
            const e2 = 2 * err;
            if (e2 >= dy) {
                err += dy;
                x0 += sx;
            }
            if (e2 <= dx) {
                err += dx;
                y0 += sy;
            }
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        const border = this._style.border && this._style.border !== 'none' ? 1 : 0;

        const innerWidth = width - border * 2;
        const innerHeight = height - border * 2;

        if (innerWidth <= 0 || innerHeight <= 0) {
            return;
        }

        const pxWidth = innerWidth * 2;
        const pxHeight = innerHeight * 4;

        if (this._canvasWidth !== pxWidth || this._canvasHeight !== pxHeight) {
            const newPixels = new Uint8Array(pxWidth * pxHeight);

            // Optionally preserve old pixels if resizing
            for (let r = 0; r < Math.min(this._canvasHeight, pxHeight); r++) {
                for (let c = 0; c < Math.min(this._canvasWidth, pxWidth); c++) {
                    newPixels[r * pxWidth + c] = this._pixels[r * this._canvasWidth + c];
                }
            }

            this._pixels = newPixels;
            this._canvasWidth = pxWidth;
            this._canvasHeight = pxHeight;
        }

        const { bg, fg } = styleToCellAttrs(this._style);
        const finalFg = this._color ? this._color : fg;

        for (let r = 0; r < innerHeight; r++) {
            for (let c = 0; c < innerWidth; c++) {
                let charCode = BRAILLE_OFFSET;
                let hasPixels = false;

                for (let br = 0; br < 4; br++) {
                    for (let bc = 0; bc < 2; bc++) {
                        const px = c * 2 + bc;
                        const py = r * 4 + br;
                        if (this._pixels[py * this._canvasWidth + px]) {
                            charCode |= BRAILLE_DOTS[br][bc];
                            hasPixels = true;
                        }
                    }
                }

                const char = hasPixels ? String.fromCharCode(charCode) : ' ';
                screen.setCell(x + border + c, y + border + r, { char, bg, fg: finalFg });
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — OrderedList widget
// ─────────────────────────────────────────────────────
import {
    type Screen,
    type Style,
    styleToCellAttrs,
    truncate,
} from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface OrderedListItem {
    text: string;
    /** Nested items */
    children?: OrderedListItem[];
}

export interface OrderedListOptions {
    /** Indent width per level. Default: 3 */
    indent?: number;
    /** Numbering style: '1.' for arabic, 'a.' for lowercase alpha, 'i.' for lowercase roman. Default: '1.' */
    style?: '1.' | 'a.' | 'i.';
}

interface FlatRow {
    text: string;
    prefix: string;
    depth: number;
}

function toAlpha(n: number): string {
    let result = '';
    while (n > 0) {
        n--;
        result = String.fromCharCode(97 + (n % 26)) + result;
        n = Math.floor(n / 26);
    }
    return result || 'a';
}

function toRoman(n: number): string {
    const vals = [1000,900,500,400,100,90,50,40,10,9,5,4,1];
    const syms = ['m','cm','d','cd','c','xc','l','xl','x','ix','v','iv','i'];
    let result = '';
    for (let i = 0; i < vals.length; i++) {
        while (n >= vals[i]) {
            result += syms[i];
            n -= vals[i];
        }
    }
    return result;
}

function getPrefix(index: number, style: '1.' | 'a.' | 'i.'): string {
    switch (style) {
        case 'a.': return toAlpha(index) + '.';
        case 'i.': return toRoman(index) + '.';
        default:   return index + '.';
    }
}

function flattenItems(
    items: OrderedListItem[],
    depth: number,
    style: '1.' | 'a.' | 'i.',
    out: FlatRow[],
): void {
    for (let i = 0; i < items.length; i++) {
        const item = items[i];
        out.push({
            text: item.text,
            prefix: getPrefix(i + 1, style),
            depth,
        });
        if (item.children && item.children.length > 0) {
            flattenItems(item.children, depth + 1, style, out);
        }
    }
}

/**
 * OrderedList — renders a numbered list with optional nesting.
 */
export class OrderedList extends Widget {
    private _items: OrderedListItem[];
    private _opts: Required<OrderedListOptions>;

    constructor(
        items: OrderedListItem[],
        style: Partial<Style> = {},
        opts: OrderedListOptions = {},
    ) {
        super(style);
        this._items = items;
        this._opts = {
            indent: Math.max(0, opts.indent ?? 3),
            style: opts.style ?? '1.',
        };
    }

    setItems(items: OrderedListItem[]): void {
        if (items === this._items) {
            return;
        }
        this._items = items;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const rows: FlatRow[] = [];
        flattenItems(this._items, 0, this._opts.style, rows);

        const visibleCount = Math.min(rows.length, height);
        for (let i = 0; i < visibleCount; i++) {
            const { text, prefix, depth } = rows[i];
            const indentStr = ' '.repeat(this._opts.indent * depth);
            let line = `${indentStr}${prefix} ${text}`;
            line = truncate(line, width);
            screen.writeString(x, y + i, line, attrs);
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — DiffView widget (unified diff viewer)
// ─────────────────────────────────────────────────────

import {
    type Screen,
    type Style,
    styleToCellAttrs,
    stringWidth,
    truncate,
} from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface DiffLine {
    type: 'add' | 'remove' | 'context';
    content: string;
    lineNo?: number; // optional line number to show in gutter
}

export interface DiffViewOptions {
    lines: DiffLine[];
    showLineNumbers?: boolean; // default: true
    gutterWidth?: number;      // default: 5 (e.g. " 123 ")
}

/**
 * DiffView — a scrollable unified diff viewer with +/- line coloring.
 *
 * Supports:
 * - Gutter with optional right-aligned line numbers (dim)
 * - '+' prefix for added lines (green fg)
 * - '-' prefix for removed lines (red fg)
 * - ' ' prefix for context lines (dim fg)
 * - Keyboard scrolling: ArrowUp/Down, j/k, PageUp/PageDown, Home/End
 */
export class DiffView extends Widget {
    private _lines: DiffLine[];
    private _scrollOffset = 0;
    private _showLineNumbers: boolean;
    private _gutterWidth: number;

    constructor(options: DiffViewOptions, style: Partial<Style> = {}) {
        super(style);
        this._lines = options.lines;
        this._showLineNumbers = options.showLineNumbers ?? true;
        this._gutterWidth = options.gutterWidth ?? 5;
        this.focusable = true;
    }

    setLines(lines: DiffLine[]): void {
        this._lines = lines;
        this._scrollOffset = 0;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const baseAttrs = styleToCellAttrs(this._style);
        const visibleLines = this._lines.slice(
            this._scrollOffset,
            this._scrollOffset + height,
        );

        for (let i = 0; i < visibleLines.length; i++) {
            const diffLine = visibleLines[i];
            let col = x;
            const row = y + i;

            // ── Determine color by type ────────────────────────
            const isAdd = diffLine.type === 'add';
            const isRemove = diffLine.type === 'remove';
            const isContext = diffLine.type === 'context';

            const fg = isAdd
                ? { type: 'named' as const, name: 'green' as const }
                : isRemove
                    ? { type: 'named' as const, name: 'red' as const }
                    : undefined;

            const lineAttrs = {
                ...baseAttrs,
                ...(fg ? { fg } : {}),
                dim: isContext,
            };

            // ── Gutter ─────────────────────────────────────────
            if (this._showLineNumbers) {
                const gutterStr =
                    diffLine.lineNo !== undefined
                        ? String(diffLine.lineNo).padStart(this._gutterWidth - 1, ' ') + ' '
                        : ' '.repeat(this._gutterWidth);

                const gutterAttrs = { ...baseAttrs, dim: true };
                screen.writeString(col, row, gutterStr.slice(0, this._gutterWidth), gutterAttrs);
                col += this._gutterWidth;
            }

            // ── Prefix character ───────────────────────────────
            const prefix = isAdd ? '+' : isRemove ? '-' : ' ';
            const remainingWidth = width - (col - x);
            if (remainingWidth <= 0) continue;

            screen.writeString(col, row, prefix, lineAttrs);
            col += 1;

            // ── Content ────────────────────────────────────────
            const contentWidth = width - (col - x);
            if (contentWidth <= 0) continue;

            const content = truncate(diffLine.content, contentWidth);
            screen.writeString(col, row, content, lineAttrs);
        }
    }

    handleKey(key: string): void {
        const rect = this._getContentRect();
        const visibleHeight = Math.max(1, rect.height);
        const maxOffset = Math.max(0, this._lines.length - visibleHeight);

        switch (key) {
            case 'up':
            case 'k':
                this._scrollOffset = Math.max(0, this._scrollOffset - 1);
                this.markDirty();
                break;

            case 'down':
            case 'j':
                this._scrollOffset = Math.min(maxOffset, this._scrollOffset + 1);
                this.markDirty();
                break;

            case 'pageup':
                this._scrollOffset = Math.max(0, this._scrollOffset - visibleHeight);
                this.markDirty();
                break;

            case 'pagedown':
                this._scrollOffset = Math.min(maxOffset, this._scrollOffset + visibleHeight);
                this.markDirty();
                break;

            case 'home':
                this._scrollOffset = 0;
                this.markDirty();
                break;

            case 'end':
                this._scrollOffset = maxOffset;
                this.markDirty();
                break;
        }
    }
}

import { type Style, parseColor, stringWidth } from '@termuijs/core';
import { Box } from '@termuijs/widgets';
import { Text } from '@termuijs/widgets';

const escapeRegExp = (v: string) => v.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

const DEFAULT_STYLE: Partial<Style> = {
    bg: parseColor('yellow'),
    fg: parseColor('black'),
};

export class Highlight extends Box {
    constructor(text: string, query: string | RegExp, style?: Partial<Style>) {
        super({ flexDirection: 'row' });
        this._buildSegments(text, query, style);
    }

    private _buildSegments(text: string, query: string | RegExp, highlightStyle?: Partial<Style>): void {
        const style = highlightStyle ?? DEFAULT_STYLE;

        if (!query) {
            this.addChild(new Text(text, { width: stringWidth(text), height: 1 }));
            return;
        }

        const pattern = query instanceof RegExp ? query.source : escapeRegExp(query);
        const baseFlags = query instanceof RegExp ? query.flags : 'i';
        const splitFlags = baseFlags.includes('g') ? baseFlags : `${baseFlags}g`;
        const splitRegex = new RegExp(`(${pattern})`, splitFlags);
        const matchRegex = new RegExp(`^(?:${pattern})$`, baseFlags.replace(/g/g, ''));

        for (const part of text.split(splitRegex)) {
            const partStyle = matchRegex.test(part) ? { ...style, width: stringWidth(part), height: 1 } : { width: stringWidth(part), height: 1 };
            this.addChild(new Text(part, partStyle));
        }
    }

    setText(text: string, query: string | RegExp, style?: Partial<Style>): void {
        this.clearChildren();
        this._buildSegments(text, query, style);
    }

    private _updateHighlight(text: string, query: string | RegExp, style?: Partial<Style>): void {
        this.setText(text, query, style);
    }

    /** @deprecated Use setText() instead. */
    update(text: string, query?: string | RegExp, style?: Partial<Style>): void;
    update<T = unknown>(_previousProps: T): void;
    update(text: unknown, query?: unknown, style?: unknown): void {
        if (typeof text === 'string') {
            const q = typeof query === 'string' || query instanceof RegExp ? query : '';
            const s = style === undefined || (typeof style === 'object' && style !== null && !Array.isArray(style))
                ? (style as Partial<Style> | undefined)
                : undefined;
            this._updateHighlight(text, q, s);
        }
    }
}

