// @termuijs/widgets — Avatar widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, styleToCellAttrs, stringWidth, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface AvatarOptions {
    /** Override the dynamically generated color */
    color?: Color;
    /** Shape of the avatar */
    shape?: 'square' | 'circle';
}

/**
 * Avatar — a widget that displays user initials with a generated color.
 */
export class Avatar extends Widget {
    private _name: string;
    private _color?: Color;
    private _shape: 'square' | 'circle';
    private _initials: string;
    private _fallbackColor: Color;

    constructor(name: string, style: Partial<Style> = {}, opts: AvatarOptions = {}) {
        super(style);
        this._name = name;
        this._color = opts.color;
        this._shape = opts.shape ?? 'square';
        this._initials = this._extractInitials(name);
        this._fallbackColor = this._generateColor(name);
    }

    setName(name: string): void {
        this._name = name;
        this._initials = this._extractInitials(name);
        this._fallbackColor = this._generateColor(name);
        this.markDirty();
    }

    getName(): string {
        return this._name;
    }

    setColor(color: Color): void {
        this._color = color;
        this.markDirty();
    }

    getColor(): Color | undefined {
        return this._color;
    }

    setShape(shape: 'square' | 'circle'): void {
        this._shape = shape;
        this.markDirty();
    }

    getShape(): 'square' | 'circle' {
        return this._shape;
    }

    private _extractInitials(name: string): string {
        if (!name) return '';
        const parts = name.trim().split(/\s+/);
        if (parts.length === 0 || parts[0] === '') return '';
        let init = '';
        if (parts.length === 1) {
            init = parts[0].substring(0, 2).toUpperCase();
        } else {
            init = (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
        }
        if (!caps.unicode) {
            init = init.replace(/[^\x00-\x7F]/g, '?');
        }
        return init;
    }

    private _generateColor(name: string): Color {
        if (!name) {
            return { type: 'named', name: 'white' };
        }
        let hash = 0;
        for (let i = 0; i < name.length; i++) {
            hash = name.charCodeAt(i) + ((hash << 5) - hash);
        }

        // Stable palette of colors
        const colors = [
            'red', 'green', 'yellow', 'blue', 'magenta', 'cyan',
            'brightRed', 'brightGreen', 'brightYellow', 'brightBlue', 'brightMagenta', 'brightCyan'
        ] as const;

        const index = Math.abs(hash) % colors.length;
        return { type: 'named', name: colors[index] };
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const avatarColor = this._color ?? this._fallbackColor;

        let text = '';
        if (this._shape === 'circle') {
            text = `(${this._initials})`;
        } else {
            text = `[${this._initials}]`;
        }

        let renderText = '';
        let currentWidth = 0;
        for (const char of text) {
            const cw = stringWidth(char);
            if (currentWidth + cw > width) break;
            currentWidth += cw;
            renderText += char;
        }

        screen.writeString(x, y, renderText, {
            ...attrs,
            fg: avatarColor,
            bold: true,
        });
    }
}

import { Widget } from '@termuijs/widgets';
import { type Screen, type Style, caps, styleToCellAttrs } from '@termuijs/core';

export interface QRCodePatternOptions {
    darkChar?: string;
    lightChar?: string;
    showText?: boolean;
}

export interface QRCodeOptions extends QRCodePatternOptions {
    errorCorrectionLevel?: 'L' | 'M' | 'Q' | 'H';
}

const SIZE = 21;

/**
 * Decorative QR-style pattern generator.
 * This widget is intentionally not a scannable QR code.
 */
function hashString(str: string): number {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
        hash = (hash * 31 + str.charCodeAt(i)) >>> 0;
    }
    return hash;
}

export class QRCodePattern extends Widget {
    private data: string;
    private opts: QRCodePatternOptions;

    constructor(data: string, style?: Partial<Style>, opts?: QRCodePatternOptions) {
        super(style);
        this.data = data;
        this.opts = opts ?? {};
    }

    setData(data: string): void {
        if(this.data === data) return;
        this.data = data;
        this.markDirty();
    }

    private isFinder(x: number, y: number): boolean {
        const inTopLeft = x < 7 && y < 7;
        const inTopRight = x > SIZE - 8 && y < 7;
        const inBottomLeft = x < 7 && y > SIZE - 8;

        return inTopLeft || inTopRight || inBottomLeft;
    }

    private renderFinder(x: number, y: number): string {
        const dark = caps.unicode ? (this.opts.darkChar ?? '█') : '#';
        const light = caps.unicode ? (this.opts.lightChar ?? ' ') : ' ';

        const dx = x % 7;
        const dy = y % 7;

        const border = dx === 0 || dx === 6 || dy === 0 || dy === 6;
        const center = dx >= 2 && dx <= 4 && dy >= 2 && dy <= 4;

        return border || center ? dark : light;
    }

    protected _renderSelf(screen: Screen): void {
        const contentRect = this._getContentRect();
        const { x: baseX, y: baseY, width, height } = contentRect;
        if (width <= 0 || height <= 0) return;

        const dark = caps.unicode ? (this.opts.darkChar ?? '█') : '#';
        const light = caps.unicode ? (this.opts.lightChar ?? ' ') : ' ';
        const attrs = styleToCellAttrs(this._style);
        const hash = hashString(this.data);

        const drawWidth = Math.min(SIZE, width);
        const drawHeight = Math.min(SIZE, height);

        for (let row = 0; row < drawHeight; row++) {
            for (let col = 0; col < drawWidth; col++) {
                let char: string;

                if (this.isFinder(col, row)) {
                    char = this.renderFinder(col, row);
                } else {
                    const bitIndex = (col * row + hash) % 32;
                    const bit = (hash >> bitIndex) & 1;
                    char = bit ? dark : light;
                }

                screen.writeString(baseX + col, baseY + row, char, attrs);
            }
        }

        if (this.opts.showText && height > drawHeight) {
            screen.writeString(
                baseX,
                baseY + drawHeight,
                this.data.slice(0, width),
                attrs
            );
        }
    }
}


export const QRCode = QRCodePattern;

