// @termuijs/widgets — Badge widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, stringWidth, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export type BadgeVariant = 'info' | 'success' | 'warning' | 'error' | 'neutral';

export interface BadgeOptions {
    /** Variant determines background color. Default: 'neutral'. */
    variant?: BadgeVariant;
}

/** Background colors for each variant. */
const BG_COLORS: Record<BadgeVariant, Color> = {
    info:    { type: 'named', name: 'cyan' },
    success: { type: 'named', name: 'green' },
    warning: { type: 'named', name: 'yellow' },
    error:   { type: 'named', name: 'red' },
    neutral: { type: 'named', name: 'white' },
};

/** Foreground color — black for readability on colored backgrounds. */
const FG_COLOR: Color = { type: 'named', name: 'black' };

/**
 * Badge — a short inline label with a colored background.
 *
 * Used for status indicators such as "online", "error", "beta".
 * Renders a bordered box with the text on a colored background.
 * Uses `caps.unicode` to choose between Unicode box-drawing and ASCII fallback.
 *
 * CONSTRUCTOR: (text, style?, opts?)
 */
export class Badge extends Widget {
    private _text: string;
    private _variant: BadgeVariant;

    constructor(text: string, style?: Partial<Style>, opts?: BadgeOptions) {
        super(style ?? {});
        this._text = text;
        this._variant = opts?.variant ?? 'neutral';
    }

    /** Update the badge text. */
    setText(text: string): void {
        if (text === this._text) return; 
        this._text = text;
        this.markDirty();
    }

    /** Get the current badge text. */
    getText(): string {
        return this._text;
    }

    /** Update the badge variant. */
    setVariant(variant: BadgeVariant): void {
        if (variant === this._variant) return;
        this._variant = variant;
        this.markDirty();
    }

    /** Get the current badge variant. */
    getVariant(): BadgeVariant {
        return this._variant;
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        const bg = BG_COLORS[this._variant];
        const fg = FG_COLOR;

        // Choose border characters based on unicode support
        const tl = caps.unicode ? '┌' : '+';
        const tr = caps.unicode ? '┐' : '+';
        const bl = caps.unicode ? '└' : '+';
        const br = caps.unicode ? '┘' : '+';
        const hz = caps.unicode ? '─' : '-';
        const vt = caps.unicode ? '│' : '|';

        const borderAttrs = { fg: bg };
        const contentAttrs = { fg, bg, bold: true };

        // Padded text: " text "
        const padded = ` ${this._text} `;
        const textWidth = stringWidth(padded);

        // Inner width is the area between left and right border
        const innerWidth = Math.min(textWidth, Math.max(0, width - 2));

        // ── Row 0: top border ──
        if (height >= 1) {
            screen.setCell(x, y, { char: tl, ...borderAttrs });
            for (let c = 1; c <= innerWidth; c++) {
                screen.setCell(x + c, y, { char: hz, ...borderAttrs });
            }
            if (innerWidth + 1 < width) {
                screen.setCell(x + innerWidth + 1, y, { char: tr, ...borderAttrs });
            }
        }

        // ── Row 1: content row ──
        if (height >= 2) {
            screen.setCell(x, y + 1, { char: vt, ...borderAttrs });

            // Write padded text with colored background
            const visibleText = padded.slice(0, innerWidth);
            screen.writeString(x + 1, y + 1, visibleText, contentAttrs);

            // Fill remaining inner space with background
            const written = stringWidth(visibleText);
            for (let c = written; c < innerWidth; c++) {
                screen.setCell(x + 1 + c, y + 1, { char: ' ', ...contentAttrs });
            }

            if (innerWidth + 1 < width) {
                screen.setCell(x + innerWidth + 1, y + 1, { char: vt, ...borderAttrs });
            }
        }

        // ── Row 2: bottom border ──
        if (height >= 3) {
            screen.setCell(x, y + 2, { char: bl, ...borderAttrs });
            for (let c = 1; c <= innerWidth; c++) {
                screen.setCell(x + c, y + 2, { char: hz, ...borderAttrs });
            }
            if (innerWidth + 1 < width) {
                screen.setCell(x + innerWidth + 1, y + 2, { char: br, ...borderAttrs });
            }
        }
    }
}

// @termuijs/widgets — Tooltip widget

import { type Screen, type Style, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface TooltipOptions {
    text: string;
    visible: boolean;
}

/**
 * Tooltip — displays contextual help text.
 *
 * The widget renders within its own assigned rect.
 * The parent is responsible for positioning it via updateRect().
 */
export class Tooltip extends Widget {
    private _text: string;
    private _visible: boolean;

    constructor(options: TooltipOptions, style: Partial<Style> = {}) {
        super(style);

        this._text = options.text;
        this._visible = options.visible;
    }

    protected _renderSelf(screen: Screen): void {
        if (!this._visible) return;

        const { x, y, width, height } = this._rect;

        if (width <= 0 || height <= 0) return;

        const tl = caps.unicode ? '┌' : '+';
        const tr = caps.unicode ? '┐' : '+';
        const bl = caps.unicode ? '└' : '+';
        const br = caps.unicode ? '┘' : '+';
        const hz = caps.unicode ? '─' : '-';
        const vt = caps.unicode ? '│' : '|';

        // Top border
        screen.setCell(x, y, { char: tl });

        for (let c = 1; c < width - 1; c++) {
            screen.setCell(x + c, y, { char: hz });
        }

        if (width > 1) {
            screen.setCell(x + width - 1, y, { char: tr });
        }

        // Content row
        if (height >= 2) {
            screen.setCell(x, y + 1, { char: vt });

            const content = this._text
                .slice(0, Math.max(0, width - 2))
                .padEnd(Math.max(0, width - 2), ' ');

            screen.writeString(x + 1, y + 1, content);

            if (width > 1) {
                screen.setCell(x + width - 1, y + 1, { char: vt });
            }
        }

        // Bottom border
        if (height >= 3) {
            screen.setCell(x, y + height - 1, { char: bl });

            for (let c = 1; c < width - 1; c++) {
                screen.setCell(x + c, y + height - 1, { char: hz });
            }

            if (width > 1) {
                screen.setCell(x + width - 1, y + height - 1, {
                    char: br,
                });
            }
        }
    }

    setText(text: string): void {
        if (this._text === text) return;
        this._text = text;
        this.markDirty();
    }

    getText(): string {
        return this._text;
    }

    setVisible(visible: boolean): void {
        if (this._visible === visible) return;
        this._visible = visible;
        this.markDirty();
    }

    getVisible(): boolean {
        return this._visible;
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Code widget
// ─────────────────────────────────────────────────────

import { caps, getBorderChars, styleToCellAttrs } from '@termuijs/core';
import { type Screen, type Style } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface CodeOptions {
    language?: string;
    showLineNumbers?: boolean;
}

export class Code extends Widget {
    private _code: string;
    private _language: string;
    private _showLineNumbers: boolean;

    constructor(code: string, style: Partial<Style> = {}, opts: CodeOptions = {}) {
        const mergedStyle: Partial<Style> = { border: 'round', ...style };
        super(mergedStyle);
        this._code = code;
        this._language = opts.language ?? '';
        this._showLineNumbers = opts.showLineNumbers ?? true;
    }

    setCode(code: string): void {
        this._code = code;
        this.markDirty();
    }

    setLanguage(language: string): void {
        this._language = language;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const lines = this._code.split('\n');
        const maxLineNum = lines.length;
        const lineNumWidth = this._showLineNumbers ? String(maxLineNum).length : 0;

        for (let i = 0; i < lines.length && i < rect.height; i++) {
            let x = rect.x;
            const y = rect.y + i;

            if (this._showLineNumbers && lineNumWidth > 0) {
                const lineNum = String(i + 1).padStart(lineNumWidth);
                screen.writeString(x, y, lineNum, { dim: true });
                x += lineNumWidth;

                screen.setCell(x, y, { char: '│', dim: true });
                x++;

                screen.setCell(x, y, { char: ' ' });
                x++;
            }

            const codeLine = lines[i];
            screen.writeString(x, y, codeLine);
        }
    }

    protected _renderBorder(screen: Screen): void {
        const border = this._style.border;
        const hasBorder = border && border !== 'none';
        if (!hasBorder) return;

        const { x, y, width, height } = this._rect;
        if (width < 2 || height < 2) return;

        const chars = getBorderChars(border);
        if (!chars) return;

        const attrs = styleToCellAttrs(this._style);
        const borderFg = this._style.borderColor ?? attrs.fg;
        const cellStyle = { fg: borderFg };

        // Top edge with language label
        const label = this._language ? `[${this._language}]` : '';

        screen.setCell(x, y, { char: chars.topLeft, ...cellStyle });

        if (label) {
            screen.setCell(x + 1, y, { char: chars.top, ...cellStyle });
            for (let i = 0; i < label.length; i++) {
                screen.setCell(x + 2 + i, y, { char: label[i], ...cellStyle, bold: true });
            }
            for (let c = 2 + label.length; c < width - 1; c++) {
                screen.setCell(x + c, y, { char: chars.top, ...cellStyle });
            }
        } else {
            for (let c = 1; c < width - 1; c++) {
                screen.setCell(x + c, y, { char: chars.top, ...cellStyle });
            }
        }
        screen.setCell(x + width - 1, y, { char: chars.topRight, ...cellStyle });

        // Bottom edge
        screen.setCell(x, y + height - 1, { char: chars.bottomLeft, ...cellStyle });
        for (let c = 1; c < width - 1; c++) {
            screen.setCell(x + c, y + height - 1, { char: chars.bottom, ...cellStyle });
        }
        screen.setCell(x + width - 1, y + height - 1, { char: chars.bottomRight, ...cellStyle });

        // Left and right edges
        for (let r = 1; r < height - 1; r++) {
            screen.setCell(x, y + r, { char: chars.left, ...cellStyle });
            screen.setCell(x + width - 1, y + r, { char: chars.right, ...cellStyle });
        }
    }
}

