// ─────────────────────────────────────────────────────
// @termuijs/widgets — ProgressCircle
// Arc/circle progress indicator
// ─────────────────────────────────────────────────────

import {
    type Screen,
    type Style,
    type Color,
    styleToCellAttrs,
    caps,
    stringWidth,
    mergeStyles,
    defaultStyle,
} from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export type ProgressCircleSize = 'sm' | 'md';

export interface ProgressCircleOptions {
    value?: number;
    size?: ProgressCircleSize;
    color?: Color;
    label?: string;
    showPercent?: boolean;
}

// Unicode arc chars mapped to 5 levels: 0% 25% 50% 75% 100%
const ARC_CHARS = ['○', '◔', '◑', '◕', '●'];
const ARC_ASCII = ['0', '1', '2', '3', '4'];

export class ProgressCircle extends Widget {
    private _value: number;
    private _size: ProgressCircleSize;
    private _color: Color;
    private _label: string;
    private _showPercent: boolean;

    constructor(style: Partial<Style> = {}, options: ProgressCircleOptions = {}) {
        const size = options.size ?? 'md';
        super(mergeStyles(defaultStyle(), { height: 1, ...style }));
        this._value = Math.max(0, Math.min(100, options.value ?? 0));
        this._size = size;
        this._color = options.color ?? { type: 'named', name: 'cyan' };
        this._label = options.label ?? '';
        this._showPercent = options.showPercent ?? true;
    }

    get value(): number { return this._value; }

    setValue(v: number): void {
        const clamped = Math.max(0, Math.min(100, v));
        if (clamped === this._value) return;
        this._value = clamped;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width } = rect;
        if (width <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        switch (this._size) {
            case 'sm': this._renderSm(screen, x, y, attrs); break;
            case 'md': this._renderMd(screen, x, y, width, attrs); break;
        }
    }

    private _renderSm(screen: Screen, x: number, y: number, attrs: ReturnType<typeof styleToCellAttrs>): void {
        const level = Math.round(this._value / 25); // 0-4
        const chars = caps.unicode ? ARC_CHARS : ARC_ASCII;
        const arc = chars[Math.min(level, 4)]!;

        screen.writeString(x, y, arc, { ...attrs, fg: this._color });

        let cx = x + stringWidth(arc) + 1;
        if (this._showPercent) {
            const pct = `${Math.round(this._value)}%`;
            screen.writeString(cx, y, pct, attrs);
            cx += pct.length + 1;
        }
        if (this._label) {
            screen.writeString(cx, y, this._label, { ...attrs, dim: true });
        }
    }

    private _renderMd(screen: Screen, x: number, y: number, width: number, attrs: ReturnType<typeof styleToCellAttrs>): void {
        // Format: [████░░░░] 50%
        const suffix = this._showPercent ? ` ${Math.round(this._value)}%` : '';
        const bracketWidth = Math.max(2, Math.min(width - suffix.length - 2, 10));
        const filled = Math.round((this._value / 100) * bracketWidth);
        const empty = bracketWidth - filled;

        const fillChar = caps.unicode ? '█' : '#';
        const emptyChar = caps.unicode ? '░' : '-';

        screen.writeString(x, y, '[', attrs);
        for (let i = 0; i < filled; i++) {
            screen.setCell(x + 1 + i, y, { char: fillChar, ...attrs, fg: this._color });
        }
        for (let i = 0; i < empty; i++) {
            screen.setCell(x + 1 + filled + i, y, { char: emptyChar, ...attrs, dim: true });
        }
        screen.writeString(x + 1 + bracketWidth, y, ']', attrs);

        if (suffix) {
            screen.writeString(x + 2 + bracketWidth, y, suffix, { ...attrs, bold: true });
        }
        if (this._label) {
            const labelX = x + 3 + bracketWidth + suffix.length;
            screen.writeString(labelX, y, this._label, { ...attrs, dim: true });
        }
    }

}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Clock widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, styleToCellAttrs } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';
import { Digits } from '@termuijs/widgets';

export interface ClockOptions {
    showSeconds?: boolean;
    use24Hour?: boolean;
    digitColor?: Color;
}

export class Clock extends Widget {
    private _showSeconds: boolean;
    private _use24Hour: boolean;
    private _digits: Digits;
    private _digitColor: Color;
    private _ampm: string = '';
    private _digitPartLength: number = 0;

    constructor(style: Partial<Style> = {}, opts: ClockOptions = {}) {
        super(style);
        this._showSeconds = opts.showSeconds ?? true;
        this._use24Hour = opts.use24Hour ?? true;
        this._digitColor = opts.digitColor ?? { type: 'named', name: 'white' };

        // Strip layout and border styles from style passed to Digits
        const { border, padding, margin, width, height, ...digitsStyle } = style;
        this._digits = new Digits(digitsStyle, { color: this._digitColor });

        // Initialize with current time
        this.setTime(new Date());
    }

    setTime(time: Date): void {
        const hours = time.getHours();
        const minutes = time.getMinutes();
        const seconds = time.getSeconds();

        const minStr = String(minutes).padStart(2, '0');
        const secStr = String(seconds).padStart(2, '0');

        let digitPart: string;
        let ampmPart: string = '';

        if (this._use24Hour) {
            const hourStr = String(hours).padStart(2, '0');
            digitPart = this._showSeconds 
                ? `${hourStr}:${minStr}:${secStr}` 
                : `${hourStr}:${minStr}`;
        } else {
            ampmPart = hours >= 12 ? 'PM' : 'AM';
            const displayHour = hours % 12 === 0 ? 12 : hours % 12;
            const hourStr = String(displayHour);
            digitPart = this._showSeconds 
                ? `${hourStr}:${minStr}:${secStr}` 
                : `${hourStr}:${minStr}`;
        }

        this._digits.setValue(digitPart);
        this._ampm = ampmPart;
        this._digitPartLength = digitPart.length;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        // Position and render the internal digits widget
        this._digits.updateRect(rect);
        this._digits.render(screen);

        // If in 12h mode, render AM/PM text separately
        if (this._ampm) {
            const digitsWidth = this._digitPartLength * 5; // each digit consumes 5 columns

            if (digitsWidth + this._ampm.length <= width && height >= 3) {
                const attrs = styleToCellAttrs(this._style);
                screen.writeString(x + digitsWidth, y + 2, this._ampm, { ...attrs, fg: this._digitColor });
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Gradient widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, styleToCellAttrs, caps, parseColor, shouldUseColor } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface GradientOptions {
    /** Start color (hex string like '#ff0000' or named color string) */
    startColor?: string;
    /** End color (hex string like '#0000ff' or named color string) */
    endColor?: string;
    /** Text alignment */
    align?: 'left' | 'center' | 'right';
}

/** Parse a hex color string to [r, g, b] */
function hexToRgb(hex: string): [number, number, number] | null {
    const clean = hex.replace('#', '');
    if (clean.length !== 6) return null;
    const r = parseInt(clean.slice(0, 2), 16);
    const g = parseInt(clean.slice(2, 4), 16);
    const b = parseInt(clean.slice(4, 6), 16);
    if (isNaN(r) || isNaN(g) || isNaN(b)) return null;
    return [r, g, b];
}

/** Interpolate between two RGB values at t ∈ [0,1] */
function lerpRgb(a: [number, number, number], b: [number, number, number], t: number): [number, number, number] {
    return [
        Math.round(a[0] + (b[0] - a[0]) * t),
        Math.round(a[1] + (b[1] - a[1]) * t),
        Math.round(a[2] + (b[2] - a[2]) * t),
    ];
}

/**
 * Gradient — text rendered with a smooth color gradient.
 *
 * Each character is colored by linearly interpolating between startColor and endColor.
 * Falls back to a single foreground color if true-color is unavailable.
 */
export class Gradient extends Widget {
    private _text: string;
    private _startColor: string;
    private _endColor: string;
    private _align: 'left' | 'center' | 'right';

    constructor(text: string, style: Partial<Style> = {}, opts: GradientOptions = {}) {
        super({ height: 1, ...style });
        this._text = text;
        this._startColor = opts.startColor ?? '#ff0000';
        this._endColor = opts.endColor ?? '#0000ff';
        this._align = opts.align ?? 'left';
    }

    setText(text: string): void {
        if (text === this._text) return;
        this._text = text;
        this.markDirty();
    }

    setColors(start: string, end: string): void {
        if (start === this._startColor && end === this._endColor) return;
        this._startColor = start;
        this._endColor = end;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width } = rect;
        if (width <= 0 || !this._text) return;

        const attrs = styleToCellAttrs(this._style);

        // Without color support: render plain text with alignment applied
        if (!shouldUseColor()) {
            const plainChars = Array.from(this._text).slice(0, width);
            const plainLen = plainChars.length;
            let plainOffsetX = 0;
            if (this._align === 'center') plainOffsetX = Math.floor((width - plainLen) / 2);
            else if (this._align === 'right') plainOffsetX = width - plainLen;
            plainOffsetX = Math.max(0, plainOffsetX);
            screen.writeString(x + plainOffsetX, y, plainChars.join(''), attrs);
            return;
        }

        const startRgb = hexToRgb(this._startColor);
        const endRgb = hexToRgb(this._endColor);

        const chars = Array.from(this._text).slice(0, width);
        const len = chars.length;

        // Alignment offset
        let offsetX = 0;
        if (this._align === 'center') offsetX = Math.floor((width - len) / 2);
        else if (this._align === 'right') offsetX = width - len;
        offsetX = Math.max(0, offsetX);

        for (let i = 0; i < chars.length; i++) {
            const t = len > 1 ? i / (len - 1) : 0;

            let fg: import('@termuijs/core').Color;

            if (startRgb && endRgb) {
                const [r, g, b] = lerpRgb(startRgb, endRgb, t);
                fg = { type: 'rgb', r, g, b };
            } else if (startRgb) {
                // Fallback: use start color parsed as hex
                fg = parseColor(this._startColor) ?? attrs.fg;
            } else {
                fg = attrs.fg;
            }

            screen.setCell(x + offsetX + i, y, { char: chars[i] ?? ' ', ...attrs, fg });
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Collapsible widget
//
// A toggleable section with a clickable title bar and
// a hidden or visible body. Press Enter or Space to toggle.
// ─────────────────────────────────────────────────────

import {
    type Screen,
    type Style,
    type KeyEvent,
    styleToCellAttrs,
    truncate,
    caps,
} from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface CollapsibleOptions {
    /** Start open. Default: false */
    open?: boolean;
    /** Expand indicator char. Default: '▶' (or '>' in ASCII) */
    expandChar?: string;
    /** Collapse indicator char. Default: '▼' (or 'v' in ASCII) */
    collapseChar?: string;
    /** Callback when toggled */
    onToggle?: (open: boolean) => void;
}

/**
 * Collapsible — a toggleable section with title and body.
 *
 * Renders:
 * - Row 0: [indicator] [title]
 * - Rows 1+: body lines (if open)
 *
 * Press Enter or Space to toggle open/closed state.
 */
export class Collapsible extends Widget {
    private _title: string;
    private _body: string;
    private _open: boolean;
    private _expandChar: string;
    private _collapseChar: string;
    private _onToggle?: (open: boolean) => void;
    focusable = true;

    constructor(
        title: string,
        body: string,
        style: Partial<Style> = {},
        opts: CollapsibleOptions = {},
    ) {
        const open = opts.open ?? false;
        const bodyLines = opts.open ? body.split('\n').length : 0;
        super({ ...style, height: 1 + bodyLines });
        this._open = open;

        this._title = title;
        this._body = body;
        this._open = opts.open ?? false;
        this._expandChar = opts.expandChar ?? (caps.unicode ? '▶' : '>');
        this._collapseChar = opts.collapseChar ?? (caps.unicode ? '▼' : 'v');
        this._onToggle = opts.onToggle;
    }

    /** Update the title and re-render. */
    setTitle(title: string): void {
        this._title = title;
        this.markDirty();
    }

    /** Update the body and re-render. */
    setBody(body: string): void {
        this._body = body;
        const bodyLines = this._open ? body.split('\n').length : 0;
        this.style.height = 1 + bodyLines;
        this.markDirty();
    }

    /** Toggle between open and closed. Fires onToggle callback. */
    toggle(): void {
        this._open = !this._open;
        const bodyLines = this._open ? this._body.split('\n').length : 0;
        this.style.height = 1 + bodyLines;
        this._onToggle?.(this._open);
        this.markDirty();
    }

    /** Check if currently open. */
    isOpen(): boolean {
        return this._open;
    }

    /**
     * Handle key events.
     */
    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'enter':
            case 'space':
                this.toggle();
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this.style);

        // Row 0: indicator + title
        const indicator = this._open ? this._collapseChar : this._expandChar;
        const titleLine = indicator + ' ' + this._title;
        screen.writeString(x, y, truncate(titleLine, width), attrs);

        // Rows 1+: body (if open)
        if (this._open) {
            const bodyLines = this._body.split('\n');
            for (let i = 0; i < bodyLines.length && i < height - 1; i++) {
                screen.writeString(x, y + 1 + i, truncate(bodyLines[i], width), attrs);
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Kbd widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, stringWidth, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface KbdOptions {
    color?: Color;
}

const BG_COLOR: Color = { type: 'named', name: 'white' };
const FG_COLOR: Color = { type: 'named', name: 'black' };

/**
 * Kbd — an inline label representing a keyboard input.
 *
 * Used for displaying hotkeys or shortcuts (e.g., "Ctrl+C").
 * Renders an inline block with a distinct background to simulate a key press.
 */
export class Kbd extends Widget {
    private _keys: string;
    private _opts: KbdOptions;

    constructor(keys: string, style?: Partial<Style>, opts?: KbdOptions) {
        super(style || {});
        this._keys = keys;
        this._opts = opts || {};
    }

    /** Update the kbd keys. */
    setKeys(keys: string): void {
        if (this._keys === keys) return; 
        this._keys = keys;
        this.markDirty();
    }

    /** Get the current kbd keys. */
    getKeys(): string {
        return this._keys;
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        const bg = BG_COLOR;
        const fg = FG_COLOR;

        // Use opts.color for border if provided, otherwise default to background color
        const borderColor = this._opts.color || bg;

        const textAttrs = { fg, bg, bold: false };
        const borderAttrs = { fg: borderColor, bg, bold: false };

        // Separator style uses standard widget style fallback
        const sepAttrs = { 
            fg: this._style.fg || { type: 'named', name: 'white' }, 
            bg: this._style.bg || { type: 'named', name: 'black' }, 
            bold: false 
        };

        const leftBracket = caps.unicode ? '⟨' : '[';
        const rightBracket = caps.unicode ? '⟩' : ']';

        // Split the keys by '+' and trim any accidental whitespace
        const parts = this._keys.split('+').map(p => p.trim());
        let currentX = x;

        if (height >= 1) {
            for (let i = 0; i < parts.length; i++) {
                const part = parts[i];
                const padded = ` ${part} `;
                const partWidth = stringWidth(padded) + 2; // +2 for brackets

                // Stop rendering if we exceed the widget's allocated width
                if (currentX - x + partWidth > width) break;

                // Draw left bracket
                screen.setCell(currentX, y, { char: leftBracket, ...borderAttrs });

                // Draw the padded text
                const visibleText = padded.slice(0, partWidth - 2);
                screen.writeString(currentX + 1, y, visibleText, textAttrs);

                // Draw right bracket
                screen.setCell(currentX + partWidth - 1, y, { char: rightBracket, ...borderAttrs });

                currentX += partWidth;

                // Draw separator ' + ' if not the last keycap
                if (i < parts.length - 1) {
                    const sep = ' + ';
                    if (currentX - x + stringWidth(sep) <= width) {
                        screen.writeString(currentX, y, sep, sepAttrs);
                        currentX += stringWidth(sep);
                    }
                }
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Timer widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, styleToCellAttrs } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface TimerOptions {
    /** Duration to count down from in milliseconds. */
    duration: number;
    /** Tick interval in milliseconds. Default: 1000. */
    interval?: number;
}

/**
 * Timer — counts down from a duration to zero.
 *
 * - Accepts `duration` in milliseconds.
 * - Exposes `start()`, `stop()`, and `reset()` methods.
 * - Fires `onComplete()` callback when it reaches zero.
 * - Renders as `MM:SS` for durations < 1 hour, `HH:MM:SS` for longer.
 * - Calls `this.markDirty()` on every tick so the render loop re-paints.
 * - Clears the interval on `stop()` and in `destroy()` to prevent leaks.
 */
export class Timer extends Widget {
    /** Duration to count down from (ms). */
    private _duration: number;

    /** Tick interval in ms (default 1000). */
    private _interval: number;

    /** Remaining time in ms. */
    private _remaining: number;

    /** Whether the timer is currently running. */
    private _running = false;

    /** Internal setInterval handle. */
    private _intervalId: ReturnType<typeof setInterval> | undefined;

    /**
     * Called when the countdown reaches zero.
     * Assign a function to this property to receive the event.
     *
     * @example
     * timer.onComplete = () => {};
     */
    onComplete: (() => void) | undefined;

    constructor(options: TimerOptions, style: Partial<Style> = {}) {
        super({ height: 1, ...style });
        this._duration = options.duration;
        this._interval = options.interval ?? 1000;
        this._remaining = options.duration;
    }

    // ── Public API ──────────────────────────────────────────────────────

    /** Start (or resume) the countdown. No-op if already running. */
    start(): void {
        if (this._running) return;
        if (this._remaining <= 0) return; // Already completed
        this._running = true;
        this._intervalId = setInterval(() => this._tick(), this._interval);
    }

    /** Pause the countdown. No-op if already stopped. */
    stop(): void {
        if (!this._running) return;
        this._running = false;
        this._clearInterval();
    }

    /**
     * Reset the remaining time back to the original duration and stop any
     * running countdown.
     */
    reset(): void {
        const wasRunning = this._running;

        this.stop();

        if (!wasRunning && this._remaining === this._duration) {
            return;
        }

        this._remaining = this._duration;
        this.markDirty();
    }

    /** Returns `true` when the countdown has reached zero. */
    isComplete(): boolean {
        return this._remaining <= 0;
    }

    /** Returns the remaining time in milliseconds. */
    getRemaining(): number {
        return this._remaining;
    }

    /**
     * Release all resources held by this widget.
     * Call this when the widget is no longer needed to avoid timer leaks.
     */
    destroy(): void {
        this.stop();
        this._clearInterval();
    }

    // ── Lifecycle ───────────────────────────────────────────────────────

    /** Stop the interval when the widget is unmounted. */
    unmount(): void {
        this._clearInterval();
        super.unmount();
    }

    // ── Internal ────────────────────────────────────────────────────────

    /** Called on each interval tick. */
    private _tick(): void {
        this._remaining = Math.max(0, this._remaining - this._interval);
        this.markDirty();

        if (this._remaining <= 0) {
            this._running = false;
            this._clearInterval();
            this.onComplete?.();
        }
    }

    /** Safely clear the internal interval. */
    private _clearInterval(): void {
        if (this._intervalId !== undefined) {
            clearInterval(this._intervalId);
            this._intervalId = undefined;
        }
    }

    // ── Formatting ──────────────────────────────────────────────────────

    /**
     * Format milliseconds as `MM:SS` or `HH:MM:SS`.
     *
     * Chooses `HH:MM:SS` when the original duration is >= 1 hour (3600000 ms).
     */
    private _format(ms: number): string {
        const totalSeconds = Math.ceil(ms / 1000);
        const hours = Math.floor(totalSeconds / 3600);
        const seconds = totalSeconds % 60;

        const ss = String(seconds).padStart(2, '0');

        if (this._duration >= 3_600_000) {
            const minutes = Math.floor((totalSeconds % 3600) / 60);
            const hh = String(hours).padStart(2, '0');
            const mm = String(minutes).padStart(2, '0');
            return `${hh}:${mm}:${ss}`;
        }

        // MM:SS branch: use total minutes (not modulo 3600) to avoid wrapping
        // when Math.ceil rounds up to exactly 3600 s on a sub-hour timer.
        const minutes = Math.floor(totalSeconds / 60);
        const mm = String(minutes).padStart(2, '0');
        return `${mm}:${ss}`;
    }

    // ── Rendering ───────────────────────────────────────────────────────

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width } = rect;
        if (width <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const label = this._format(this._remaining);

        screen.writeString(x, y, label, attrs);
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — ThinkingBlock widget
// ─────────────────────────────────────────────────────

import {
    type Screen,
    type Style,
    type KeyEvent,
    styleToCellAttrs,
    wordWrap,
    caps,
    prefersReducedMotion,
} from '@termuijs/core';

import { timerPoolSubscribe } from '@termuijs/motion';
import { Widget } from '@termuijs/widgets';

export interface ThinkingBlockOptions {
    width?: number;
    thinking?: string;
}

export class ThinkingBlock extends Widget {
    private _text: string;
    private _expanded = false;
    private _streaming = false;

    private _dots = '';
    private _timerUnsub?: () => void;

    constructor(
        options: ThinkingBlockOptions = {},
        style: Partial<Style> = {},
    ) {
        super(style);

        this._text = options.thinking ?? '';
        this.focusable = true;
    }

    appendText(chunk: string): void {
        this._text += chunk;
        this.markDirty();
    }

    setStreaming(streaming: boolean): void {
        this._streaming = streaming;
        this.markDirty();
    }

    toggle(): void {
        this._expanded = !this._expanded;
        this.markDirty();
    }

    handleKey(event: KeyEvent): void {
        if (event.key === 'enter' || event.key === 't') {
            this.toggle();
        }
    }

    mount(): void {
        super.mount();

        if (prefersReducedMotion()) return;

        this._timerUnsub = timerPoolSubscribe(300, () => {
            this._dots =
                this._dots.length >= 3
                    ? ''
                    : this._dots + '.';

            this.markDirty();
        });
    }

    unmount(): void {
        this._timerUnsub?.();
        this._timerUnsub = undefined;
        super.unmount();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const attrs = styleToCellAttrs(this._style);

        if (!this._expanded) {
            const text = `[thinking${this._streaming ? this._dots : ''}]`;
            screen.writeString(rect.x, rect.y, text, attrs);
            return;
        }

        const boxWidth = Math.max(4, rect.width);

        const tl = caps.unicode ? '┌' : '+';
        const tr = caps.unicode ? '┐' : '+';
        const bl = caps.unicode ? '└' : '+';
        const br = caps.unicode ? '┘' : '+';
        const h = caps.unicode ? '─' : '-';
        const v = caps.unicode ? '│' : '|';

        screen.writeString(
            rect.x,
            rect.y,
            tl + h.repeat(Math.max(0, boxWidth - 2)) + tr,
            attrs,
        );

        const wrapped = wordWrap(
            this._text +
                (this._streaming ? `\n\nthinking${this._dots}` : ''),
            Math.max(1, boxWidth - 4),
        );

        const lines = wrapped.split('\n');

        const availableHeight = Math.max(0, rect.height - 2);
        const limit = Math.min(lines.length, availableHeight);

        for (let i = 0; i < limit; i++) {
            const line = lines[i];

            screen.writeString(
                rect.x,
                rect.y + i + 1,
                v,
                attrs,
            );

            screen.writeString(
                rect.x + 2,
                rect.y + i + 1,
                line,
                attrs,
            );

            screen.writeString(
                rect.x + boxWidth - 1,
                rect.y + i + 1,
                v,
                attrs,
            );
        }

        screen.writeString(
            rect.x,
            rect.y + limit + 1,
            bl + h.repeat(Math.max(0, boxWidth - 2)) + br,
            attrs,
        );
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — StreamingText widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, styleToCellAttrs, wordWrap, caps, prefersReducedMotion } from '@termuijs/core';
import { timerPoolSubscribe } from '@termuijs/motion';
import { Widget } from '@termuijs/widgets';

export interface StreamingTextOptions {
    /** Full text content */
    text: string;
    /** Cursor character. Default: '▋' */
    cursor?: string;
    /** Characters to reveal per tick (0 = show all immediately). Default: 0 */
    speed?: number;
    /** Cursor blink interval in ms. Default: 530 */
    blinkInterval?: number;
}

const segmenter = new Intl.Segmenter();

/**
 * StreamingText — renders text that "streams in" token by token with a blinking cursor.
 *
 * Useful for displaying AI response streams or typewriter-style text effects.
 *
 * - When `speed === 0`: shows full text immediately, cursor blinks at end.
 * - When `speed > 0`: reveals `speed` chars per `tick()` call until complete.
 * - Cursor blinks every `blinkInterval` ms via the shared timer pool.
 */
export class StreamingText extends Widget {
    private _text: string;
    private _cursor: string;
    private _speed: number;
    private _blinkInterval: number;
    /** Number of characters currently revealed (used when speed > 0) */
    private _revealed: number;
    private _cursorVisible: boolean;
    private _blinkUnsub?: () => void;

    constructor(options: StreamingTextOptions, style: Partial<Style> = {}) {
        super(style);
        this._text = options.text;
        this._cursor = options.cursor ?? (caps.unicode ? '▋' : '_');
        this._speed = options.speed ?? 0;
        this._blinkInterval = options.blinkInterval ?? 530;
        this._revealed = 0;
        this._cursorVisible = true;
    }

    /** Replace text content and reset the revealed counter to 0. */
    setText(text: string): void {
        if (text === this._text) return;
        this._text = text;
        this._revealed = 0;
        this.markDirty();
    }

    /**
     * Advance `_revealed` by `speed` characters.
     * Call this from an external tick/render loop when `speed > 0`.
     */
    tick(): void {
        if (this._speed <= 0 || this.isComplete()) return;
        const len = Array.from(segmenter.segment(this._text)).length;
        this._revealed = Math.min(this._revealed + this._speed, len);
        this.markDirty();
    }

    /** Returns true when all text has been revealed. */
    isComplete(): boolean {
        if (this._speed === 0) return true;
        const len = Array.from(segmenter.segment(this._text)).length;
        return this._revealed >= len;
    }

    /** Lifecycle: start the blink timer (only when motion is enabled). */
    mount(): void {
        super.mount();
        if (prefersReducedMotion()) {
            this._cursorVisible = false;  // Don't show cursor in reduced-motion
            return;
        }
        this._blinkUnsub = timerPoolSubscribe(this._blinkInterval, () => {
            this._cursorVisible = !this._cursorVisible;
            this.markDirty();
        });
    }

    /** Lifecycle: stop the blink timer. */
    unmount(): void {
        this._blinkUnsub?.();
        this._blinkUnsub = undefined;
        super.unmount();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        // Determine how much text to display
        const segments = Array.from(segmenter.segment(this._text));
        const displayText = this._speed > 0
            ? segments.slice(0, this._revealed).map(s => s.segment).join('')
            : this._text;

        // Append cursor if visible
        const fullText = this._cursorVisible
            ? displayText + this._cursor
            : displayText;

        // Word-wrap to fit within content width
        const wrapped = wordWrap(fullText, width);
        const lines = wrapped.split('\n');

        // Render up to rect.height lines
        const limit = Math.min(lines.length, height);
        for (let i = 0; i < limit; i++) {
            const line = lines[i];
            if (line === undefined) continue;
            screen.writeString(x, y + i, line, attrs);
        }
    }
}

// -----------------------------------------------------------------------------
// @termuijs/widgets - Watermark widget
// -----------------------------------------------------------------------------

import { type Screen, type Style, type Color, styleToCellAttrs, stringWidth } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface WatermarkOptions {
    /** Color of the repeated text. Default: brightBlack */
    color?: Color;
    /** Diagonal tilt angle in characters. 0 = horizontal rows. Default: 0 */
    angle?: 0 | 45;
}

const segmenter = new Intl.Segmenter();

/**
 * Watermark - fills its area with faint repeating text.
 */
export class Watermark extends Widget {
    private _text: string;
    private _color: Color;
    private _angle: 0 | 45;

    constructor(text: string, style: Partial<Style> = {}, opts: WatermarkOptions = {}) {
        super(style);
        this._text = text;
        this._color = opts.color ?? { type: 'named', name: 'brightBlack' };
        this._angle = opts.angle ?? 0;
    }

    setText(text: string): void {
        if (this._text === text) return;
        this._text = text;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._getContentRect();
        if (width <= 0 || height <= 0 || this._text.length === 0) return;

        const attrs = { ...styleToCellAttrs(this._style), fg: this._color };
        const rowOffsetStep = this._angle === 45 ? 1 : 0;

        const segments = Array.from(segmenter.segment(this._text)).map(s => s.segment);
        if (segments.length === 0) return;

        for (let row = 0; row < height; row++) {
            let col = 0;
            // row * rowOffsetStep produces the 45° horizontal offset per row
            // row * width contributes to linearizing row/col into the segments index
            let index = (row * width + row * rowOffsetStep) % segments.length;

            while (col < width) {
                const char = segments[index];
                const charWidth = Math.max(1, stringWidth(char));

                if (col + charWidth > width) break;

                screen.setCell(x + col, y + row, {
                    char,
                    width: charWidth,
                    ...attrs,
                });

                for (let i = 1; i < charWidth; i++) {
                    if (col + i < width) {
                        screen.setCell(x + col + i, y + row, {
                            char: '',
                            width: 0,
                            ...attrs,
                        });
                    }
                }
                col += charWidth;
                index = (index + 1) % segments.length;
            }
        }
    }
}

import { Widget } from '@termuijs/widgets';
import { type Screen, type Style, caps, styleToCellAttrs, stringWidth, prefersReducedMotion } from '@termuijs/core';

// ─────────────────────────────────────────────────────────────────────────────
// TypewriterOptions
// ─────────────────────────────────────────────────────────────────────────────

export interface TypewriterOptions {
  /** Characters revealed per tick. Must be a positive integer. Default: 1 */
  speed?: number;
  /** Cursor glyph drawn at the reveal head. Default: caps-aware block. */
  cursor?: string;
}

// ─────────────────────────────────────────────────────────────────────────────
// Typewriter
// ─────────────────────────────────────────────────────────────────────────────

const segmenter = new Intl.Segmenter();

/**
 * Reveals static text character by character.
 *
 * The host is responsible for calling `tick()` at whatever cadence it likes
 * (timer, animation loop, etc.). No internal timer is used.
 *
 * @example
 * ```ts
 * const tw = new Typewriter('hello world');
 * const interval = setInterval(() => {
 *   tw.tick();
 *   screen.render();
 * }, 80);
 * ```
 */
export class Typewriter extends Widget {
  private _text: string;
  private _revealed: number;
  private _speed: number;
  private _cursor: string | undefined;

  constructor(
    text: string,
    style: Partial<Style> = {},
    opts: TypewriterOptions = {},
  ) {
    super(style);
    this._text = text;
    this._revealed = 0;
    // Clamp speed to a positive integer: non-positive, NaN, and fractional
    // values would cause reveal to stall or behave non-deterministically.
    const raw = opts.speed ?? 1;
    this._speed = Number.isFinite(raw) && raw > 0 ? Math.floor(raw) : 1;
    // undefined means "auto from caps at render time"; a caller-supplied string
    // overrides it unconditionally.
    this._cursor = opts.cursor;
  }

  // ── Public mutating methods ────────────────────────────────────────────────

  /** Advance the reveal head by `speed` characters. No-op once fully revealed. */
  tick(): void {
    const len = Array.from(segmenter.segment(this._text)).length;

    if (prefersReducedMotion()) {
      if (this._revealed >= len) return;
      this._revealed = len;
      this.markDirty();
      return;
    }

    if (this._revealed >= len) return;

    this._revealed = Math.min(this._revealed + this._speed, len);
    this.markDirty();
  }

  /** Return the reveal counter to zero. */
  reset(): void {
    this._revealed = 0;
    this.markDirty();
  }

  /** Replace the text and reset the reveal counter. */
  setText(text: string): void {
    this._text = text;
    this._revealed = 0;
    this.markDirty();
  }

  // ── Rendering ─────────────────────────────────────────────────────────────

  protected _renderSelf(screen: Screen): void {
    const { x, y, width, height } = this._getContentRect();
    if (width <= 0 || height <= 0) return;

    const segments = Array.from(segmenter.segment(this._text));
    const fullyRevealed = this._revealed >= segments.length;

    // Cursor glyph: caller-supplied string wins; otherwise caps-aware default.
    const cursorGlyph =
      this._cursor ?? (caps.unicode ? '▋' : '_');

    // Visible text slice (by grapheme cluster count).
    const visibleText = segments.slice(0, this._revealed).map(s => s.segment).join('');

    // Append cursor when not yet fully revealed.
    const lineWithCursor = fullyRevealed
      ? visibleText
      : visibleText + cursorGlyph;

    // Truncate to the available terminal columns using display-width-aware
    // slicing so that full-width Unicode glyphs (e.g. CJK) never overflow
    // the content rect. stringWidth() counts terminal columns, not code units.
    let line = '';
    let cols = 0;
    const lineSegments = segmenter.segment(lineWithCursor);
    for (const { segment } of lineSegments) {
      const w = stringWidth(segment);
      if (cols + w > width) break;
      line += segment;
      cols += w;
    }

    const attrs = styleToCellAttrs(this._style);
    screen.writeString(x, y, line, attrs);
  }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Timeline widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, styleToCellAttrs, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export type TimelineStatus = 'done' | 'active' | 'pending';

export interface TimelineItem {
    title: string;
    time?: string;
    status?: TimelineStatus;
}

/**
 * Timeline — renders a vertical list of timeline items.
 *
 * Each item gets a connector (├─ / └─) and a status icon:
 *   ● active (cyan/bold), ✓ done (green), ○ pending (dim).
 */
export class Timeline extends Widget {
    private _items: TimelineItem[];

    constructor(
        items: TimelineItem[],
        style: Partial<Style> = {},
    ) {
        super(style);
        this._items = items;
    }

    setItems(items: TimelineItem[]): void {
        this._items = items;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0 || this._items.length === 0) return;

        const attrs = styleToCellAttrs(this._style);
        const visibleCount = Math.min(this._items.length, height);

        for (let i = 0; i < visibleCount; i++) {
            const item = this._items[i];
            const isLast = i === this._items.length - 1;
            const status = item.status ?? 'pending';

            let connector: string;
            if (isLast) {
                connector = '\u2514\u2500'; // └─
            } else {
                connector = '\u251C\u2500'; // ├─
            }

            let icon: string;
            if (caps.unicode) {
                switch (status) {
                    case 'active':
                        icon = '\u25CF'; // ●
                        break;
                    case 'done':
                        icon = '\u2713'; // ✓
                        break;
                    default:
                        icon = '\u25CB'; // ○
                        break;
                }
            } else {
                switch (status) {
                    case 'done':
                        icon = 'v';
                        break;
                    default:
                        icon = 'o';
                        break;
                }
            }

            const isActive = status === 'active';
            const isDone = status === 'done';
            const isPending = status === 'pending';

            const statusColor: Color = isDone
                ? { type: 'named', name: 'green' }
                : isActive
                    ? { type: 'named', name: 'cyan' }
                    : { type: 'named', name: 'white' };

            // Connector + icon portion: e.g. "├─ ● "
            const iconX = x + connector.length;
            const titleX = iconX + 2;

            screen.writeString(x, y + i, connector, {
                ...attrs,
                fg: statusColor,
                bold: isActive,
                dim: isPending,
            });

            screen.setCell(iconX, y + i, {
                char: icon,
                fg: statusColor,
                bold: isActive,
                dim: isPending,
            });

            screen.writeString(titleX, y + i, item.title, {
                ...attrs,
                bold: isActive,
                dim: isPending,
            });

            // Time — dimmed right-aligned
            if (item.time) {
                const timeStr = ` ${item.time}`;
                const timeX = x + width - timeStr.length;
                if (timeX > titleX) {
                    screen.writeString(timeX, y + i, timeStr, {
                        ...attrs,
                        dim: true,
                    });
                }
            }
        }
    }
}

// @termuijs/widgets - NotificationBadge widget

import { type Screen, type Style, type Color, stringWidth } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export type BadgePosition = 'top-right' | 'top-left' | 'bottom-right' | 'bottom-left';

export interface NotificationBadgeOptions {
    /** Notification count to display. Default: 0. */
    count?: number;
    /** Corner position for the badge. Default: 'top-right'. */
    position?: BadgePosition;
}

/** Badge background: red, the universal notification color. */
const BADGE_BG: Color = { type: 'named', name: 'red' };

/** Badge foreground: white for contrast on red. */
const BADGE_FG: Color = { type: 'named', name: 'white' };

/**
 * NotificationBadge - a small count label rendered at a corner position.
 *
 * Used for unread counts, alert indicators, and notification overlays.
 * Renders the count as a compact colored label at one of four corner positions.
 * Shows "99+" when the count exceeds 99. Renders nothing when count is 0.
 */
export class NotificationBadge extends Widget {
    private _count: number;
    private _position: BadgePosition;

    constructor(opts: NotificationBadgeOptions = {}, style: Partial<Style> = {}) {
        super(style);
        this._count = opts.count ?? 0;
        this._position = opts.position ?? 'top-right';
    }

    /** Update the notification count. */
    setCount(count: number): void {
        if (count === this._count) return;
        this._count = count;
        this.markDirty();
    }

    /** Get the current notification count. */
    getCount(): number {
        return this._count;
    }

    /** Update the badge position. */
    setPosition(position: BadgePosition): void {
        if (position === this._position) return;
        this._position = position;
        this.markDirty();
    }

    /** Get the current badge position. */
    getPosition(): BadgePosition {
        return this._position;
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        // Show nothing when count is zero
        if (this._count === 0) return;

        // Format the label: "99+" for counts over 99
        const label = this._count > 99 ? '99+' : String(this._count);
        const labelWidth = stringWidth(label);

        // Compute badge position based on corner setting
        let bx: number;
        let by: number;

        switch (this._position) {
            case 'top-left':
                bx = x;
                by = y;
                break;
            case 'top-right':
                bx = x + width - labelWidth;
                by = y;
                break;
            case 'bottom-left':
                bx = x;
                by = y + height - 1;
                break;
            case 'bottom-right':
                bx = x + width - labelWidth;
                by = y + height - 1;
                break;
        }

        // Clamp to widget bounds
        bx = Math.max(x, bx);

        // Render the label with notification colors
        const attrs = { fg: BADGE_FG, bg: BADGE_BG, bold: true };
        screen.writeString(bx, by, label, attrs);
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Tree widget (collapsible hierarchy)
// ─────────────────────────────────────────────────────

import {
    type Screen,
    type Style,
    styleToCellAttrs,
    truncate,
    stringWidth,
    caps,
    normalizeNavigationKey,
} from '@termuijs/core';
import { Widget } from '@termuijs/widgets';
import { computeRange } from '@termuijs/widgets';

export interface TreeNode {
    label: string;
    children?: TreeNode[];
    expanded?: boolean; // default: false
    data?: unknown;     // user data attached to node
}

export interface TreeOptions {
    nodes: TreeNode[];
    onSelect?: (node: TreeNode, path: number[]) => void;
    indent?: number;    // spaces per level, default 2
}

interface VisibleEntry {
    node: TreeNode;
    depth: number;
    path: number[];
}

/**
 * Tree — a collapsible tree widget for displaying hierarchical data.
 *
 * Supports:
 * - Expand/collapse of parent nodes
 * - Keyboard navigation (up/down/left/right, j/k/h/l, home/end)
 * - Enter/Space to toggle or select
 * - onSelect callback for leaf nodes
 * - Unicode and ASCII fallback symbols
 * - Scrolling when tree exceeds visible height
 * - Virtualized rendering
 */
export class Tree extends Widget {
    private _nodes: TreeNode[];
    private _onSelect?: (node: TreeNode, path: number[]) => void;
    protected _indent: number;
    protected _selectedIndex = 0;
    protected _scrollOffset = 0;
    protected _visibleNodes: VisibleEntry[] = [];

    constructor(options: TreeOptions, style: Partial<Style> = {}) {
        super(style);
        this._nodes = options.nodes;
        this._onSelect = options.onSelect;
        this._indent = options.indent ?? 2;
        this.focusable = true;
        this._buildVisibleNodes();
    }

    // ── Public API ─────────────────────────────────────

    get selectedIndex(): number { return this._selectedIndex; }

    get selectedNode(): TreeNode | undefined {
        return this._visibleNodes[this._selectedIndex]?.node;
    }

    setNodes(nodes: TreeNode[]): void {
        this._nodes = nodes;
        this._selectedIndex = 0;
        this._scrollOffset = 0;
        this._buildVisibleNodes();
        this.markDirty();
    }

    /** Move cursor up one visible row */
    movePrev(): void {
        if (this._selectedIndex > 0) {
            this._selectedIndex--;
            this._clampScroll();
            this.markDirty();
        }
    }

    /** Move cursor down one visible row */
    moveNext(): void {
        if (this._selectedIndex < this._visibleNodes.length - 1) {
            this._selectedIndex++;
            this._clampScroll();
            this.markDirty();
        }
    }

    /** Go to first visible node */
    moveFirst(): void {
        this._selectedIndex = 0;
        this._clampScroll();
        this.markDirty();
    }

    /** Go to last visible node */
    moveLast(): void {
        if (this._visibleNodes.length > 0) {
            this._selectedIndex = this._visibleNodes.length - 1;
            this._clampScroll();
            this.markDirty();
        }
    }

    /** Expand the selected node (if it's a collapsed parent) */
    expand(): void {
        const entry = this._visibleNodes[this._selectedIndex];
        if (!entry) return;
        const node = entry.node;
        if (_isParent(node) && !node.expanded) {
            node.expanded = true;
            this._buildVisibleNodes();
            this.markDirty();
        }
    }

    /** Collapse the selected node, or move to parent if already collapsed/leaf */
    collapse(): void {
        const entry = this._visibleNodes[this._selectedIndex];
        if (!entry) return;
        const node = entry.node;

        if (_isParent(node) && node.expanded) {
            // Collapse current node
            node.expanded = false;
            this._buildVisibleNodes();
            this._clampScroll();
            this.markDirty();
        } else if (entry.depth > 0) {
            // Move to parent
            const parentPath = entry.path.slice(0, -1);
            const parentIdx = this._visibleNodes.findIndex(
                e => _pathsEqual(e.path, parentPath),
            );
            if (parentIdx >= 0) {
                this._selectedIndex = parentIdx;
                this._clampScroll();
                this.markDirty();
            }
        }
    }

    /** Toggle expand/collapse (parent) or call onSelect (leaf) */
    toggle(): void {
        const entry = this._visibleNodes[this._selectedIndex];
        if (!entry) return;
        const node = entry.node;

        if (_isParent(node)) {
            node.expanded = !node.expanded;
            this._buildVisibleNodes();
            this._clampScroll();
            this.markDirty();
        } else {
            // Leaf — call onSelect
            this._onSelect?.(node, entry.path);
        }
    }

    /**
     * Handle a key event. Call this from your app's key-routing logic
     * when this widget is focused.
     */
    handleKey(key: string): void {
        const normalized = normalizeNavigationKey(key.toLowerCase());
        switch (normalized) {
            case 'arrowup':
            case 'up':
                this.movePrev();
                break;
            case 'arrowdown':
            case 'down':
                this.moveNext();
                break;
            case 'enter':
            case ' ':
            case 'space':
                this.toggle();
                break;
            case 'arrowleft':
            case 'left':
                this.collapse();
                break;
            case 'arrowright':
            case 'right':
                this.expand();
                break;
            case 'home':
                this.moveFirst();
                break;
            case 'end':
                this.moveLast();
                break;
        }
    }

    // ── Rendering ──────────────────────────────────────

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const useUnicode = caps.unicode;

        const collapsedChevron = useUnicode ? '▶ ' : '> ';
        const expandedChevron  = useUnicode ? '▼ ' : 'v ';
        const leafPrefix       = useUnicode ? '• ' : '* ';

        // Use the virtualization engine
        const range = computeRange(this._scrollOffset, height, this._visibleNodes.length, 0);

        for (let entryIdx = range.start; entryIdx < range.end; entryIdx++) {
            const entry = this._visibleNodes[entryIdx];
            const { node, depth } = entry;
            const isSelected = entryIdx === this._selectedIndex;

            const screenY = y + (entryIdx - this._scrollOffset);
            if (screenY < y || screenY >= y + height) continue;

            // Build line text
            const indentStr = ' '.repeat(this._indent * depth);
            let chevron: string;
            if (_isParent(node)) {
                chevron = node.expanded ? expandedChevron : collapsedChevron;
            } else {
                chevron = leafPrefix;
            }
            let line = indentStr + chevron + node.label;
            line = truncate(line, width);

            // Cell style for selected row
            const cellStyle = isSelected && this.isFocused
                ? {
                    ...attrs,
                    bg: { type: 'named' as const, name: 'blue' as const },
                    bold: true,
                }
                : isSelected
                    ? { ...attrs, bold: true }
                    : attrs;

            screen.writeString(x, screenY, line, cellStyle);

            // Fill rest of row for selection highlight
            if (isSelected && this.isFocused) {
                const lineWidth = stringWidth(line);
                const remaining = width - lineWidth;
                for (let c = 0; c < remaining; c++) {
                    screen.setCell(x + lineWidth + c, screenY, {
                        char: ' ',
                        ...cellStyle,
                    });
                }
            }
        }
    }

    // ── Private helpers ────────────────────────────────

    /** Rebuild the flat visible-node list from the tree */
    private _buildVisibleNodes(): void {
        this._visibleNodes = [];
        _collectVisible(this._nodes, 0, [], this._visibleNodes);
        // If the visible set shrank (e.g. a parent collapsed elsewhere),
        // ensure the selected index remains in-bounds.
        if (this._selectedIndex >= this._visibleNodes.length) {
            this._selectedIndex = Math.max(0, this._visibleNodes.length - 1);
            this._clampScroll();
        }
    }

    /** Ensure scroll keeps the selected index in view */
    private _clampScroll(): void {
        const rect = this._getContentRect();
        const visibleHeight = rect.height > 0 ? rect.height : 24; // fallback for zero-rect

        if (this._selectedIndex < this._scrollOffset) {
            this._scrollOffset = this._selectedIndex;
        }
        if (this._selectedIndex >= this._scrollOffset + visibleHeight) {
            this._scrollOffset = this._selectedIndex - visibleHeight + 1;
        }
        this._scrollOffset = Math.max(0, this._scrollOffset);
    }
}

// ── Module-level helpers ───────────────────────────────

function _isParent(node: TreeNode): boolean {
    return Array.isArray(node.children) && node.children.length > 0;
}

function _pathsEqual(a: number[], b: number[]): boolean {
    if (a.length !== b.length) return false;
    for (let i = 0; i < a.length; i++) {
        if (a[i] !== b[i]) return false;
    }
    return true;
}

function _collectVisible(
    nodes: TreeNode[],
    depth: number,
    parentPath: number[],
    out: VisibleEntry[],
): void {
    for (let i = 0; i < nodes.length; i++) {
        const node = nodes[i];
        const path = [...parentPath, i];
        out.push({ node, depth, path });
        if (_isParent(node) && node.expanded) {
            _collectVisible(node.children!, depth + 1, path, out);
        }
    }
}

import { type Screen, type Style, type KeyEvent } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';
import { ChatMessage } from '@termuijs/widgets';

export interface ThreadMessage {
    role: 'user' | 'assistant' | 'system';
    content: string;
}

export class ChatThread extends Widget {
    private _messages: ThreadMessage[] = [];
    private _scrollOffset = 0;

    constructor(
        style: Partial<Style> = {},
        messages: ThreadMessage[] = [],
    ) {
        super(style);
        this._messages = messages.slice();
        this.focusable = true;
    }

    addMessage(message: ThreadMessage): void {
        this._messages.push(message);
        this._scrollToBottom();
        this.markDirty();
    }

    private _scrollToBottom(): void {
        const rect = this._getContentRect();
        const visibleRows = Math.max(1, rect.height);

        this._scrollOffset = Math.max(
            0,
            this._messages.length - visibleRows,
        );
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'up':
                this._scrollOffset = Math.max(
                    0,
                    this._scrollOffset - 1,
                );
                this.markDirty();
                break;

            case 'down': {
                const rect = this._getContentRect();
                const visibleRows = Math.max(1, rect.height);

                const maxOffset = Math.max(
                    0,
                    this._messages.length - visibleRows,
                );

                this._scrollOffset = Math.min(
                    maxOffset,
                    this._scrollOffset + 1,
                );

                this.markDirty();
                break;
            }
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;

        if (width <= 0 || height <= 0) {
            return;
        }

        const visibleMessages = this._messages.slice(
            this._scrollOffset,
            this._scrollOffset + height,
        );

        for (let i = 0; i < visibleMessages.length; i++) {
            const msg = visibleMessages[i];

            const widget = new ChatMessage({
                role: msg.role,
                content: msg.content,
            });

            let msgX = x;

            if (msg.role === 'user') {
                msgX = x + Math.floor(width / 2);
            } else if (msg.role === 'system') {
                msgX = x + Math.floor(width / 4);
            }

            widget.updateRect({
                x: msgX,
                y: y + i,
                width: Math.floor(width / 2),
                height: 2,
            });

            widget.render(screen);
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Stepper widget
// Renders sequential step progress with status indicators
// ─────────────────────────────────────────────────────

import {
    type Screen,
    type Style,
    type Color,
    styleToCellAttrs,
    stringWidth,
    truncate,
    caps,
} from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export type StepStatus = 'completed' | 'active' | 'pending';
export type StepperOrientation = 'horizontal' | 'vertical';

export interface StepperStep {
    /** Step label */
    label: string;
    /** Step status. Default: 'pending' */
    status?: StepStatus;
}

export interface StepperOptions {
    /** Layout direction. Default: 'horizontal' */
    orientation?: StepperOrientation;
    /** Color for active step. Default: cyan */
    activeColor?: Color;
    /** Color for completed step. Default: green */
    completedColor?: Color;
    /** Color for pending step. Default: white */
    pendingColor?: Color;
}

/**
 * Stepper — renders a sequence of steps with status indicators.
 *
 * Horizontal example:
 *   ✓ Setup ──── ● Config ──── ○ Review ──── ○ Done
 *
 * Vertical example:
 *   ✓ Setup
 *   │
 *   ● Config
 *   │
 *   ○ Review
 *
 * Icons: ✓/+ (completed), ●/* (active), ○/- (pending)
 * Unicode fallback via caps.unicode.
 */
export class Stepper extends Widget {
    private _steps: StepperStep[];
    private _orientation: StepperOrientation;
    private _activeColor: Color;
    private _completedColor: Color;
    private _pendingColor: Color;

    constructor(
        steps: StepperStep[],
        style: Partial<Style> = {},
        opts: StepperOptions = {},
    ) {
        super(style);
        // Clone steps to prevent external mutation bypassing markDirty()
        this._steps = steps.map(s => ({ ...s }));
        this._orientation = opts.orientation ?? 'horizontal';
        this._activeColor = opts.activeColor ?? { type: 'named', name: 'cyan' };
        this._completedColor = opts.completedColor ?? { type: 'named', name: 'green' };
        this._pendingColor = opts.pendingColor ?? { type: 'named', name: 'white' };
    }

    // ── Public API ──────────────────────────────────────────────────────

    /** Replace all steps. Clones input to prevent external mutation. */
    setSteps(steps: StepperStep[]): void {
        this._steps = steps.map(s => ({ ...s }));
        this.markDirty();
    }

    /** Get current steps. Returns copies to prevent external mutation. */
    getSteps(): StepperStep[] {
        return this._steps.map(s => ({ ...s }));
    }

    /** Update the status of a single step by index. */
    setStepStatus(index: number, status: StepStatus): void {
        if (index < 0 || index >= this._steps.length) return;
        this._steps[index].status = status;
        this.markDirty();
    }

    /** Advance the active step to the next one. */
    nextStep(): void {
        const activeIdx = this._steps.findIndex(s => s.status === 'active');
        if (activeIdx === -1 || activeIdx >= this._steps.length - 1) return;
        this._steps[activeIdx].status = 'completed';
        this._steps[activeIdx + 1].status = 'active';
        this.markDirty();
    }

    /** Move the active step to the previous one. */
    prevStep(): void {
        const activeIdx = this._steps.findIndex(s => s.status === 'active');
        if (activeIdx <= 0) return;
        this._steps[activeIdx].status = 'pending';
        this._steps[activeIdx - 1].status = 'active';
        this.markDirty();
    }

    // ── Render ──────────────────────────────────────────────────────────

    /** Render all steps with connectors and status icons. */
    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0 || this._steps.length === 0) return;

        if (this._orientation === 'horizontal') {
            this._renderHorizontal(screen, x, y, width);
        } else {
            this._renderVertical(screen, x, y, width, height);
        }
    }

    // ── Private ─────────────────────────────────────────────────────────

    /** Render steps left-to-right on a single row. */
    private _renderHorizontal(
        screen: Screen,
        x: number,
        y: number,
        width: number,
    ): void {
        const attrs = styleToCellAttrs(this._style);
        const connector = caps.unicode ? '────' : '----';
        let cursorX = x;

        for (let i = 0; i < this._steps.length; i++) {
            if (cursorX >= x + width) break;
            const step = this._steps[i];
            const status = step.status ?? 'pending';
            const { icon, color, bold, dim } = this._stepStyle(status);

            // Icon
            screen.setCell(cursorX, y, { char: icon, fg: color, bold, dim });
            cursorX++;

            // Space + label
            const labelStr = ' ' + step.label;
            const labelWidth = stringWidth(labelStr);
            if (cursorX + labelWidth > x + width) break;
            screen.writeString(cursorX, y, labelStr, { ...attrs, fg: color, bold, dim });
            cursorX += labelWidth;

            // Connector between steps (not after last)
            if (i < this._steps.length - 1) {
                const connWidth = stringWidth(connector);
                if (cursorX + connWidth > x + width) break;
                screen.writeString(cursorX, y, connector, {
                    ...attrs,
                    fg: { type: 'named', name: 'brightBlack' },
                });
                cursorX += connWidth;
            }
        }
    }

    /** Render steps top-to-bottom with vertical connectors. */
    private _renderVertical(
        screen: Screen,
        x: number,
        y: number,
        width: number,
        height: number,
    ): void {
        const attrs = styleToCellAttrs(this._style);
        const connectorChar = caps.unicode ? '│' : '|';
        let row = 0;

        for (let i = 0; i < this._steps.length; i++) {
            if (row >= height) break;
            const step = this._steps[i];
            const status = step.status ?? 'pending';
            const { icon, color, bold, dim } = this._stepStyle(status);

            // Icon + label row — use truncate for correct terminal cell width clipping
            const line = icon + ' ' + step.label;
            screen.writeString(x, y + row, truncate(line, width), {
                ...attrs,
                fg: color,
                bold,
                dim,
            });
            row++;

            // Connector row between steps (not after last)
            if (i < this._steps.length - 1 && row < height) {
                screen.setCell(x, y + row, {
                    char: connectorChar,
                    fg: { type: 'named', name: 'brightBlack' },
                });
                row++;
            }
        }
    }

    /** Returns the icon, color, and text attributes for a given status. */
    private _stepStyle(status: StepStatus): {
        icon: string;
        color: Color;
        bold: boolean;
        dim: boolean;
    } {
        switch (status) {
            case 'completed':
                return {
                    icon: caps.unicode ? '✓' : '+',
                    color: this._completedColor,
                    bold: false,
                    dim: false,
                };
            case 'active':
                return {
                    icon: caps.unicode ? '●' : '*',
                    color: this._activeColor,
                    bold: true,
                    dim: false,
                };
            default:
                return {
                    icon: caps.unicode ? '○' : '-',
                    color: this._pendingColor,
                    bold: false,
                    dim: true,
                };
        }
    }
}

import { type Screen, type Style, styleToCellAttrs, stringWidth, prefersReducedMotion } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export type MarqueeDirection = 'left' | 'right';

export interface MarqueeOptions {
    direction?: MarqueeDirection;
    speed?: number;
    gap?: number;
}

export class Marquee extends Widget {
    private _text: string;
    private _direction: MarqueeDirection;
    private _speed: number;
    private _gap: number;
    private _offset: number = 0;

    constructor(text: string, style: Partial<Style> = {}, opts: MarqueeOptions = {}) {
        super(style);
        this._text = text;
        this._direction = opts.direction ?? 'left';
        this._speed = opts.speed ?? 1;
        this._gap = opts.gap ?? 4;
    }

    tick(): void {
        if (prefersReducedMotion()) return;
        this._offset += this._speed;
        this.markDirty();
    }

    setText(text: string): void {
        if (text === this._text) return;
        this._text = text;
        this._offset = 0;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0 || !this._text) return;

        const attrs = styleToCellAttrs(this._style);

        const textW = stringWidth(this._text);
        if (textW === 0) return;

        const gapSpaces = ' '.repeat(this._gap);
        const repeatLen = textW + this._gap;

        const totalNeeded = width + repeatLen;
        const repeats = Math.ceil(totalNeeded / repeatLen);
        let full = '';
        for (let i = 0; i < repeats; i++) {
            full += this._text + gapSpaces;
        }

        const effectiveOffset = this._direction === 'left'
            ? (this._offset % repeatLen)
            : (repeatLen - (this._offset % repeatLen));

        const start = effectiveOffset % full.length;
        const visible = full.slice(start, start + width);

        screen.writeString(x, y, visible, attrs);
    }
}

import { Widget } from '@termuijs/widgets';
import { type Style, type Color, type Screen, caps, styleToCellAttrs, parseColor, stringWidth } from '@termuijs/core';

export interface LinkOptions {
    /** The target URL for the OSC 8 hyperlink anchor. */
    url: string;
    /** Underline and anchor fallback color object. Default: blue */
    color?: Color;
    /** Whether to append the URL visually when terminal capabilities lack unicode/OSC 8 support. Default: true */
    showUrlFallback?: boolean;
}

export class Link extends Widget {
    private _text: string;
    private _url: string;
    private _color: Color;
    private _showUrlFallback: boolean;

    // Fixed constructor mapping: opts is now required to prevent missing URL type errors
    constructor(text: string, style: Partial<Style> | undefined, opts: LinkOptions) {
        super(style);

        this._text = text;
        this._url = opts.url;
        this._color = opts.color ?? parseColor('blue');
        this._showUrlFallback = opts.showUrlFallback ?? true;
    }

    public setText(text: string): void {
        if (this._text !== text) {
            this._text = text;
            this.markDirty();
        }
    }

    public setUrl(url: string): void {
        if (this._url !== url) {
            this._url = url;
            this.markDirty();
        }
    }

    /**
     * Helper to safely slice text based on its visible terminal cell width grid blocks
     */
    private _sliceByWidth(str: string, maxWidth: number): string {
        let currentWidth = 0;
        let result = '';
        for (const char of str) {
            const charWidth = stringWidth(char);
            if (currentWidth + charWidth > maxWidth) {
                break;
            }
            result += char;
            currentWidth += charWidth;
        }
        return result;
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        if (rect.width <= 0 || rect.height <= 0) {
            return;
        }

        let targetText = this._text;
        let cellLinkTarget: string | undefined = undefined;

        // 1. If terminal environment supports modern capabilities, set the metadata link directly
        if (caps.unicode) {
            cellLinkTarget = this._url;
            if (stringWidth(targetText) > rect.width) {
                targetText = this._sliceByWidth(targetText, rect.width);
            }
        } 
        // 2. Fallback execution layout block for legacy or raw non-unicode terminal windows
        else if (this._showUrlFallback && this._url) {
            const fallbackSuffix = ` (${this._url})`;
            if (stringWidth(targetText + fallbackSuffix) > rect.width) {
                const availableWidthForText = rect.width - stringWidth(fallbackSuffix);
                targetText = availableWidthForText > 0 
                    ? this._sliceByWidth(targetText, availableWidthForText) + fallbackSuffix
                    : this._sliceByWidth(fallbackSuffix, rect.width);
            } else {
                targetText = targetText + fallbackSuffix;
            }
        } else {
            if (stringWidth(targetText) > rect.width) {
                targetText = this._sliceByWidth(targetText, rect.width);
            }
        }

        const cellAttrs = styleToCellAttrs({
            underline: true,
            fg: this._color,
            ...this.style,
        });

        // screen.writeString will map this property directly to cell.link without breaking string widths!
        screen.writeString(rect.x, rect.y, targetText, {
            ...cellAttrs,
            link: cellLinkTarget
        });
    }
}

// -----------------------------------------------------------------------------
// @termuijs/widgets - Placeholder widget
// -----------------------------------------------------------------------------

import { type Screen, type Style, type Color, caps, stringWidth, styleToCellAttrs } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface PlaceholderOptions {
    /** Fill character. Default: '░' with ASCII fallback '.' */
    fillChar?: string;
    borderColor?: Color;
    labelColor?: Color;
}

/**
 * Placeholder - a labeled stand-in box for prototyping terminal layouts.
 */
export class Placeholder extends Widget {
    private _label: string;
    private _fillChar?: string;
    private _borderColor?: Color;
    private _labelColor?: Color;

    constructor(label: string, style: Partial<Style> = {}, opts: PlaceholderOptions = {}) {
        super(style);
        this._label = label;
        this._fillChar = opts.fillChar;
        this._borderColor = opts.borderColor;
        this._labelColor = opts.labelColor;
    }

    setLabel(label: string): void {
        if (this._label === label) return;
        this._label = label;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._getContentRect();
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const fillAttrs = { ...attrs };
        const borderAttrs = { ...attrs, fg: this._borderColor };
        const labelAttrs = { ...attrs, fg: this._labelColor };

        const fillChar = this._fillChar ?? (caps.unicode ? '\u2591' : '.');
        const tl = caps.unicode ? '\u250c' : '+';
        const tr = caps.unicode ? '\u2510' : '+';
        const bl = caps.unicode ? '\u2514' : '+';
        const br = caps.unicode ? '\u2518' : '+';
        const hz = caps.unicode ? '\u2500' : '-';
        const vt = caps.unicode ? '\u2502' : '|';

        for (let row = 0; row < height; row++) {
            for (let col = 0; col < width; col++) {
                screen.setCell(x + col, y + row, { char: fillChar, ...fillAttrs });
            }
        }

        for (let col = 0; col < width; col++) {
            screen.setCell(x + col, y, { char: hz, ...borderAttrs });
            screen.setCell(x + col, y + height - 1, { char: hz, ...borderAttrs });
        }

        for (let row = 0; row < height; row++) {
            screen.setCell(x, y + row, { char: vt, ...borderAttrs });
            screen.setCell(x + width - 1, y + row, { char: vt, ...borderAttrs });
        }

        screen.setCell(x, y, { char: tl, ...borderAttrs });
        screen.setCell(x + width - 1, y, { char: tr, ...borderAttrs });
        screen.setCell(x, y + height - 1, { char: bl, ...borderAttrs });
        screen.setCell(x + width - 1, y + height - 1, { char: br, ...borderAttrs });

        if (width <= 2 || height <= 2 || this._label.length === 0) return;

        const innerWidth = width - 2;
        const visibleLabel = this._label.slice(0, innerWidth);
        const labelWidth = Math.min(stringWidth(visibleLabel), innerWidth);
        const labelX = x + 1 + Math.max(0, Math.floor((innerWidth - labelWidth) / 2));
        const labelY = y + Math.floor(height / 2);

        screen.writeString(labelX, labelY, visibleLabel, labelAttrs);
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Scrollbar widget
// Proportional scrollbar with 4 orientation modes.
// ─────────────────────────────────────────────────────

import {
    type Screen, type Style, type Color,
    ScrollbarSets,
} from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

// ── Types ────────────────────────────────────────────

export type ScrollbarOrientation =
    | 'verticalRight'
    | 'verticalLeft'
    | 'horizontalBottom'
    | 'horizontalTop';

export interface ScrollbarOptions {
    /** Total number of content items. */
    contentLength: number;
    /** Number of items visible in the viewport. */
    viewportLength: number;
    /** Current scroll position (0-based). */
    position?: number;
    /** Scrollbar orientation. Default: 'verticalRight'. */
    orientation?: ScrollbarOrientation;
    /** Color of the thumb. */
    thumbColor?: Color;
    /** Color of the track. */
    trackColor?: Color;
    /** Show begin/end arrow symbols. Default: true. */
    showArrows?: boolean;
}

// ── Widget ───────────────────────────────────────────

export class Scrollbar extends Widget {
    private _contentLength: number;
    private _viewportLength: number;
    private _position: number;
    private _orientation: ScrollbarOrientation;
    private _thumbColor: Color;
    private _trackColor: Color;
    private _showArrows: boolean;

    constructor(style: Partial<Style> = {}, opts: ScrollbarOptions) {
        super(style);
        this._contentLength = opts.contentLength;
        this._viewportLength = opts.viewportLength;
        this._position = opts.position ?? 0;
        this._orientation = opts.orientation ?? 'verticalRight';
        this._thumbColor = opts.thumbColor ?? { type: 'named', name: 'white' };
        this._trackColor = opts.trackColor ?? { type: 'named', name: 'brightBlack' };
        this._showArrows = opts.showArrows ?? true;
    }

    setPosition(position: number): void {
        if (position === this._position) {
            return;
        }
        this._position = position;
        this.markDirty();
    }

    setContentLength(length: number): void {
        if (length === this._contentLength) {
            return;
        }
        this._contentLength = length;
        this.markDirty();
    }

    setViewportLength(length: number): void {
        if (length === this._viewportLength) {
            return;
        }
        this._viewportLength = length;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0 || this._contentLength <= 0) return;
        if (this._contentLength <= this._viewportLength) return;

        const vertical = this._orientation === 'verticalRight'
            || this._orientation === 'verticalLeft';

        const symbols = vertical
            ? ScrollbarSets.VERTICAL
            : ScrollbarSets.HORIZONTAL;

        // Determine track position
        const trackX = this._orientation === 'verticalLeft' ? x
            : this._orientation === 'verticalRight' ? x + width - 1
                : x;
        const trackY = this._orientation === 'horizontalTop' ? y
            : this._orientation === 'horizontalBottom' ? y + height - 1
                : y;

        const totalLength = vertical ? height : width;
        if (totalLength <= 0) return;

        let trackStart = 0;
        let trackLength = totalLength;

        // Draw arrow symbols
        if (this._showArrows && totalLength > 2) {
            const beginX = vertical ? trackX : x;
            const beginY = vertical ? y : trackY;
            screen.setCell(beginX, beginY, {
                char: symbols.begin,
                fg: this._trackColor,
            });

            const endX = vertical ? trackX : x + totalLength - 1;
            const endY = vertical ? y + totalLength - 1 : trackY;
            screen.setCell(endX, endY, {
                char: symbols.end,
                fg: this._trackColor,
            });

            trackStart = 1;
            trackLength -= 2;
        }

        if (trackLength <= 0) return;

        // Compute thumb size and position
        const thumbSize = Math.max(1, Math.floor(
            (trackLength * this._viewportLength) / this._contentLength
        ));
        const maxScroll = Math.max(1, this._contentLength - this._viewportLength);
        const thumbOffset = Math.min(
            trackLength - thumbSize,
            Math.floor((this._position * (trackLength - thumbSize)) / maxScroll),
        );

        // Draw track and thumb
        for (let i = 0; i < trackLength; i++) {
            const pos = trackStart + i;
            const cellX = vertical ? trackX : x + pos;
            const cellY = vertical ? y + pos : trackY;

            const isThumb = i >= thumbOffset && i < thumbOffset + thumbSize;

            screen.setCell(cellX, cellY, {
                char: isThumb ? symbols.thumb : symbols.track,
                fg: isThumb ? this._thumbColor : this._trackColor,
            });
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Alert widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, styleToCellAttrs, getBorderChars, caps, stringWidth, truncate } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';
import { type StatusVariant } from '@termuijs/widgets';

export interface AlertOptions {
    /** Variant determines icon and border color */
    variant?: StatusVariant;
    /** The message to display */
    message: string;
}

const VARIANT_COLORS: Record<StatusVariant, Color> = {
    success: { type: 'named', name: 'green' },
    error:   { type: 'named', name: 'red' },
    warning: { type: 'named', name: 'yellow' },
    info:    { type: 'named', name: 'cyan' },
};

const ICONS_UNICODE: Record<StatusVariant, string> = {
    info: '●',
    success: '✓',
    warning: '!',
    error: '✗',
};

const ICONS_ASCII: Record<StatusVariant, string> = {
    info: 'i',
    success: '[OK]',
    warning: '[!]',
    error: '[x]',
};

/**
 * Alert — full-width status message box with a colored border and an icon prefix.
 *
 * Renders a bordered box containing an icon and a message on a single line,
 * colored according to the variant. Uses `caps.unicode` to choose between
 * Unicode box-drawing/icons and ASCII fallback borders/icons.
 */
export class Alert extends Widget {
    private _variant: StatusVariant;
    private _message: string;

    constructor(opts: AlertOptions, style: Partial<Style> = {}) {
        // Do NOT set border in style — we render it manually for color control
        super({
            width: '100%',
            padding: 1,
            ...style,
        });
        this._variant = opts.variant ?? 'info';
        this._message = opts.message ?? '';
    }

    /** Set the alert message */
    setMessage(message: string): void {
        if (message === this._message) {
            return;
        }
        this._message = message;
        this.markDirty();
    }

    /** Get the alert message */
    getMessage(): string {
        return this._message;
    }

    /** Set the alert variant */
    setVariant(variant: StatusVariant): void {
        if (variant === this._variant) {
            return;
        }
        this._variant = variant;
        this.markDirty();
    }

    /** Get the alert variant */
    getVariant(): StatusVariant {
        return this._variant;
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width < 2 || height < 2) return;

        const attrs = styleToCellAttrs(this._style);
        const color = VARIANT_COLORS[this._variant];
        const fg = color;

        // Draw border manually in variant color, respecting caps.unicode
        const borderChars = caps.unicode
            ? getBorderChars('single')
            : {
                topLeft: '+',
                top: '-',
                topRight: '+',
                right: '|',
                bottomRight: '+',
                bottom: '-',
                bottomLeft: '+',
                left: '|',
            };

        if (borderChars) {
            // Top edge
            screen.setCell(x, y, { char: borderChars.topLeft, fg });
            for (let c = 1; c < width - 1; c++) {
                screen.setCell(x + c, y, { char: borderChars.top, fg });
            }
            screen.setCell(x + width - 1, y, { char: borderChars.topRight, fg });

            // Bottom edge
            screen.setCell(x, y + height - 1, { char: borderChars.bottomLeft, fg });
            for (let c = 1; c < width - 1; c++) {
                screen.setCell(x + c, y + height - 1, { char: borderChars.bottom, fg });
            }
            screen.setCell(x + width - 1, y + height - 1, { char: borderChars.bottomRight, fg });

            // Left and right edges
            for (let r = 1; r < height - 1; r++) {
                screen.setCell(x, y + r, { char: borderChars.left, fg });
                screen.setCell(x + width - 1, y + r, { char: borderChars.right, fg });
            }
        }

        // Content area (inside border + padding=1)
        const cx = x + 2; // border(1) + padding(1)
        const cy = y + 2;
        const contentWidth = Math.max(0, width - 4);  // left/right border+padding
        const contentHeight = Math.max(0, height - 4); // top/bottom border+padding

        if (contentHeight <= 0 || contentWidth <= 0) return;

        const iconMap = caps.unicode ? ICONS_UNICODE : ICONS_ASCII;
        const icon = iconMap[this._variant];

        // Render icon in variant color, bold
        const iconLen = stringWidth(icon);
        screen.writeString(cx, cy, truncate(icon, contentWidth, ''), {
            ...attrs,
            fg: color,
            bold: true,
        });

        // Space + message
        const msgX = cx + iconLen + 1;
        const remaining = contentWidth - iconLen - 1;
        if (remaining > 0) {
            screen.writeString(msgX, cy, truncate(this._message, remaining, ''), {
                ...attrs,
                fg: color,
            });
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Banner widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, styleToCellAttrs, getBorderChars, normalizeEdges, truncate } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';
import { type StatusVariant } from '@termuijs/widgets';

export interface BannerOptions {
    /** Variant determines border color */
    variant?: StatusVariant;
    /** Title displayed on first line in bold */
    title?: string;
    /** Body text */
    body?: string;
}

const VARIANT_COLORS: Record<StatusVariant, Color> = {
    success: { type: 'named', name: 'green' },
    error:   { type: 'named', name: 'red' },
    warning: { type: 'named', name: 'yellow' },
    info:    { type: 'named', name: 'cyan' },
};

/**
 * Banner — full-width alert with title and body text.
 *
 * Shows a bordered box with a bold title line and body text,
 * colored according to variant. The border is drawn manually
 * to use the variant color.
 */
export class Banner extends Widget {
    private _variant: StatusVariant;
    private _title: string;
    private _body: string;

    constructor(style: Partial<Style> = {}, opts: BannerOptions = {}) {
        // Do NOT set border in style — we render it manually for color control
        super({
            width: '100%',
            padding: 1,
            ...style,
        });
        this._variant = opts.variant ?? 'info';
        this._title = opts.title ?? '';
        this._body = opts.body ?? '';
    }

    setTitle(title: string): void {
        if (this._title === title) return;

        this._title = title;
        this.markDirty();
    }

    setBody(body: string): void {
        if (this._body === body) return;

        this._body = body;
        this.markDirty();
    }

    setVariant(variant: StatusVariant): void {
        if (this._variant === variant) return;

        this._variant = variant;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width < 2 || height < 2) return;

        const attrs = styleToCellAttrs(this._style);
        const color = VARIANT_COLORS[this._variant];
        const fg = color;

        // Draw border manually in variant color
        const borderChars = getBorderChars('single');
        if (borderChars) {
            // Top edge
            screen.setCell(x, y, { char: borderChars.topLeft, fg });
            for (let c = 1; c < width - 1; c++) {
                screen.setCell(x + c, y, { char: borderChars.top, fg });
            }
            screen.setCell(x + width - 1, y, { char: borderChars.topRight, fg });

            // Bottom edge
            screen.setCell(x, y + height - 1, { char: borderChars.bottomLeft, fg });
            for (let c = 1; c < width - 1; c++) {
                screen.setCell(x + c, y + height - 1, { char: borderChars.bottom, fg });
            }
            screen.setCell(x + width - 1, y + height - 1, { char: borderChars.bottomRight, fg });

            // Left and right edges
            for (let r = 1; r < height - 1; r++) {
                screen.setCell(x, y + r, { char: borderChars.left, fg });
                screen.setCell(x + width - 1, y + r, { char: borderChars.right, fg });
            }
        }

        // Content area (inside border + padding)
        const padding = normalizeEdges(this._style.padding);
        const borderWidth = borderChars ? 1 : 0;
        const cx = x + borderWidth + padding.left;
        const cy = y + borderWidth + padding.top;
        const contentWidth = Math.max(0, width - borderWidth * 2 - padding.left - padding.right);
        const contentHeight = Math.max(0, height - borderWidth * 2 - padding.top - padding.bottom);

        let row = 0;

        // Title (bold)
        if (this._title && row < contentHeight) {
            screen.writeString(cx, cy + row, truncate(this._title, contentWidth, ''), {
                ...attrs,
                fg: color,
                bold: true,
            });
            row++;
        }

        // Body text
        if (this._body) {
            const lines = this._body.split('\n');
            for (const line of lines) {
                if (row >= contentHeight) break;
                screen.writeString(cx, cy + row, truncate(line, contentWidth, ''), {
                    ...attrs,
                    fg: color,
                });
                row++;
            }
        }
    }
}

