                framesToUse = SPINNER_FRAMES[presetName].asciiFrames;
            } else if (spinnerDef && 'asciiFrames' in spinnerDef && Array.isArray((spinnerDef as any).asciiFrames)) { // as any: asciiFrames is an optional SpinnerDef extension not in the base interface
                framesToUse = (spinnerDef as any).asciiFrames; // as any: asciiFrames is an optional SpinnerDef extension not in the base interface
            } else if (framesToUse.some(f => f.codePointAt(0)! > 127)) {
                // Generic fallback for custom unicode frames
                framesToUse = Array.from(BRAILLE_SPIN);
                this._interval = options.interval ?? 130;
            }
        }

        this._frames = framesToUse;
        this._label = options.label ?? '';
        this._color = options.color ?? { type: 'named', name: 'cyan' };
        this._active = options.active !== false;
        this._doneText = options.doneText;
    }

    /** Update the active state */
    setActive(active: boolean): void {
        if (this._active === active) return;
        this._active = active;
        this.markDirty();

        // Dynamically manage timer if mounted
        this._timerUnsub?.();
        this._timerUnsub = undefined;
        if (active && !prefersReducedMotion()) {
            this._startTime = Date.now();
            this._timerUnsub = timerPoolSubscribe(this._interval, () => {
                this.markDirty();
            });
        }
    }

    /** Update the spinner label */
    setLabel(label: string): void {
        this._label = label;
        this.markDirty();
    }

    /** Update doneText */
    setDoneText(doneText: string): void {
        this._doneText = doneText;
        this.markDirty();
    }

    /**
     * Advance the spinner frame based on elapsed time.
     * Call this with a delta (ms) from the render loop.
     */
    tick(deltaMs: number): void {
        if (prefersReducedMotion() || !this._active) return;

        this._elapsed += deltaMs;
        this._frameIndex = Math.floor(this._elapsed / this._interval) % this._frames.length;
    }

    /** Lifecycle: start the frame-advance timer (only when motion is enabled). */
    mount(): void {
        super.mount();
        if (prefersReducedMotion() || !this._active) return;
        this._startTime = Date.now();
        this._timerUnsub = timerPoolSubscribe(this._interval, () => {
            this.markDirty();
        });
    }

    /** Lifecycle: stop the frame-advance timer. */
    unmount(): void {
        this._timerUnsub?.();
        this._timerUnsub = undefined;
        super.unmount();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width } = rect;
        if (width <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        let char = '';
        if (this._active) {
            if (prefersReducedMotion()) {
                // Static fallback when motion is disabled
                char = '[...]';
            } else {
                let idx = this._frameIndex;
                if (this._startTime !== undefined) {
                    const elapsed = Date.now() - this._startTime;
                    idx = Math.floor(elapsed / this._interval) % this._frames.length;
                }
                char = this._frames[idx];
            }
        } else {
            char = this._doneText ?? '';
        }

        // Render spinner character or doneText
        if (char) {
            screen.writeString(x, y, char, { ...attrs, fg: this._color });
        }

        // Render label
        if (this._label) {
            const labelX = char ? x + stringWidth(char) + 1 : x;
            screen.writeString(labelX, y, this._label, attrs);
        }
    }
}

import { type Screen, type Style, type Color, styleToCellAttrs, caps, stringWidth, truncate } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export type CalloutVariant = 'info' | 'warn' | 'success' | 'danger';

export interface CalloutOptions {
    variant?: CalloutVariant;
    title?: string;
}

const ICONS_UNICODE: Record<CalloutVariant, string> = {
    info:    'ℹ',
    warn:    '⚠',
    success: '✓',
    danger:  '✗',
};

const ICONS_ASCII: Record<CalloutVariant, string> = {
    info:    'i',
    warn:    '!',
    success: 'v',
    danger:  'x',
};

const COLORS: Record<CalloutVariant, Color> = {
    info:    { type: 'named', name: 'blue' },
    warn:    { type: 'named', name: 'yellow' },
    success: { type: 'named', name: 'green' },
    danger:  { type: 'named', name: 'red' },
};

export class Callout extends Widget {
    private _message: string;
    private _variant: CalloutVariant;
    private _title: string;

    constructor(message: string, style: Partial<Style> = {}, opts: CalloutOptions = {}) {
        super({ height: 1, ...style });
        this._message = message;
        this._variant = opts.variant ?? 'info';
        this._title = opts.title ?? '';
    }

    setMessage(message: string): void {
        if (message === this._message) return;

        this._message = message;
        this.markDirty();
    }

    setVariant(variant: CalloutVariant): void {
        if (variant === this._variant) return;

        this._variant = variant;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width } = rect;
        if (width <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const color = COLORS[this._variant];
        const iconMap = caps.unicode ? ICONS_UNICODE : ICONS_ASCII;
        const icon = iconMap[this._variant];

        let cursor = x;

        screen.writeString(cursor, y, icon, { ...attrs, fg: color, bold: true });
        cursor += stringWidth(icon);

        if (this._title) {
            const titleStr = ' ' + this._title;
            const avail = width - cursor;
            if (avail > 0) {
                const truncated = truncate(titleStr, avail);
                screen.writeString(cursor, y, truncated, { ...attrs, fg: color, bold: true });
                cursor += stringWidth(truncated);
            }
        }

        const msgPrefix = this._title || this._message ? ' ' : '';
        const msgStr = msgPrefix + this._message;
        const avail = width - cursor;
        if (avail > 0) {
            screen.writeString(cursor, y, msgStr.slice(0, avail), { ...attrs, fg: color });
        }
    }
}

