// @termuijs/widgets — LoadingDots widget
// ─────────────────────────────────────────────────────

import { type Style, type Color, type Screen, caps, styleToCellAttrs, stringWidth, prefersReducedMotion } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface LoadingDotsOptions {
    /** Label shown before the dots. */
    label?: string;
    /** Maximum number of dots in the cycle. Default: 3 */
    maxDots?: number;
    /** Dot color. Default: cyan */
    color?: Color;
}

export class LoadingDots extends Widget {
    private _label: string;
    private _maxDots: number;
    private _color: Color;
    private _dotCount = 1;

    constructor(style: Partial<Style> = {}, opts: LoadingDotsOptions = {}) {
        super({ height: 1, ...style });
        this._label = opts.label ?? '';
        this._maxDots = opts.maxDots ?? 3;
        this._color = opts.color ?? { type: 'named', name: 'cyan' };
    }

    tick(): void {
        if (prefersReducedMotion()) return;
        this._dotCount = (this._dotCount % this._maxDots) + 1;
        this.markDirty();
    }

    setLabel(label: string): void {
        if (label === this._label) return;

        this._label = label;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        let currentX = x;

        if (this._label) {
            screen.writeString(currentX, y, this._label, attrs);
            currentX += stringWidth(this._label);
        }

        const dotChar = caps.unicode ? '·' : '.';
        const dots = dotChar.repeat(this._dotCount);
        const padding = ' '.repeat(this._maxDots - this._dotCount);

        screen.writeString(currentX, y, dots + padding, { ...attrs, fg: this._color });
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Progress
// ─────────────────────────────────────────────────────

import { Widget } from '@termuijs/widgets';
import type { ProgressColumnDefinition } from '@termuijs/widgets';
import {
    BarColumn,
    TextColumn,
    PercentageColumn,
} from '@termuijs/widgets';
import type { Screen, Style } from '@termuijs/core';
export interface ProgressTask {
    label?: string;
    value?: number;
    status?: string;
    [key: string]: unknown;
}

export interface ProgressProps {
    tasks?: ProgressTask[];
    columns?: ProgressColumnDefinition[];
     children?: unknown;
}

export class Progress extends Widget {
    private _tasks: ProgressTask[];
    private _columns: ProgressColumnDefinition[];

  private _resolveColumns(
    children?: unknown,
): ProgressColumnDefinition[] {
    if (!children) return [];

    const items = Array.isArray(children)
        ? children
        : [children];

    const columns: ProgressColumnDefinition[] = [];

    for (const item of items) {
        if (
            item &&
            typeof item === 'object' &&
            'type' in (item as Record<string, unknown>)
        ) {
            const vnode = item as {
                type?: unknown;
                props?: Record<string, unknown>;
            };

            const props = vnode.props ?? {};

            if (vnode.type === BarColumn) {
                columns.push(BarColumn(props));
            } else if (vnode.type === TextColumn) {
                columns.push(TextColumn(props));
            } else if (vnode.type === PercentageColumn) {
                columns.push(PercentageColumn(props));
            }
        }
    }

    return columns;
}

    constructor(
        props: ProgressProps = {},
        style: Partial<Style> = {},
    ) {
        super(style);

        this._tasks = props.tasks ?? [];

        const childColumns = this._resolveColumns(
    props.children,
);

this._columns =
    childColumns.length
        ? childColumns
        : props.columns?.length
            ? props.columns
            : [
                BarColumn(),
                TextColumn(),
                PercentageColumn(),
            ];


    }

    get tasks(): ProgressTask[] {
        return this._tasks;
    }

    get columns(): ProgressColumnDefinition[] {
        return this._columns;
    }

    public setTasks(tasks: ProgressTask[]): void {
        if (tasks === this._tasks) {
            return;
        }
    this._tasks = tasks;
    this.markDirty();
}

    protected _renderSelf(screen: Screen): void {
    const rect = this._getContentRect();
    const { x, y, width, height } = rect;

    if (width <= 0 || height <= 0) return;

    this._tasks.forEach((task, index) => {
        if (index >= height) return;

        const parts: string[] = [];

        for (const [, column] of this._columns.entries()) {

            if (column.render) {
        parts.push(column.render(task));
        continue;
    }

            switch (column.kind) {
                case 'text': {
    const template = column.template;

    if (template) {
        const match = template.match(
            /^\{task\.([a-zA-Z0-9_]+)\}$/
        );

        if (match) {
            parts.push(
                String(
                    task[match[1]] ?? ''
                )
            );
        } else {
            parts.push(template);
        }
    } else {
        parts.push(String(task.label ?? ''));
    }

    break;
}

                case 'percentage':
                    parts.push(`${Math.round((task.value ?? 0) * 100)}%`);
                    break;

                case 'bar': {
                    const value = Math.max(0, Math.min(1, task.value ?? 0));
                    const filled = Math.round(value * 10);
                    const empty = 10 - filled;

                    parts.push(
                        `[${'█'.repeat(filled)}${'░'.repeat(empty)}]`,
                    );
                    break;
                }
            }
        }

        screen.writeString(
            x,
            y + index,
            parts.join(' '),
            this.style,
        );
    });
}
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — TaskList widget
// Renders a list of tasks with status indicators.
// ─────────────────────────────────────────────────────

import { type Screen, type Style, styleToCellAttrs, caps, truncate } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

// ── Types ────────────────────────────────────────────

export type TaskStatus = 'pending' | 'running' | 'done' | 'error';

export interface TaskItem {
    id: string | number;
    label: string;
    status: TaskStatus;
}

export interface TaskListOptions {
    pendingText?: string;
    runningText?: string;
    doneText?: string;
    errorText?: string;
    /** When true, the running indicator animates with a spinner. */
    wheelspin?: boolean;
}

// ── Spinner frames ────────────────────────────────────

/** Braille dot spinner — used when caps.unicode is true. */
const SPINNER_FRAMES_UNICODE = ['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠇', '⠏'];

/** ASCII fallback — used when caps.unicode is false. */
const SPINNER_FRAMES_ASCII = ['|', '/', '-', '\\'];

const SPINNER_INTERVAL = 80;

// ── Widget ───────────────────────────────────────────

/**
 * TaskList — a vertical list of tasks with status indicators.
 *
 * Each task renders on its own row:
 *   Build      ⠋        ← running + wheelspin + unicode
 *   Lint       ...      ← pending (default pendingText)
 *   Tests      ✓        ← done (custom doneText)
 *   Deploy     ✗        ← error (custom errorText)
 */
export class TaskList extends Widget {
    private _tasks: TaskItem[];
    private _pendingText: string;
    private _runningText: string;
    private _doneText: string;
    private _errorText: string;
    private _wheelspin: boolean;

    private _frameIndex = 0;
    private _elapsed = 0;

    constructor(
        style: Partial<Style> = {},
        options: TaskListOptions = {},
        tasks: TaskItem[] = [],
    ) {
        super(style);
        this._tasks = tasks;
        this._pendingText = options.pendingText ?? '...';
        this._runningText = options.runningText ?? '...';
        this._doneText = options.doneText ?? '...';
        this._errorText = options.errorText ?? '...';
        this._wheelspin = options.wheelspin ?? false;
    }

    /** Replace the task list and schedule a re-render. */
    setTasks(tasks: TaskItem[]): void {
        if (tasks === this._tasks) {
            return;
        }
        this._tasks = tasks;
        this.markDirty();
    }

    /**
     * Advance the spinner animation by `dt` milliseconds.
     * Only has an effect when `wheelspin` is enabled and there is at least
     * one running task. Call this from the app's render/tick loop.
     */
    tick(dt: number): void {
        if (!this._wheelspin) return;

        const hasRunning = this._tasks.some(t => t.status === 'running');
        if (!hasRunning) return;

        this._elapsed += dt;
        if (this._elapsed >= SPINNER_INTERVAL) {
            const frames = caps.unicode ? SPINNER_FRAMES_UNICODE : SPINNER_FRAMES_ASCII;
            const steps = Math.floor(this._elapsed / SPINNER_INTERVAL);
            this._frameIndex = (this._frameIndex + steps) % frames.length;
            this._elapsed %= SPINNER_INTERVAL;
            this.markDirty();
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this.rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const frames = caps.unicode ? SPINNER_FRAMES_UNICODE : SPINNER_FRAMES_ASCII;

        this._tasks.forEach((task, index) => {
            if (index >= height) return;

            let indicator: string;
            switch (task.status) {
                case 'pending': indicator = this._pendingText; break;
                case 'running': indicator = this._wheelspin
                    ? (frames[this._frameIndex] ?? frames[0])
                    : this._runningText;
                    break;
                case 'done':    indicator = this._doneText;   break;
                case 'error':   indicator = this._errorText;  break;
            }

            const rowText = `${task.label} ${indicator}`;
            screen.writeString(x, y + index, truncate(rowText, width), attrs);
        });
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — ProgressBar widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, styleToCellAttrs, type Color, caps, stringWidth } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface ProgressBarOptions {
    /** Current value (0–1) */
    value?: number;
    /** Character for the filled portion */
    fillChar?: string;
    /** Character for the empty portion */
    emptyChar?: string;
    /** Color of the filled portion */
    fillColor?: Color;
    /** Show percentage label */
    showLabel?: boolean;
    /** Label format: 'percent' | 'fraction' | 'custom' */
    labelFormat?: 'percent' | 'fraction';
    /** Total for fraction display */
    total?: number;
}

/**
 * ProgressBar — horizontal progress indicator.
 *
 * Supports:
 * - Configurable fill/empty characters
 * - Custom fill color
 * - Percentage or fraction label
 * - Smooth animation-ready value changes
 */
export class ProgressBar extends Widget {
    private _value: number;
    private _fillChar: string;
    private _emptyChar: string;
    private _fillColor: Color;
    private _showLabel: boolean;
    private _labelFormat: 'percent' | 'fraction';
    private _total: number;

    constructor(style: Partial<Style> = {}, options: ProgressBarOptions = {}) {
        super({ height: 1, ...style });
        this._value = Math.max(0, Math.min(1, options.value ?? 0));
        this._fillChar = options.fillChar ?? (caps.unicode ? '█' : '#');
        this._emptyChar = options.emptyChar ?? (caps.unicode ? '░' : '-');
        this._fillColor = options.fillColor ?? { type: 'named', name: 'green' };
        this._showLabel = options.showLabel ?? true;
        this._labelFormat = options.labelFormat ?? 'percent';
        this._total = options.total ?? 100;
    }

    /** Set progress value (0–1) */
    setValue(value: number): void {
        const normalized = Math.max(0, Math.min(1, value));

        if (this._value === normalized) {
            return;
        }

        this._value = normalized;
        this.markDirty();
    }

    get value(): number { return this._value; }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width } = rect;
        if (width <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        // Label
        let label = '';
        if (this._showLabel) {
            if (this._labelFormat === 'percent') {
                label = ` ${Math.round(this._value * 100)}%`;
            } else {
                label = ` ${Math.round(this._value * this._total)}/${this._total}`;
            }
        }

        const barWidth = Math.max(0, width - stringWidth(label));
        const filled = this._value <= 0 ? 0 : Math.round(barWidth * this._value);
        const empty = barWidth - filled;

        // Render bar
        for (let i = 0; i < filled; i++) {
            screen.setCell(x + i, y, { char: this._fillChar, ...attrs, fg: this._fillColor });
        }
        for (let i = 0; i < empty; i++) {
            screen.setCell(x + filled + i, y, { char: this._emptyChar, ...attrs, dim: true });
        }

        // Render label
        if (label) {
            screen.writeString(x + barWidth, y, label, { ...attrs, bold: true });
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — MultiProgress widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, styleToCellAttrs, type Color, caps, BLOCK } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

/**
 * A single progress item in MultiProgress
 */
export interface ProgressItem {
    label: string;
    value: number; // 0–1
    color?: Color;  // optional fill color override
}

/**
 * Options for MultiProgress widget
 */
export interface MultiProgressOptions {
    items: ProgressItem[];
    labelWidth?: number; // chars reserved for label column, default: 12
    showValues?: boolean; // show percentage after bar, default: true
}

/**
 * MultiProgress — stacks multiple labeled progress bars in a vertical list.
 *
 * Each item renders on its own row with a label, bar, and optional percentage.
 *
 * Supports:
 * - Multiple items with individual colors
 * - Custom label column width
 * - Optional percentage display
 * - Smooth animation-ready value changes
 */
export class MultiProgress extends Widget {
    private _items: ProgressItem[];
    private _labelWidth: number;
    private _showValues: boolean;

    constructor(options: MultiProgressOptions, style: Partial<Style> = {}) {
        const height = options.items.length;
        super({ height, ...style });
        this._items = options.items.map(item => ({
            ...item,
            value: Math.max(0, Math.min(1, item.value)),
        }));
        this._labelWidth = options.labelWidth ?? 12;
        this._showValues = options.showValues ?? true;
    }

    /**
     * Replace all items and mark dirty
     */
    setItems(items: ProgressItem[]): void {
        this._items = items.map(item => ({
            ...item,
            value: Math.max(0, Math.min(1, item.value)),
        }));
        this.markDirty();
    }

    /**
     * Update a single item's value
     */
    updateItem(index: number, value: number): void {
        if (index >= 0 && index < this._items.length) {
            const normalized = Math.max(0, Math.min(1, value));

            if (this._items[index].value === normalized) {
                return;
            }

            this._items[index].value = normalized;
            this.markDirty();
        }
    }

    /**
     * Test-only getter for items array
     * @internal
     */
    getItemsForTest(): ProgressItem[] {
        return this._items;
    }

    /**
     * Test-only getter for labelWidth
     * @internal
     */
    getLabelWidthForTest(): number {
        return this._labelWidth;
    }

    /**
     * Test-only getter for showValues
     * @internal
     */
    getShowValuesForTest(): boolean {
        return this._showValues;
    }

    /**
     * Test-only getter for style height
     * @internal
     */
    getHeightForTest(): number {
        // Height is always set as number in constructor (options.items.length)
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        return this._style.height as number;
    }

    /**
     * Test-only setter for dirty state
     * @internal
     */
    setDirtyForTest(value: boolean): void {
        // _dirty is protected in Widget base class; accessible directly from subclass
        this._dirty = value;
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width } = rect;
        if (width <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        // Determine bar characters (unicode or ASCII fallback)
        const fillChar = caps.unicode ? '█' : BLOCK.full;   // '█' or '#'
        const emptyChar = caps.unicode ? '░' : BLOCK.empty; // '░' or ' '

        // Render each item on its own row
        for (let i = 0; i < this._items.length; i++) {
            const item = this._items[i];
            const rowY = y + i;
            let colX = x;

            // 1. Render label (left-aligned, truncated/padded to labelWidth)
            const label = item.label.length > this._labelWidth
                ? item.label.substring(0, this._labelWidth)
                : item.label.padEnd(this._labelWidth);
            screen.writeString(colX, rowY, label, attrs);
            colX += this._labelWidth;

            // 2. Space after label
            if (colX < x + width) {
                screen.setCell(colX, rowY, { char: ' ', ...attrs });
                colX++;
            }

            // 3. Calculate bar width (accounting for percentage label if shown)
            let percentLabel = '';
            if (this._showValues) {
                percentLabel = ` ${Math.round(item.value * 100)}%`;
            }
            const barWidth = Math.max(0, x + width - colX - percentLabel.length);
            const filled = Math.round(barWidth * item.value);
            const empty = barWidth - filled;

            // 4. Render filled portion
            const fillColor = item.color ?? { type: 'named', name: 'green' };
            for (let j = 0; j < filled; j++) {
                screen.setCell(colX + j, rowY, { char: fillChar, ...attrs, fg: fillColor });
            }

            // 5. Render empty portion
            for (let j = 0; j < empty; j++) {
                screen.setCell(colX + filled + j, rowY, { char: emptyChar, ...attrs, dim: true });
            }

            // 6. Render percentage label if enabled
            if (percentLabel) {
                const labelX = colX + barWidth;
                screen.writeString(labelX, rowY, percentLabel, { ...attrs, bold: true });
            }
        }
    }
}

import { type Screen, type Style, type Color, caps, prefersReducedMotion } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';
import { timerPoolSubscribe } from '@termuijs/motion';

export interface SkeletonOptions {
    variant?: 'pulse' | 'shimmer';
    speed?: 'slow' | 'normal' | 'fast';
    shape?: 'text' | 'card' | 'table' | 'list';
    intervalMs?: number;
    chars?: [string, string];
    color?: Color;
}

export class Skeleton extends Widget {
    private _frame = 0;
    private _shimmerPos = 0;
    private _variant: 'pulse' | 'shimmer';
    private _shape: 'text' | 'card' | 'table' | 'list';
    private _chars: [string, string];
    private _intervalMs: number;
    private _unsubscribe?: () => void;

    constructor(style: Partial<Style> = {}, opts: SkeletonOptions = {}) {
        super(style);

        this._variant = opts.variant ?? 'pulse';
        this._shape = opts.shape ?? 'text';

        const speeds = { slow: 1000, normal: 600, fast: 300 };
        this._intervalMs = opts.intervalMs ?? speeds[opts.speed ?? 'normal'];

        this._chars = opts.chars ?? (caps.unicode ? ['░', '▒'] : ['-', '#']);

        if (!prefersReducedMotion()) {
            this._unsubscribe = timerPoolSubscribe(this._intervalMs, () => {
                this._frame = 1 - this._frame;
                this._shimmerPos++;
                this.markDirty();
            });
        }
    }

    override unmount(): void {
        this._unsubscribe?.();
        super.unmount();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width } = rect;

        let height = rect.height;
        if (this._shape === 'text') height = Math.min(height, 3);
        else if (this._shape === 'list') height = Math.min(height, 5);
        else if (this._shape === 'table') height = Math.min(height, 6);

        if (width <= 0 || height <= 0) return;

        if (this._variant === 'pulse') {
            const char = this._chars[this._frame];

            for (let r = 0; r < height; r++) {
                for (let c = 0; c < width; c++) {
                    screen.setCell(x + c, y + r, {
                        char,
                        dim: this._frame === 0,
                    });
                }
            }
        } else {
            const band = Math.max(1, Math.floor(width * 0.2));
            const total = width + band;
            const start = this._shimmerPos % total;

            for (let r = 0; r < height; r++) {
                for (let c = 0; c < width; c++) {
                    const inBand = c >= start && c < start + band;
                    screen.setCell(x + c, y + r, {
                        char: inBand ? this._chars[1] : this._chars[0],
                        dim: !inBand,
                    });
                }
            }
        }
    }
}

import { type Screen, type Style, styleToCellAttrs, stringWidth, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface EmptyStateOptions {
    icon?: string;
    description?: string;
    hint?: string;
}

export class EmptyState extends Widget {
    private _title: string;
    private _icon: string;
    private _description: string = '';
    private _hint: string = '';

    constructor(title: string, style: Partial<Style> = {}, opts: EmptyStateOptions = {}) {
        super(style);
        this._title = title;
        this._icon = opts.icon ?? (caps.unicode ? '📭' : '[]');
        if (opts.description !== undefined) this._description = opts.description;
        if (opts.hint !== undefined) this._hint = opts.hint;
    }

    setTitle(title: string): void {
        if (this._title === title) return;

        this._title = title;
        this.markDirty();
    }

    setDescription(description: string): void {
        if (this._description === description) return;

        this._description = description;
        this.markDirty();
    }

    setIcon(icon: string): void {
        if (this._icon === icon) return;

        this._icon = icon;
        this.markDirty();
    }

    setHint(hint: string): void {
        if (this._hint === hint) return;

        this._hint = hint;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const hasHint = this._hint.length > 0;
        const hasDesc = this._description.length > 0;

        const hintRow = hasHint ? y + height - 1 : -1;
        const mainHeight = hasHint ? height - 1 : height;

        const contentLines = 1 + 1 + (hasDesc ? 1 : 0);
        const startRow = y + Math.max(0, Math.floor((mainHeight - contentLines) / 2));

        const iconX = x + Math.max(0, Math.floor((width - stringWidth(this._icon)) / 2));
        screen.writeString(iconX, startRow, this._icon, attrs);

        const titleStr = this._title;
        const titleX = x + Math.max(0, Math.floor((width - stringWidth(titleStr)) / 2));
        screen.writeString(titleX, startRow + 1, titleStr, { ...attrs, bold: true });

        if (hasDesc) {
            const descStr = this._description;
            const descX = x + Math.max(0, Math.floor((width - stringWidth(descStr)) / 2));
            screen.writeString(descX, startRow + 2, descStr, { ...attrs, dim: true });
        }

        if (hasHint) {
            const hintStr = this._hint;
            const hintX = x + Math.max(0, Math.floor((width - stringWidth(hintStr)) / 2));
            screen.writeString(hintX, hintRow, hintStr, { ...attrs, dim: true });
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — ContextMenu widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, styleToCellAttrs, stringWidth, truncate, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface ContextMenuItem {
    label: string;
    value: string;
    disabled?: boolean;
}

/**
 * ContextMenu — a floating menu widget positioned at absolute coordinates.
 *
 * Supports:
 * - Keyboard navigation (up/down arrows)
 * - Selection confirmation (Enter)
 * - Menu dismissal (Escape)
 * - Callback on item selection
 * - Disabled items
 * - Safe ASCII fallback for unicode icons
 */
export class ContextMenu extends Widget {
    private _items: ContextMenuItem[];
    private _selectedIndex = 0;
    private _x: number;
    private _y: number;
    private _onItemSelect?: (item: ContextMenuItem, index: number) => void;
    private _onClose?: () => void;

    constructor(
        items: ContextMenuItem[],
        x: number,
        y: number,
        style: Partial<Style> = {},
        callbacks?: {
            onItemSelect?: (item: ContextMenuItem, index: number) => void;
            onClose?: () => void;
        },
    ) {
        super(style);
        this._items = items;
        this._x = x;
        this._y = y;
        this._onItemSelect = callbacks?.onItemSelect;
        this._onClose = callbacks?.onClose;
        this.focusable = true;

        // Set position-based rect for context menu
        this._updateRect();
    }

    /**
     * Update the internal rect based on position and items count.
     * ContextMenu is typically 1-2 characters wider than the longest item label,
     * and height matches the number of items.
     */
    private _updateRect(): void {
        let maxWidth = 10; // Minimum width
        for (const item of this._items) {
            const w = stringWidth(item.label) + 2; // +2 for prefix (e.g., '> ')
            maxWidth = Math.max(maxWidth, w);
        }

        this._rect = {
            x: this._x,
            y: this._y,
            width: maxWidth,
            height: Math.max(1, this._items.length),
        };
    }

    get selectedIndex(): number { return this._selectedIndex; }
    get selectedItem(): ContextMenuItem | undefined { return this._items[this._selectedIndex]; }

    /**
     * Move selection up
     */
    selectPrev(): void {
        let next = this._selectedIndex - 1;
        while (next >= 0 && this._items[next].disabled) next--;
        if (next >= 0) {
            this._selectedIndex = next;
            this.markDirty();
        }
    }

    /**
     * Move selection down
     */
    selectNext(): void {
        let next = this._selectedIndex + 1;
        while (next < this._items.length && this._items[next].disabled) next++;
        if (next < this._items.length) {
            this._selectedIndex = next;
            this.markDirty();
        }
    }

    /**
     * Confirm the current selection
     */
    confirm(): void {
        const item = this._items[this._selectedIndex];
        if (item && !item.disabled) {
            this._onItemSelect?.(item, this._selectedIndex);
        }
    }

    /**
     * Close the context menu
     */
    close(): void {
        this._onClose?.();
    }

    /**
     * Move the context menu to a new position
     */
    moveTo(x: number, y: number): void {
        if (this._x === x && this._y === y) {
            return;
        }
        this._x = x;
        this._y = y;
        this._updateRect();
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        for (let i = 0; i < this._items.length && i < height; i++) {
            const item = this._items[i];
            const isSelected = i === this._selectedIndex;

            // Compose the line with a prefix indicator
            const prefix = isSelected ? (caps.unicode ? '▸ ' : '> ') : '  ';
            let line = prefix + item.label;
            line = truncate(line, width);

            // Cell style: bold if selected, dim if disabled
            const cellStyle = {
                ...attrs,
                bold: isSelected,
                dim: item.disabled ?? false,
                inverse: isSelected && this.isFocused,
            };

            screen.writeString(x, y + i, line, cellStyle);

            // Fill rest of line for inverse highlight
            if (isSelected && this.isFocused) {
                const remaining = width - stringWidth(line);
                for (let c = 0; c < remaining; c++) {
                    screen.setCell(x + stringWidth(line) + c, y + i, { char: ' ', ...cellStyle });
                }
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — CommandPalette widget
//
// A fuzzy-search overlay widget. Shows a floating box
// with a text input and a filtered list of commands.
//
// Usage:
//   const palette = new CommandPalette({
//       commands: [
//           { id: 'open', label: 'Open File', description: 'Ctrl+O', action: () => {} },
//       ],
//       onClose: () => palette.setStyle({ visible: false }),
//   });
// ─────────────────────────────────────────────────────

import { type Screen, type Style, styleToCellAttrs, stringWidth, truncate } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface Command {
    id: string;
    label: string;
    description?: string;
    action: () => void;
}

export interface CommandPaletteOptions {
    commands: Command[];
    onClose?: () => void;
    /** Placeholder shown when query is empty. Default: 'Type to search...' */
    placeholder?: string;
    /** Max number of commands shown at once. Default: 8 */
    maxVisible?: number;
}

/**
 * CommandPalette — a fuzzy-search overlay widget.
 *
 * Renders a floating panel with:
 * - Row 0: `> ` + query text (or placeholder when empty)
 * - Rows 1..N: filtered command list with label + description
 *
 * Key bindings:
 * - Printable chars: append to query
 * - Backspace: delete last query character
 * - ArrowUp / k: move selection up
 * - ArrowDown / j: move selection down
 * - Enter: execute selected command
 * - Escape: call onClose
 */
export class CommandPalette extends Widget {
    private _commands: Command[];
    private _filtered: Command[];
    private _query = '';
    private _selectedIndex = 0;
    private _options: CommandPaletteOptions;

    constructor(options: CommandPaletteOptions, style: Partial<Style> = {}) {
        super({ border: 'single', ...style });
        this._options = {
            placeholder: 'Type to search...',
            maxVisible: 8,
            ...options,
        };
        this._commands = options.commands;
        this._filtered = [...this._commands];
        this.focusable = true;
    }

    /** Update the full command list and re-filter. */
    setCommands(commands: Command[]): void {
        this._commands = commands;
        this._filter();
        this.markDirty();
    }

    /**
     * Reset query, re-filter all commands, reset selection.
     * Call this when opening the palette.
     */
    open(): void {
        this._query = '';
        this._selectedIndex = 0;
        this._filtered = [...this._commands];
        this.markDirty();
    }

    /** Current query string. */
    getQuery(): string {
        return this._query;
    }

    // ─── Private helpers ────────────────────────────────


    /** Compute a fuzzy-match score for a single text against a query. */
    private _fuzzyScore(text: string, query: string): number {
    text = text.toLowerCase();
    query = query.toLowerCase();

    if (text === query) return 1000;

    if (text.includes(query)) {
        return 500 - text.indexOf(query);
    }

    let score = 0;
    let qi = 0;

    for (let i = 0; i < text.length && qi < query.length; i++) {
        if (text[i] === query[qi]) {
            score += 10;
            qi++;
        }
    }

    return qi === query.length ? score : -1;
}

    /** Filter commands based on current query (case-insensitive substring). */
    private _filter(): void {
    const q = this._query.toLowerCase();

    if (q === '') {
        this._filtered = [...this._commands];
    } else {
        this._filtered = this._commands
            .map((cmd) => ({
                cmd,
                score: Math.max(
                    this._fuzzyScore(cmd.label, q),
                    this._fuzzyScore(cmd.id, q),
                ),
            }))
            .filter((item) => item.score >= 0)
            .sort((a, b) => b.score - a.score)
            .map((item) => item.cmd);
    }

    const max = Math.max(0, this._filtered.length - 1);
    this._selectedIndex = Math.min(this._selectedIndex, max);
}

    private _executeSelected(): void {
        const cmd = this._filtered[this._selectedIndex];
        if (cmd) {
            cmd.action();
        }
    }

    private _moveUp(): void {
        if (this._selectedIndex > 0) {
            this._selectedIndex--;
        }
    }

    private _moveDown(): void {
        const maxVisible = this._options.maxVisible ?? 8;
        const visibleCount = Math.min(this._filtered.length, maxVisible);
        if (this._selectedIndex < visibleCount - 1) {
            this._selectedIndex++;
        }
    }

    // ─── Key handling ────────────────────────────────────

    handleKey(key: string): void {
        switch (key) {
            case 'escape':
                this._options.onClose?.();
                break;
            case 'enter':
                this._executeSelected();
                break;
            case 'up':
            case 'k':
                this._moveUp();
                break;
            case 'down':
            case 'j':
                this._moveDown();
                break;
            case 'backspace':
                this._query = this._query.slice(0, -1);
                this._filter();
                break;
            default:
                if (key.length === 1) {
                    this._query += key;
                    this._filter();
                }
                break;
        }
        this.markDirty();
    }

    // ─── Rendering ───────────────────────────────────────

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const maxVisible = this._options.maxVisible ?? 8;
        const placeholder = this._options.placeholder ?? 'Type to search...';

        // ── Row 0: query line ──────────────────────────
        const prefix = '> ';
        const queryDisplay = this._query.length > 0 ? this._query : placeholder;
        const queryDim = this._query.length === 0;
        const queryLine = truncate(prefix + queryDisplay, width);

        screen.writeString(x, y, queryLine, { ...attrs, dim: queryDim });

        // Fill rest of query row with spaces (clean background)
        const queryLineWidth = stringWidth(queryLine);
        for (let c = queryLineWidth; c < width; c++) {
            screen.setCell(x + c, y, { char: ' ', ...attrs });
        }

        // ── Rows 1..N: command list ────────────────────
        const listStartRow = 1;
        const listHeight = height - listStartRow;
        const visibleCount = Math.min(this._filtered.length, maxVisible, listHeight);

        for (let i = 0; i < visibleCount; i++) {
            const cmd = this._filtered[i];
            const isSelected = i === this._selectedIndex;
            const rowY = y + listStartRow + i;

            // Compose left part: prefix + label
            const rowPrefix = isSelected ? '▸ ' : '  ';
            const labelPart = rowPrefix + cmd.label;

            // Compose right part: description (dim, right-aligned)
            const desc = cmd.description ?? '';
            const descWidth = stringWidth(desc);

            // Available width for label (leave room for desc if it fits)
            const gap = 1; // minimum space between label and desc
            const labelMaxWidth = desc
                ? Math.max(0, width - descWidth - gap)
                : width;

            const labelTruncated = truncate(labelPart, labelMaxWidth);
            const labelWidth = stringWidth(labelTruncated);

            // Cell style for the row
            const cellStyle = {
                ...attrs,
                bold: isSelected,
                inverse: isSelected,
            };
            const dimStyle = {
                ...attrs,
                dim: true,
                inverse: isSelected,
            };

            // Write label
            screen.writeString(x, rowY, labelTruncated, cellStyle);

            // Fill gap between label and description
            if (desc) {
                const descX = x + width - descWidth;
                // Fill blank between label end and desc start
                for (let c = x + labelWidth; c < descX; c++) {
                    screen.setCell(c, rowY, { char: ' ', ...cellStyle });
                }
                // Write description (right-aligned, dim)
                screen.writeString(descX, rowY, desc, dimStyle);
            } else {
                // Fill remainder of row for inverse highlight
                for (let c = x + labelWidth; c < x + width; c++) {
                    screen.setCell(c, rowY, { char: ' ', ...cellStyle });
                }
            }
        }

        // Clear any rows below the visible commands (in case widget was larger)
        for (let i = visibleCount; i < listHeight; i++) {
            const rowY = y + listStartRow + i;
            for (let c = 0; c < width; c++) {
                screen.setCell(x + c, rowY, { char: ' ', ...attrs });
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Checkbox widget
// A toggleable boolean input with label and keyboard support
// ─────────────────────────────────────────────────────

import {
    type Screen,
    type Style,
    type Color,
    type KeyEvent,
    stringWidth,
    truncate,
    caps,
} from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface CheckboxOptions {
    /** Initial checked state. Default: false */
    checked?: boolean;
    /** Callback fired when checked state changes */
    onChange?: (checked: boolean) => void;
    /** Character shown when checked. Default: '✓' (unicode) or '+' (ASCII) */
    checkedChar?: string;
    /** Character shown when unchecked. Default: ' ' */
    uncheckedChar?: string;
    /** Whether the checkbox is disabled. Default: false */
    disabled?: boolean;
    /** Color of the check mark. Default: green */
    checkedColor?: Color;
}

/**
 * Checkbox — a toggleable boolean input with a label.
 *
 * Renders as:
 *   [✓] Enable notifications   (checked)
 *   [ ] Enable notifications   (unchecked)
 *
 * Press Enter or Space to toggle.
 * Unicode fallback: uses '+' for checked, ' ' for unchecked.
 */
export class Checkbox extends Widget {
    private _label: string;
    private _checked: boolean;
    private _disabled: boolean;
    private _onChange?: (checked: boolean) => void;
    private _checkedChar?: string;
    private _uncheckedChar?: string;
    private _checkedColor: Color;

    constructor(
        label: string,
        style: Partial<Style> = {},
        opts: CheckboxOptions = {},
    ) {
        super(style);
        this.focusable = true;
        this._label = label;
        this._checked = opts.checked ?? false;
        this._disabled = opts.disabled ?? false;
        this._onChange = opts.onChange;
        this._checkedChar = opts.checkedChar;
        this._uncheckedChar = opts.uncheckedChar;
        this._checkedColor = opts.checkedColor ?? { type: 'named', name: 'green' };
    }

    // ── Public API ──────────────────────────────────────────────────────

    /** Toggle the checked state. No-op if disabled. */
    toggle(): void {
        if (this._disabled) return;
        this._checked = !this._checked;
        this._onChange?.(this._checked);
        this.markDirty();
    }

    /** Set the checked state explicitly. No-op if already the same value. */
    setChecked(checked: boolean): void {
        if (this._checked === checked) return;
        this._checked = checked;
        this._onChange?.(this._checked);
        this.markDirty();
    }

    /** Returns the current checked state. */
    isChecked(): boolean {
        return this._checked;
    }

    /** Update the label text. No-op if unchanged. */
    setLabel(label: string): void {
        if (this._label === label) return;
        this._label = label;
        this.markDirty();
    }

    /** Get the current label. */
    getLabel(): string {
        return this._label;
    }

    /** Enable or disable the checkbox. No-op if unchanged. */
    setDisabled(disabled: boolean): void {
        if (this._disabled === disabled) return;
        this._disabled = disabled;
        this.markDirty();
    }

    /** Returns true if the checkbox is disabled. */
    isDisabled(): boolean {
        return this._disabled;
    }

    // ── Keyboard ────────────────────────────────────────────────────────

    /** Handle key events. Enter and Space toggle the checkbox. */
    handleKey(event: KeyEvent): void {
        if (this._disabled) return;
        if (event.key === 'enter' || event.key === 'space') {
            this.toggle();
        }
    }

    // ── Render ──────────────────────────────────────────────────────────

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        // Resolve chars at render time so caps.unicode is current
        const checkedChar = this._checkedChar ?? (caps.unicode ? '✓' : '+');
        const uncheckedChar = this._uncheckedChar ?? ' ';

        // Box: [✓] or [ ]
        const boxOpen = '[';
        const boxClose = ']';
        const mark = this._checked ? checkedChar : uncheckedChar;

        const box = `${boxOpen}${mark}${boxClose}`;
        const boxWidth = stringWidth(box);

        // Full line: "[✓] Label"
        const gap = ' ';
        const labelPart = this._label;
        const fullLine = box + gap + labelPart;

        // Colors
        const markColor: Color = this._checked
            ? this._checkedColor
            : { type: 'named', name: 'white' };

        const labelColor: Color = this._disabled
            ? { type: 'named', name: 'brightBlack' }
            : { type: 'named', name: 'white' };

        const focusColor: Color = { type: 'named', name: 'cyan' };

        if (stringWidth(fullLine) > width) {
            // Not enough room — render truncated
            screen.writeString(x, y, truncate(fullLine, width), { fg: labelColor });
            return;
        }

        // Write '['
        screen.setCell(x, y, {
            char: boxOpen,
            fg: this.isFocused ? focusColor : labelColor,
        });

        // Write mark char
        screen.setCell(x + 1, y, {
            char: mark,
            fg: markColor,
            bold: this._checked,
        });

        // Write ']'
        screen.setCell(x + 2, y, {
            char: boxClose,
            fg: this.isFocused ? focusColor : labelColor,
        });

        // Write ' Label'
        const labelX = x + boxWidth + stringWidth(gap);
        screen.writeString(labelX, y, labelPart, {
            fg: labelColor,
            dim: this._disabled,
        });
    }
}

import {
  type Screen,
  type Style,
  type Color,
  type KeyEvent,
  styleToCellAttrs,
  caps,
  stringWidth,
} from "@termuijs/core";
import { Widget } from "@termuijs/widgets";

export interface KnobOptions {
  min?: number;
  max?: number;
  step?: number;
  color?: Color;
  showValue?: boolean;
  onChange?: (value: number) => void;
}

export class Knob extends Widget {
  private _label: string;
  private _value: number;
  private _min: number;
  private _max: number;
  private _step: number;
  private _color: Color;
  private _showValue: boolean;
  private _onChange?: (value: number) => void;

  constructor(
    label?: string,
    style: Partial<Style> = {},
    opts: KnobOptions = {}
  ) {
    super(style);

    this.focusable = true;
    this._label = label ?? "";
    this._min = opts.min ?? 0;

    // Validate max to ensure min <= max
    const maxVal = opts.max ?? 100;
    this._max = maxVal >= this._min ? maxVal : this._min;

    this._value = this._min;

    // Validate step to ensure it is positive
    const stepVal = opts.step ?? 1;
    this._step = stepVal > 0 ? stepVal : 1;

    this._color = opts.color ?? { type: "named", name: "cyan" };
    this._showValue = opts.showValue ?? true;
    this._onChange = opts.onChange;
  }

  get value(): number {
    return this._value;
  }

  setValue(value: number): void {
    const clamped = Math.max(this._min, Math.min(this._max, value));
    if (this._value === clamped) return;

    this._value = clamped;
    this.markDirty();
    this._onChange?.(this._value);
  }

  handleKey(event: KeyEvent): void {
    switch (event.key) {
      case "up":
      case "right":
        this.setValue(this._value + this._step);
        break;
      case "down":
      case "left":
        this.setValue(this._value - this._step);
        break;
    }
  }

  protected _renderSelf(screen: Screen): void {
    const rect = this._getContentRect();
    const { x, y, width, height } = rect;

    if (width <= 0 || height <= 0) return;

    const attrs = styleToCellAttrs(this._style);

    const cx = (width - 1) / 2;
    const cy = (height - 1) / 2;
    // Account for character aspect ratio (roughly 1:2)
    const radiusX = Math.max(1, (width - 1) / 2);
    const radiusY = Math.max(1, (height - 1) / 2);

    // We want the arc to sweep from bottom-left (-135 deg or ~235 deg) 
    // to bottom-right (135 deg or ~305 deg). 
    // In polar coordinates with Y pointing down (terminal grids):
    // 0 rad is pointing right (3 o'clock).
    // Math.PI/2 is pointing down (6 o'clock).
    // We'll define startAngle = 135 deg (3/4 PI)
    // and endAngle = 45 deg (1/4 PI) BUT looping clockwise.
    // Meaning it spans from 135 deg -> 180 -> 270(up) -> 0 -> 45 deg.
    // Total sweep is 270 degrees.
    const sweepRange = 270;

    const rangeSize = Math.max(1, this._max - this._min);
    const ratio = (this._value - this._min) / rangeSize;
    const filledSweepDegrees = ratio * sweepRange;

    for (let row = 0; row < height; row++) {
      for (let col = 0; col < width; col++) {
        // Normalize dx, dy to a pure circle
        const dx = (col - cx) / radiusX;
        const dy = (row - cy) / radiusY;

        // Distance from center in normalized space
        const r = Math.sqrt(dx * dx + dy * dy);

        // We only draw if it's on the edge of the circle (thickness ~0.2)
        if (r < 0.8 || r > 1.2) {
          continue;
        }

        // Calculate angle. atan2(dy, dx) returns angle from -PI to PI.
        // Convert to degrees 0-360 starting from 3 o'clock clockwise.
        let angleDeg = Math.atan2(dy, dx) * (180 / Math.PI);
        if (angleDeg < 0) {
          angleDeg += 360;
        }

        // We shift the angle so 0 starts at bottom-left (135 deg original)
        // 135 becomes 0.
        // 270(up) becomes 135.
        // 0(right) becomes 225.
        // 45(bottom-right) becomes 270.
        let shiftedAngle = angleDeg - 135;
        if (shiftedAngle < 0) {
          shiftedAngle += 360;
        }

        // If it falls in the "gap" at the bottom (between 270 and 360 in shifted coordinates)
        if (shiftedAngle > sweepRange) {
          continue;
        }

        const isFilled = shiftedAngle <= filledSweepDegrees;
        const charToRender = caps.unicode ? "█" : "#";

        screen.setCell(x + col, y + row, {
          ...attrs,
          char: charToRender,
          fg: isFilled 
            ? (this.isFocused ? { type: "named", name: "white" } : this._color)
            : { type: "named", name: "brightBlack" },
        });
      }
    }

    if (this._showValue) {
      const valStr = String(this._value);
      const valWidth = stringWidth(valStr);
      const valX = x + Math.floor((width - valWidth) / 2);
      const valY = y + Math.floor(height / 2);

      // Print in center, but only if it fits inside the circle
      // We assume it fits if the width/height are reasonable (>4)
      if (width >= 4 && height >= 3) {
        screen.writeString(valX, valY, valStr, {
          ...attrs,
          bold: true,
          fg: this.isFocused ? { type: "named", name: "white" } : this._color
        });
      }
    }
  }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Button widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, type KeyEvent, stringWidth, caps, prefersReducedMotion } from '@termuijs/core';
import { timerPoolSubscribe } from '@termuijs/motion';
import { Widget } from '@termuijs/widgets';
import { SPINNER_FRAMES } from '@termuijs/widgets';

export type ButtonVariant = 'default' | 'primary' | 'danger' | 'ghost';

export interface ButtonOptions {
    variant?: ButtonVariant;
    disabled?: boolean;
    onPress?: () => void;
    color?: Color;
    /** Show a loading spinner and suppress activation while true (default: false) */
    loading?: boolean;
    /** Label to display while loading (e.g. "Submitting...") — falls back to the normal label if omitted */
    loadingText?: string;
}

const LOADING_SPINNER = SPINNER_FRAMES.dots;

/** Background colors for each variant */
const BG_COLORS: Record<ButtonVariant, Color> = {
    default: { type: 'named', name: 'brightBlack' },
    primary: { type: 'named', name: 'blue' },
    danger: { type: 'named', name: 'red' },
    ghost: { type: 'named', name: 'brightBlack' },
};

/** Foreground colors for each variant */
const FG_COLORS: Record<ButtonVariant, Color> = {
    default: { type: 'named', name: 'white' },
    primary: { type: 'named', name: 'white' },
    danger: { type: 'named', name: 'white' },
    ghost: { type: 'named', name: 'white' },
};

/**
 * Button — a pressable button with a label and visual variants.
 *
 * Renders a button with different visual styles based on variant.
 * Handles key events for activation when not disabled.
 */
export class Button extends Widget {
    private _label: string;
    private _variant: ButtonVariant;
    private _disabled: boolean;
    private _onPress?: () => void;
    private _color?: Color;
    private _loading: boolean;
    private _loadingText?: string;
    private _frames: string[];
    private _interval: number;
    private _startTime?: number;
    private _timerUnsub?: () => void;

    constructor(label: string, style: Partial<Style> = {}, opts: ButtonOptions = {}) {
        super(style);
        this._label = label;
        this._variant = opts.variant ?? 'default';
        this._disabled = opts.disabled ?? false;
        this._onPress = opts.onPress;
        this._color = opts.color;
        this._loading = opts.loading ?? false;
        this._loadingText = opts.loadingText;
        this._frames = caps.unicode ? LOADING_SPINNER.frames : LOADING_SPINNER.asciiFrames;
        this._interval = LOADING_SPINNER.interval;
        this.focusable = true;
    }

    setLabel(label: string): void {
        if (this._label === label) return;
        this._label = label;
        this.markDirty();
    }

    setDisabled(disabled: boolean): void {
        if (this._disabled === disabled) return;
        this._disabled = disabled;
        this.markDirty();
    }

    /** Toggle the loading state. While loading, the button shows a spinner and ignores activation. */
    setLoading(loading: boolean): void {
        if (this._loading === loading) return;

        this._loading = loading;
        this.markDirty();

        this._timerUnsub?.();
        this._timerUnsub = undefined;
        if (loading && !prefersReducedMotion()) {
            this._startTime = Date.now();
            this._timerUnsub = timerPoolSubscribe(this._interval, () => {
                this.markDirty();
            });
        }
    }

    /** Update the text shown while loading (e.g. "Submitting..."). */
    setLoadingText(loadingText: string | undefined): void {
        this._loadingText = loadingText;
        if (this._loading) this.markDirty();
    }

    handleKey(event: KeyEvent): void {
        if (this._disabled || this._loading) return;

        if (event.key === 'enter' || event.key === 'space') {
            this._onPress?.();
        }
    }

    /** Lifecycle: start the spinner timer if mounted while already loading. */
    mount(): void {
        super.mount();
        if (this._loading && !prefersReducedMotion()) {
            this._timerUnsub?.();
            this._startTime = Date.now();
            this._timerUnsub = timerPoolSubscribe(this._interval, () => {
                this.markDirty();
            });
        }
    }

    /** Lifecycle: stop the spinner timer. */
    unmount(): void {
        this._timerUnsub?.();
        this._timerUnsub = undefined;
        super.unmount();
    }

    /** Compute the current spinner frame character based on elapsed time. */
    private _currentFrame(): string {
        if (prefersReducedMotion() || this._startTime === undefined) return this._frames[0];
        const elapsed = Date.now() - this._startTime;
        const idx = Math.floor(elapsed / this._interval) % this._frames.length;
        return this._frames[idx];
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        const bg = this._color ?? BG_COLORS[this._variant];
        const fg = FG_COLORS[this._variant];
        const borderFg = this.isFocused
            ? { type: 'named' as const, name: 'cyan' as const }
            : fg;

        const tl = caps.unicode ? '┌' : '+';
        const tr = caps.unicode ? '┐' : '+';
        const bl = caps.unicode ? '└' : '+';
        const br = caps.unicode ? '┘' : '+';
        const hz = caps.unicode ? '─' : '-';
        const vt = caps.unicode ? '│' : '|';

        // Padded text: " label " — swap in spinner + loading text while loading
        const displayLabel = this._loading
            ? `${this._currentFrame()} ${this._loadingText ?? this._label}`
            : this._label;
        const padded = ` ${displayLabel} `;
        const textWidth = stringWidth(padded);

        const innerWidth = Math.min(textWidth, Math.max(0, width - 2));

        if (height >= 1) {
            screen.setCell(x, y, { char: tl, fg: borderFg, bg });
            for (let c = 1; c <= innerWidth; c++) {
                screen.setCell(x + c, y, { char: hz, fg: borderFg, bg });
            }
            if (innerWidth + 1 < width) {
                screen.setCell(x + innerWidth + 1, y, { char: tr, fg: borderFg, bg });
            }
        }

        if (height >= 2) {
            screen.setCell(x, y + 1, { char: vt, fg: borderFg, bg });
            const startX = x + 1;
            const textStartX = startX + Math.floor((innerWidth - textWidth) / 2);
            screen.writeString(textStartX, y + 1, padded, { fg: borderFg, bg });
            for (let c = textStartX + textWidth; c < startX + innerWidth; c++) {
                screen.setCell(c, y + 1, { char: ' ', fg: borderFg, bg });
            }
            if (innerWidth + 1 < width) {
                screen.setCell(x + innerWidth + 1, y + 1, { char: vt, fg: borderFg, bg });
            }
        }

        if (height >= 3) {
            screen.setCell(x, y + 2, { char: bl, fg: borderFg, bg });
            for (let c = 1; c <= innerWidth; c++) {
                screen.setCell(x + c, y + 2, { char: hz, fg: borderFg, bg });
            }
            if (innerWidth + 1 < width) {
                screen.setCell(x + innerWidth + 1, y + 2, { char: br, fg: borderFg, bg });
            }
        }
    }
}

import {
  type Screen,
  type Style,
  type KeyEvent,
  styleToCellAttrs,
  caps,
} from "@termuijs/core";
import { Widget } from "@termuijs/widgets";

export interface PinInputOptions {
  length?: number;
  masked?: boolean;
  onChange?: (value: string) => void;
  onComplete?: (value: string) => void;
}

export class PinInput extends Widget {
  private _length: number;
  private _masked: boolean;
  private _value: string[];
  private _cursorPos: number = 0;
  private _onChange?: (value: string) => void;
  private _onComplete?: (value: string) => void;

  /**
   * Creates a new PinInput widget.
   *
   * @param style Partial style properties for the widget.
   * @param opts Configuration options for the PinInput.
   */
  constructor(
    style: Partial<Style> = {},
    opts: PinInputOptions = {}
  ) {
    super(style);
    this.focusable = true;

    this._length = Math.max(1, Math.floor(opts.length ?? 4));
    this._masked = opts.masked ?? false;
    this._onChange = opts.onChange;
    this._onComplete = opts.onComplete;

    // Initialize empty array of correct length
    this._value = Array(this._length).fill("");
  }

  get value(): string {
    return this._value.join("");
  }

  private get _isFull(): boolean {
    return this._value.every((v) => v !== "");
  }

  handleKey(event: KeyEvent): void {
    const key = event.key;

    if (key === "left") {
      this._cursorPos = Math.max(0, this._cursorPos - 1);
      this.markDirty();
      return;
    }

    if (key === "right") {
      this._cursorPos = Math.min(this._length - 1, this._cursorPos + 1);
      this.markDirty();
      return;
    }

    if (key === "backspace" || key === "delete") {
      if (this._value[this._cursorPos] !== "") {
        // Clear current block
        this._value[this._cursorPos] = "";
      } else if (this._cursorPos > 0) {
        // Move back and clear
        this._cursorPos--;
        this._value[this._cursorPos] = "";
      }

      this.markDirty();
      this._onChange?.(this.value);
      return;
    }

    // Handle character input
    if (key.length === 1) {
      // Set value at current position
      this._value[this._cursorPos] = key;
      this.markDirty();

      const currentVal = this.value;
      this._onChange?.(currentVal);

      // Advance cursor or trigger complete
        this._cursorPos = Math.min(this._length - 1, this._cursorPos + 1);

        if (this._isFull) {
          this._onComplete?.(this.value);
        }
    }
  }

  protected _renderSelf(screen: Screen): void {
    const rect = this._getContentRect();
    const { x, y, width, height } = rect;

    if (width <= 0 || height <= 0) return;

    const attrs = styleToCellAttrs(this._style);

    let currentX = x;

    for (let i = 0; i < this._length; i++) {
      // Check if this block would render out of bounds
      if (currentX + 5 > x + width) {
          break; // Stop rendering if it exceeds width
      }

      const isFocusedBlock = this.isFocused && this._cursorPos === i;
      const charVal = this._value[i];
      let displayChar = " ";

      if (charVal !== "") {
          displayChar = this._masked ? (caps.unicode ? "•" : "*") : charVal;
      }

        const blockStr = `[ ${displayChar} ]`;

      // Apply inverse colors for the focused block
      const blockAttrs = {
        ...attrs,
        inverse: isFocusedBlock ? !attrs.inverse : attrs.inverse,
      };

      screen.writeString(currentX, y, blockStr, blockAttrs);
      currentX += 5; // [ + space + char + space + ] -> 5 columns. We space them out.

      // Add gap between blocks
      currentX += 1;
    }
  }
}

import {
  type Screen,
  type Style,
  type Color,
  type KeyEvent,
  styleToCellAttrs,
  stringWidth,
  caps,
} from "@termuijs/core";
import { Widget } from "@termuijs/widgets";

export interface SliderOptions {
  min?: number;
  max?: number;
  step?: number;
  color?: Color;
  showValue?: boolean;
}

export class Slider extends Widget {
  focusable = true;
  private _label: string;
  private _value = 0;
  private _min: number;
  private _max: number;
  private _step: number;
  private _color: Color;
  private _showValue: boolean;

  constructor(
    label: string,
    style: Partial<Style> = {},
    opts: SliderOptions = {}
  ) {
    super(style);

    this._label = label;
    this._min = opts.min ?? 0;
    this._max = opts.max ?? 100;
    this._step = opts.step ?? 1;
    this._color = opts.color ?? { type: "named", name: "cyan" };
    this._showValue = opts.showValue ?? true;
  }

  getValue(): number {
    return this._value;
  }

  setValue(value: number): void {
    this._value = Math.max(this._min, Math.min(this._max, value));
    this.markDirty();
  }

  setLabel(label: string): void {
    this._label = label;
    this.markDirty();
  }

  handleKey(event: KeyEvent): void {
    switch (event.key) {
      case "right":
        this.setValue(this._value + this._step);
        break;
      case "left":
        this.setValue(this._value - this._step);
        break;
    }
  }

  protected _renderSelf(screen: Screen): void {
    const rect = this._getContentRect();
    const { x, y, width, height } = rect;

    if (width <= 0 || height <= 0) return;

    const attrs = styleToCellAttrs(this._style);

    const leftArrow = caps.unicode ? "◄" : "<";
    const rightArrow = caps.unicode ? "►" : ">";

    const valueStr = this._showValue ? ` ${this._value}%` : "";
    const prefix = `${this._label} ${leftArrow} `;
    const suffix = ` ${rightArrow}${valueStr}`;

    const prefixWidth = stringWidth(prefix);
    const suffixWidth = stringWidth(suffix);

    const trackWidth = Math.max(
      0,
      width - prefixWidth - suffixWidth
    );

    const ratio =
      (this._value - this._min) /
      Math.max(1, this._max - this._min);

    const filled = Math.round(trackWidth * ratio);

    screen.writeString(x, y, prefix, {
      ...attrs,
      bold: true,
    });

    const trackX = x + prefixWidth;

    for (let i = 0; i < trackWidth; i++) {
      const filledChar = caps.unicode ? "█" : "#";
      const emptyChar = caps.unicode ? "░" : "-";

      screen.setCell(trackX + i, y, {
        char: i < filled ? filledChar : emptyChar,
        fg:
          i < filled
            ? this._color
            : { type: "named", name: "brightBlack" },
      });
    }

    screen.writeString(trackX + trackWidth, y, suffix, {
      ...attrs,
      bold: true,
    });
  }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — TextInput widget
// ─────────────────────────────────────────────────────

import {
    type Screen,
    type Style,
    styleToCellAttrs,
    stringWidth,
    truncate,
    type KeyEvent,
    splitGraphemes
} from '@termuijs/core';
import { Widget } from '@termuijs/widgets';
import { type VimMode } from '@termuijs/widgets';

export type { VimMode };

/**
 * TextInput — a single-line text input field
 * with optional command auto-completion support.
 */
export class TextInput extends Widget {
    private _value = '';
    private _cursorPos = 0;
    private _placeholder: string;
    private _mask: string | null;
    private _maxLength: number;
    private _onChange?: (value: string) => void;
    private _onSubmit?: (value: string) => void;
    private _vimMode: VimMode = process.env.TERMUI_KEYBINDINGS === 'vim' ? 'normal' : 'insert';
    private _suggestions: string[] = [];
    private _suggestionIndex = 0;

    constructor(
        style: Partial<Style> = {},
        options: {
            placeholder?: string;
            mask?: string;
            maxLength?: number;
            suggestions?: string[];
            onChange?: (value: string) => void;
            onSubmit?: (value: string) => void;
        } = {},
    ) {
        super({ border: 'single', height: 3, ...style });

        this._placeholder = options.placeholder ?? '';
        this._mask = options.mask ?? null;
        this._maxLength = options.maxLength ?? Infinity;
        this._onChange = options.onChange;
        this._onSubmit = options.onSubmit;
        this._suggestions = options.suggestions ?? [];

        this.focusable = true;

        this.events.on('key', (event: KeyEvent) => this.handleKey(event));
    }

    get value(): string {
        return this._value;
    }

    set value(v: string) {
        const graphemes = splitGraphemes(v);
        if (graphemes.length > this._maxLength) {
            this._value = graphemes.slice(0, this._maxLength).join('');
        } else {
            this._value = v;
        }
        this._cursorPos = Math.min(this._cursorPos, splitGraphemes(this._value).length);
        this.markDirty();
    }

    get vimMode(): VimMode {
        return this._vimMode;
    }

    set vimMode(mode: VimMode) {
        this._vimMode = mode;
        this.markDirty();
    }

    getSuggestions(input: string): string[] {
        return this._suggestions.filter(s => s.toLowerCase().includes(input.toLowerCase()));
    }

    acceptSuggestion(): void {
        const suggestions = this.getSuggestions(this._value);
        if (suggestions.length === 0) return;
        this.value = suggestions[this._suggestionIndex % suggestions.length];
        this._cursorPos = splitGraphemes(this._value).length;
        this.markDirty();
    }

    insertChar(char: string): void {
        const graphemes = splitGraphemes(this._value);
        if (graphemes.length >= this._maxLength) return;
        graphemes.splice(this._cursorPos, 0, char);
        this._value = graphemes.join('');
        this._cursorPos++;
        this._suggestionIndex = 0;
        this._onChange?.(this._value);
        this.markDirty();
    }

    deleteBack(): void {
        if (this._cursorPos > 0) {
            const graphemes = splitGraphemes(this._value);
            graphemes.splice(this._cursorPos - 1, 1);
            this._value = graphemes.join('');
            this._cursorPos--;
            this._onChange?.(this._value);
            this.markDirty();
        }
    }

    deleteForward(): void {
        const graphemes = splitGraphemes(this._value);
        if (this._cursorPos < graphemes.length) {
            graphemes.splice(this._cursorPos, 1);
            this._value = graphemes.join('');
            this._onChange?.(this._value);
            this.markDirty();
        }
    }

    deleteWordBack(): void {
        if (this._cursorPos === 0) return;

        const graphemes = splitGraphemes(this._value);
        let i = this._cursorPos - 1;

        // Skip trailing spaces
        while (i >= 0 && graphemes[i] === ' ') {
            i--;
        }

        // Find the start of the word
        while (i >= 0 && graphemes[i] !== ' ') {
            i--;
        }

        const deleteStart = i + 1;

        graphemes.splice(deleteStart, this._cursorPos - deleteStart);
        this._value = graphemes.join('');
        this._cursorPos = deleteStart;
        this._onChange?.(this._value);
        this.markDirty();
    }

    moveCursorLeft(): void {
        const next = Math.max(0, this._cursorPos - 1);

        if (next === this._cursorPos) {
            return;
        }

        this._cursorPos = next;
        this.markDirty();
    }

    moveCursorRight(): void {
        const graphemes = splitGraphemes(this._value);
        const next = Math.min(graphemes.length, this._cursorPos + 1);

        if (next === this._cursorPos) {
            return;
        }

        this._cursorPos = next;
        this.markDirty();
    }

    moveCursorHome(): void {
        if (this._cursorPos === 0) {
            return;
        }

        this._cursorPos = 0;
        this.markDirty();
    }

    moveCursorEnd(): void {
        const graphemes = splitGraphemes(this._value);
        if (this._cursorPos === graphemes.length) {
            return;
        }

        this._cursorPos = graphemes.length;
        this.markDirty();
    }

    submit(): void {
        this._onSubmit?.(this._value);
    }

    clear(): void {
        this._value = '';
        this._cursorPos = 0;
        this._suggestionIndex = 0;
        this._onChange?.('');
        this.markDirty();
    }

    clearLine(): void {
        this._value = '';
        this._cursorPos = 0;
        this._onChange?.('');
        this.markDirty();
    }

    handleKey(event: KeyEvent): void {
        const isVim = process.env.TERMUI_KEYBINDINGS === 'vim';

        if (isVim) {
            if (this._vimMode === 'normal') {
                switch (event.key) {
                    case 'i':
                        this._vimMode = 'insert';
                        this.markDirty();
                        event.preventDefault();
                        event.stopPropagation();
                        break;
                    case 'a':
                        this._vimMode = 'insert';
                        this.moveCursorRight();
                        this.markDirty();
                        event.preventDefault();
                        event.stopPropagation();
                        break;
                    case 'v':
                        this._vimMode = 'visual';
                        this.markDirty();
                        event.preventDefault();
                        event.stopPropagation();
                        break;
                    case 'h':
                        this.moveCursorLeft();
                        event.preventDefault();
                        event.stopPropagation();
                        break;
                    case 'l':
                        this.moveCursorRight();
                        event.preventDefault();
                        event.stopPropagation();
                        break;
                    case 'x': {
                        const graphemes = splitGraphemes(this._value);
                        if (this._cursorPos < graphemes.length) {
                            graphemes.splice(this._cursorPos, 1);
                            this._value = graphemes.join('');
                            this._cursorPos = Math.min(this._cursorPos, graphemes.length - 1);
                            this._cursorPos = Math.max(0, this._cursorPos);
                            this._onChange?.(this._value);
                            this.markDirty();
                        }
                        event.preventDefault();
                        event.stopPropagation();
                        break;
                    }
                    case 'j':
                        event.key = 'tab';
                        event.shift = false;
                        break;
                    case 'k':
                        event.key = 'tab';
                        event.shift = true;
                        break;
                    case 'enter':
                    case 'return':
                        this.submit();
                        event.preventDefault();
                        event.stopPropagation();
                        break;
                    default:
                        event.preventDefault();
                        event.stopPropagation();
                        break;
                }
                return;
            } else if (this._vimMode === 'visual') {
                if (event.key === 'escape') {
                    this._vimMode = 'normal';
                    this.markDirty();
                    event.preventDefault();
                    event.stopPropagation();
                } else {
                    event.preventDefault();
                    event.stopPropagation();
                }
                return;
            } else if (this._vimMode === 'insert') {
                if (event.key === 'escape') {
                    this._vimMode = 'normal';
                    this.moveCursorLeft();
                    this.markDirty();
                    event.preventDefault();
                    event.stopPropagation();
                    return;
                }
            }
        }

        if (event.ctrl) {
            if (event.key === 'u') {
                this.clearLine();
                event.preventDefault();
                event.stopPropagation();
                return;
            } else if (event.key === 'w') {
                this.deleteWordBack();
                event.preventDefault();
                event.stopPropagation();
                return;
            }
        }

        switch (event.key) {
            case 'tab':
                this.acceptSuggestion();
                event.preventDefault();
                event.stopPropagation();
                break;
            case 'backspace':
                this.deleteBack();
                event.preventDefault();
                event.stopPropagation();
                break;
            case 'delete':
                this.deleteForward();
                event.preventDefault();
                event.stopPropagation();
                break;
            case 'left':
                this.moveCursorLeft();
                event.preventDefault();
                event.stopPropagation();
                break;
            case 'right':
                this.moveCursorRight();
                event.preventDefault();
                event.stopPropagation();
                break;
            case 'home':
                this.moveCursorHome();
                event.preventDefault();
                event.stopPropagation();
                break;
            case 'end':
                this.moveCursorEnd();
                event.preventDefault();
                event.stopPropagation();
                break;
            case 'return':
            case 'enter':
                this.submit();
                event.preventDefault();
                event.stopPropagation();
                break;
            default:
                if (event.key && splitGraphemes(event.key).length === 1 && !event.ctrl && !event.alt) {
                    this.insertChar(event.key);
                    event.preventDefault();
                    event.stopPropagation();
                }
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        if (this._value.length === 0 && !this.isFocused) {
            screen.writeString(x, y, truncate(this._placeholder, width), { ...attrs, dim: true });
            return;
        }

        const graphemes = splitGraphemes(this._value);
        const displayGraphemes = this._mask
            ? Array(graphemes.length).fill(this._mask)
            : graphemes;

        let rightReserved = 0;
        let modeIndicator = '';
        if (process.env.TERMUI_KEYBINDINGS === 'vim' && this.isFocused && width > 15) {
            modeIndicator = ` -- ${this._vimMode.toUpperCase()} -- `;
            rightReserved = modeIndicator.length;
        } else if (this.isFocused) {
            const length = this._value.length;
            const max = this._maxLength === Infinity ? null : this._maxLength;
            const counterText = max ? `${length}/${max}` : `${length}`;
            const counterWidth = stringWidth(counterText);
            if (x + width - counterWidth >= x) {
                rightReserved = counterWidth;
            }
        }

        const maxVisibleWidth = width - rightReserved;
        if (maxVisibleWidth <= 0) return;

        // Calculate visual width prefix sums
        const prefixWidths: number[] = [0];
        for (let i = 0; i < displayGraphemes.length; i++) {
            prefixWidths.push(prefixWidths[i] + stringWidth(displayGraphemes[i]));
        }

        let scrollGraphemeIndex = 0;
        const targetVisualEnd = this._cursorPos < displayGraphemes.length
            ? prefixWidths[this._cursorPos + 1]
            : prefixWidths[this._cursorPos];

        while (scrollGraphemeIndex < this._cursorPos && targetVisualEnd - prefixWidths[scrollGraphemeIndex] > maxVisibleWidth) {
            scrollGraphemeIndex++;
        }

        let endGraphemeIndex = scrollGraphemeIndex;
        while (endGraphemeIndex < displayGraphemes.length && prefixWidths[endGraphemeIndex + 1] - prefixWidths[scrollGraphemeIndex] <= maxVisibleWidth) {
            endGraphemeIndex++;
        }

        const visibleGraphemes = displayGraphemes.slice(scrollGraphemeIndex, endGraphemeIndex);
        const visibleText = visibleGraphemes.join('');
        screen.writeString(x, y, visibleText, attrs);

        if (this.isFocused) {
            const cursorOffset = prefixWidths[this._cursorPos] - prefixWidths[scrollGraphemeIndex];
            const cursorScreenPos = x + cursorOffset;
            if (cursorScreenPos >= x && cursorScreenPos < x + maxVisibleWidth) {
                const cursorChar = this._cursorPos < displayGraphemes.length
                    ? displayGraphemes[this._cursorPos]
                    : ' ';
                const isBlock = this._vimMode === 'normal' || this._vimMode === 'visual';
                screen.setCell(cursorScreenPos, y, {
                    char: cursorChar[0] || ' ',
                    ...attrs,
                    inverse: isBlock,
                    underline: !isBlock,
                });
            }
        }

        if (modeIndicator) {
            screen.writeString(x + width - modeIndicator.length, y, modeIndicator, { ...attrs, dim: true });
        } else if (this.isFocused) {
            const length = this._value.length;
            const max = this._maxLength === Infinity ? null : this._maxLength;
            const counterText = max ? `${length}/${max}` : `${length}`;
            const counterWidth = stringWidth(counterText);
            const counterX = x + width - counterWidth;
            if (counterX >= x) {
                screen.writeString(counterX, y, counterText, { ...attrs, dim: true });
            }
        }

        // Inline suggestions (only visible when height > 1, e.g. opts.style.height > 3)
        const suggestions = this.getSuggestions(this._value).slice(0, height - 1);
        for (let i = 0; i < suggestions.length; i++) {
            screen.writeString(x, y + i + 1, truncate(suggestions[i], width), { ...attrs, dim: true });
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — List widget (selectable)
// ─────────────────────────────────────────────────────

import { type Screen, type Style, styleToCellAttrs, stringWidth, truncate, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';
import { type ListState } from '@termuijs/widgets';

export interface ListItem {
    label: string;
    value: string;
    disabled?: boolean;
}

export interface ListProps {
    items?: ListItem[];
    style?: Partial<Style>;
    onSelect?: (item: ListItem, index: number) => void;
    /** External state object – if provided, List reads/writes selection through it */
    state?: ListState;
    /** Called whenever selection or scroll changes */
    onStateChange?: (state: ListState) => void;
    /** Message to display when the list is empty */
    emptyMessage?: string;
    /** Allow items to be reordered via moveItem() */
    reorderable?: boolean;
}


/**
 * List — a scrollable, selectable list of items.
 *
 * Supports:
 * - Keyboard navigation (up/down/Home/End)
 * - Scrolling when items exceed visible height
 * - Custom item styling
 * - Disabled items
 * - External state via `state` prop and `useListState` hook
 */
export class List extends Widget {
    private _items: ListItem[];
    private _selectedIndex = 0;
    private _scrollOffset = 0;
    private _onSelect?: (item: ListItem, index: number) => void;
    private _state?: ListState;
    private _onStateChange?: (state: ListState) => void;
    private _emptyMessage?: string;
    private _reorderable = false;

    constructor(
        itemsOrProps: ListItem[] | ListProps,
        style: Partial<Style> = {},
        onSelect?: (item: ListItem, index: number) => void,
    ) {
        super({ border: 'single', ...style });

        if (Array.isArray(itemsOrProps)) {
            this._items = itemsOrProps;
            this._onSelect = onSelect;
        } else {
            const props = itemsOrProps as ListProps;
            this._items = props.items ?? [];
            this._state = props.state;
            this._onStateChange = props.onStateChange;
            this._onSelect = props.onSelect ?? onSelect;
            this._emptyMessage = props.emptyMessage;
            this._reorderable = props.reorderable ?? false;

            // Initialise from external state if provided
            if (props.state) {
                this._selectedIndex = props.state.selectedIndex;
                this._scrollOffset = props.state.scrollOffset;
            }
        }

        this.focusable = true;
    }

    // ── Getters ───────────────────────────────────────

    get selectedIndex(): number { return this._selectedIndex; }
    get selectedItem(): ListItem | undefined { return this._items[this._selectedIndex]; }

    // ── Mutations ─────────────────────────────────────

    setItems(items: ListItem[]): void {
        this._items = items;
        if (this._selectedIndex >= items.length) {
            this._selectedIndex = Math.max(0, items.length - 1);
        }
        this._clampScroll();
        this.markDirty();
        this._pushState();
    }

    /** Move an item to a new position (requires reorderable: true). */
    moveItem(from: number, to: number): void {
        if (!this._reorderable) return;
        if (from < 0 || to < 0 || from >= this._items.length || to >= this._items.length) return;
        const [item] = this._items.splice(from, 1);
        if (item) {
            this._items.splice(to, 0, item);
            this._selectedIndex = to;
            this._clampScroll();
            this.markDirty();
            this._pushState();
        }
    }

    /** Move selection up */
    selectPrev(): void {
        let next = this._selectedIndex - 1;
        while (next >= 0 && this._items[next]?.disabled) next--;
        if (next >= 0) {
            this._selectedIndex = next;
            this._clampScroll();
            this.markDirty();
            this._pushState();
        }
    }

    /** Move selection down */
    selectNext(): void {
        let next = this._selectedIndex + 1;
        while (next < this._items.length && this._items[next]?.disabled) next++;
        if (next < this._items.length) {
            this._selectedIndex = next;
            this._clampScroll();
            this.markDirty();
            this._pushState();
        }
    }

    /** Confirm the current selection */
    confirm(): void {
        const item = this._items[this._selectedIndex];
        if (item && !item.disabled) {
            this._onSelect?.(item, this._selectedIndex);
        }
    }

    // ── External state sync ───────────────────────────

    private _pushState(): void {
        if (this._state) {
            this._state.items = this._items;
            this._state.selectedIndex = this._selectedIndex;
            this._state.scrollOffset = this._scrollOffset;
            this._onStateChange?.(this._state);
        }
    }

    // ── Rendering ─────────────────────────────────────

       protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        // Render Empty State if no items exist
        if (this._items.length === 0 && this._emptyMessage) {
            const msg = truncate(this._emptyMessage, width);
            const msgX = x + Math.floor((width - stringWidth(msg)) / 2);
            const msgY = y + Math.floor(height / 2);
            screen.writeString(msgX, msgY, msg, { ...attrs, dim: true });
            return;
        }

        const visibleCount = Math.min(this._items.length - this._scrollOffset, height);

        for (let i = 0; i < visibleCount; i++) {
            const itemIdx = this._scrollOffset + i;
            const item = this._items[itemIdx];
            const isSelected = itemIdx === this._selectedIndex;

            // Compose the line
            const prefix = isSelected ? (caps.unicode ? '▸ ' : '> ') : '  ';
            let line = prefix + item.label;
            line = truncate(line, width);

            // Style
            const cellStyle = {
                ...attrs,
                bold: isSelected,
                dim: item.disabled ?? false,
                inverse: isSelected && this.isFocused,
            };

            screen.writeString(x, y + i, line, cellStyle);

            // Fill rest of line for inverse highlight
            if (isSelected && this.isFocused) {
                const remaining = width - stringWidth(line);
                for (let c = 0; c < remaining; c++) {
                    screen.setCell(x + stringWidth(line) + c, y + i, { char: ' ', ...cellStyle });
                }
            }
        }

        // Scrollbar indicator
        if (this._items.length > height) {
            const scrollRatio = this._scrollOffset / (this._items.length - height);
            const scrollPos = Math.floor(scrollRatio * (height - 1));
            for (let r = 0; r < height; r++) {
                const scrollChar = r === scrollPos ? (caps.unicode ? '█' : '#') : (caps.unicode ? '░' : '-');
                screen.setCell(x + width - 1, y + r, { char: scrollChar, ...attrs, dim: true });
            }
        }
    }

    private _clampScroll(): void {
        const rect = this._getContentRect();
        const visibleHeight = rect.height;
        if (visibleHeight <= 0) { this._scrollOffset = 0; return; }

        if (this._selectedIndex < this._scrollOffset) {
            this._scrollOffset = this._selectedIndex;
        }
        if (this._selectedIndex >= this._scrollOffset + visibleHeight) {
            this._scrollOffset = this._selectedIndex - visibleHeight + 1;
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — VirtualList (scroll virtualization)
//
// Renders only the visible rows of a large dataset.
// Supports keyboard navigation, custom item rendering,
// and variable-height items.
//
// Usage:
//   const list = new VirtualList({
//       totalItems: 100_000,
//       itemHeight: 1,
//       renderItem: (index) => `Row #${index}`,
//   });
// ─────────────────────────────────────────────────────

import { type Cell, type Screen, type Style, styleToCellAttrs, truncate, stringWidth, caps, prefersReducedMotion } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';
import { computeRange } from '@termuijs/widgets';
import { calculateSpringScroll, type ScrollSpringState } from '@termuijs/widgets';

export interface VirtualListOptions {
    /** Total number of items (the full dataset size) */
    totalItems: number;
    /** Height of each item in rows (default: 1) */
    itemHeight?: number;
    /** Fixed height of each item, alias for itemHeight */
    fixedItemHeight?: number;
    /** Whether to memoize the layout and bypass Flexbox recalculation on scroll frames (default: true) */
    memoizeLayout?: boolean;
    /** Render function: returns the string content for an item at a given index */
    renderItem: (index: number) => string;
    /** Style overrides */
    style?: Partial<Style>;
    /** Callback when an item is selected (Enter key) */
    onSelect?: (index: number) => void;
    /** Number of overscan rows to render above/below the viewport (default: 2) */
    overscan?: number;
    /** Show scrollbar (default: true) */
    showScrollbar?: boolean;
    /** Enable spring scroll animations (default: true, respects prefersReducedMotion) */
    springScroll?: boolean;
}

/**
 * VirtualList — a scroll-virtualized list widget.
 *
 * Only renders the items visible in the viewport plus
 * a small overscan buffer, enabling smooth scrolling
 * through datasets of any size.
 *
 * Performance:
 * - 100 items → renders ~26 rows
 * - 1,000,000 items → still renders only ~26 rows
 */
export class VirtualList extends Widget {
    private _totalItems: number;
    private _itemHeight: number;
    private _renderItem: (index: number) => string;
    private _onSelect?: (index: number) => void;
    private _selectedIndex = 0;
    private _scrollOffset = 0;
    private _overscan: number;
    private _showScrollbar: boolean;

    private _memoizeLayout: boolean;
    private _isScrolling = false;
    private _lastContentWidth = 0;
    private _renderCache = new Map<number, {
        line: string;
        cellStyle:  Partial<Omit<Cell, 'char' | 'width'>>;
        isSelected: boolean;
        isFocused: boolean;
    }>();

    // ── Spring scroll animation state ──
    private _springScroll: boolean;
    private _targetScrollOffset = 0;
    private _spring: ScrollSpringState = { position: 0, velocity: 0 };
    private _lastUpdateTime = 0;
    private _isAnimating = false;
    private _animationTimeoutId: ReturnType<typeof setTimeout> | null = null;

    constructor(options: VirtualListOptions) {
        super({ border: 'single', ...options.style });
        this._totalItems = options.totalItems;
        const resolvedItemHeight = options.fixedItemHeight ?? options.itemHeight ?? 1;
        if (!Number.isFinite(resolvedItemHeight) || resolvedItemHeight <= 0) {
            throw new Error('VirtualList itemHeight must be a positive number');
        }
        this._itemHeight = resolvedItemHeight;
        this._memoizeLayout = options.memoizeLayout ?? true;
        this._renderItem = options.renderItem;
        this._onSelect = options.onSelect;
        this._overscan = options.overscan ?? 2;
        this._showScrollbar = options.showScrollbar ?? true;
        this._springScroll = options.springScroll ?? !prefersReducedMotion();
        this.focusable = true;
    }

    // ── Getters ──

    get totalItems(): number { return this._totalItems; }
    get selectedIndex(): number { return this._selectedIndex; }
    get scrollOffset(): number { return this._scrollOffset; }

    // ── Public API ──

    /** Update the total item count (e.g., after data refresh) */
    setTotalItems(count: number): void {
        this._clearCache();
        this._totalItems = count;
        this._selectedIndex = Math.min(this._selectedIndex, Math.max(0, count - 1));
        this._clampScroll();
        this.markDirty();
    }

    /** Update the render function (e.g., when data changes) */
    setRenderItem(fn: (index: number) => string): void {
        this._clearCache();
        this._renderItem = fn;
        this.markDirty();
    }

    /** Move selection up by one */
    selectPrev(): void {
        if (this._selectedIndex > 0) {
            this._runScrollAction(() => {
                this._selectedIndex--;
                this._clampScroll();
                this.markDirty();
            });
        }
    }

    /** Move selection down by one */
    selectNext(): void {
        if (this._selectedIndex < this._totalItems - 1) {
            this._runScrollAction(() => {
                this._selectedIndex++;
                this._clampScroll();
                this.markDirty();
            });
        }
    }

    /** Jump to the first item */
    selectFirst(): void {
        this._runScrollAction(() => {
            this._selectedIndex = 0;
            this._clampScroll();
            this.markDirty();
        });
    }

    /** Jump to the last item */
    selectLast(): void {
        this._runScrollAction(() => {
            this._selectedIndex = Math.max(0, this._totalItems - 1);
            this._clampScroll();
            this.markDirty();
        });
    }

    /** Page up — move by viewport height */
    pageUp(): void {
        this._runScrollAction(() => {
            const rect = this._getContentRect();
            const pageSize = Math.max(1, Math.floor(rect.height / this._itemHeight));
            this._selectedIndex = Math.max(0, this._selectedIndex - pageSize);
            this._clampScroll();
            this.markDirty();
        });
    }

    /** Page down — move by viewport height */
    pageDown(): void {
        this._runScrollAction(() => {
            const rect = this._getContentRect();
            const pageSize = Math.max(1, Math.floor(rect.height / this._itemHeight));
            this._selectedIndex = Math.min(this._totalItems - 1, this._selectedIndex + pageSize);
            this._clampScroll();
            this.markDirty();
        });
    }

    /** Scroll to a specific index */
    scrollTo(index: number): void {
        this._runScrollAction(() => {
            this._selectedIndex = Math.max(0, Math.min(index, this._totalItems - 1));
            this._clampScroll();
            this.markDirty();
        });
    }

    /** Confirm the current selection */
    confirm(): void {
        if (this._totalItems > 0) {
            this._onSelect?.(this._selectedIndex);
        }
    }

    override setStyle(style: Partial<Style>): void {
        this._clearCache();
        super.setStyle(style);
    }

    override markDirty(): void {
        if (this._memoizeLayout && this._isScrolling) {
            this._markDirtyNoLayout();
            return;
        }
        super.markDirty();
    }

    override destroy(): void {
        if (this._animationTimeoutId !== null) {
            clearTimeout(this._animationTimeoutId);
            this._animationTimeoutId = null;
        }
        super.destroy();
    }

    // ── Rendering ──

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0 || this._totalItems === 0) return;

        // Update spring animation if active
        if (this._springScroll && this._isAnimating) {
            const now = performance.now();
            let dt = this._lastUpdateTime > 0 ? (now - this._lastUpdateTime) / 1000 : 1 / 60;
            if (dt <= 0 || dt > 0.1) {
                dt = 1 / 60;
            }
            this._lastUpdateTime = now;

            const nextSpring = calculateSpringScroll(this._spring, this._targetScrollOffset, dt);
            this._spring = nextSpring;
            this._scrollOffset = Math.round(nextSpring.position);

            const posDiff = Math.abs(nextSpring.position - this._targetScrollOffset);
            const velDiff = Math.abs(nextSpring.velocity);

            if (posDiff < 0.05 && velDiff < 0.05) {
                this._spring.position = this._targetScrollOffset;
                this._spring.velocity = 0;
                this._scrollOffset = this._targetScrollOffset;
                this._isAnimating = false;
                this._lastUpdateTime = 0;
                if (this._animationTimeoutId !== null) {
                    clearTimeout(this._animationTimeoutId);
                    this._animationTimeoutId = null;
                }
            } else {
                // Request next frame update
                if (this._animationTimeoutId === null) {
                    this._animationTimeoutId = setTimeout(() => {
                        this._animationTimeoutId = null;
                        this.markDirty();
                    }, 16);
                }
            }
        }

        const attrs = styleToCellAttrs(this._style);
        const visibleItemCount = Math.floor(height / this._itemHeight);

        // Calculate the visible window with overscan
        const { start: startIdx, end: endIdx } = computeRange(
            this._scrollOffset, visibleItemCount, this._totalItems, this._overscan,
        );

        // Content width (leave room for scrollbar)
        const contentWidth = this._showScrollbar && this._totalItems > visibleItemCount
            ? width - 1
            : width;

        if (this._lastContentWidth !== contentWidth) {
            this._clearCache();
            this._lastContentWidth = contentWidth;
        }

        // Only render items in the visible window
        for (let idx = startIdx; idx < endIdx; idx++) {
            const rowY = y + (idx - this._scrollOffset) * this._itemHeight;

            // Skip if outside the visible rect
            if (rowY < y || rowY >= y + height) continue;

            const isSelected = idx === this._selectedIndex;
            const isFocused = this.isFocused;

            let cached = this._renderCache.get(idx);
            if (!cached || cached.isSelected !== isSelected || cached.isFocused !== isFocused) {
                // Get the item content
                let content: string;
                try {
                    content = this._renderItem(idx);
                } catch {
                    content = `[Error: item ${idx}]`;
                }

                // Add selection prefix
                const prefix = isSelected ? (caps.unicode ? '▸ ' : '> ') : '  ';
                let line = prefix + content;
                line = truncate(line, contentWidth);

                // Style
                const cellStyle = {
                    ...attrs,
                    bold: isSelected,
                    inverse: isSelected && isFocused,
                };

                cached = { line, cellStyle, isSelected, isFocused };
                this._renderCache.set(idx, cached);
            }

            screen.writeString(x, rowY, cached.line, cached.cellStyle);

            // Fill rest of line for inverse highlight
            if (isSelected && isFocused) {
                const remaining = contentWidth - stringWidth(cached.line);
                for (let c = 0; c < remaining; c++) {
                    screen.setCell(x + stringWidth(cached.line) + c, rowY, { char: ' ', ...cached.cellStyle });
                }
            }
        }

        // Scrollbar
        if (this._showScrollbar && this._totalItems > visibleItemCount) {
            const scrollbarX = x + width - 1;
            const totalPages = this._totalItems - visibleItemCount;
            const scrollRatio = totalPages > 0 ? this._scrollOffset / totalPages : 0;
            const thumbPos = Math.floor(scrollRatio * (height - 1));
            const thumbChar = caps.unicode ? '█' : '#';
            const trackChar = caps.unicode ? '░' : '|';

            for (let r = 0; r < height; r++) {
                const scrollChar = r === thumbPos ? thumbChar : trackChar;
                screen.setCell(scrollbarX, y + r, { char: scrollChar, ...attrs, dim: r !== thumbPos });
            }
        }
    }

    private _clearCache(): void {
        this._renderCache.clear();
    }

    private _runScrollAction(action: () => void): void {
        this._isScrolling = true;
        try {
            action();
        } finally {
            this._isScrolling = false;
        }
    }

    // ── Internal ──

    private _clampScroll(): void {
        const rect = this._getContentRect();
        const visibleHeight = Math.floor(rect.height / this._itemHeight);
        if (visibleHeight <= 0) {
            this._scrollOffset = 0;
            this._targetScrollOffset = 0;
            return;
        }

        // Keep selected item visible
        let target = this._targetScrollOffset;
        if (this._selectedIndex < target) {
            target = this._selectedIndex;
        }
        if (this._selectedIndex >= target + visibleHeight) {
            target = this._selectedIndex - visibleHeight + 1;
        }

        // Clamp scroll offset
        target = Math.max(0, Math.min(target, this._totalItems - visibleHeight));
        this._targetScrollOffset = target;

        if (!this._springScroll) {
            this._scrollOffset = target;
            this._spring.position = target;
            this._spring.velocity = 0;
        } else {
            if (!this._isAnimating && this._scrollOffset !== target) {
                this._lastUpdateTime = performance.now();
                this._isAnimating = true;
                this.markDirty();
            }
        }
    }
}

import { Widget } from '@termuijs/widgets';
import {
    type Screen,
    type Style,
    type Color,
    type KeyEvent,
    styleToCellAttrs,
    caps,
    stringWidth,
} from '@termuijs/core';

export interface RangeInputOptions {
    min?: number;
    max?: number;
    step?: number;
    color?: Color;
    showValue?: boolean;
    onChange?: (low: number, high: number) => void;
}

export class RangeInput extends Widget {
    private _label: string;
    private _min: number;
    private _max: number;
    private _step: number;
    private _color: Color;
    private _showValue: boolean;
    private _activeHandle: 'low' | 'high';
    private _low: number;
    private _high: number;
    private _onChange?: (low: number, high: number) => void;

    constructor(
        label: string,
        style: Partial<Style> = {},
        opts: RangeInputOptions = {},
    ) {
        super(style);

        this._label = label;
        this._min = opts.min ?? 0;
        this._max = opts.max ?? 100;
        this._step = opts.step ?? 1;
        this._color = opts.color ?? { type: 'named', name: 'cyan' };
        this._showValue = opts.showValue ?? true;
        this._low = this._min;
        this._high = this._max;
        this._activeHandle = 'low';
        this._onChange = opts.onChange;

        this.focusable = true;
    }

    getLow(): number {
        return this._low;
    }

    getHigh(): number {
        return this._high;
    }

    setLow(value: number): void {
        const clamped = Math.max(this._min, Math.min(value, this._high));
        if (clamped === this._low) return;
        this._low = clamped;
        this.markDirty();
        this._onChange?.(this._low, this._high);
    }

    setHigh(value: number): void {
        const clamped = Math.min(this._max, Math.max(value, this._low));
        if (clamped === this._high) return;
        this._high = clamped;
        this.markDirty();
        this._onChange?.(this._low, this._high);
    }

    setRange(low: number, high: number): void {
        const newLow = Math.max(this._min, Math.min(low, high));
        const newHigh = Math.min(this._max, Math.max(low, high));
        if (newLow === this._low && newHigh === this._high) return;
        this._low = newLow;
        this._high = newHigh;
        this.markDirty();
        this._onChange?.(this._low, this._high);
    }

    handleKey(event: KeyEvent): void {
        if (event.key === 'tab') {
            this._activeHandle =
                this._activeHandle === 'low' ? 'high' : 'low';
            this.markDirty();
            event.preventDefault();
            event.stopPropagation();
            return;
        }

        if (this._activeHandle === 'low') {
            if (event.key === 'right') this.setLow(this._low + this._step);
            if (event.key === 'left') this.setLow(this._low - this._step);
        } else {
            if (event.key === 'right') this.setHigh(this._high + this._step);
            if (event.key === 'left') this.setHigh(this._high - this._step);
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        // Layout: "Label  ◄ [track] ►  low – high"
        const labelStr = this._label + '  ';
        const leftCap = caps.unicode ? '◄ ' : '< ';
        const rightCap = caps.unicode ? ' ►' : ' >';
        const valueStr = this._showValue
            ? `  ${this._low} – ${this._high}`
            : '';

        const labelWidth = stringWidth(labelStr);
        const leftCapWidth = stringWidth(leftCap);
        const rightCapWidth = stringWidth(rightCap);
        const valueWidth = stringWidth(valueStr);

        const trackWidth = Math.max(
            0,
            width - labelWidth - leftCapWidth - rightCapWidth - valueWidth,
        );

        // Render label
        screen.writeString(x, y, labelStr, { ...attrs, bold: true });

        // Render left cap
        screen.writeString(x + labelWidth, y, leftCap, attrs);

        // Render track (3 zones: before low, between low–high, after high)
        const range = this._max - this._min || 1;
        const lowCell = Math.round(trackWidth * (this._low - this._min) / range);
        const highCell = Math.round(trackWidth * (this._high - this._min) / range);
        const trackX = x + labelWidth + leftCapWidth;

        for (let i = 0; i < trackWidth; i++) {
            const inRange = i >= lowCell && i < highCell;
            const isActiveLow = i === lowCell && this._activeHandle === 'low';
            const isActiveHigh = i === highCell - 1 && this._activeHandle === 'high';

            const char = inRange
                ? (caps.unicode ? '█' : '#')
                : (caps.unicode ? '░' : '-');

            screen.setCell(trackX + i, y, {
                char,
                fg: (isActiveLow || isActiveHigh)
                    ? { type: 'named', name: 'yellow' }
                    : inRange
                        ? this._color
                        : { type: 'named', name: 'brightBlack' },
            });
        }

        // Render right cap
        screen.writeString(trackX + trackWidth, y, rightCap, attrs);

        // Render value
        if (this._showValue) {
            screen.writeString(trackX + trackWidth + rightCapWidth, y, valueStr, {
                ...attrs,
                bold: true,
            });
        }
    }
}

export interface ScrollRange {
    start: number;    // first item index to render
    end: number;      // one past last item index to render (exclusive)
    offsetPx: number; // scroll offset in pixels (for variable height)
}

/**
 * Compute visible range for fixed-height items.
 * @param scrollOffset - first visible item index (scroll position in items, NOT pixels)
 * @param viewportItems - number of items visible in the viewport
 * @param itemCount - total number of items
 * @param overscan - extra items to render beyond viewport edges (default: 2)
 */
export function computeRange(
    scrollOffset: number,
    viewportItems: number,
    itemCount: number,
    overscan = 2,
): ScrollRange {
    const start = Math.max(0, scrollOffset - overscan);
    const end = Math.min(itemCount, scrollOffset + viewportItems + overscan);
    return { start, end, offsetPx: start };
}

/**
 * Compute visible range for variable-height items.
 * @param scrollPx - scroll position in pixels
 * @param viewportPx - viewport height in pixels
 * @param sizes - array of item heights in pixels
 * @param overscan - extra items to render (default: 2)
 */
export function computeVariableRange(
    scrollPx: number,
    viewportPx: number,
    sizes: number[],
    overscan = 2,
): ScrollRange {
    const cumulative: number[] = [];
    let sum = 0;
    for (const s of sizes) {
        cumulative.push(sum);
        sum += s;
    }
    cumulative.push(sum); // sentinel

    // First item that starts within or before the viewport
    let startIdx = cumulative.findIndex((c, i) => i < sizes.length && c + sizes[i] > scrollPx);
    if (startIdx < 0) startIdx = sizes.length;
    startIdx = Math.max(0, startIdx - overscan);

    // Last item that starts before viewport end
    const viewportEnd = scrollPx + viewportPx;
    let endIdx = cumulative.findIndex((c) => c >= viewportEnd);
    if (endIdx < 0) endIdx = sizes.length;
    endIdx = Math.min(sizes.length, endIdx + overscan);

    return { start: startIdx, end: endIdx, offsetPx: cumulative[startIdx] };
}

