// @termuijs/widgets — ScrollView widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, styleToCellAttrs, type KeyEvent, normalizeNavigationKey } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';
import { ScrollAcceleration } from '@termuijs/widgets';


export interface ScrollViewOptions {
    /** Total height of content in rows */
    contentHeight?: number;
    /** Show scrollbar indicator on right edge */
    showScrollbar?: boolean;
     /** Whether to use scroll acceleration */
    scrollAccel?: boolean;
}

/**
 * ScrollView — a height-bounded scrollable container.
 *
 * Children are rendered with a vertical offset applied (scrolling).
 * Responds to up/down arrow keys and Page Up/Page Down.
 */
export class ScrollView extends Widget {
    private _scrollOffset: number = 0;
    private _contentHeight: number;
    private _showScrollbar: boolean;
    private _scrollAccel: boolean;
    private _acceleration = new ScrollAcceleration();


    constructor(style: Partial<Style> = {}, opts: ScrollViewOptions = {}) {
        super({ overflow: 'hidden', ...style });
        this._contentHeight = opts.contentHeight ?? 0;
        this._showScrollbar = opts.showScrollbar ?? true;
        this._scrollAccel = opts.scrollAccel ??  false;
        this.focusable = true;
    }

    /** Set the total content height (in rows) */
    setContentHeight(h: number): void {
        if (this._contentHeight === h) return;

        this._contentHeight = h;
        this._clampOffset();
        this.markDirty();
    }

    /** Get current scroll offset */
    get scrollOffset(): number { return this._scrollOffset; }

    /** Scroll by delta rows */
    scrollBy(delta: number): void {
        this._scrollOffset = Math.round(this._scrollOffset + delta);
        this._clampOffset();
        this.markDirty();
    }

    /** Scroll to absolute offset */
    scrollTo(offset: number): void {
        const previousOffset = this._scrollOffset;

        this._scrollOffset = Math.round(offset);
        this._clampOffset();

        if (previousOffset !== this._scrollOffset) {
            this.markDirty();
        }
    }

    private _clampOffset(): void {
        const viewHeight = this._rect.height;
        const maxOffset = Math.max(0, this._contentHeight - viewHeight);
        this._scrollOffset = Math.max(0, Math.min(this._scrollOffset, maxOffset));
    }

    private getScrollDelta(baseDelta: number): number {
    if (!this._scrollAccel) {
        return baseDelta;
    }

    const multiplier =
        this._acceleration.getMultiplier(
            Date.now()
        );

    return baseDelta * multiplier; 
}
    /** Handle keyboard navigation */
    handleKey(event: KeyEvent): void {
        switch (normalizeNavigationKey(event.key)) {
            case 'up':       this.scrollBy(-this.getScrollDelta(1)); break;
            case 'down':     this.scrollBy(this.getScrollDelta(1)); break;
            case 'pageup':   this.scrollBy(-this.getScrollDelta(Math.max(1, this._rect.height - 1))); break;
            case 'pagedown': this.scrollBy(this.getScrollDelta(Math.max(1, this._rect.height - 1))); break;
        }
    }

    override render(screen: Screen): void {
        if (this._style.visible === false) return;

        const shouldClip = true;
        if (shouldClip) screen.pushClip(this._rect);

        this._renderSelf(screen);
        this._renderBorder(screen);

        // Render children with a Y offset for scrolling
        const rect = this._getContentRect();
        screen.pushTranslateY(-this._scrollOffset);
        for (const child of this._children) {
            child.render(screen);
        }
        screen.popTranslateY();

        if (shouldClip) screen.popClip();

        // Draw scrollbar on top (outside clip)
        if (this._showScrollbar && this._contentHeight > this._rect.height) {
            this._renderScrollbar(screen, rect);
        }
    }

    private _renderScrollbar(screen: Screen, contentRect: { x: number; y: number; width: number; height: number }): void {
        const { y, width, height } = contentRect;
        const scrollX = contentRect.x + width; // right edge of content
        if (scrollX >= this._rect.x + this._rect.width) return;

        const trackHeight = height;
        const thumbSize = Math.max(1, Math.round((height / this._contentHeight) * trackHeight));
        const maxOffset = Math.max(1, this._contentHeight - height);
        const thumbPos = Math.round((this._scrollOffset / maxOffset) * (trackHeight - thumbSize));

        const attrs = styleToCellAttrs(this._style);
        const thumbChar = '█';
        const trackChar = '░';

        for (let i = 0; i < trackHeight; i++) {
            const isThumb = i >= thumbPos && i < thumbPos + thumbSize;
            screen.setCell(scrollX, y + i, {
                char: isThumb ? thumbChar : trackChar,
                ...attrs,
                dim: !isThumb,
            });
        }
    }

    protected _renderSelf(_screen: Screen): void {
        // Container only
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Columns widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';
import { Box } from '@termuijs/widgets';

export interface ColumnsOptions {
    /** Gap between columns in cells (default: 1) */
    gap?: number;
}

/**
 * Columns — splits available width evenly across child widgets.
 *
 * Children are laid out side-by-side with equal flex-grow.
 * Internally uses a flex-row Box; the addChild override applies
 * flexGrow:1 to each child so the reconciler's generic loop works.
 */
export class Columns extends Widget {
    private _inner: Box;

    constructor(style: Partial<Style> = {}, opts: ColumnsOptions = {}) {
        super(style);
        this._inner = new Box({
            flexDirection: 'row',
            gap: opts.gap ?? 1,
            width: '100%',
            height: '100%',
        });
        super.addChild(this._inner);
    }

    override addChild(widget: Widget): void {
        widget.setStyle({ flexGrow: 1 });
        this._inner.addChild(widget);
    }

    override removeChild(widget: Widget): void {
        this._inner.removeChild(widget);
    }

    override clearChildren(): void {
        this._inner.clearChildren();
    }

    protected _renderSelf(_screen: Screen): void {
        // Pure layout container
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Card widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, styleToCellAttrs, caps, stringWidth } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface CardOptions {
    /** Optional title shown in the top border */
    title?: string;
    /** Color for the border and title */
    borderColor?: Color;
}

/**
 * Card — a bordered container with an optional title in the top border.
 *
 * Like a Box with border + padding, but supports embedding a title string
 * directly in the top border line.
 */
export class Card extends Widget {
    private _title: string;
    private _borderColor?: Color;

    constructor(style: Partial<Style> = {}, opts: CardOptions = {}) {
        super({
            border: 'single',
            padding: 1,
            ...style,
        });
        this._title = opts.title ?? '';
        this._borderColor = opts.borderColor;
    }

    setTitle(title: string): void {
        this._title = title;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        if (!this._title) return;

        const { x, y, width } = this._rect;
        if (width < 4) return;

        const attrs = styleToCellAttrs(this._style);
        const fg = this._borderColor ?? attrs.fg;

        // Title rendered into top border: ─ Title ─
        const titleText = ` ${this._title} `;
        const titleWidth = stringWidth(titleText);
        const innerWidth = width - 2; // minus corners
        if (titleWidth > innerWidth) return;

        const titleX = x + 1 + Math.floor((innerWidth - titleWidth) / 2);
        screen.writeString(titleX, y, titleText, { fg, bold: true });
    }
}

import { type Screen, type Style } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface AspectRatioOptions {
    /** Width:height ratio */
    ratio?: number;

    /** contain = fit inside, cover = fill */
    fit?: 'contain' | 'cover';
}

export class AspectRatio extends Widget {
    private _ratio: number;
    private _fit: 'contain' | 'cover';

    constructor(
        child: Widget,
        style: Partial<Style> = {},
        opts: AspectRatioOptions = {},
    ) {
        super(style);

        this._ratio = opts.ratio ?? 2;
        this._fit = opts.fit ?? 'contain';

        this.addChild(child);
    }

    setChild(child: Widget): void {
        this.clearChildren();
        this.addChild(child);
        this.markDirty();
    }

    protected _renderSelf(_screen: Screen): void {
        // Pure layout widget
    }

    override render(screen: Screen): void {
        if (this._style.visible === false) return;

        const shouldClip = this._style.overflow !== 'visible';

        if (shouldClip) {
            screen.pushClip(this._rect);
        }

        this._renderSelf(screen);
        this._renderBorder(screen);

        const content = this._getContentRect();

        for (const child of this._children) {
            const originalRect = { ...child.rect };

            const targetHeight = Math.round(
                content.width / this._ratio,
            );

            const childHeight =
                this._fit === 'contain'
                    ? Math.min(content.height, targetHeight)
                    : content.height;

            const childY =
                content.y +
                Math.floor(
                    (content.height - childHeight) / 2,
                );

            (child as any)._rect = { // as any: _rect is protected; no public API for temporary rect override during measurement
                x: content.x,
                y: childY,
                width: content.width,
                height: childHeight,
            };

            child.render(screen);

            (child as any)._rect = originalRect; // as any: _rect is protected; no public API for temporary rect override during measurement
        }

        if (shouldClip) {
            screen.popClip();
        }
    }
}

import type { Screen, Style, Rect } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export type DockEdge = 'top' | 'right' | 'bottom' | 'left' | 'fill';

export interface DockItem {
  widget: Widget;
  edge: DockEdge;
  size?: number;
}

export interface DockOptions {
  style?: Partial<Style>;
}

export class Dock extends Widget {
  private _items: DockItem[];

  constructor(items: DockItem[], style: Partial<Style> = {}) {
    super(style);
    this._items = items;
    for (const { widget } of items) {
      widget.parent = this;
    }
  }

  setItems(items: DockItem[]): void {
    this._items = items;
    for (const { widget } of items) {
      widget.parent = this;
    }
    this.markDirty();
  }

  override updateRect(rect: Rect): void {
    super.updateRect(rect);

    let top = rect.y;
    let bottom = rect.y + rect.height;
    let left = rect.x;
    let right = rect.x + rect.width;

    for (const { widget, edge, size } of this._items) {
      if (edge === 'top') {
        const h = size ?? 1;
        widget.updateRect({ x: left, y: top, width: right - left, height: h });
        top += h;
      } else if (edge === 'bottom') {
        const h = size ?? 1;
        bottom -= h;
        widget.updateRect({ x: left, y: bottom, width: right - left, height: h });
      } else if (edge === 'left') {
        const w = size ?? 1;
        widget.updateRect({ x: left, y: top, width: w, height: bottom - top });
        left += w;
      } else if (edge === 'right') {
        const w = size ?? 1;
        right -= w;
        widget.updateRect({ x: right, y: top, width: w, height: bottom - top });
      } else if (edge === 'fill') {
        widget.updateRect({ x: left, y: top, width: right - left, height: bottom - top });
      }
    }
  }

  protected _renderSelf(_screen: Screen): void {
    // Pure layout container — no self-rendering needed.
  }

  override render(screen: Screen): void {
    super.render(screen);
    for (const { widget } of this._items) {
      widget.render(screen);
    }
  }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Center widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface CenterOptions {
    /** Center horizontally (default: true) */
    horizontal?: boolean;
    /** Center vertically (default: true) */
    vertical?: boolean;
}

/**
 * Center — centers a single child widget horizontally and/or vertically.
 *
 * Computes centering offsets at render time from the child's measured size.
 */
export class Center extends Widget {
    private _horizontal: boolean;
    private _vertical: boolean;

    constructor(style: Partial<Style> = {}, opts: CenterOptions = {}) {
        super(style);
        this._horizontal = opts.horizontal ?? true;
        this._vertical = opts.vertical ?? true;
    }

    protected _renderSelf(_screen: Screen): void {
        // Pure layout container — no self-rendering
    }

    override render(screen: Screen): void {
        if (this._style.visible === false) return;

        const shouldClip = this._style.overflow !== 'visible';
        if (shouldClip) screen.pushClip(this._rect);

        this._renderSelf(screen);
        this._renderBorder(screen);

        const content = this._getContentRect();

        for (const child of this._children) {
            const childRect = child.rect;
            const origRect = { ...childRect };

            let offsetX = content.x;
            let offsetY = content.y;

            if (this._horizontal) {
                offsetX = content.x + Math.max(0, Math.floor((content.width - childRect.width) / 2));
            }
            if (this._vertical) {
                offsetY = content.y + Math.max(0, Math.floor((content.height - childRect.height) / 2));
            }

            // Access protected _rect to temporarily modify for centering
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            (child as any)._rect = {
                x: offsetX,
                y: offsetY,
                width: childRect.width,
                height: childRect.height,
            };
            child.render(screen);
            // Restore original rect after rendering
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            (child as any)._rect = origRect;
        }

        if (shouldClip) screen.popClip();
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Divider widget
// Renders a horizontal or vertical line with optional label
// ─────────────────────────────────────────────────────
import {
    type Screen,
    type Style,
    type Color,
    styleToCellAttrs,
    stringWidth,
    caps,
} from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export type DividerOrientation = 'horizontal' | 'vertical';

export interface DividerOptions {
    /** Direction of the divider line */
    orientation?: DividerOrientation;
    /** Optional centered label inside the line */
    label?: string;
    /** Character used to draw the line (overrides default) */
    char?: string;
    /** Color of the line */
    color?: Color;
}

/**
 * Divider — a horizontal or vertical separator line with optional label.
 *
 * Examples:
 *   ──────────────── Stats ────────────────   (horizontal with label)
 *   ────────────────────────────────────────  (horizontal)
 *   │  (vertical, repeating down the height)
 */
export class Divider extends Widget {
    private _orientation: DividerOrientation;
    private _label: string;
    private _char: string | undefined;
    private _color: Color | undefined;

    constructor(style: Partial<Style> = {}, opts: DividerOptions = {}) {
        super(style);
        this._orientation = opts.orientation ?? 'horizontal';
        this._label = opts.label ?? '';
        this._char = opts.char;
        this._color = opts.color;
    }

    setLabel(label: string): void {
        this._label = label;
        this.markDirty();
    }

    setOrientation(orientation: DividerOrientation): void {
        this._orientation = orientation;
        this.markDirty();
    }

    setChar(char: string): void {
        this._char = char;
        this.markDirty();
    }

    setColor(color: Color): void {
        this._color = color;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const cellAttrs = this._color
            ? { ...attrs, fg: this._color }
            : attrs;

        if (this._orientation === 'horizontal') {
            this._renderHorizontal(screen, x, y, width, cellAttrs);
        } else {
            this._renderVertical(screen, x, y, height, cellAttrs);
        }
    }

    private _renderHorizontal(
        screen: Screen,
        x: number,
        y: number,
        width: number,
        attrs: ReturnType<typeof styleToCellAttrs>,
    ): void {
        const lineChar = this._char ?? (caps.unicode ? '─' : '-');

        if (!this._label) {
            // Simple full-width line
            for (let i = 0; i < width; i++) {
                screen.setCell(x + i, y, { char: lineChar, ...attrs });
            }
            return;
        }

        // Centered label: ─── Label ───
        const labelWithPad = ` ${this._label} `;
        const labelWidth = stringWidth(labelWithPad);

        if (labelWidth >= width) {
            // Not enough room — just write the label truncated
            screen.writeString(x, y, labelWithPad.slice(0, width), attrs);
            return;
        }

        const leftLen = Math.floor((width - labelWidth) / 2);
        const rightLen = width - labelWidth - leftLen;

        // Left line
        for (let i = 0; i < leftLen; i++) {
            screen.setCell(x + i, y, { char: lineChar, ...attrs });
        }

        // Label
        screen.writeString(x + leftLen, y, labelWithPad, attrs);

        // Right line
        for (let i = 0; i < rightLen; i++) {
            screen.setCell(x + leftLen + labelWidth + i, y, {
                char: lineChar,
                ...attrs,
            });
        }
    }

    private _renderVertical(
        screen: Screen,
        x: number,
        y: number,
        height: number,
        attrs: ReturnType<typeof styleToCellAttrs>,
    ): void {
        const lineChar = this._char ?? (caps.unicode ? '│' : '|');

        for (let i = 0; i < height; i++) {
            screen.setCell(x, y + i, { char: lineChar, ...attrs });
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — SplitPane layout widget
// ─────────────────────────────────────────────────────

import {
    type Screen,
    type Style,
    type KeyEvent,
    caps,
    styleToCellAttrs,
} from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export type SplitDirection = 'horizontal' | 'vertical';

export interface SplitPaneOptions {
    ratio?: number;
    minSize?: number;
    direction?: SplitDirection;
    persistent?: boolean;
}

/**
 * SplitPane — two-pane resizable layout widget.
 */
export class SplitPane extends Widget {
    private _ratio: number;
    private readonly _minSize: number;
    private _direction: SplitDirection;
    private readonly _persistent: boolean;

    constructor(
        left: Widget,
        right: Widget,
        style: Partial<Style> = {},
        opts: SplitPaneOptions = {},
    ) {
        super(style);

        this._ratio = opts.ratio ?? 0.5;
        this._minSize = opts.minSize ?? 1;
        this._direction = opts.direction ?? 'horizontal';
        this._persistent = opts.persistent ?? false;

        this.focusable = true;
        this.addChild(left);
        this.addChild(right);
    }

    getRatio(): number {
        return this._ratio;
    }

    setRatio(ratio: number): void {
        const content = this._getContentRect();

        const totalSize =
            this._direction === 'horizontal'
                ? content.width
                : content.height;

        const newRatio =
            totalSize > 0 ? this._clampRatio(ratio, totalSize) : ratio;

        if (newRatio !== this._ratio) {
            this._ratio = newRatio;
            this.markDirty();
        }
    }

    handleKey(event: KeyEvent): void {
        if (!event.shift) return;

        const content = this._getContentRect();

        const totalSize =
            this._direction === 'horizontal'
                ? content.width
                : content.height;

        if (totalSize <= 0) return;

        const step = 1 / totalSize;

        if (
            (this._direction === 'horizontal' &&
                event.key === 'left') ||
            (this._direction === 'vertical' &&
                event.key === 'up')
        ) {
            this.setRatio(this._ratio - step);
        } else if (
            (this._direction === 'horizontal' &&
                event.key === 'right') ||
            (this._direction === 'vertical' &&
                event.key === 'down')
        ) {
            this.setRatio(this._ratio + step);
        }
    }

    saveLayout(): string {
        if (!this._persistent) {
            return '';
        }

        return JSON.stringify({
            ratio: this._ratio,
            direction: this._direction,
        });
    }

    loadLayout(data: string): void {
        try {
            const layout = JSON.parse(data);

            let changed = false;

            if (
                typeof layout.ratio === 'number' &&
                layout.ratio !== this._ratio
            ) {
                this._ratio = layout.ratio;
                changed = true;
            }

            if (
                layout.direction === 'horizontal' ||
                layout.direction === 'vertical'
            ) {
                if (layout.direction !== this._direction) {
                    this._direction = layout.direction;
                    changed = true;
                }
            }

            if (changed) {
                this.markDirty();
            }
        } catch {
            // Ignore malformed layout data
        }
    }

    override syncLayout(): void {
        super.syncLayout();
        this._positionChildren();
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._getContentRect();

        if (width <= 0 || height <= 0) {
            return;
        }

        const dividerChar = caps.unicode ? '│' : '|';
        const attrs = styleToCellAttrs(this._style);

        if (this._direction === 'horizontal') {
            const firstSize = Math.floor(this._ratio * width);
            const dividerX = x + firstSize;

            for (let row = 0; row < height; row++) {
                screen.setCell(dividerX, y + row, {
                    char: dividerChar,
                    ...attrs,
                });
            }
        } else {
            const firstSize = Math.floor(this._ratio * height);
            const dividerY = y + firstSize;

            for (let col = 0; col < width; col++) {
                screen.setCell(col + x, dividerY, {
                    char: '─',
                    ...attrs,
                });
            }
        }
    }

    private _clampRatio(
        ratio: number,
        totalSize: number,
    ): number {
        const minRatio = this._minSize / totalSize;
        const maxRatio = 1 - this._minSize / totalSize;

        return Math.max(minRatio, Math.min(maxRatio, ratio));
    }

    private _positionChildren(): void {
        const left = this._children[0];
        const right = this._children[1];

        if (!left || !right) {
            return;
        }

        const { x, y, width, height } = this._getContentRect();

        if (width <= 0 || height <= 0) {
            return;
        }

        if (this._direction === 'horizontal') {
            const firstWidth = Math.floor(this._ratio * width);

            left.updateRect({
                x,
                y,
                width: firstWidth,
                height,
            });

            right.updateRect({
                x: x + firstWidth + 1,
                y,
                width: Math.max(0, width - firstWidth - 1),
                height,
            });
        } else {
            const firstHeight = Math.floor(this._ratio * height);

            left.updateRect({
                x,
                y,
                width,
                height: firstHeight,
            });

            right.updateRect({
                x,
                y: y + firstHeight + 1,
                width,
                height: Math.max(0, height - firstHeight - 1),
            });
        }
    }
}

import { type Screen, type Style, type Color } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface FillOptions {
    char?: string;
    color?: Color;
}

export class Fill extends Widget {
    private _char: string;
    private _color?: Color;

    constructor(style: Partial<Style> = {}, opts: FillOptions = {}) {
        super(style);
        this._char = opts.char ?? ' ';
        this._color = opts.color;
    }

    setChar(char: string): void {
        this._char = char;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._getContentRect();

        if (width <= 0 || height <= 0) return;

        for (let row = y; row < y + height; row++) {
            for (let col = x; col < x + width; col++) {
                screen.setCell(col, row, {
                    char: this._char,
                    fg: this._color,
                });
            }
        }
    }
}

import { Widget } from '@termuijs/widgets';
import { type Screen, type Style } from '@termuijs/core';

export interface MasonryOptions {
  /** Number of columns. Default: 2 */
  columns?: number;
  /** Vertical gap between items. Default: 0 */
  gap?: number;
}

export class Masonry extends Widget {
  private _columns: number;
  private _gap: number;

  constructor(
    children: Widget[],
    style?: Partial<Style>,
    opts?: MasonryOptions,
  ) {
    super(style);
    this._columns = opts?.columns ?? 2;
    this._gap = opts?.gap ?? 0;
    this.setChildren(children);
  }

  setChildren(children: Widget[]): void {
    this.clearChildren();
    for (const child of children) this.addChild(child);
    this._layout();
    this.markDirty();
  }

  override syncLayout(): void {
    super.syncLayout();
    this._layout();
  }

  protected _renderSelf(_screen: Screen): void {}

  private _layout(): void {
    const totalWidth = this.rect.width || 80;
    const colWidth = Math.floor(totalWidth / this._columns);
    const colHeights = new Array<number>(this._columns).fill(0);

    for (const child of this.children) {
      const col = colHeights.indexOf(Math.min(...colHeights));
      const x = col * colWidth;
      const y = colHeights[col];
      // preferredHeight is a test-only property set by test helper
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const height = (child as any).preferredHeight ?? (child.rect.height || 1);

      child.updateRect({ x, y, width: colWidth, height });

      colHeights[col] += height + this._gap;
    }
  }
}

export class ScrollAcceleration {
    private lastScrollTime: number | null = null;

    getMultiplier(now: number): number {
        if (this.lastScrollTime === null) {
            this.lastScrollTime = now;
            return 1;
        }

        const deltaMs = now - this.lastScrollTime;
        this.lastScrollTime = now;

        if (deltaMs > 300) return 1;
        if (deltaMs > 200) return 2;
        if (deltaMs > 100) return 3;
        if (deltaMs > 50) return 4;
        if (deltaMs > 25) return 5;

        return 6;
    }

    reset(): void {
        this.lastScrollTime = null;
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — CSS Grid Layout Widgets
// ─────────────────────────────────────────────────────

import type { Screen, Style } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface GridOptions {
    /** CSS grid-template-columns track definitions, e.g. "1fr 2fr", "10 20" or number of columns */
    columns?: number | string;
    /** CSS grid-template-rows track definitions, e.g. "1fr 1fr", "auto" or number of rows */
    rows?: number | string;
    /** Grid gap in characters/cells */
    gap?: number;
}

export interface GridItemOptions {
    /** grid-column-start index (1-indexed) or "span N" */
    columnStart?: number | string;
    /** grid-column-end index (1-indexed) or "span N" */
    columnEnd?: number | string;
    /** grid-row-start index (1-indexed) or "span N" */
    rowStart?: number | string;
    /** grid-row-end index (1-indexed) or "span N" */
    rowEnd?: number | string;
}

/**
 * Grid — a true CSS-Grid-like layout container.
 */
export class Grid extends Widget {
    constructor(style: Partial<Style> = {}, options: GridOptions = {}) {
        const columns = typeof options.columns === 'number'
            ? Array(Math.max(1, options.columns)).fill('1fr').join(' ')
            : options.columns;
        const rows = typeof options.rows === 'number'
            ? Array(Math.max(1, options.rows)).fill('1fr').join(' ')
