// @termuijs/widgets — BulletChart widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, styleToCellAttrs, stringWidth, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface BulletRange {
    to: number;
    color?: Color;
}

export interface BulletChartOptions {
    max?: number;
    ranges?: BulletRange[];
    valueColor?: Color;
    targetColor?: Color;
    label?: string;
}

/**
 * BulletChart — a metric display with target marker and qualitative range bands.
 */
export class BulletChart extends Widget {
    private _value: number = 0;
    private _target: number = 0;
    private _max: number;
    private _ranges: BulletRange[];
    private _valueColor: Color;
    private _targetColor: Color;
    private _label: string;

    constructor(style: Partial<Style> = {}, opts: BulletChartOptions = {}) {
        super(style);
        this._max = opts.max !== undefined && opts.max > 0 ? opts.max : 100;
        this._ranges = [...(opts.ranges ?? [])].sort((a, b) => a.to - b.to);
        this._valueColor = opts.valueColor ?? { type: 'named', name: 'cyan' };
        this._targetColor = opts.targetColor ?? { type: 'named', name: 'white' };
        this._label = opts.label ?? '';
    }

    setValue(value: number): void {
        this._value = Math.max(0, Math.min(this._max, value));
        this.markDirty();
    }

    setTarget(target: number): void {
        this._target = Math.max(0, Math.min(this._max, target));
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        const labelStr = this._label ? this._label + ' ' : '';
        const labelWidth = stringWidth(labelStr);
        const barWidth = Math.max(0, width - labelWidth);

        if (this._label) {
            screen.writeString(x, y, labelStr, { ...attrs, bold: true });
        }

        if (barWidth <= 0) return;

        const valueCells = Math.max(0, Math.min(barWidth, Math.round((this._value / this._max) * barWidth)));
        const targetCell = Math.max(0, Math.min(barWidth - 1, Math.round((this._target / this._max) * barWidth)));

        const barX = x + labelWidth;

        for (let i = 0; i < barWidth; i++) {
            const cellValue = (i / barWidth) * this._max;
            let rangeColor: Color | undefined = undefined;
            for (const range of this._ranges) {
                if (cellValue <= range.to) {
                    rangeColor = range.color;
                    break;
                }
            }

            let char = ' ';
            let fg = attrs.fg;
            let bg = rangeColor ?? attrs.bg;

            if (caps.unicode) {
                if (i === targetCell) {
                    char = '│';
                    fg = this._targetColor;
                } else if (i < valueCells) {
                    char = '▄';
                    fg = this._valueColor;
                } else {
                    char = ' ';
                }
            } else {
                // ASCII Fallback
                if (i === targetCell) {
                    char = '|';
                    fg = this._targetColor;
                } else if (i < valueCells) {
                    char = '=';
                    fg = this._valueColor;
                } else {
                    char = '-';
                    if (!rangeColor) {
                        fg = { type: 'named', name: 'brightBlack' };
                    }
                }
            }

            screen.setCell(barX + i, y, { char, fg, bg });
        }
    }
}

import { Widget } from '@termuijs/widgets'
import { type Screen, type Style, styleToCellAttrs } from '@termuijs/core'

export interface HexdumpOptions {
    /** Bytes per row. Default: 16 */
    bytesPerRow?: number

    /** Character shown for non-printable bytes in ASCII column. Default: '.' */
    placeholder?: string
}

export class Hexdump extends Widget {
    private data!: Uint8Array
    private opts!: HexdumpOptions

    constructor(
        data: Uint8Array,
        style?: Partial<Style>,
        opts?: HexdumpOptions,
    ) {
        super(style)

        this.data = data
        this.opts = {
            bytesPerRow: 16,
            placeholder: '.',
            ...opts,
        }
    }

    setData(data: Uint8Array): void {
        this.data = data
        this.markDirty()
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect()
        const { x, y, width, height } = rect
        if (width <= 0 || height <= 0) return

        const attrs = styleToCellAttrs(this._style)
        const bytesPerRow = this.opts.bytesPerRow!
        const placeholder = this.opts.placeholder!

        const numRows = Math.ceil(this.data.length / bytesPerRow)
        const renderRows = Math.min(height, numRows)

        const half = Math.floor(bytesPerRow / 2)

        for (let row = 0; row < renderRows; row++) {
            const offset = row * bytesPerRow
            const chunk = this.data.subarray(offset, offset + bytesPerRow)

            // 1. Offset string (8 chars)
            const offsetStr = offset.toString(16).padStart(8, '0')

            // 2. Hex strings (e.g. "41 42 43 ")
            let hexStr = ''
            for (let i = 0; i < bytesPerRow; i++) {
                if (i < chunk.length) {
                    hexStr += chunk[i].toString(16).padStart(2, '0') + ' '
                } else {
                    hexStr += '   '
                }

                // Add extra space halfway
                if (i === half - 1 && bytesPerRow > 1) {
                    hexStr += ' '
                }
            }

            // 3. ASCII column
            let asciiStr = '|'
            for (let i = 0; i < chunk.length; i++) {
                const byte = chunk[i]
                // Printable ASCII: 32 to 126
                if (byte >= 32 && byte <= 126) {
                    asciiStr += String.fromCharCode(byte)
                } else {
                    asciiStr += placeholder
                }
            }
            for (let i = chunk.length; i < bytesPerRow; i++) {
                asciiStr += ' '
            }
            asciiStr += '|'

            const line = `${offsetStr}  ${hexStr} ${asciiStr}`

            // Render line, truncate to width if necessary
            screen.writeString(x, y + row, line.substring(0, width), attrs)
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — TreeTable widget
// ─────────────────────────────────────────────────────

import {
    type Screen,
    type Style,
    type Color,
    type KeyEvent,
    styleToCellAttrs,
    stringWidth,
    truncate,
    caps,
} from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface TreeTableColumn {
    /** Column header label */
    header: string;
    /** Key to pull data from row objects */
    key: string;
    /** Fixed width (chars). If omitted, auto-distributes. */
    width?: number;
    /** Text alignment within the column */
    align?: 'left' | 'center' | 'right';
}

export interface TreeTableRow {
    children?: TreeTableRow[];
    expanded?: boolean;
    [key: string]: unknown;
}

export interface TreeTableOptions {
    /** Whether to show the header row */
    showHeader?: boolean;
    /** Color for the header row */
    headerColor?: Color;
    /** Whether rows are zebra-striped */
    stripe?: boolean;
    /** Stripe color */
    stripeColor?: Color;
    /** Column separator character */
    separator?: string;
    /** Indentation per depth (default 2) */
    indent?: number;
    /** Callback when a row is selected */
    onSelect?: (row: TreeTableRow) => void;
}

interface VisibleEntry {
    row: TreeTableRow;
    depth: number;
}

/**
 * TreeTable — combines Tree expand/collapse with Table columns.
 *
 * Supports:
 * - Nested rows with column alignment
 * - Expand/collapse with arrows or Enter
 * - Keyboard navigation
 * - Unicode and ASCII symbols
 * - Zebra striping
 * - Header styling
 */
export class TreeTable extends Widget {
    private _columns: TreeTableColumn[];
    private _rows: TreeTableRow[];
    private _showHeader: boolean;
    private _headerColor: Color;
    private _stripe: boolean;
    private _stripeColor: Color;
    private _separator: string;
    private _indent: number;
    private _onSelect?: (row: TreeTableRow) => void;
    protected _selectedIndex = 0;
    protected _scrollOffset = 0;
    protected _visibleRows: VisibleEntry[] = [];

    constructor(
        columns: TreeTableColumn[],
        rows: TreeTableRow[],
        style: Partial<Style> = {},
        options: TreeTableOptions = {},
    ) {
        super(style);
        this._columns = columns;
        this._rows = rows;
        this._showHeader = options.showHeader ?? true;
        this._headerColor = options.headerColor ?? { type: 'named', name: 'cyan' };
        this._stripe = options.stripe ?? true;
        this._stripeColor = options.stripeColor ?? { type: 'named', name: 'brightBlack' };
        this._separator = options.separator ?? ' │ ';
        this._indent = options.indent ?? 2;
        this._onSelect = options.onSelect;
        this.focusable = true;
        this._buildVisibleRows();
    }

    // ── Public API ─────────────────────────────────────

    get selectedIndex(): number { return this._selectedIndex; }

    get selectedRow(): TreeTableRow | undefined {
        return this._visibleRows[this._selectedIndex]?.row;
    }

    setRows(rows: TreeTableRow[]): void {
        this._rows = rows;
        this._selectedIndex = 0;
        this._scrollOffset = 0;
        this._buildVisibleRows();
        this.markDirty();
    }

    /** Move cursor up one visible row */
    movePrev(): void {
        if (this._selectedIndex > 0) {
            this._selectedIndex--;
            this._clampScroll();
            this.markDirty();
            this._onSelect?.(this._visibleRows[this._selectedIndex].row);
        }
    }

    /** Move cursor down one visible row */
    moveNext(): void {
        if (this._selectedIndex < this._visibleRows.length - 1) {
            this._selectedIndex++;
            this._clampScroll();
            this.markDirty();
            this._onSelect?.(this._visibleRows[this._selectedIndex].row);
        }
    }

    /** Go to first visible row */
    moveFirst(): void {
        this._selectedIndex = 0;
        this._clampScroll();
        this.markDirty();
        this._onSelect?.(this._visibleRows[this._selectedIndex].row);
    }

    /** Go to last visible row */
    moveLast(): void {
        if (this._visibleRows.length > 0) {
            this._selectedIndex = this._visibleRows.length - 1;
            this._clampScroll();
            this.markDirty();
            this._onSelect?.(this._visibleRows[this._selectedIndex].row);
        }
    }

    /** Expand the selected row (if it has children and is collapsed) */
    expand(): void {
        const entry = this._visibleRows[this._selectedIndex];
        if (!entry) return;
        const row = entry.row;
        if (_isParent(row) && !row.expanded) {
            row.expanded = true;
            this._buildVisibleRows();
            this.markDirty();
        }
    }

    /** Collapse the selected row, or move to parent if already collapsed/leaf */
    collapse(): void {
        const entry = this._visibleRows[this._selectedIndex];
        if (!entry) return;
        const row = entry.row;

        if (_isParent(row) && row.expanded) {
            row.expanded = false;
            this._buildVisibleRows();
            this._clampScroll();
            this.markDirty();
        }
    }

    /** Toggle expand/collapse */
    toggle(): void {
        const entry = this._visibleRows[this._selectedIndex];
        if (!entry) return;
        const row = entry.row;

        if (_isParent(row)) {
            row.expanded = !row.expanded;
            this._buildVisibleRows();
            this._clampScroll();
            this.markDirty();
        } else {
            this._onSelect?.(row);
        }
    }

    /**
     * Handle a key event. Call this from your app's key-routing logic
     * when this widget is focused.
     */
    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'up':
            case 'k':
                this.movePrev();
                break;
            case 'down':
            case 'j':
                this.moveNext();
                break;
            case 'enter':
            case 'space':
                this.toggle();
                break;
            case 'left':
            case 'h':
                this.collapse();
                break;
            case 'right':
            case 'l':
                this.expand();
                break;
            case 'home':
                this.moveFirst();
                break;
            case 'end':
                this.moveLast();
                break;
        }
    }

    // ── Rendering ──────────────────────────────────────

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const sepWidth = stringWidth(this._separator);
        const useUnicode = caps.unicode;

        const collapsedChevron = useUnicode ? '▶ ' : '> ';
        const expandedChevron = useUnicode ? '▼ ' : 'v ';
        const leafPrefix = useUnicode ? '• ' : '* ';

        // Calculate column widths
        const colWidths = this._computeColumnWidths(
            width - (this._columns.length - 1) * sepWidth,
        );

        let row = 0;

        // Render header
        if (this._showHeader && row < height) {
            let cx = x;
            for (let c = 0; c < this._columns.length; c++) {
                const col = this._columns[c];
                const cellText = this._alignText(col.header, colWidths[c], col.align ?? 'left');
                screen.writeString(cx, y + row, cellText, {
                    ...attrs,
                    fg: this._headerColor,
                    bold: true,
                });
                cx += colWidths[c];
                if (c < this._columns.length - 1) {
                    screen.writeString(cx, y + row, this._separator, { ...attrs, dim: true });
                    cx += sepWidth;
                }
            }
            row++;

            // Header separator line
            if (row < height) {
                const sepLine = '─'.repeat(width);
                screen.writeString(x, y + row, sepLine, { ...attrs, dim: true });
                row++;
            }
        }

        // Render visible data rows
        const visibleCount = Math.min(this._visibleRows.length - this._scrollOffset, height - row);
        for (let i = 0; i < visibleCount; i++) {
            const entryIdx = this._scrollOffset + i;
            const entry = this._visibleRows[entryIdx];
            const { row: dataRow, depth } = entry;
            const isSelected = entryIdx === this._selectedIndex && this.isFocused;
            const isStripe = this._stripe && i % 2 === 1;

            const indentStr = ' '.repeat(this._indent * depth);
            let prefix: string;
            if (_isParent(dataRow)) {
                prefix = dataRow.expanded ? expandedChevron : collapsedChevron;
            } else {
                prefix = leafPrefix;
            }
            const fullPrefix = indentStr + prefix;

            let cx = x;
            for (let c = 0; c < this._columns.length; c++) {
                const col = this._columns[c];
                const rawValue = String(dataRow[col.key] ?? '');
                const cellContent = c === 0 ? fullPrefix + rawValue : rawValue;
                const cellText = this._alignText(cellContent, colWidths[c], col.align ?? 'left');

                const cellStyle = isSelected
                    ? {
                        ...attrs,
                        bg: { type: 'named' as const, name: 'blue' as const },
                        bold: true,
                    }
                    : isStripe
                    ? { ...attrs, bg: this._stripeColor }
                    : attrs;

                screen.writeString(cx, y + row, cellText, cellStyle);
                cx += colWidths[c];
                if (c < this._columns.length - 1) {
                    screen.writeString(cx, y + row, this._separator, {
                        ...attrs,
                        dim: true,
                        bg: isSelected ? { type: 'named', name: 'blue' } : isStripe ? this._stripeColor : attrs.bg,
                    });
                    cx += sepWidth;
                }
            }

            // Fill remaining width for stripe/selection
            if (isSelected || isStripe) {
                const bg: Color = isSelected ? { type: 'named', name: 'blue' as const } : this._stripeColor;
                for (let fx = cx; fx < x + width; fx++) {
                    screen.setCell(fx, y + row, { char: ' ', bg });
                }
            }

            row++;
        }
    }

    private _computeColumnWidths(totalWidth: number): number[] {
        const fixedCols = this._columns.filter(c => c.width !== undefined);
        const flexCols = this._columns.filter(c => c.width === undefined);

        let usedWidth = fixedCols.reduce((sum, c) => sum + (c.width ?? 0), 0);
        const remainingWidth = Math.max(0, totalWidth - usedWidth);
        const flexWidth = flexCols.length > 0 ? Math.floor(remainingWidth / flexCols.length) : 0;

        return this._columns.map(c => c.width ?? flexWidth);
    }

    private _alignText(text: string, width: number, align: 'left' | 'center' | 'right'): string {
        const truncated = truncate(text, width);
        const textWidth = stringWidth(truncated);
        const pad = Math.max(0, width - textWidth);

        switch (align) {
            case 'right':
                return ' '.repeat(pad) + truncated;
            case 'center': {
                const left = Math.floor(pad / 2);
                const right = pad - left;
                return ' '.repeat(left) + truncated + ' '.repeat(right);
            }
            case 'left':
            default:
                return truncated + ' '.repeat(pad);
        }
    }

    private _buildVisibleRows(): void {
        this._visibleRows = [];
        _collectVisible(this._rows, 0, this._visibleRows);
    }

    private _clampScroll(): void {
        const rect = this._getContentRect();
        const headerOffset = this._showHeader ? 2 : 0;
        const visibleHeight = Math.max(1, rect.height - headerOffset);

        if (this._selectedIndex < this._scrollOffset) {
            this._scrollOffset = this._selectedIndex;
        }
        if (this._selectedIndex >= this._scrollOffset + visibleHeight) {
            this._scrollOffset = this._selectedIndex - visibleHeight + 1;
        }
        this._scrollOffset = Math.max(0, this._scrollOffset);
    }
}

function _isParent(row: TreeTableRow): boolean {
    return Array.isArray(row.children) && row.children.length > 0;
}

function _collectVisible(
    rows: TreeTableRow[],
    depth: number,
    out: VisibleEntry[],
): void {
    for (let i = 0; i < rows.length; i++) {
        const row = rows[i];
        out.push({ row, depth });
        if (_isParent(row) && row.expanded) {
            _collectVisible(row.children!, depth + 1, out);
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Table widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, type KeyEvent, styleToCellAttrs, stringWidth, truncate } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';
import { type TableState } from '@termuijs/widgets';
import { computeRange } from '@termuijs/widgets';

export interface TableColumn {
    /** Column header label */
    header: string;
    /** Key to pull data from row objects */
    key: string;
    /** Fixed width (chars). If omitted, auto-distributes. */
    width?: number;
    /** Text alignment within the column */
    align?: 'left' | 'center' | 'right';
}

export type TableRow = Record<string, string | number>;

export interface TableOptions {
    /** Whether to show the header row */
    showHeader?: boolean;
    /** Color for the header row */
    headerColor?: Color;
    /** Whether rows are zebra-striped */
    stripe?: boolean;
    /** Stripe color */
    stripeColor?: Color;
    /** Column separator character */
    separator?: string;
}

export interface TableProps {
    columns: TableColumn[];
    rows?: TableRow[];
    style?: Partial<Style>;
    options?: TableOptions;
    /** External state object – if provided, Table syncs rows through it */
    state?: TableState;
    /** Called whenever rows change via setRows */
    onStateChange?: (state: TableState) => void;
}

/**
 * Table — renders tabular data with columns, headers, and optional zebra-striping.
 *
 * Supports:
 * - Auto-width column distribution
 * - Fixed and percentage widths
 * - Header styling
 * - Zebra striping
 * - Text alignment per column
 * - Truncation for overflow
 * - External state via `state` prop and `useTableState` hook
 * - Virtualized scrolling
 */
export class Table extends Widget {
    focusable = true;
    protected _columns: TableColumn[];
    protected _rows: TableRow[];
    protected _showHeader: boolean;
    protected _headerColor: Color;
    protected _stripe: boolean;
    protected _stripeColor: Color;
    protected _separator: string;
    private _state?: TableState;
    private _onStateChange?: (state: TableState) => void;
    private _selectedRow = 0;
    private _scrollOffset = 0;
    private _sortColumn = '';

    constructor(
        columnsOrProps: TableColumn[] | TableProps,
        rows: TableRow[] = [],
        style: Partial<Style> = {},
        options: TableOptions = {},
    ) {
        let columns: TableColumn[];
        let state: TableState | undefined;
        let onStateChange: ((s: TableState) => void) | undefined;

        if (Array.isArray(columnsOrProps)) {
            columns = columnsOrProps;
        } else {
            const props = columnsOrProps as TableProps;
            columns = props.columns;
            rows = props.rows ?? [];
            style = props.style ?? style;
            options = props.options ?? options;
            state = props.state;
            onStateChange = props.onStateChange;
        }

        super(style);
        this._columns = columns;
        this._rows = rows;
        this._showHeader = options.showHeader ?? true;
        this._headerColor = options.headerColor ?? { type: 'named', name: 'cyan' };
        this._stripe = options.stripe ?? true;
        this._stripeColor = options.stripeColor ?? { type: 'named', name: 'brightBlack' };
        this._separator = options.separator ?? ' │ ';
        this._state = state;
        this._onStateChange = onStateChange;
    }

    // ── Public API ────────────────────────────────────

    get selectedRow(): number { return this._selectedRow; }

    // ── Mutations ─────────────────────────────────────

    setRows(rows: TableRow[]): void {
        this._rows = rows;
        this._clampScroll();
        this.markDirty();
        this._pushState();
    }

    sortByColumn(columnKey: string): void {
        this._sortColumn = columnKey;

        this._rows.sort((a, b) =>
            String(a[columnKey] ?? '').localeCompare(
                String(b[columnKey] ?? '')
            )
        );

        this.markDirty();
    }

    // ── External state sync ───────────────────────────

    private _pushState(): void {
        if (this._state) {
            this._state.rows = this._rows;
            this._onStateChange?.(this._state);
        }
    }

    handleKey(event: KeyEvent): void {
        if (event.key === 'up') {
            this._selectedRow = Math.max(0, this._selectedRow - 1);
        }

        if (event.key === 'down') {
            this._selectedRow = Math.min(
                this._rows.length - 1,
                this._selectedRow + 1
            );
        }

        this._clampScroll();
        this.markDirty();
    }

    private _clampScroll(): void {
        const rect = this._getContentRect();
        let visibleHeight = rect.height;
        if (this._showHeader) {
            visibleHeight -= 2; // header + separator
        }
        if (visibleHeight <= 0) { this._scrollOffset = 0; return; }

        if (this._selectedRow < this._scrollOffset) {
            this._scrollOffset = this._selectedRow;
        }
        if (this._selectedRow >= this._scrollOffset + visibleHeight) {
            this._scrollOffset = this._selectedRow - visibleHeight + 1;
        }
        this._scrollOffset = Math.max(0, this._scrollOffset);
    }

    // ── Rendering ─────────────────────────────────────

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const sepWidth = stringWidth(this._separator);

        // Calculate column widths
        const colWidths = this._computeColumnWidths(
            width - (this._columns.length - 1) * sepWidth,
        );

        let headerOffset = 0;

        // Render header
        if (this._showHeader && headerOffset < height) {
            let cx = x;
            for (let c = 0; c < this._columns.length; c++) {
                const col = this._columns[c];
                const cellText = this._alignText(col.header, colWidths[c], col.align ?? 'left');
                screen.writeString(cx, y + headerOffset, cellText, {
                    ...attrs,
                    fg: this._headerColor,
                    bold: true,
                });
                cx += colWidths[c];
                if (c < this._columns.length - 1) {
                    screen.writeString(cx, y + headerOffset, this._separator, { ...attrs, dim: true });
                    cx += sepWidth;
                }
            }
            headerOffset++;

            // Header separator line
            if (headerOffset < height) {
                const sepLine = '─'.repeat(width);
                screen.writeString(x, y + headerOffset, sepLine, { ...attrs, dim: true });
                headerOffset++;
            }
        }

        const dataHeight = height - headerOffset;
        if (dataHeight <= 0) return;

        // Use the virtualization engine
        const range = computeRange(this._scrollOffset, dataHeight, this._rows.length, 0);

        // Render data rows within the virtual range
        for (let r = range.start; r < range.end; r++) {
            const dataRow = this._rows[r];
            const isStripe = this._stripe && r % 2 === 1;
            const isSelected = r === this._selectedRow;

            const screenY = y + headerOffset + (r - this._scrollOffset);
            if (screenY < y || screenY >= y + height) continue;

            let cx = x;

            for (let c = 0; c < this._columns.length; c++) {
                const col = this._columns[c];
                const rawValue = String(dataRow[col.key] ?? '');
                const cellText = this._alignText(rawValue, colWidths[c], col.align ?? 'left');

                screen.writeString(cx, screenY, cellText, {
                    ...attrs,
                    bg: isSelected
                        ? { type: 'named', name: 'blue' }
                        : isStripe
                            ? this._stripeColor
                            : attrs.bg,
                });
                cx += colWidths[c];
                if (c < this._columns.length - 1) {
                    screen.writeString(cx, screenY, this._separator, {
                        ...attrs,
                        dim: true,
                        bg: isStripe ? this._stripeColor : attrs.bg,
                    });
                    cx += sepWidth;
                }
            }

            // Fill remaining width for stripe/selection highlight
            if (isStripe || isSelected) {
                const rowBg = isSelected ? { type: 'named' as const, name: 'blue' as const } : this._stripeColor;
                for (let fx = cx; fx < x + width; fx++) {
                    screen.setCell(fx, screenY, { char: ' ', bg: rowBg });
                }
            }
        }
    }

    protected _computeColumnWidths(totalWidth: number): number[] {
        const fixedCols = this._columns.filter(c => c.width !== undefined);
        const flexCols = this._columns.filter(c => c.width === undefined);

        const usedWidth = fixedCols.reduce((sum, c) => sum + (c.width ?? 0), 0);
        const remainingWidth = Math.max(0, totalWidth - usedWidth);
        const flexWidth = flexCols.length > 0 ? Math.floor(remainingWidth / flexCols.length) : 0;

        return this._columns.map(c => c.width ?? flexWidth);
    }

    protected _alignText(text: string, width: number, align: 'left' | 'center' | 'right'): string {
        const truncated = truncate(text, width);
        const textWidth = stringWidth(truncated);
        const pad = Math.max(0, width - textWidth);

        switch (align) {
            case 'right':
                return ' '.repeat(pad) + truncated;
            case 'center': {
                const left = Math.floor(pad / 2);
                const right = pad - left;
                return ' '.repeat(left) + truncated + ' '.repeat(right);
            }
            case 'left':
            default:
                return truncated + ' '.repeat(pad);
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — RadarChart (Self-Contained)
// ─────────────────────────────────────────────────────

import { Widget } from '@termuijs/widgets';
import { type Style, type Color, Screen } from '@termuijs/core';

export interface RadarSeries {
    label: string;
    /** One value per axis, range [0, 1] */
    values: number[];
    color?: Color;
}

export interface RadarChartOptions {
    /** Axis names, one per spoke */
    axes?: string[];
    lineColor?: Color;
}

export class RadarChart extends Widget {
    private series: RadarSeries[] = [];
    private options: RadarChartOptions;

    constructor(style?: Partial<Style>, opts?: RadarChartOptions) {
        super(style);
        this.options = opts || {};
    }

    setSeries(series: RadarSeries[]): void {
        this.series = series;
        this.markDirty();
    }

    protected override _renderSelf(screen: Screen): void {
        if (!this.rect || this.series.length === 0) return;

        const { x, y, width, height } = this.rect;
        const cx = Math.floor(x + width / 2);
        const cy = Math.floor(y + height / 2);
        // Standard radius calculation
        const maxR = Math.min(width / 2, height / 2) - 1; 

        if (maxR <= 0) return;

        for (const s of this.series) {
            const numAxes = s.values.length;
            if (numAxes === 0) continue;

            const points = s.values.map((val, i) => {
                const theta = -Math.PI / 2 + (i * 2 * Math.PI) / numAxes;
                const clampedVal = Math.max(0, Math.min(1, val));
                return {
                    // Multiply X by 2 to compensate for tall terminal character aspect ratio
                    px: Math.floor(cx + clampedVal * maxR * Math.cos(theta) * 2),
                    py: Math.floor(cy + clampedVal * maxR * Math.sin(theta))
                };
            });

            // Connect the points using Bresenham's line algorithm directly on the screen
            for (let i = 0; i < points.length; i++) {
                const p1 = points[i];
                const p2 = points[(i + 1) % points.length];
                this.drawLine(screen, p1.px, p1.py, p2.px, p2.py, s.color || this.options.lineColor);
            }
        }

        this.renderLabels(screen, x, y, width, height);
    }

    private drawLine(screen: Screen, x0: number, y0: number, x1: number, y1: number, color?: Color) {
        let dx = Math.abs(x1 - x0);
        let dy = Math.abs(y1 - y0);
        let sx = x0 < x1 ? 1 : -1;
        let sy = y0 < y1 ? 1 : -1;
        let err = dx - dy;

        while (true) {
            screen.writeString(x0, y0, '*', { fg: color });
            if (x0 === x1 && y0 === y1) break;
            let e2 = 2 * err;
            if (e2 > -dy) { err -= dy; x0 += sx; }
            if (e2 < dx) { err += dx; y0 += sy; }
        }
    }

    private renderLabels(screen: Screen, x: number, y: number, width: number, height: number) {
        if (!this.options.axes || this.series.length === 0) return;

        const numAxes = this.options.axes.length;
        const cx = Math.floor(x + width / 2);
        const cy = Math.floor(y + height / 2);
        const maxR = Math.min(width / 2, height / 2) - 1;

        for (let i = 0; i < numAxes; i++) {
            const label = this.options.axes[i];
            if (!label) continue;

            const theta = -Math.PI / 2 + (i * 2 * Math.PI) / numAxes;
            const lx = Math.floor(cx + maxR * Math.cos(theta) * 2.2); 
            const ly = Math.floor(cy + maxR * Math.sin(theta) * 1.2);

            // Clamp the X coordinate to prevent horizontal clipping
            const rawX = lx - Math.floor(label.length / 2);
            const startX = Math.max(x, Math.min(x + width - label.length, rawX));

            // Clamp the Y coordinate to prevent vertical clipping (fixes "Speed" disappearing)
            const startY = Math.max(y, Math.min(y + height - 1, ly));

            screen.writeString(startX, startY, label);
        }
    }
}

import { type Screen, type Style, type Color, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface BrailleCanvasOptions {
    width: number;
    height: number;
    color?: Color;
}

const BRAILLE_BITS = [
    [0x01, 0x08],
    [0x02, 0x10],
    [0x04, 0x20],
    [0x40, 0x80],
] as const;

export class BrailleCanvas extends Widget {
    private _canvasWidth: number;
    private _canvasHeight: number;
    private _pixels: boolean[][];
    private _color?: Color;

    constructor(
        opts: BrailleCanvasOptions,
        style: Partial<Style> = {},
    ) {
        super(style);

        this._canvasWidth = opts.width;
        this._canvasHeight = opts.height;
        this._color = opts.color;

        this._pixels = Array.from(
            { length: this._canvasHeight },
            () => Array(this._canvasWidth).fill(false),
        );
    }

    drawPixel(x: number, y: number): void {
        if (
            x < 0 ||
            y < 0 ||
            x >= this._canvasWidth ||
            y >= this._canvasHeight
        ) {
            return;
        }

        this._pixels[y]![x] = true;
        this.markDirty();
    }

    drawLine(
        x0: number,
        y0: number,
        x1: number,
        y1: number,
    ): void {

    const dx = Math.abs(x1 - x0);
    const dy = Math.abs(y1 - y0);

    const sx = x0 < x1 ? 1 : -1;
    const sy = y0 < y1 ? 1 : -1;

    let err = dx - dy;

    while (true) {
        this.drawPixel(x0, y0);

        if (x0 === x1 && y0 === y1) {
            break;
        }

        const e2 = err * 2;

        if (e2 > -dy) {
            err -= dy;
            x0 += sx;
        }

        if (e2 < dx) {
            err += dx;
            y0 += sy;
        }

    }
    this.markDirty();
}


    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();

        if (rect.width <= 0 || rect.height <= 0) {
            return;
        }

        const { x, y } = rect;

        const cellWidth = Math.ceil(this._canvasWidth / 2);
        const cellHeight = Math.ceil(this._canvasHeight / 4);

        for (let cy = 0; cy < cellHeight; cy++) {
            for (let cx = 0; cx < cellWidth; cx++) {
                let pattern = 0;

                for (let py = 0; py < 4; py++) {
                    for (let px = 0; px < 2; px++) {
                        const pixelX = cx * 2 + px;
                        const pixelY = cy * 4 + py;

                        if (
                            pixelY < this._canvasHeight &&
                            pixelX < this._canvasWidth &&
                            this._pixels[pixelY]?.[pixelX]
                        ) {
                            pattern |= BRAILLE_BITS[py]![px]!;
                        }
                    }
                }

                 const char = caps.unicode
                   ? String.fromCharCode(0x2800 + pattern)
                   : pattern === 0
                  ? ' '
                  : '#';

                screen.setCell(
                    x + cx,
                    y + cy,
                    {
                        char,
                        fg: this._color,
                    },
                );
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Definition widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, styleToCellAttrs, stringWidth, truncate } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface DefinitionPair {
    term: string;
    definition: string;
}

export interface DefinitionOptions {
    /** Indentation for definition lines (default: 2) */
    indent?: number;
    /** Blank line between pairs (default: true) */
    spacing?: boolean;
    /** Color for term labels */
    termColor?: import('@termuijs/core').Color;
    /** Color for definition text */
    definitionColor?: import('@termuijs/core').Color;
}

/**
 * Definition — term + definition pairs, stacked vertically.
 *
 * Each pair renders as:
 *   Term
 *     definition text (indented)
 *
 * Similar to KeyValue but stacked rather than inline.
 */
export class Definition extends Widget {
    private _pairs: DefinitionPair[];
    private _indent: number;
    private _spacing: boolean;
    private _termColor?: import('@termuijs/core').Color;
    private _definitionColor?: import('@termuijs/core').Color;

    constructor(
        pairs: DefinitionPair[] | Record<string, string>,
        style: Partial<Style> = {},
        opts: DefinitionOptions = {},
    ) {
        super(style);
        this._pairs = Array.isArray(pairs)
            ? pairs
            : Object.entries(pairs).map(([term, definition]) => ({ term, definition }));
        this._indent = opts.indent ?? 2;
        this._spacing = opts.spacing ?? true;
        this._termColor = opts.termColor;
        this._definitionColor = opts.definitionColor;
    }

    setPairs(pairs: DefinitionPair[] | Record<string, string>): void {
        this._pairs = Array.isArray(pairs)
            ? pairs
            : Object.entries(pairs).map(([term, definition]) => ({ term, definition }));
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0 || this._pairs.length === 0) return;

        const attrs = styleToCellAttrs(this._style);
        const indent = Math.min(this._indent, width - 1);

        let row = 0;

        for (const pair of this._pairs) {
            if (row >= height) break;

            // Term (bold)
            screen.writeString(x, y + row, truncate(pair.term, width, ''), {
                ...attrs,
                fg: this._termColor ?? attrs.fg,
                bold: true,
            });
            row++;

            if (row >= height) break;

            // Definition (indented, may span multiple lines via simple wrapping)
            const defWidth = Math.max(1, width - indent);
            const words = pair.definition.split(' ');
            let line = '';
            let lineWidth = 0;

            for (const word of words) {
                const wordWidth = stringWidth(word);
                if (lineWidth === 0) {
                    line = word;
                    lineWidth = wordWidth;
                } else if (lineWidth + 1 + wordWidth <= defWidth) {
                    line += ' ' + word;
                    lineWidth += 1 + wordWidth;
                } else {
                    if (row >= height) break;
                    screen.writeString(x + indent, y + row, line, {
                        ...attrs,
                        fg: this._definitionColor ?? attrs.fg,
                    });
                    row++;
                    line = word;
                    lineWidth = wordWidth;
                }
            }

            if (line && row < height) {
                screen.writeString(x + indent, y + row, line, {
                    ...attrs,
                    fg: this._definitionColor ?? attrs.fg,
                });
                row++;
            }

            // Blank line between pairs
            if (this._spacing && row < height) {
                row++;
            }
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// @termuijs/widgets — DataGrid widget
//
// A table with sort indicators and a filter row. Extends Table and adds:
// - `s` key cycles sort on the selected column (none → asc → desc → none)
// - `/` opens a filter row; typing narrows displayed rows
// - `escape` closes the filter row and clears the filter
// - Sort indicators: ▲ / ▼ (Unicode) or ^ / v (ASCII) appended to headers
// ─────────────────────────────────────────────────────────────────────────────

import {
    type Screen,
    type Style,
    type KeyEvent,
    styleToCellAttrs,
    stringWidth,
    truncate,
    caps,
} from '@termuijs/core';
import { Table, type TableColumn, type TableRow, type TableOptions } from '@termuijs/widgets';

export type SortDirection = 'asc' | 'desc' | 'none';

export interface DataGridColumn extends TableColumn {
    /** Whether the column can be sorted. Default: true. */
    sortable?: boolean;
}

export type DataGridRow = TableRow;

export interface DataGridOptions extends TableOptions {
    /** Callback fired when sort changes. */
    onSort?: (key: string, direction: SortDirection) => void;
    /** Callback fired when the filter changes. */
    onFilter?: (filter: string) => void;
}

export class DataGrid extends Table {
    private _onSort?: (key: string, direction: SortDirection) => void;
    private _onFilter?: (filter: string) => void;

    private _sortKey: string | null = null;
    private _sortDir: SortDirection = 'none';
    private _filter = '';
    private _filterOpen = false;
    private _selectedCol = 0;

    focusable = true;

    constructor(
        columns: DataGridColumn[],
        rows: DataGridRow[],
        style: Partial<Style> = {},
        options: DataGridOptions = {},
    ) {
        const normalizedColumns: DataGridColumn[] = columns.map(c => ({
            ...c,
            sortable: c.sortable ?? true,
        }));
        super(normalizedColumns, rows, style, options);
        this._onSort = options.onSort;
        this._onFilter = options.onFilter;
    }

    // ── Public API ──────────────────────────────────

    get sortKey(): string | null { return this._sortKey; }
    get sortDirection(): SortDirection { return this._sortDir; }
    get filter(): string { return this._filter; }
    get filterOpen(): boolean { return this._filterOpen; }
    get selectedColumn(): number { return this._selectedCol; }

    setSelectedColumn(col: number): void {
        if (col < 0 || col >= this._columns.length) return;
        this._selectedCol = col;
        this.markDirty();
    }

    setFilter(filter: string): void {
        this._filter = filter;
        this._filterOpen = true;
        this._onFilter?.(filter);
        this.markDirty();
    }

    clearFilter(): void {
        if (this._filter === '' && !this._filterOpen) return;
        this._filter = '';
        this._filterOpen = false;
        this._onFilter?.('');
        this.markDirty();
    }

    cycleSort(): void {
        const column = this._columns[this._selectedCol] as DataGridColumn | undefined;
        if (!column || column.sortable === false) return;

        if (this._sortKey !== column.key) {
            this._sortKey = column.key;
            this._sortDir = 'asc';
        } else if (this._sortDir === 'asc') {
            this._sortDir = 'desc';
        } else if (this._sortDir === 'desc') {
            this._sortDir = 'none';
            this._sortKey = null;
        } else {
            this._sortDir = 'asc';
        }

        this._onSort?.(column.key, this._sortDir);
        this.markDirty();
    }

    handleKey(event: KeyEvent): void {
        // While filter is open, capture printable keys + escape + backspace.
        if (this._filterOpen) {
            switch (event.key) {
                case 'escape':
                    this.clearFilter();
                    return;
                case 'backspace':
                    if (this._filter.length > 0) {
                        this.setFilter(this._filter.slice(0, -1));
                    }
                    return;
                default:
                    if (
                        event.key.length === 1
                        && !event.ctrl
                        && !event.alt
                    ) {
                        this.setFilter(this._filter + event.key);
                    }
                    return;
            }
        }

        // Normal mode: navigation + sort + filter
        switch (event.key) {
            case 's':
            case 'S':
                if (!event.ctrl && !event.alt) this.cycleSort();
                break;

            case '/':
                this._filterOpen = true;
                this.markDirty();
                break;

            case 'escape':
                this.clearFilter();
                break;

            case 'left':
                this.setSelectedColumn(this._selectedCol - 1);
                break;

            case 'right':
                this.setSelectedColumn(this._selectedCol + 1);
                break;

            default:
                super.handleKey(event);
                break;
        }
    }

    // ── Rendering ───────────────────────────────────

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const sepWidth = stringWidth(this._separator);
        const sortIndicator = (dir: SortDirection): string => {
            if (dir === 'asc') return caps.unicode ? ' \u25B2' : ' ^';
            if (dir === 'desc') return caps.unicode ? ' \u25BC' : ' v';
            return '';
        };

        const filterRowHeight = this._filterOpen ? 1 : 0;
        const filterY = y;
        const tableY = y + filterRowHeight;
        const tableHeight = Math.max(0, height - filterRowHeight);

        if (this._filterOpen) {
            const filterText = `/${this._filter}`;
            screen.writeString(x, filterY, truncate(filterText, width), { ...attrs, dim: true });
        }

        if (tableHeight <= 0) return;

        // Available width for headers and data
        const usableWidth = width - (this._columns.length - 1) * sepWidth;
        const colWidths = this._computeColumnWidths(usableWidth);

        let row = 0;

        if (this._showHeader && row < tableHeight) {
            let cx = x;
            for (let c = 0; c < this._columns.length; c++) {
                const col = this._columns[c] as DataGridColumn;
                const isSortKey = this._sortKey === col.key;
                const indicator = isSortKey ? sortIndicator(this._sortDir) : '';
                const indicatorStripped = stringWidth(indicator);
                const cellWidth = colWidths[c] ?? 0;
                const headerWidth = Math.max(0, cellWidth - indicatorStripped);
                const headerText = this._alignText(col.header, headerWidth, col.align ?? 'left');

                screen.writeString(cx, tableY + row, headerText, {
                    ...attrs,
                    bold: true,
                    underline: c === this._selectedCol,
                });

                if (indicator) {
                    screen.writeString(cx + headerWidth, tableY + row, indicator, {
                        ...attrs,
                        bold: true,
                    });
                }

                cx += cellWidth;
                if (c < this._columns.length - 1) {
                    screen.writeString(cx, tableY + row, this._separator, { ...attrs, dim: true });
                    cx += sepWidth;
                }
            }
            row++;

            // Header separator line
            if (row < tableHeight) {
                const sepLine = (caps.unicode ? '\u2500' : '-').repeat(width);
                screen.writeString(x, tableY + row, sepLine, { ...attrs, dim: true });
                row++;
            }
        }

        const dataRows = this._getVisibleRows();
        for (let r = 0; r < dataRows.length && row < tableHeight; r++) {
            const dataRow = dataRows[r];
            if (!dataRow) continue;
            const isStripe = this._stripe && r % 2 === 1;
            let cx = x;

            for (let c = 0; c < this._columns.length; c++) {
                const col = this._columns[c];
                const cellWidth = colWidths[c] ?? 0;
                const rawValue = String(dataRow[col.key] ?? '');
                const cellText = this._alignText(rawValue, cellWidth, col.align ?? 'left');

                screen.writeString(cx, tableY + row, cellText, {
                    ...attrs,
                    bg: isStripe ? this._stripeColor : attrs.bg,
                });
                cx += cellWidth;
                if (c < this._columns.length - 1) {
                    screen.writeString(cx, tableY + row, this._separator, {
                        ...attrs,
                        dim: true,
                        bg: isStripe ? this._stripeColor : attrs.bg,
                    });
                    cx += sepWidth;
                }
            }

            if (isStripe) {
                for (let fx = cx; fx < x + width; fx++) {
                    screen.setCell(fx, tableY + row, { char: ' ', bg: this._stripeColor });
                }
            }

            row++;
        }
    }

    private _getVisibleRows(): DataGridRow[] {
        let rows = [...this._rows];
        if (this._filter.length > 0) {
            const needle = this._filter.toLowerCase();
            rows = rows.filter(r =>
                this._columns.some(c => {
                    const v = r[c.key];
                    return v !== undefined && String(v).toLowerCase().includes(needle);
                }),
            );
        }
        if (this._sortDir !== 'none' && this._sortKey !== null) {
            const key = this._sortKey;
            const dir = this._sortDir;
            rows.sort((a, b) => {
                const left = a[key] ?? '';
                const right = b[key] ?? '';
                if (typeof left === 'number' && typeof right === 'number') {
                    return dir === 'asc' ? left - right : right - left;
                }
                const l = String(left);
                const r = String(right);
                if (l === r) return 0;
                return dir === 'asc' ? (l > r ? 1 : -1) : (l < r ? 1 : -1);
            });
        }
        return rows;
    }
}

// packages/widgets/src/data/ListState.ts
import { ListItem } from '@termuijs/widgets';

/**
 * External state object for List widget.
 * It owns the items, selected index and scroll offset.
 * The hook returns the same mutable object that can be passed to <List state={s} />.
 */
export interface ListState {
  /** The items displayed by the list */
  items: ListItem[];
  /** Index of the currently selected item */
  selectedIndex: number;
  /** Scroll offset (first visible item index) */
  scrollOffset: number;
  /** Update items */
  setItems(items: ListItem[]): void;
  /** Move selection up */
  selectPrev(): void;
  /** Move selection down */
  selectNext(): void;
  /** Confirm current selection (optional hook) */
  confirm(): void;
}

/** Hook that creates a fresh ListState. */
export function useListState(initial: { items: ListItem[] }): ListState {
  const state: ListState = {
    items: initial.items,
    selectedIndex: 0,
    scrollOffset: 0,
    setItems(items: ListItem[]) {
      state.items = items;
      if (state.selectedIndex >= items.length) {
        state.selectedIndex = Math.max(0, items.length - 1);
      }
    },
    selectPrev() {
      let next = state.selectedIndex - 1;
      while (next >= 0 && state.items[next]?.disabled) next--;
      if (next >= 0) {
        state.selectedIndex = next;
        if (next < state.scrollOffset) {
          state.scrollOffset = next;
        }
      }
    },
    selectNext() {
      let next = state.selectedIndex + 1;
      while (next < state.items.length && state.items[next]?.disabled) next++;
      if (next < state.items.length) {
        state.selectedIndex = next;
        // Note: scroll logic will be handled by List.render when needed
      }
    },
    confirm() {
      // No‑op placeholder – UI can call this when Enter is pressed.
    },
  };
  return state;
}

import { type Screen, type Style, type Color, styleToCellAttrs, stringWidth } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface StatOptions {
    delta?: number;
    valueColor?: Color;
}

export class Stat extends Widget {
    private _label: string;
    private _value: string;
    private _delta: number | undefined;
    private _valueColor: Color;

    constructor(label: string, value: string, style: Partial<Style> = {}, opts: StatOptions = {}) {
        super(style);
        this._label = label;
        this._value = value;
        this._delta = opts.delta;
        this._valueColor = opts.valueColor ?? { type: 'named', name: 'white' };
    }

    setValue(value: string): void {
        this._value = value;
        this.markDirty();
    }

    setDelta(delta: number | undefined): void {
        this._delta = delta;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        // Row 0: label (bold)
        screen.writeString(x, y, this._label, { ...attrs, bold: true });

        if (height < 2) return;

        // Row 1: value
        screen.writeString(x, y + 1, this._value, { ...attrs, fg: this._valueColor });

        // Optional delta arrow
        if (this._delta !== undefined) {
            const valueWidth = stringWidth(this._value);
            const arrowX = x + valueWidth + 1;

            if (arrowX >= x + width) return;

            if (this._delta > 0) {
                screen.setCell(arrowX, y + 1, { char: '\u2191', fg: { type: 'named', name: 'green' } });
            } else if (this._delta < 0) {
                screen.setCell(arrowX, y + 1, { char: '\u2193', fg: { type: 'named', name: 'red' } });
            } else {
                screen.setCell(arrowX, y + 1, { char: '\u2192', dim: true });
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — BarChart widget
// Grouped bar chart with vertical and horizontal modes.
// ─────────────────────────────────────────────────────

import {
    type Screen, type Style, type Color,
    styleToCellAttrs, stringWidth,
    VERTICAL_BAR_SYMBOLS, HORIZONTAL_BAR_SYMBOLS,
} from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

// ── Types ────────────────────────────────────────────

export interface Bar {
    value: number;
    label?: string;
    color?: Color;
}

export interface BarGroup {
    label?: string;
    bars: Bar[];
}

export type BarChartDirection = 'vertical' | 'horizontal';

export interface BarChartOptions {
    /** Direction bars grow. Default: 'vertical'. */
    direction?: BarChartDirection;
    /** Width of each bar in cells. Default: 1. */
    barWidth?: number;
    /** Gap between bars in a group. Default: 1. */
    barGap?: number;
    /** Gap between groups. Default: 2. */
    groupGap?: number;
    /** Max value for scaling. Auto-detected if not set. */
    max?: number;
    /** Color for bars without a per-bar color. */
    barColor?: Color;
    /** Color for value labels. */
    valueColor?: Color;
    /** Color for text labels. */
    labelColor?: Color;
}

// ── Widget ───────────────────────────────────────────

export class BarChart extends Widget {
    private _data: BarGroup[] = [];
    private _direction: BarChartDirection;
    private _barWidth: number;
    private _barGap: number;
    private _groupGap: number;
    private _max?: number;
    private _barColor: Color;
    private _valueColor: Color;
    private _labelColor: Color;

    constructor(data: BarGroup[], style: Partial<Style> = {}, opts: BarChartOptions = {}) {
        super(style);
        this._data = data;
        this._direction = opts.direction ?? 'vertical';
        this._barWidth = opts.barWidth ?? 1;
        this._barGap = opts.barGap ?? 1;
        this._groupGap = opts.groupGap ?? 2;
        this._max = opts.max;
        this._barColor = opts.barColor ?? { type: 'named', name: 'cyan' };
        this._valueColor = opts.valueColor ?? { type: 'named', name: 'white' };
        this._labelColor = opts.labelColor ?? { type: 'named', name: 'brightBlack' };
    }

    setData(data: BarGroup[]): void {
        this._data = data;
        this.markDirty();
    }

    setMax(max: number | undefined): void {
        this._max = max;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0 || this._data.length === 0) return;

        const maxVal = this._computeMax();
        if (maxVal === 0) return;

        if (this._direction === 'vertical') {
            this._renderVertical(screen, x, y, width, height, maxVal);
        } else {
            this._renderHorizontal(screen, x, y, width, height, maxVal);
        }
    }

    private _computeMax(): number {
        if (this._max !== undefined) return this._max;
        let max = 0;
        for (const group of this._data) {
            for (const bar of group.bars) {
                if (bar.value > max) max = bar.value;
            }
        }
        return max;
    }

    // ── Vertical Rendering ───────────────────────────

    private _renderVertical(
        screen: Screen, ox: number, oy: number,
        width: number, height: number, maxVal: number,
    ): void {
        const valueRows = 1;
        const hasLabels = this._data.some(g =>
            g.bars.some(b => b.label !== undefined)
        );
        const labelRows = hasLabels ? 1 : 0;
        const hasGroupLabels = this._data.some(g => g.label !== undefined);
        const groupLabelRows = hasGroupLabels ? 1 : 0;
        const reservedRows = valueRows + labelRows + groupLabelRows;

        if (height <= reservedRows) return;

        const barAreaHeight = height - reservedRows;
        let cx = ox;

        for (let gi = 0; gi < this._data.length; gi++) {
            const group = this._data[gi];
            if (!group) continue;
            const groupStartX = cx;

            for (let bi = 0; bi < group.bars.length; bi++) {
                const bar = group.bars[bi];
                if (!bar) continue;
                if (cx + this._barWidth > ox + width) break;

                const color = bar.color ?? this._barColor;

                // Draw bar from bottom up using sub-cell symbols (8 levels per cell)
                const scaledHeight = (bar.value / maxVal) * (barAreaHeight * 8);
                let remaining = Math.round(scaledHeight);

                for (let row = barAreaHeight - 1; row >= 0; row--) {
                    if (remaining <= 0) break;
                    const level = Math.min(remaining, 8);
                    const symbol = VERTICAL_BAR_SYMBOLS[level] ?? ' ';
                    const cellY = oy + row;

                    for (let col = 0; col < this._barWidth; col++) {
                        const cellX = cx + col;
                        if (cellX < ox + width) {
                            screen.setCell(cellX, cellY, { char: symbol, fg: color });
                        }
                    }
                    remaining -= 8;
                }

                // Value text below bar
                const valStr = Math.round(bar.value).toString();
                const valX = cx + Math.floor((this._barWidth - stringWidth(valStr)) / 2);
                screen.writeString(
                    Math.max(cx, valX), oy + barAreaHeight,
                    valStr.slice(0, this._barWidth),
                    { fg: this._valueColor },
                );

                // Bar label below value
                if (hasLabels && bar.label) {
                    const label = bar.label.slice(0, this._barWidth);
                    const labelX = cx + Math.floor((this._barWidth - stringWidth(label)) / 2);
                    screen.writeString(
                        Math.max(cx, labelX), oy + barAreaHeight + valueRows,
                        label,
                        { fg: this._labelColor },
                    );
                }

                cx += this._barWidth;
                if (bi < group.bars.length - 1) cx += this._barGap;
            }

            // Group label at bottom
            if (hasGroupLabels && group.label) {
                const groupWidth = cx - groupStartX;
                const label = group.label.slice(0, groupWidth);
                const labelX = groupStartX + Math.floor((groupWidth - stringWidth(label)) / 2);
                screen.writeString(
                    Math.max(groupStartX, labelX), oy + height - 1,
                    label,
                    { fg: this._labelColor },
                );
            }

            if (gi < this._data.length - 1) cx += this._groupGap;
        }
    }

    // ── Horizontal Rendering ─────────────────────────

    private _renderHorizontal(
        screen: Screen, ox: number, oy: number,
        width: number, height: number, maxVal: number,
    ): void {
        // Compute label column width
        let maxLabelWidth = 0;
        let maxValueWidth = 0;
        for (const group of this._data) {
            for (const bar of group.bars) {
                if (bar.label) {
                    const w = stringWidth(bar.label);
                    if (w > maxLabelWidth) maxLabelWidth = w;
                }
                const vw = Math.round(bar.value).toString().length;
                if (vw > maxValueWidth) maxValueWidth = vw;
            }
        }

        const labelColWidth = maxLabelWidth > 0 ? maxLabelWidth + 1 : 0;
        const valueColWidth = maxValueWidth > 0 ? maxValueWidth + 1 : 0;
        const barAreaWidth = width - labelColWidth - valueColWidth;

        if (barAreaWidth <= 0) return;

        let cy = oy;

        for (let gi = 0; gi < this._data.length; gi++) {
            const group = this._data[gi];
            if (!group) continue;

            for (let bi = 0; bi < group.bars.length; bi++) {
                const bar = group.bars[bi];
                if (!bar) continue;

                for (let row = 0; row < this._barWidth; row++) {
                    const cellY = cy + row;
                    if (cellY >= oy + height) break;

                    // Label on first row
                    if (row === 0 && bar.label) {
                        const label = bar.label.slice(0, maxLabelWidth);
                        const padded = label.padStart(maxLabelWidth);
                        screen.writeString(ox, cellY, padded, { fg: this._labelColor });
                    }

                    // Draw horizontal bar using sub-cell symbols
                    const color = bar.color ?? this._barColor;
                    const scaledWidth = (bar.value / maxVal) * (barAreaWidth * 8);
                    let remaining = Math.round(scaledWidth);
                    const barStartX = ox + labelColWidth;

                    for (let col = 0; col < barAreaWidth; col++) {
                        if (remaining <= 0) break;
                        const level = Math.min(remaining, 8);
                        const symbol = HORIZONTAL_BAR_SYMBOLS[level] ?? ' ';
                        screen.setCell(barStartX + col, cellY, { char: symbol, fg: color });
                        remaining -= 8;
                    }

                    // Value text on first row
                    if (row === 0) {
                        const valStr = Math.round(bar.value).toString();
                        screen.writeString(
                            ox + labelColWidth + barAreaWidth, cellY,
                            ` ${valStr}`,
                            { fg: this._valueColor },
                        );
                    }
                }

                cy += this._barWidth;
                if (bi < group.bars.length - 1) cy += this._barGap;
            }

            if (gi < this._data.length - 1) cy += this._groupGap;
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Calendar widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, type KeyEvent, styleToCellAttrs, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface CalendarOptions {
    date?: Date;
    selectedColor?: Color;
    todayColor?: Color;
    onSelect?: (date: Date) => void;
}

const MONTH_NAMES = [
    'January', 'February', 'March', 'April', 'May', 'June',
    'July', 'August', 'September', 'October', 'November', 'December'
];

export class Calendar extends Widget {
    private _selectedDate: Date;
    private _currentMonth: Date;
    private _selectedColor: Color;
    private _todayColor: Color;
    private _onSelect?: (date: Date) => void;
    focusable = true;

    constructor(style: Partial<Style> = {}, opts: CalendarOptions = {}) {
        super(style);
        this._selectedDate = opts.date ? new Date(opts.date) : new Date();
        this._selectedDate.setHours(0, 0, 0, 0);

        this._currentMonth = new Date(this._selectedDate.getFullYear(), this._selectedDate.getMonth(), 1);
        this._currentMonth.setHours(0, 0, 0, 0);

        this._selectedColor = opts.selectedColor ?? { type: 'named', name: 'cyan' };
        this._todayColor = opts.todayColor ?? { type: 'named', name: 'green' };
        this._onSelect = opts.onSelect;
    }

    setMonth(year: number, month: number): void {
        this._currentMonth = new Date(year, month, 1);
        this._currentMonth.setHours(0, 0, 0, 0);
        this.markDirty();
    }

    getSelectedDate(): Date {
        return new Date(this._selectedDate);
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'left':
                this._moveSelection(-1);
                break;
            case 'right':
                this._moveSelection(1);
                break;
            case 'up':
                this._moveSelection(-7);
                break;
            case 'down':
                this._moveSelection(7);
                break;
            case 'enter':
                this._onSelect?.(new Date(this._selectedDate));
                break;
        }
    }

    private _moveSelection(days: number): void {
        const newDate = new Date(this._selectedDate);
        newDate.setDate(newDate.getDate() + days);
        this._selectedDate = newDate;

        if (
            newDate.getMonth() !== this._currentMonth.getMonth() ||
            newDate.getFullYear() !== this._currentMonth.getFullYear()
        ) {
            this._currentMonth = new Date(newDate.getFullYear(), newDate.getMonth(), 1);
            this._currentMonth.setHours(0, 0, 0, 0);
        }
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;

        // Minimum required dimensions to prevent rendering cutoff / overflow
        if (width < 20 || height < 8) return;

        const attrs = styleToCellAttrs(this._style);

        const year = this._currentMonth.getFullYear();
        const month = this._currentMonth.getMonth();

        // 1. Render Month Header (◀ Month Year ▶)
        const prevArrow = caps.unicode ? '◀' : '<';
        const nextArrow = caps.unicode ? '▶' : '>';
        const monthName = MONTH_NAMES[month];
        const title = `${prevArrow} ${monthName} ${year} ${nextArrow}`;
        const titleX = x + Math.floor((width - title.length) / 2);
        screen.writeString(Math.max(x, titleX), y, title, { ...attrs, bold: true });

        // 2. Render Weekdays Header
        const weekdays = 'Su Mo Tu We Th Fr Sa';
        const weekdayX = x + Math.floor((width - weekdays.length) / 2);
        screen.writeString(Math.max(x, weekdayX), y + 1, weekdays, { ...attrs, dim: true });

        // 3. Render Calendar Grid (Days)
        const daysInMonth = new Date(year, month + 1, 0).getDate();
        const firstDay = new Date(year, month, 1).getDay();

        const gridStartY = y + 2;
        const maxWeeks = 6;

        const today = new Date();
        today.setHours(0, 0, 0, 0);

        for (let w = 0; w < maxWeeks; w++) {
            const rowY = gridStartY + w;
            if (rowY >= y + height) break;

            for (let d = 0; d < 7; d++) {
                const colX = Math.max(x, weekdayX) + d * 3;
                if (colX >= x + width) continue;

                const dayVal = w * 7 + d - firstDay + 1;

                if (dayVal >= 1 && dayVal <= daysInMonth) {
                    const label = String(dayVal).padStart(2, ' ');
                    const cellDate = new Date(year, month, dayVal);
                    cellDate.setHours(0, 0, 0, 0);

                    const isSelected = cellDate.getTime() === this._selectedDate.getTime();
                    const isToday = cellDate.getTime() === today.getTime();

                    if (isSelected) {
                        screen.writeString(colX, rowY, label, {
                            ...attrs,
                            fg: this._selectedColor,
                            bold: true,
                            inverse: this.isFocused,
                            underline: !this.isFocused,
                        });
                    } else if (isToday) {
                        screen.writeString(colX, rowY, label, {
                            ...attrs,
                            fg: this._todayColor,
                            bold: true,
                        });
                    } else {
                        screen.writeString(colX, rowY, label, attrs);
                    }
                } else {
                    // Blank spacer for out-of-bounds days
                    screen.writeString(colX, rowY, '  ', attrs);
                }
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Sparkline widget (braille chart)
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, styleToCellAttrs, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';
import { BrailleCanvas } from '@termuijs/widgets';

export interface SparklineOptions {
    /** Color of the sparkline */
    color?: Color;

    /** Show min/max labels */
    showRange?: boolean;

    /** Rendering style */
    marker?: 'block' | 'braille';
}

// Sparkline characters (8 levels per cell, bottom to top)
// Falls back to ASCII digits when unicode is not available.
const SPARK_CHARS_UNICODE = ['▁', '▂', '▃', '▄', '▅', '▆', '▇', '█'];
const SPARK_CHARS_ASCII = ['1', '2', '3', '4', '5', '6', '7', '8'];

/**
 * Sparkline — a compact inline chart showing a data trend.
 *
 * Example:
 *   Latency ▂▃▅▇▅▃▂▁▃▅█▅▃
 */
export class Sparkline extends Widget {
    private _label: string;
    private _data: number[] = [];
    private _color: Color;
    private _showRange: boolean;
    private _marker: 'block' | 'braille';
    constructor(label: string, style: Partial<Style> = {}, opts: SparklineOptions = {}) {
        super(style);
        this._label = label;
        this._color = opts.color ?? { type: 'named', name: 'cyan' };
        this._showRange = opts.showRange ?? false;
        this._marker = opts.marker ?? 'block';
    }

    setData(data: number[]): void {
        this._data = data;
        this.markDirty();
    }

    pushValue(value: number): void {
        this._data.push(value);
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const labelStr = this._label + ' ';
        const labelWidth = labelStr.length;

        // Render label
        screen.writeString(x, y, labelStr, { ...attrs, bold: true });

        // Available sparkline width
        const sparkWidth = width - labelWidth;
        if (sparkWidth <= 0 || this._data.length === 0) return;

        // Take the most recent data points that fit
        const data = this._data.slice(-sparkWidth);

        // Normalize data to 0–7 range
        const min = Math.min(...data);
        const max = Math.max(...data);
        const range = max - min || 1;

        if (caps.unicode && this._marker === 'braille') {
    const canvas = new BrailleCanvas({
        width: sparkWidth * 2,
        height: 4,
        color: this._color,
    });

    for (let i = 0; i < data.length; i++) {
        const normalized = (data[i] - min) / range;

        const barHeight = Math.max(
            1,
            Math.ceil(normalized * 4),
        );

        for (let py = 0; py < barHeight; py++) {
            canvas.drawPixel(
                i * 2,
                3 - py,
            );

            canvas.drawPixel(
                i * 2 + 1,
                3 - py,
            );
        }
    }

    canvas.updateRect({
        x: x + labelWidth,
        y,
        width: sparkWidth,
        height: 1,
    });

    canvas.render(screen);

    return;
}

        const sparkChars = caps.unicode ? SPARK_CHARS_UNICODE : SPARK_CHARS_ASCII;
        for (let i = 0; i < data.length; i++) {
            const normalized = (data[i] - min) / range;
            const charIdx = Math.min(7, Math.round(normalized * 7));
            screen.setCell(x + labelWidth + i, y, {
                char: sparkChars[charIdx],
                fg: this._color,
            });
        }

        // Optional range labels on second line
        if (this._showRange && height > 1) {
            const rangeStr = `${min.toFixed(0)}–${max.toFixed(0)}`;
            screen.writeString(x + labelWidth, y + 1, rangeStr, {
                ...attrs,
                dim: true,
            });
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — CandlestickChart widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, styleToCellAttrs, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface Candle {
    open: number;
    high: number;
    low: number;
    close: number;
}

export interface CandlestickChartOptions {
    /** Color for bullish (close > open) candles */
    upColor?: Color;
    /** Color for bearish (close < open) candles */
    downColor?: Color;
    /** Color for the wick (high/low lines) */
    wickColor?: Color;
}

const DEFAULT_UP_COLOR: Color = { type: 'named', name: 'green' };
const DEFAULT_DOWN_COLOR: Color = { type: 'named', name: 'red' };

/**
 * CandlestickChart — renders OHLC candle data as a terminal chart.
 *
 * Each candle occupies one column. The body shows open/close range,
 * wicks extend to high/low. Bullish candles use upColor, bearish use downColor.
 */
export class CandlestickChart extends Widget {
    private _candles: Candle[] = [];
    private _upColor: Color;
    private _downColor: Color;
    private _wickColor: Color | undefined;

    constructor(style?: Partial<Style>, opts?: CandlestickChartOptions) {
        super(style);
        this._upColor = opts?.upColor ?? DEFAULT_UP_COLOR;
        this._downColor = opts?.downColor ?? DEFAULT_DOWN_COLOR;
        this._wickColor = opts?.wickColor;
    }

    setData(candles: Candle[]): void {
        this._candles = candles;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        if (this._candles.length === 0) return;

        const rect = this._getContentRect();
        const { x: startX, y: startY, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        const candleCount = Math.min(this._candles.length, width);
        const visibleCandles = this._candles.slice(0, candleCount);

        let maxHigh = 0;
        let minLow = 0;
        if (visibleCandles.length > 0) {
            maxHigh = Math.max(...visibleCandles.map(c => c.high));
            minLow = Math.min(...visibleCandles.map(c => c.low));
        }

        const priceRange = maxHigh - minLow || 1;

        for (let i = 0; i < candleCount; i++) {
            const candle = this._candles[i];
            const colX = startX + i;

            const mapY = (val: number): number => {
                const ratio = (val - minLow) / priceRange;
                return Math.round(startY + height - 1 - ratio * (height - 1));
            };

            const highY = mapY(candle.high);
            const lowY = mapY(candle.low);
            const openY = mapY(candle.open);
            const closeY = mapY(candle.close);

            const bodyTop = Math.min(openY, closeY);
            const bodyBottom = Math.max(openY, closeY);

            const isBullish = candle.close > candle.open;
            const bodyColor = isBullish ? this._upColor : this._downColor;
            const wickColor = this._wickColor ?? bodyColor;

            const wickChar = '|';
            const bodyChar = caps.unicode ? '┃' : '=';

            for (let rowY = Math.min(highY, lowY); rowY <= Math.max(highY, lowY); rowY++) {
                if (rowY >= bodyTop && rowY <= bodyBottom) {
                    screen.setCell(colX, rowY, { char: bodyChar, ...attrs, fg: bodyColor });
                } else {
                    screen.setCell(colX, rowY, { char: wickChar, ...attrs, fg: wickColor });
                }
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — LineChart widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, styleToCellAttrs, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface LineChartOptions {
    /** Color of the plotted points/lines */
    color?: Color;
    /** Show Y-axis labels */
    showYAxis?: boolean;
    /** Show X-axis labels */
    showXAxis?: boolean;
    /** Label for the Y axis */
    yLabel?: string;
    /** Maximum Y value (auto if not set) */
    max?: number;
    /** Minimum Y value (auto if not set) */
    min?: number;
}

// Unicode point character; ASCII fallback
const POINT_CHAR_UNICODE = '●';
const POINT_CHAR_ASCII = '*';

/**
 * LineChart — ASCII/Unicode line plot for a series of numbers.
 *
 * Normalizes data to the available height, samples to fit width.
 * Plots points with simple vertical bar connectors between adjacent points.
 */
export class LineChart extends Widget {
    private _data: number[];
    private _color: Color;
    private _showYAxis: boolean;
    private _showXAxis: boolean;
    private _yLabel: string;
    private _max?: number;
    private _min?: number;

    constructor(data: number[], style: Partial<Style> = {}, opts: LineChartOptions = {}) {
        super(style);
        this._data = data;
        this._color = opts.color ?? { type: 'named', name: 'cyan' };
        this._showYAxis = opts.showYAxis ?? false;
        this._showXAxis = opts.showXAxis ?? false;
        this._yLabel = opts.yLabel ?? '';
        this._max = opts.max;
        this._min = opts.min;
    }

    setData(data: number[]): void {
        this._data = data;
        this.markDirty();
    }

    pushValue(value: number): void {
        this._data.push(value);
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        let { x, y, width, height } = rect;
        if (width <= 0 || height <= 0 || this._data.length === 0) return;

        const attrs = styleToCellAttrs(this._style);

        // Reserve rows for X axis
        const plotHeight = this._showXAxis ? Math.max(1, height - 1) : height;
        // Reserve cols for Y axis
        const yAxisWidth = this._showYAxis ? 5 : 0;
        const plotWidth = Math.max(1, width - yAxisWidth);
        const plotX = x + yAxisWidth;

        // Compute range
        const min = this._min ?? Math.min(...this._data);
        const max = this._max ?? Math.max(...this._data);
        const range = max - min || 1;

        // Sample data to fit plotWidth
        const samples: number[] = [];
        for (let col = 0; col < plotWidth; col++) {
            const idx = Math.floor((col / plotWidth) * this._data.length);
            const val = this._data[Math.min(idx, this._data.length - 1)];
            samples.push(val ?? min);
        }

        // Map value to row (row 0 = top = max)
        const toRow = (v: number): number => {
            const norm = (v - min) / range;
            return Math.max(0, Math.min(plotHeight - 1, Math.round((1 - norm) * (plotHeight - 1))));
        };

        // Render Y axis
        if (this._showYAxis && yAxisWidth > 0) {
            for (let row = 0; row < plotHeight; row++) {
                const v = plotHeight > 1 ? max - (row / (plotHeight - 1)) * range : max;
                if (row === 0 || row === plotHeight - 1) {
                    const label = v.toFixed(0).padStart(yAxisWidth - 1, ' ');
                    screen.writeString(x, y + row, label + '┤', { ...attrs, dim: true });
                } else {
                    screen.writeString(x + yAxisWidth - 1, y + row, '│', { ...attrs, dim: true });
                }
            }
        }

        // Render points and connectors
        const pointChar = caps.unicode ? POINT_CHAR_UNICODE : POINT_CHAR_ASCII;

        let prevRow: number | null = null;
        for (let col = 0; col < samples.length; col++) {
            const val = samples[col];
            if (val === undefined) continue;
            const row = toRow(val);

            // Draw vertical connector from prev point to current
            if (prevRow !== null && Math.abs(row - prevRow) > 1) {
                const top = Math.min(prevRow, row) + 1;
                const bottom = Math.max(prevRow, row);
                for (let r = top; r < bottom; r++) {
                    screen.setCell(plotX + col, y + r, { char: '│', fg: this._color, dim: true });
                }
            }

            // Draw point
            screen.setCell(plotX + col, y + row, { char: pointChar, fg: this._color });

            prevRow = row;
        }

        // X axis
        if (this._showXAxis) {
            const axisY = y + height - 1;
            for (let col = 0; col < plotWidth; col++) {
                screen.setCell(plotX + col, axisY, { char: '─', ...attrs, dim: true });
            }
            if (yAxisWidth > 0) {
                screen.setCell(plotX - 1, axisY, { char: '└', ...attrs, dim: true });
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — AreaChart widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, styleToCellAttrs, caps, stringWidth, BRAILLE_DOTS, BRAILLE_OFFSET } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface AreaChartOptions {
    xLabel?: string;
    yLabel?: string;
    lineColor?: Color;
    fillColor?: Color;
    showLine?: boolean;
}

type CanvasLayer = 'fill' | 'line';

interface BrailleCell {
    fillBits: number;
    lineBits: number;
}

class BrailleCanvas {
    private _cellWidth: number;
    private _cellHeight: number;
    private _cells: BrailleCell[];

    constructor(width: number, height: number) {
        this._cellWidth = Math.max(1, Math.ceil(width / 2));
        this._cellHeight = Math.max(1, Math.ceil(height / 4));
        this._cells = Array.from({ length: this._cellWidth * this._cellHeight }, () => ({
            fillBits: 0,
            lineBits: 0,
        }));
    }

    drawPixel(x: number, y: number, layer: CanvasLayer = 'fill'): void {
        if (x < 0 || y < 0) return;

        const cellX = Math.floor(x / 2);
        const cellY = Math.floor(y / 4);
        if (cellX < 0 || cellY < 0 || cellX >= this._cellWidth || cellY >= this._cellHeight) return;

        const dotRow = y % 4;
        const dotCol = x % 2;
        const dotBits = BRAILLE_DOTS[dotRow];
        if (!dotBits) return;

        const bit = dotCol === 0 ? dotBits[0] : dotBits[1];
        const cell = this._cells[cellY * this._cellWidth + cellX];
        if (!cell) return;

        if (layer === 'line') {
            cell.lineBits |= bit;
        } else {
            cell.fillBits |= bit;
        }
    }

    drawLine(x0: number, y0: number, x1: number, y1: number, layer: CanvasLayer = 'line'): void {
        let cx = x0;
        let cy = y0;
        const dx = Math.abs(x1 - x0);
        const dy = Math.abs(y1 - y0);
        const sx = x0 < x1 ? 1 : -1;
        const sy = y0 < y1 ? 1 : -1;
        let err = dx - dy;

        while (true) {
            this.drawPixel(cx, cy, layer);
            if (cx === x1 && cy === y1) break;

            const e2 = err * 2;
            if (e2 > -dy) {
                err -= dy;
                cx += sx;
            }
            if (e2 < dx) {
                err += dx;
                cy += sy;
            }
        }
    }

    render(
        screen: Screen,
        x: number,
        y: number,
        fillColor: Color,
        lineColor: Color,
        attrs: ReturnType<typeof styleToCellAttrs>,
        asciiFallback: boolean,
    ): void {
        for (let cy = 0; cy < this._cellHeight; cy++) {
            for (let cx = 0; cx < this._cellWidth; cx++) {
                const cell = this._cells[cy * this._cellWidth + cx];
                if (!cell) continue;

                const unionBits = cell.fillBits | cell.lineBits;
                if (unionBits === 0) continue;

                const char = asciiFallback
                    ? '#'
                    : String.fromCharCode(BRAILLE_OFFSET + unionBits);

                const fg = cell.lineBits !== 0 ? lineColor : fillColor;
                screen.setCell(x + cx, y + cy, { char, ...attrs, fg });
            }
        }
    }
}

export class AreaChart extends Widget {
    private _data: number[] = [];
    private _xLabel: string;
    private _yLabel: string;
    private _lineColor: Color;
    private _fillColor: Color;
    private _showLine: boolean;

    constructor(style: Partial<Style> = {}, opts: AreaChartOptions = {}) {
        super(style);
        this._xLabel = opts.xLabel ?? '';
        this._yLabel = opts.yLabel ?? '';
        this._lineColor = opts.lineColor ?? { type: 'named', name: 'cyan' };
        this._fillColor = opts.fillColor ?? { type: 'named', name: 'brightBlack' };
        this._showLine = opts.showLine ?? true;
    }

    setData(values: number[]): void {
        this._data = values;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;

        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const topLabelRows = this._yLabel ? 1 : 0;
        const bottomLabelRows = this._xLabel ? 1 : 0;
        const plotY = y + topLabelRows;
        const plotHeight = height - topLabelRows - bottomLabelRows;

        if (this._yLabel) {
            screen.writeString(x, y, this._yLabel.slice(0, width), attrs);
        }

        if (this._xLabel) {
            const labelWidth = stringWidth(this._xLabel);
            const labelX = x + Math.max(0, width - labelWidth);
            screen.writeString(labelX, y + height - 1, this._xLabel.slice(0, width), attrs);
        }

        if (plotHeight <= 0 || this._data.length === 0) return;

        const min = Math.min(...this._data);
        const max = Math.max(...this._data);
        const range = max - min || 1;

        const pixelWidth = width * 2;
        const pixelHeight = plotHeight * 4;
        const fillCanvas = new BrailleCanvas(pixelWidth, pixelHeight);
        const lineCanvas = new BrailleCanvas(pixelWidth, pixelHeight);

        const sampleValueAt = (pixelX: number): number => {
            if (this._data.length === 1) return this._data[0] ?? min;

            const position = (pixelX / Math.max(1, pixelWidth - 1)) * (this._data.length - 1);
            const leftIndex = Math.floor(position);
            const rightIndex = Math.min(this._data.length - 1, leftIndex + 1);
            const t = position - leftIndex;
            const left = this._data[leftIndex] ?? min;
            const right = this._data[rightIndex] ?? left;
            return left + (right - left) * t;
        };

        let previousX: number | null = null;
        let previousY: number | null = null;

        for (let pixelX = 0; pixelX < pixelWidth; pixelX++) {
            const value = sampleValueAt(pixelX);
            const normalized = (value - min) / range;
            const lineY = Math.max(0, Math.min(pixelHeight - 1, Math.round((1 - normalized) * (pixelHeight - 1))));

            for (let pixelY = lineY; pixelY < pixelHeight; pixelY++) {
                fillCanvas.drawPixel(pixelX, pixelY, 'fill');
            }

            if (this._showLine) {
                if (previousX !== null && previousY !== null) {
                    lineCanvas.drawLine(previousX, previousY, pixelX, lineY, 'line');
                } else {
                    lineCanvas.drawPixel(pixelX, lineY, 'line');
                }
            }

            previousX = pixelX;
            previousY = lineY;
        }

        fillCanvas.render(screen, x, plotY, this._fillColor, this._lineColor, attrs, !caps.unicode);
        if (this._showLine) {
            lineCanvas.render(screen, x, plotY, this._fillColor, this._lineColor, attrs, !caps.unicode);
        }
    }
}

// packages/widgets/src/data/TableState.ts
import { TableRow } from '@termuijs/widgets';

/** External state object for Table widget. */
export interface TableState {
  /** Rows displayed by the table */
  rows: TableRow[];
  /** Scroll offset (first visible row index) */
  scrollOffset: number;
  /** Update rows */
  setRows(rows: TableRow[]): void;
  /** Scroll up */
  scrollPrev(): void;
  /** Scroll down */
  scrollNext(): void;
}

/** Hook that creates a fresh TableState. */
export function useTableState(initial: { rows: TableRow[] }): TableState {
  const state: TableState = {
    rows: initial.rows,
    scrollOffset: 0,
    setRows(rows: TableRow[]) {
      state.rows = rows;
      if (state.scrollOffset >= rows.length) {
        state.scrollOffset = Math.max(0, rows.length - 1);
      }
    },
    scrollPrev() {
      if (state.scrollOffset > 0) {
        state.scrollOffset--;
      }
    },
    scrollNext() {
      state.scrollOffset++;
    },
  };
  return state;
}

import { type Color, type Screen, type Style, caps, truncate } from "@termuijs/core";
import { Widget } from "@termuijs/widgets";
import { BrailleCanvas } from "@termuijs/widgets";

export interface StackedSeries {
    label: string;
    data: number[];
    color?: Color;
}

export interface StackedBarChartOptions {
    categories?: string[];
    barWidth?: number;
}

export class StackedBarChart extends Widget {
    private _series: StackedSeries[] = [];
    private _categories: string[];
    private _barWidth: number;

    constructor(style: Partial<Style> = {}, opts: StackedBarChartOptions = {}) {
        super(style);
        this._categories = opts.categories ?? [];
        this._barWidth = opts.barWidth ?? 2;
    }

    setSeries(series: StackedSeries[]): void {
        this._series = series;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._getContentRect();

        if (width <= 0 || height <= 0 || this._series.length === 0) {
            return;
        }

        if (!caps.unicode) {
            this._renderAscii(screen, x, y, width, height);
            return;
        }

        this._renderBraille(screen, x, y, width, height);
    }

    private _categoryCount(): number {
        return Math.max(
            this._categories.length,
            ...this._series.map((series) => series.data.length),
        );
    }

    private _totals(categoryCount: number): number[] {
        return Array.from({ length: categoryCount }, (_, index) =>
            this._series.reduce(
                (sum, series) => sum + Math.max(0, series.data[index] ?? 0),
                0,
            ),
        );
    }

    private _renderBraille(
        screen: Screen,
        x: number,
        y: number,
        width: number,
        height: number,
    ): void {
        const categoryCount = this._categoryCount();
        if (categoryCount === 0) return;

        const labelRows = this._categories.length > 0 ? 1 : 0;
        const chartHeight = height - labelRows;
        if (chartHeight <= 0) return;

        const totals = this._totals(categoryCount);
        const maxTotal = Math.max(...totals);
        if (maxTotal <= 0) return;

        const pixelWidth = width * 2;
        const pixelHeight = chartHeight * 4;
        const gap = 1;
        const barWidth = Math.max(1, this._barWidth);
        const step = barWidth + gap;

        this._series.forEach((series, seriesIndex) => {
            const canvas = new BrailleCanvas(
                {
                    width: pixelWidth,
                    height: pixelHeight,
                    color: series.color,
                },
                {},
            );

            for (
                let categoryIndex = 0;
                categoryIndex < categoryCount;
                categoryIndex++
            ) {
                const stackBase = this._series
                    .slice(0, seriesIndex)
                    .reduce(
                        (sum, item) =>
                            sum + Math.max(0, item.data[categoryIndex] ?? 0),
                        0,
                    );

                const value = Math.max(0, series.data[categoryIndex] ?? 0);
                const start = Math.round((stackBase / maxTotal) * pixelHeight);
                const end = Math.round(
                    ((stackBase + value) / maxTotal) * pixelHeight,
                );
                const startX = categoryIndex * step;

                for (
                    let px = startX;
                    px < startX + barWidth && px < pixelWidth;
                    px++
                ) {
                    for (let py = start; py < end; py++) {
                        canvas.drawPixel(px, pixelHeight - 1 - py);
                    }
                }
            }

            canvas.updateRect({ x, y, width, height: chartHeight });
            canvas.render(screen);
        });

        this._renderLabels(screen, x, y + chartHeight, width);
    }

    private _renderAscii(
        screen: Screen,
        x: number,
        y: number,
        width: number,
        height: number,
    ): void {
        const categoryCount = this._categoryCount();
        if (categoryCount === 0) return;

        const labelRows = this._categories.length > 0 ? 1 : 0;
        const chartHeight = height - labelRows;
        if (chartHeight <= 0) return;

        const totals = this._totals(categoryCount);
        const maxTotal = Math.max(...totals);
        if (maxTotal <= 0) return;

        const gap = 1;
        const barWidth = Math.max(1, this._barWidth);
        const step = barWidth + gap;

        for (
            let categoryIndex = 0;
            categoryIndex < categoryCount;
            categoryIndex++
        ) {
            let stackBase = 0;

            for (const series of this._series) {
                const value = Math.max(0, series.data[categoryIndex] ?? 0);
                const start = Math.round((stackBase / maxTotal) * chartHeight);
                const end = Math.round(
                    ((stackBase + value) / maxTotal) * chartHeight,
                );
                const startX = x + categoryIndex * step;

                for (let col = 0; col < barWidth; col++) {
                    const cellX = startX + col;
                    if (cellX >= x + width) continue;

                    for (let row = start; row < end; row++) {
                        const cellY = y + chartHeight - 1 - row;
                        screen.setCell(cellX, cellY, {
                            char: "|",
                            fg: series.color,
                        });
                    }
                }

                stackBase += value;
            }
        }

        this._renderLabels(screen, x, y + chartHeight, width);
    }

    private _renderLabels(
        screen: Screen,
        x: number,
        y: number,
        width: number,
    ): void {
        if (this._categories.length === 0) return;

        const gap = 1;
        const barWidth = Math.max(1, this._barWidth);
        const step = barWidth + gap;

        this._categories.forEach((category, index) => {
            const labelX = x + index * step;
            if (labelX >= x + width) return;

            screen.writeString(labelX, y, truncate(category, barWidth), {});
        });
    }
}

import { type Screen, type Style, type Color, caps, truncate } from "@termuijs/core";
import { Widget } from "@termuijs/widgets";

export interface HistogramOptions {
    bins?: number;
    barColor?: Color;
    xLabel?: string;
}

export class Histogram extends Widget {
    private _values: number[] = [];
    private _bins: number;
    private _barColor: Color;
    private _xLabel?: string;

    constructor(style: Partial<Style> = {}, opts: HistogramOptions = {}) {
        super(style);

        this._bins = opts.bins ?? 10;
        this._barColor = opts.barColor ?? { type: "named", name: "cyan" };
        this._xLabel = opts.xLabel;
    }

    setData(values: number[]): void {
        this._values = values;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;

        if (width <= 0 || height <= 0 || this._values.length === 0) {
            return;
        }

        const counts = this._computeBins();
        const maxCount = Math.max(...counts);

        if (maxCount === 0) {
            return;
        }

        const labelRows = this._xLabel ? 1 : 0;
        const barAreaHeight = height - labelRows;

        if (barAreaHeight <= 0) {
            return;
        }

        const barWidth = Math.max(1, Math.floor(width / counts.length));

        for (let i = 0; i < counts.length; i++) {
            const count = counts[i];

            if (count === undefined) {
                continue;
            }

            const scaledHeight = Math.round((count / maxCount) * barAreaHeight);

            for (let row = 0; row < scaledHeight; row++) {
                for (let col = 0; col < barWidth; col++) {
                    const cellX = x + i * barWidth + col;

                    if (cellX >= x + width) {
                        continue;
                    }

                    screen.setCell(cellX, y + barAreaHeight - 1 - row, {
                        char: caps.unicode ? "█" : "|",
                        fg: this._barColor,
                    });
                }
            }
        }

        if (this._xLabel) {
            screen.writeString(
                x,
                y + height - 1,
                truncate(this._xLabel, width),
                {},
            );
        }
    }

    private _computeBins(): number[] {
        const counts = Array(this._bins).fill(0);

        if (this._values.length === 0) {
            return counts;
        }

        const min = Math.min(...this._values);
        const max = Math.max(...this._values);

        if (min === max) {
            counts[0] = this._values.length;
            return counts;
        }

        const bucketSize = (max - min) / this._bins;

        for (const value of this._values) {
            let index = Math.floor((value - min) / bucketSize);

            if (index >= this._bins) {
                index = this._bins - 1;
            }

            counts[index]++;
        }

        return counts;
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Meter widget (label + bar + value with thresholds)
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, styleToCellAttrs, stringWidth, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface MeterOptions {
    /** Value below this fraction renders the low color. Default: 0.25 */
    low?: number;
    /** Value at or above this fraction renders the high color. Default: 0.75 */
    high?: number;
    /** Show the percentage label. Default: true */
    showLabel?: boolean;
}

/**
 * Meter — a self-contained metric display with label, bar, and value with low/optimum/high thresholds.
 *
 * Example:
 *   Disk ████████░░░░ 65%
 *
 * Color logic:
 *   - value < low threshold → low color (red)
 *   - value >= high threshold → high color (yellow)
 *   - value between → optimum color (green)
 */
export class Meter extends Widget {
    private _label: string;
    private _value: number = 0;
    private _low: number;
    private _high: number;
    private _showLabel: boolean;

    constructor(label: string, style: Partial<Style> = {}, opts: MeterOptions = {}) {
        super(style);
        this._label = label;
        this._low = opts.low ?? 0.25;
        this._high = opts.high ?? 0.75;
        this._showLabel = opts.showLabel ?? true;
    }

    setValue(value: number): void {
        this._value = Math.max(0, Math.min(1, value));
        this.markDirty();
    }

    getValue(): number {
        return this._value;
    }

    setLabel(label: string): void {
        this._label = label;
        this.markDirty();
    }

    private _getBarColor(): Color {
        if (this._value < this._low) {
            return { type: 'named', name: 'red' };
        } else if (this._value >= this._high) {
            return { type: 'named', name: 'yellow' };
        } else {
            return { type: 'named', name: 'green' };
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const barColor = this._getBarColor();

        // Layout: "Label ████████░░░░ XX%"
        const labelStr = this._label + ' ';
        const percentStr = this._showLabel ? ` ${Math.round(this._value * 100)}%` : '';
        const labelWidth = stringWidth(labelStr);
        const percentWidth = stringWidth(percentStr);
        const barWidth = Math.max(0, width - labelWidth - percentWidth);

        // Render label
        screen.writeString(x, y, labelStr, { ...attrs, bold: true });

        // Render bar
        const filled = Math.round(barWidth * this._value);
        const barX = x + labelWidth;
        for (let i = 0; i < barWidth; i++) {
            const char = i < filled ? (caps.unicode ? '█' : '#') : (caps.unicode ? '░' : '-');
            screen.setCell(barX + i, y, {
                char,
                fg: i < filled ? barColor : { type: 'named', name: 'brightBlack' },
            });
        }

        // Render percentage
        if (this._showLabel) {
            screen.writeString(barX + barWidth, y, percentStr, {
                ...attrs,
                bold: true,
            });
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — PieChart widget
//
// Renders proportional slices using block characters
// (Unicode) or a horizontal bar chart (ASCII fallback),
// with a legend below.
// ─────────────────────────────────────────────────────

import {
    type Screen,
    type Style,
    type Color,
    styleToCellAttrs,
    caps,
    parseColor,
    truncate,
} from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface PieSlice {
    label: string;
    value: number;
    color: string | Color;
}

export interface PieChartOptions {
    slices?: PieSlice[];
    style?: Partial<Style>;
    showLegend?: boolean;
}

const LEGEND_BULLET_UNICODE = '\u25CF';
const LEGEND_BULLET_ASCII = '*';

export class PieChart extends Widget {
    private _slices: PieSlice[];
    private _showLegend: boolean;

    constructor(options: PieChartOptions = {}) {
        super(options.style);
        this._slices = options.slices ?? [];
        this._showLegend = options.showLegend ?? true;
    }

    get slices(): ReadonlyArray<PieSlice> { return this._slices; }

    setSlices(slices: PieSlice[]): void {
        this._slices = slices;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        if (this._slices.length === 0) return;

        const totalHeight = this._showLegend ? Math.max(0, height - this._slices.length) : height;
        if (totalHeight <= 0) {
            this._renderLegend(screen, x, y, width);
            return;
        }

        if (caps.unicode) {
            this._renderPie(screen, x, y, width, totalHeight);
        } else {
            this._renderBars(screen, x, y, width, totalHeight);
        }

        if (this._showLegend) {
            this._renderLegend(screen, x, y + totalHeight, width);
        }
    }

    // ── Unicode pie ──────────────────────────────────

    private _renderPie(screen: Screen, ox: number, oy: number, width: number, height: number): void {
        const total = this._total();
        if (total <= 0) return;

        const cx = (width - 1) / 2;
        const cy = (height - 1) / 2;
        // Each cell is ~2x taller than wide; scale vertical to match.
        const radius = Math.min(cx, cy * 2);

        for (let row = 0; row < height; row++) {
            for (let col = 0; col < width; col++) {
                const dx = col - cx;
                const dy = (row - cy) * 2;
                const r = Math.sqrt(dx * dx + dy * dy);
                if (r > radius) continue;

                const slice = this._findSliceAt(dx, dy, total);
                if (!slice) continue;
                screen.setCell(ox + col, oy + row, { char: '\u2588', fg: this._colorOf(slice) });
            }
        }
    }

    private _findSliceAt(dx: number, dy: number, total: number): PieSlice | null {
        // 0 rad = up, clockwise
        const angle = Math.atan2(dx, -dy);
        const normalized = (angle + Math.PI * 2) % (Math.PI * 2);
        let cumulative = 0;
        for (const slice of this._slices) {
            if (slice.value <= 0) continue;
            const sliceAngle = (slice.value / total) * Math.PI * 2;
            if (normalized < cumulative + sliceAngle) return slice;
            cumulative += sliceAngle;
        }
        return this._slices[this._slices.length - 1] ?? null;
    }

    // ── ASCII bar fallback ──────────────────────────

    private _renderBars(screen: Screen, ox: number, oy: number, width: number, height: number): void {
        const total = this._total();
        if (total <= 0) return;
        const maxValue = Math.max(...this._slices.map(s => s.value));
        if (maxValue <= 0) return;

        const usable = Math.max(1, width - 8);
        for (let i = 0; i < this._slices.length && i < height; i++) {
            const slice = this._slices[i];
            if (!slice) continue;
            const barLen = Math.round((slice.value / maxValue) * usable);
            const pct = Math.round((slice.value / total) * 100);
            const line = '#'.repeat(barLen).padEnd(usable) + ` ${String(pct).padStart(3)}%`;
            screen.writeString(ox, oy + i, line.slice(0, width), { ...styleToCellAttrs(this._style), fg: this._colorOf(slice) });
        }
    }

    // ── Legend ───────────────────────────────────────

    private _renderLegend(screen: Screen, ox: number, oy: number, width: number): void {
        const total = this._total();
        const bullet = caps.unicode ? LEGEND_BULLET_UNICODE : LEGEND_BULLET_ASCII;
        const attrs = styleToCellAttrs(this._style);
        for (let i = 0; i < this._slices.length; i++) {
            const slice = this._slices[i];
            if (!slice) continue;
            const pct = total > 0 ? Math.round((slice.value / total) * 100) : 0;
            const text = `${bullet} ${slice.label} ${pct}%`;
            screen.writeString(ox, oy + i, truncate(text, width), { ...attrs, fg: this._colorOf(slice) });
        }
    }

    private _total(): number {
        return this._slices.reduce((s, x) => s + (x.value > 0 ? x.value : 0), 0);
    }

    private _colorOf(slice: PieSlice): Color {
        return typeof slice.color === 'string' ? parseColor(slice.color) : slice.color;
    }
}

import {
  type Screen,
  type Style,
  type Color,
  styleToCellAttrs,
  stringWidth,
  HORIZONTAL_BAR_SYMBOLS,
  caps,
} from "@termuijs/core";
import { Widget } from "@termuijs/widgets";

export interface GanttTask {
  label?: string;
  start: number;
  duration: number;
  color?: Color;
}

export interface GanttChartOptions {
  taskHeight?: number;
  taskGap?: number;
  minTime?: number;
  maxTime?: number;
  barColor?: Color;
  labelColor?: Color;
}

export class GanttChart extends Widget {
  private _tasks: GanttTask[] = [];
  private _taskHeight: number;
  private _taskGap: number;
  private _minTime?: number;
  private _maxTime?: number;
  private _barColor: Color;
  private _labelColor: Color;

  constructor(
    tasks: GanttTask[],
    style: Partial<Style> = {},
    opts: GanttChartOptions = {}
  ) {
    super(style);
    this._tasks = tasks;
    this._taskHeight = opts.taskHeight ?? 1;
    this._taskGap = opts.taskGap ?? 1;
    this._minTime = opts.minTime;
    this._maxTime = opts.maxTime;
    this._barColor = opts.barColor ?? { type: "named", name: "cyan" };
    this._labelColor = opts.labelColor ?? { type: "named", name: "brightBlack" };
  }

  setTasks(tasks: GanttTask[]): void {
    this._tasks = tasks;
    this.markDirty();
  }

  protected _renderSelf(screen: Screen): void {
    const rect = this._getContentRect();
    const { x, y, width, height } = rect;

    if (width <= 0 || height <= 0 || this._tasks.length === 0) return;

    let minT = this._minTime;
    let maxT = this._maxTime;

    // Auto-calculate bounds if missing
    if (minT === undefined || maxT === undefined) {
      let calculatedMin = Infinity;
      let calculatedMax = -Infinity;

      for (const task of this._tasks) {
        if (task.start < calculatedMin) calculatedMin = task.start;
        const end = task.start + task.duration;
        if (end > calculatedMax) calculatedMax = end;
      }

      if (minT === undefined) minT = calculatedMin === Infinity ? 0 : calculatedMin;
      if (maxT === undefined) maxT = calculatedMax === -Infinity ? 100 : calculatedMax;
    }

    const timeSpan = maxT - minT;
    if (timeSpan <= 0) return; // Degenerate span, can't map width

    // Calculate maximum label width
    let maxLabelWidth = 0;
    for (const task of this._tasks) {
      if (task.label) {
        const w = stringWidth(task.label);
        if (w > maxLabelWidth) maxLabelWidth = w;
      }
    }

    const labelColWidth = maxLabelWidth > 0 ? maxLabelWidth + 1 : 0;
    const barAreaWidth = width - labelColWidth;

    if (barAreaWidth <= 0) return; // No space for bars

    let currentY = y;

    for (let i = 0; i < this._tasks.length; i++) {
      const task = this._tasks[i];

      // Prevent rendering past widget height bounds
      if (currentY >= y + height) break;

      for (let row = 0; row < this._taskHeight; row++) {
        const cellY = currentY + row;
        if (cellY >= y + height) break;

        // Render label only on the first row of a task
        if (row === 0 && task.label) {
          // Truncate by column width (not codepoints) to handle multi-byte chars
          let truncated = '';
          let cols = 0;
          for (const ch of task.label) {
            const w = stringWidth(ch);
            if (cols + w > maxLabelWidth) break;
            truncated += ch;
            cols += w;
          }
          // Pad with spaces to fill maxLabelWidth columns
          const padded = truncated + ' '.repeat(maxLabelWidth - stringWidth(truncated));
          screen.writeString(x, cellY, padded, { fg: this._labelColor });
        }

        // Calculate bar geometry using sub-cell precision
        const color = task.color ?? this._barColor;

        // Find start column relative to bar area
        // Clamp it to 0 just in case start < minT
        const startOffsetVal = Math.max(0, task.start - minT);
        const startCols = (startOffsetVal / timeSpan) * barAreaWidth;
        const startColInt = Math.floor(startCols);

        // Find duration width
        const durWidth = (task.duration / timeSpan) * barAreaWidth;

        // Total sub-cells scaled (8 levels per cell)
        let remainingSubCells = Math.round(durWidth * 8);

        const barStartX = x + labelColWidth + startColInt;

        for (let col = 0; col < barAreaWidth - startColInt; col++) {
          if (remainingSubCells <= 0) break;
          const level = Math.min(remainingSubCells, 8);
          let symbol = HORIZONTAL_BAR_SYMBOLS[level] ?? " ";
          if (!caps.unicode && level > 0) {
            symbol = level === 8 ? "=" : "-";
          }
          screen.setCell(barStartX + col, cellY, { char: symbol, fg: color });
          remainingSubCells -= 8;
        }
      }

      currentY += this._taskHeight;
      if (i < this._tasks.length - 1) currentY += this._taskGap;
    }
  }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — StatusIndicator widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, styleToCellAttrs } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface StatusIndicatorOptions {
    /** Color when up/active */
    upColor?: Color;
    /** Color when down/inactive */
    downColor?: Color;
}

/**
 * StatusIndicator — simple up/down indicator with label.
 *
 * Example:
 *   ● API Server — Online
 *   ○ Worker — Offline
 */
export class StatusIndicator extends Widget {
    private _label: string;
    private _isUp: boolean;
    private _upColor: Color;
    private _downColor: Color;

    constructor(label: string, isUp: boolean, style: Partial<Style> = {}, opts: StatusIndicatorOptions = {}) {
        super(style);
        this._label = label;
        this._isUp = isUp;
        this._upColor = opts.upColor ?? { type: 'named', name: 'green' };
        this._downColor = opts.downColor ?? { type: 'named', name: 'red' };
    }

    setStatus(isUp: boolean): void {
        this._isUp = isUp;
        this.markDirty();
    }

    getStatus(): boolean {
        return this._isUp;
    }

    setLabel(label: string): void {
        this._label = label;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const dot = this._isUp ? '●' : '○';
        const statusText = this._isUp ? 'Online' : 'Offline';
        const color = this._isUp ? this._upColor : this._downColor;

        screen.setCell(x, y, { char: dot, fg: color });
        screen.writeString(x + 2, y, `${this._label} — ${statusText}`, {
            ...attrs,
            fg: color,
        });
    }
}

import { Widget } from '@termuijs/widgets';
import { type Style, type Color, Screen, caps } from '@termuijs/core';

export interface ScatterPoint {
    x: number;
    y: number;
    color?: Color;
}

export interface ScatterPlotOptions {
    /** X axis label */
    xLabel?: string;
    /** Y axis label */
    yLabel?: string;
    /** Point marker. Default: '•' with ASCII fallback '.' */
    marker?: string;
    pointColor?: Color;
}

export class ScatterPlot extends Widget {
    private points: ScatterPoint[] = [];
    private options: ScatterPlotOptions;

    constructor(style?: Partial<Style>, opts?: ScatterPlotOptions) {
        super(style);
        this.options = opts || {};
    }

    setData(points: ScatterPoint[]): void {
        this.points = points;
        this.markDirty();
    }

    protected override _renderSelf(screen: Screen): void {
        if (!this.rect) return;

        const { x, y, width, height } = this.rect;
        if (width < 2 || height < 2) return;

        const isUnicode = caps.unicode;
        const vLine = isUnicode ? '│' : '|';
        const hLine = isUnicode ? '─' : '-';
        const corner = isUnicode ? '└' : '+';

        const plotX = x + 1;
        const plotY = y;
        const plotW = width - 1;
        const plotH = height - 1;
        const originY = y + height - 1;

        // Render Y-Axis
        for (let i = plotY; i < originY; i++) {
            screen.writeString(x, i, vLine, { fg: this.options.pointColor });
        }

        // Render X-Axis
        for (let i = plotX; i < x + width; i++) {
            screen.writeString(i, originY, hLine, { fg: this.options.pointColor });
        }

        // Render Origin Corner
        screen.writeString(x, originY, corner, { fg: this.options.pointColor });

        // Render Labels
        if (this.options.yLabel) {
            screen.writeString(x + 1, y, this.options.yLabel);
        }
        if (this.options.xLabel) {
            const xL = this.options.xLabel;
            const startX = Math.max(plotX, x + width - xL.length);
            screen.writeString(startX, originY, xL);
        }

        // Plot Points
        if (this.points.length === 0) return;

        let minX = Infinity, maxX = -Infinity;
        let minY = Infinity, maxY = -Infinity;

        for (const p of this.points) {
            if (p.x < minX) minX = p.x;
            if (p.x > maxX) maxX = p.x;
            if (p.y < minY) minY = p.y;
            if (p.y > maxY) maxY = p.y;
        }

        // Prevent division by zero if all points have the same coordinate
        if (minX === maxX) { minX -= 1; maxX += 1; }
        if (minY === maxY) { minY -= 1; maxY += 1; }

        const marker = this.options.marker ?? (isUnicode ? '•' : '.');

        for (const p of this.points) {
            const normalizedX = (p.x - minX) / (maxX - minX);
            const normalizedY = (p.y - minY) / (maxY - minY);

            const px = Math.floor(plotX + normalizedX * (plotW - 1));
            const py = Math.floor(originY - 1 - normalizedY * (plotH - 1));

            // Ensure points remain inside drawing bounds
            if (px >= plotX && px < x + width && py >= plotY && py < originY) {
                screen.writeString(px, py, marker, { fg: p.color || this.options.pointColor });
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — KeyValue widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, styleToCellAttrs, stringWidth, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface KeyValuePair {
    key: string;
    // any is used because the value can be of completely arbitrary nested object structures or primitive types
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    value: any;
}

export interface KeyValueOptions {
    /** Separator between key and value (default: ': ') */
    separator?: string;
    /** Color for keys */
    keyColor?: import('@termuijs/core').Color;
    /** Color for values */
    valueColor?: import('@termuijs/core').Color;
}

/**
 * KeyValue — aligned key: value pairs.
 *
 * Keys are right-aligned to the width of the longest key.
 * Values follow after the separator.
 */
export class KeyValue extends Widget {
    private _pairs: KeyValuePair[];
    private _separator: string;
    private _keyColor?: import('@termuijs/core').Color;
    private _valueColor?: import('@termuijs/core').Color;

    private _expandedPaths = new Set<string>();
    private _selectedIndex = 0;

    constructor(
        // any is used because pairs can be objects with unknown/arbitrary arbitrary depth properties
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        pairs: Array<KeyValuePair> | Record<string, any>,
        style: Partial<Style> = {},
        opts: KeyValueOptions = {},
    ) {
        super(style);
        this._pairs = Array.isArray(pairs)
            ? pairs
            : Object.entries(pairs).map(([key, value]) => ({ key, value }));
        this._separator = opts.separator ?? ': ';
        this._keyColor = opts.keyColor;
        this._valueColor = opts.valueColor;

        this._updateFocusable();
    }

    // any is used because pairs can be objects with unknown/arbitrary arbitrary depth properties
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    setPairs(pairs: Array<KeyValuePair> | Record<string, any>): void {
        this._pairs = Array.isArray(pairs)
            ? pairs
            : Object.entries(pairs).map(([key, value]) => ({ key, value }));
        this._updateFocusable();
        this.markDirty();
    }

    private _updateFocusable() {
        this.focusable = this._pairs.some(p => typeof p.value === 'object' && p.value !== null && !Array.isArray(p.value));
    }

    private _getVisibleRows() {
        const rows: { id: string; displayKey: string; valStr: string; isObj: boolean }[] = [];

        const traverse = (items: KeyValuePair[], depth: number, basePath: string) => {
            for (const item of items) {
                const isObj = typeof item.value === 'object' && item.value !== null && !Array.isArray(item.value);
                const id = basePath ? `${basePath}.${item.key}` : item.key;

                let prefix = '';
                if (isObj) {
                    prefix = this._expandedPaths.has(id) ? (caps.unicode ? '▼ ' : 'v ') : (caps.unicode ? '▶ ' : '> ');
                }

                const indent = '  '.repeat(depth);
                const displayKey = indent + prefix + item.key;

                let valStr = String(item.value);
                if (isObj) {
                    valStr = `[${Object.keys(item.value).length} keys]`;
                }

                rows.push({ id, displayKey, valStr, isObj });

                if (isObj && this._expandedPaths.has(id)) {
                    const children = Object.entries(item.value).map(([k, v]) => ({ key: k, value: v }));
                    traverse(children, depth + 1, id);
                }
            }
        };

        traverse(this._pairs, 0, '');
        return rows;
    }

    moveUp(): void {
        this._selectedIndex = Math.max(0, this._selectedIndex - 1);
        this.markDirty();
    }

    moveDown(): void {
        const rows = this._getVisibleRows();
        this._selectedIndex = Math.min(rows.length - 1, this._selectedIndex + 1);
        this.markDirty();
    }

    toggleSelected(): void {
        const rows = this._getVisibleRows();
        const row = rows[this._selectedIndex];
        if (row && row.isObj) {
            if (this._expandedPaths.has(row.id)) {
                this._expandedPaths.delete(row.id);
            } else {
                this._expandedPaths.add(row.id);
            }
            this.markDirty();
        }
    }

    handleKey(key: string): void {
        const lowerKey = key.toLowerCase();
        if (lowerKey === 'up' || lowerKey === 'k') {
            this.moveUp();
        } else if (lowerKey === 'down' || lowerKey === 'j') {
            this.moveDown();
        } else if (lowerKey === 'enter' || lowerKey === ' ' || lowerKey === 'space') {
            this.toggleSelected();
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0 || this._pairs.length === 0) return;

        const rows = this._getVisibleRows();
        if (rows.length === 0) return;

        // Keep selection in bounds
        if (this._selectedIndex >= rows.length) {
            this._selectedIndex = Math.max(0, rows.length - 1);
        }

        const attrs = styleToCellAttrs(this._style);

        // Find max key width for alignment
        let maxKeyWidth = 0;
        for (const row of rows) {
            const w = stringWidth(row.displayKey);
            if (w > maxKeyWidth) maxKeyWidth = w;
        }

        const sepWidth = stringWidth(this._separator);

        // Calculate scroll offset to keep selected row in view
        let startIdx = 0;
        if (this._selectedIndex >= height) {
            startIdx = this._selectedIndex - height + 1;
        }

        for (let i = 0; i < height; i++) {
            const rowIdx = startIdx + i;
            const row = rows[rowIdx];
            if (!row) continue;

            const isSelected = this.isFocused && rowIdx === this._selectedIndex;

            const keyWidth = stringWidth(row.displayKey);
            const keyX = x + (maxKeyWidth - keyWidth); // right-align key
            const sepX = x + maxKeyWidth;
            const valX = sepX + sepWidth;
            const valWidth = Math.max(0, width - maxKeyWidth - sepWidth);

            // Highlight using dim/bold styles to keep minimalism without causing weird blockiness
            const displayFg = isSelected ? { type: 'named' as const, name: 'cyan' as const } : undefined;

            // Key
            screen.writeString(keyX, y + i, row.displayKey, {
                ...attrs,
                fg: displayFg ?? this._keyColor ?? attrs.fg,
                bold: isSelected || true,
            });

            // Separator
            screen.writeString(sepX, y + i, this._separator, { 
                ...attrs, 
                dim: true,
                fg: displayFg ?? attrs.fg
            });

            // Value
            if (valWidth > 0) {
                screen.writeString(valX, y + i, row.valStr.slice(0, valWidth), {
                    ...attrs,
                    fg: displayFg ?? this._valueColor ?? attrs.fg,
                    dim: row.isObj && !isSelected
                });
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Gauge widget (label + bar + value)
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, styleToCellAttrs, stringWidth, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface GaugeOptions {
    /** Color of the filled portion */
    color?: Color;
    /** Show percentage label */
    showLabel?: boolean;
}

/**
 * Gauge — a self-contained metric display with label, bar, and value.
 *
 * Example:
 *   CPU ████████░░░░ 65%
 */
export class Gauge extends Widget {
    private _label: string;
    private _value: number = 0;
    private _color: Color;
    private _showLabel: boolean;

    constructor(label: string, style: Partial<Style> = {}, opts: GaugeOptions = {}) {
        super(style);
        this._label = label;
        this._color = opts.color ?? { type: 'named', name: 'green' };
        this._showLabel = opts.showLabel ?? true;
    }

    setValue(value: number): void {
        this._value = Math.max(0, Math.min(1, value));
        this.markDirty();
    }

    getValue(): number {
        return this._value;
    }

    setLabel(label: string): void {
        this._label = label;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        // Layout: "Label ████████░░░░ XX%"
        const labelStr = this._label + ' ';
        const percentStr = this._showLabel ? ` ${Math.round(this._value * 100)}%` : '';
        const labelWidth = stringWidth(labelStr);
        const percentWidth = stringWidth(percentStr);
        const barWidth = Math.max(0, width - labelWidth - percentWidth);

        // Render label
        screen.writeString(x, y, labelStr, { ...attrs, bold: true });

        // Render bar
        const filled = Math.round(barWidth * this._value);
        const barX = x + labelWidth;
        for (let i = 0; i < barWidth; i++) {
            const char = i < filled ? (caps.unicode ? '█' : '#') : (caps.unicode ? '░' : '-');
            screen.setCell(barX + i, y, {
                char,
                fg: i < filled ? this._color : { type: 'named', name: 'brightBlack' },
            });
        }

        // Render percentage
        if (this._showLabel) {
            screen.writeString(barX + barWidth, y, percentStr, {
                ...attrs,
                bold: true,
            });
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — HeatMap widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, type Color, styleToCellAttrs, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface HeatMapOptions {
    /** Color for maximum value cells */
    highColor?: Color;
    /** Color for minimum value cells */
    lowColor?: Color;
    /** Row labels (left side) */
    rowLabels?: string[];
    /** Column labels (top) */
    colLabels?: string[];
}

// Shading characters from sparse to dense
const SHADE_CHARS_UNICODE = ['░', '▒', '▓', '█'];
const SHADE_CHARS_ASCII   = ['.', ':', '+', '#'];

/**
 * HeatMap — 2D matrix displayed with character-density shading.
 *
 * Values are normalized 0–1 and mapped to 4 shading levels.
 */
export class HeatMap extends Widget {
    private _matrix: number[][];
    private _highColor: Color;
    private _lowColor: Color;
    private _rowLabels: string[];
    private _colLabels: string[];

    constructor(matrix: number[][], style: Partial<Style> = {}, opts: HeatMapOptions = {}) {
        super(style);
        this._matrix = matrix;
        this._highColor = opts.highColor ?? { type: 'named', name: 'red' };
        this._lowColor  = opts.lowColor  ?? { type: 'named', name: 'brightBlack' };
        this._rowLabels = opts.rowLabels ?? [];
        this._colLabels = opts.colLabels ?? [];
    }

    setMatrix(matrix: number[][]): void {
        this._matrix = matrix;
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0 || this._matrix.length === 0) return;

        const attrs = styleToCellAttrs(this._style);
        const shadeChars = caps.unicode ? SHADE_CHARS_UNICODE : SHADE_CHARS_ASCII;

        // Compute row label width
        const labelWidth = this._rowLabels.length > 0
            ? Math.max(...this._rowLabels.map(l => l.length)) + 1
            : 0;

        // Compute global min/max for normalization
        let globalMin = Infinity;
        let globalMax = -Infinity;
        for (const row of this._matrix) {
            for (const val of row) {
                if (val < globalMin) globalMin = val;
                if (val > globalMax) globalMax = val;
            }
        }
        const range = globalMax - globalMin || 1;

        // Column labels
        let startRow = 0;
        if (this._colLabels.length > 0) {
            for (let col = 0; col < this._colLabels.length; col++) {
                const cx = x + labelWidth + col;
                if (cx >= x + width) break;
                const label = (this._colLabels[col] ?? '').charAt(0);
                screen.setCell(cx, y, { char: label, ...attrs, dim: true });
            }
            startRow = 1;
        }

        // Render matrix rows
        for (let r = 0; r < this._matrix.length; r++) {
            const rowY = y + startRow + r;
            if (rowY >= y + height) break;

            // Row label
            if (this._rowLabels[r]) {
                const label = this._rowLabels[r].slice(0, labelWidth - 1).padEnd(labelWidth - 1, ' ');
                screen.writeString(x, rowY, label + ' ', { ...attrs, dim: true });
            }

            const row = this._matrix[r];
            if (!row) continue;

            for (let col = 0; col < row.length; col++) {
                const cx = x + labelWidth + col;
                if (cx >= x + width) break;

                const val = row[col] ?? 0;
                const norm = (val - globalMin) / range; // 0..1
                const level = Math.min(3, Math.floor(norm * 4));
                const char = shadeChars[level] ?? shadeChars[0]!;

                // Blend color: low → high based on norm
                // Use high color for dense cells
                const fg = norm >= 0.75 ? this._highColor : this._lowColor;

                screen.setCell(cx, rowY, { char, fg });
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/widgets — Sidebar widget
// ─────────────────────────────────────────────────────

import { type Screen, type Style, styleToCellAttrs, stringWidth } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface SidebarItem {
    label: string;
    badge?: string;
    active?: boolean;
}

export interface SidebarOptions {
    /** Whether the sidebar is collapsed */
    collapsed?: boolean;
    /** Collapsed width in cells (default: 3) */
    collapsedWidth?: number;
    /** Active item highlight color */
    activeColor?: import('@termuijs/core').Color;
    /** Badge color */
    badgeColor?: import('@termuijs/core').Color;
}

/**
 * Sidebar — a vertical list of navigation items with optional badges.
 *
 * Supports active item highlighting and collapsible mode.
 */
export class Sidebar extends Widget {
    private _items: SidebarItem[];
    private _collapsed: boolean;
    private _collapsedWidth: number;
    private _activeColor: import('@termuijs/core').Color;
    private _badgeColor: import('@termuijs/core').Color;

    constructor(items: SidebarItem[], style: Partial<Style> = {}, opts: SidebarOptions = {}) {
        super(style);
        this._items = items;
        this._collapsed = opts.collapsed ?? false;
        this._collapsedWidth = opts.collapsedWidth ?? 3;
        this._activeColor = opts.activeColor ?? { type: 'named', name: 'cyan' };
        this._badgeColor = opts.badgeColor ?? { type: 'named', name: 'yellow' };
    }

    setItems(items: SidebarItem[]): void {
        this._items = items;
        this.markDirty();
    }

    setCollapsed(collapsed: boolean): void {
        this._collapsed = collapsed;
        this.markDirty();
    }

    toggle(): void {
        this._collapsed = !this._collapsed;
        this.markDirty();
    }

    get isCollapsed(): boolean { return this._collapsed; }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        for (let i = 0; i < this._items.length && i < height; i++) {
            const item = this._items[i];
            if (!item) continue;

            const isActive = item.active ?? false;
            const fg = isActive ? this._activeColor : attrs.fg;

            if (this._collapsed) {
                // Collapsed: show first character of label only
                const char = item.label.charAt(0) || ' ';
                screen.writeString(x, y + i, char, { ...attrs, fg, bold: isActive });
            } else {
                // Active indicator
                const prefix = isActive ? '▶ ' : '  ';
                const prefixWidth = stringWidth(prefix);

                screen.writeString(x, y + i, prefix, { ...attrs, fg });

                // Label
                const badgeText = item.badge ? ` [${item.badge}]` : '';
                const badgeWidth = stringWidth(badgeText);
                const labelWidth = Math.max(0, width - prefixWidth - badgeWidth);
                const label = item.label.slice(0, labelWidth);

                screen.writeString(x + prefixWidth, y + i, label, {
                    ...attrs,
                    fg,
                    bold: isActive,
                });

                // Badge
                if (item.badge && badgeWidth > 0) {
                    const badgeX = x + width - badgeWidth;
                    screen.writeString(badgeX, y + i, badgeText, {
                        ...attrs,
                        fg: this._badgeColor,
                    });
                }
            }
        }
    }
}

import { type Screen, type Style, type Color, styleToCellAttrs, stringWidth, caps } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface LineGaugeOptions {
    /** Filled portion character. Default: '━' with ASCII fallback '=' */
    filledChar?: string;

    /** Empty portion character. Default: '─' with ASCII fallback '-' */
    emptyChar?: string;

    /** Show percentage label at right. Default: true */
    showLabel?: boolean;

    fillColor?: Color;
    emptyColor?: Color;
}

export class LineGauge extends Widget {
    private _value = 0;
    private _filledChar: string;
    private _emptyChar: string;
    private _showLabel: boolean;
    private _fillColor?: Color;
    private _emptyColor?: Color;

    constructor(style: Partial<Style> = {}, opts: LineGaugeOptions = {}) {
        super(style);
        this._filledChar = opts.filledChar ?? (caps.unicode ? '━' : '=');
        this._emptyChar = opts.emptyChar ?? (caps.unicode ? '─' : '-');
        this._showLabel = opts.showLabel ?? true;
        this._fillColor = opts.fillColor;
        this._emptyColor = opts.emptyColor;
    }

    setValue(value: number): void {
        const clamped = Math.max(0, Math.min(1, value));
        if (clamped === this._value) return;
        this._value = clamped;
        this.markDirty();
    }

    getValue(): number {
        return this._value;
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const percentStr = this._showLabel ? ` ${Math.round(this._value * 100)}%` : '';
        const percentWidth = stringWidth(percentStr);
        const barWidth = Math.max(0, width - percentWidth);
        const filled = Math.round(barWidth * this._value);

        for (let i = 0; i < barWidth; i++) {
            const char = i < filled ? this._filledChar : this._emptyChar;
            screen.setCell(x + i, y, {
                char,
                fg: i < filled
                    ? (this._fillColor ?? attrs.fg)
                    : (this._emptyColor ?? { type: 'named', name: 'brightBlack' }),
            });
        }

        if (this._showLabel) {
            screen.writeString(x + barWidth, y, percentStr, attrs);
        }
    }
}

﻿import { useRef, useState } from '@termuijs/jsx';

export interface UseCounterOptions {
    min?: number;
    max?: number;
    step?: number;
}

export interface UseCounterActions {
    increment: () => void;
    decrement: () => void;
    reset: () => void;
    set: (v: number) => void;
}

function clamp(value: number, min?: number, max?: number): number {
    if (typeof min === 'number' && value < min) return min;
    if (typeof max === 'number' && value > max) return max;
    return value;
}

export function useCounter(
    initialValue = 0,
    opts: UseCounterOptions = {},
): [number, UseCounterActions] {
    const initialRef = useRef(clamp(initialValue, opts.min, opts.max));
    const [count, setCount] = useState(initialRef.current);
    const step = opts.step ?? 1;

    const set = (value: number): void => {
        setCount(clamp(value, opts.min, opts.max));
    };

    const increment = (): void => {
        setCount((current) => clamp(current + step, opts.min, opts.max));
    };

    const decrement = (): void => {
        setCount((current) => clamp(current - step, opts.min, opts.max));
    };

    const reset = (): void => {
        setCount(initialRef.current);
    };

    return [count, { increment, decrement, reset, set }];
}

// ─────────────────────────────────────────────────────
// @termuijs/jsx — useModal
//
// Lightweight typed modal dialog controller with FIFO queueing.
// Each modal is shown in order, and show() resolves when the
// active modal is dismissed or hidden.
//
// Usage:
//   const confirm = useModal<{ message: string }, boolean>();
//   const ok = await confirm.show({ message: 'Delete this file?' });
// ─────────────────────────────────────────────────────

import { useState, useEffect, useRef, useCallback } from '@termuijs/jsx';

interface ModalEntry<Props, Result> {
    props: Props | undefined;
    resolve: (value: Result | undefined) => void;
}

type ModalShow<Props, Result> = [Props] extends [undefined]
    ? () => Promise<Result | undefined>
    : (props: Props) => Promise<Result | undefined>;

export interface UseModalResult<Props = unknown, Result = unknown> {
    /** True when a modal is currently active */
    visible: boolean;
    /** Props passed to the active modal, or undefined when no modal is active */
    props?: Props;
    /** Show a modal and await its resolution */
    show: ModalShow<Props, Result>;
    /** Hide the active modal and resolve it with undefined */
    hide: () => void;
    /** Dismiss the active modal and resolve it with the provided value */
    dismiss: (value: Result) => void;
}

/**
 * useModal — typed modal manager with queueing and cleanup.
 *
 * Manages a queue of modals and shows them one at a time. Each modal
 * can be dismissed with a typed result value or hidden (resolving undefined).
 * Modals are processed in FIFO order.
 *
 * ```tsx
 * const confirm = useModal<{ message: string }, boolean>();
 * const ok = await confirm.show({ message: 'Delete this file?' });
 * if (ok === true) deleteFile();
 * ```
 */
export function useModal<Props = unknown, Result = unknown>(): UseModalResult<Props, Result> {
    const [visible, setVisible] = useState(false);
    const [props, setProps] = useState<Props | undefined>(undefined);
    const queueRef = useRef<ModalEntry<Props, Result>[]>([]);

    // Cleanup on unmount: resolve all pending modals with undefined
    useEffect(() => {
        return () => {
            const queue = queueRef.current.splice(0);
            for (const entry of queue) {
                entry.resolve(undefined);
            }
        };
    }, []);

    const advanceQueue = useCallback(() => {
        const queue = queueRef.current;

        queue.shift();

        if (queue.length > 0) {
            setProps(queue[0]!.props);
            setVisible(true);
            return;
        }

        setProps(undefined);
        setVisible(false);
    }, []);

    const show = useCallback(((nextProps?: Props) => {
        return new Promise<Result | undefined>((resolve) => {
            const queue = queueRef.current;
            queue.push({ props: nextProps as Props | undefined, resolve });

            if (queue.length === 1) {
                setProps(nextProps as Props | undefined);
                setVisible(true);
            }
        });
    }) as ModalShow<Props, Result>, []);

    const hide = useCallback(() => {
        const queue = queueRef.current;
        if (queue.length === 0) return;

        queue[0]!.resolve(undefined);
        advanceQueue();
    }, [advanceQueue]);

    const dismiss = useCallback((value: Result) => {
        const queue = queueRef.current;
        if (queue.length === 0) return;

        queue[0]!.resolve(value);
        advanceQueue();
    }, [advanceQueue]);

    return {
        visible,
        props,
        show,
        hide,
        dismiss,
    };
}

import { ansi } from '@termuijs/core';
import { useEffect } from '@termuijs/jsx';

export type ViewMetaCursor = 'block' | 'underline' | 'bar';

export type ViewMetaMouseMode = 'none' | 'click' | 'drag';

export interface ViewMeta {
    title?: string;
    cursor?: ViewMetaCursor;
    mouseMode?: ViewMetaMouseMode;
}

const defaultCursorShape = `${ansi.CSI}0 q`;
const clickMouseMode = `${ansi.CSI}?1000h${ansi.CSI}?1006h`;
const dragMouseMode = `${ansi.CSI}?1000h${ansi.CSI}?1002h${ansi.CSI}?1006h`;

function writeAnsi(sequence: string): void {
    process.stdout.write(sequence);
}

function mouseModeSequence(mode: ViewMetaMouseMode): string {
    if (mode === 'click') {
        return clickMouseMode;
    }

    if (mode === 'drag') {
        return dragMouseMode;
    }

    return ansi.disableMouse;
}

export function useViewMeta(meta: ViewMeta): void {
    const { title, cursor, mouseMode } = meta;

    useEffect(() => {
        const restoreTitle = title !== undefined;
        const restoreCursor = cursor !== undefined;
        const restoreMouseMode = mouseMode !== undefined;

        if (title !== undefined) {
            writeAnsi(ansi.setTitle(title));
        }

        if (cursor !== undefined) {
            writeAnsi(ansi.cursorShape(cursor, false));
        }

        if (mouseMode !== undefined) {
            writeAnsi(mouseModeSequence(mouseMode));
        }

        return () => {
            if (restoreTitle) {
                writeAnsi(ansi.setTitle(''));
            }

            if (restoreCursor) {
                writeAnsi(defaultCursorShape);
            }

            if (restoreMouseMode) {
                writeAnsi(ansi.disableMouse);
            }
        };
    }, [title, cursor, mouseMode]);
}

import { useState, useEffect } from '@termuijs/jsx';
import { getCurrentApp } from '@termuijs/jsx';

export interface TerminalSize {
    cols: number;
    rows: number;
}

export function useTerminalSize(): TerminalSize {
    const app = getCurrentApp();

    const [size, setSize] = useState<TerminalSize>({
        cols: app?.terminal?.cols ?? 0,
        rows: app?.terminal?.rows ?? 0,
    });

    useEffect(() => {
        const currentApp = getCurrentApp();

        if (!currentApp) {
            return;
        }

        const handleResize = ({
            cols,
            rows,
        }: {
            cols: number;
            rows: number;
        }) => {
            setSize({ cols, rows });
        };

        const unsubscribe =
            currentApp.events.on('resize', handleResize);

        return () => {
            unsubscribe();
        };
    }, []);

    return size;
}

// useFeedback — map UI events to terminal audio cues (bell)

export type FeedbackType =
  | 'click' | 'success' | 'error' | 'warning' | 'copy'
  | 'toggleOn' | 'toggleOff' | 'select' | 'submit' | 'cancel'
  | 'delete' | 'complete' | 'info';

export interface FeedbackOptions {
  /** Set false to silence all feedback (e.g. user preference). Default: true */
  enabled?: boolean;
}

/** Types that produce an audible bell. All others are silent. */
export const AUDIBLE_FEEDBACK_TYPES: ReadonlySet<FeedbackType> = new Set([
  'success', 'error', 'warning', 'copy', 'submit', 'delete', 'complete',
]);

/** Fire feedback for a given interaction type. */
export function triggerFeedback(type: FeedbackType, options?: FeedbackOptions): void {
  if (options?.enabled === false) return;
  if (AUDIBLE_FEEDBACK_TYPES.has(type)) {
    process.stdout.write('\x07'); // BEL character
  }
  // Silent types (click, select, cancel, etc.) produce no output —
  // callers can extend this for visual-only effects.
}

export function useFeedback(options?: FeedbackOptions): (type: FeedbackType) => void {
  return (type: FeedbackType) => triggerFeedback(type, options);
}

