// ─────────────────────────────────────────────────────
// @termuijs/jsx — useFocusWithin
//
// Hook that reports whether focus currently lies on
// any element in a given list of IDs.
// ─────────────────────────────────────────────────────

import { useContext } from '@termuijs/jsx';
import { FocusContext } from '@termuijs/jsx';

export interface UseFocusWithinOptions {
    /** List of focusable element IDs to check against */
    ids: string[];
}

/**
 * useFocusWithin — check if focus is within a list of IDs.
 */
export function useFocusWithin(opts: UseFocusWithinOptions): boolean {
    const ctx = useContext(FocusContext);
    const focusedId = ctx?.focused;
    if (!focusedId) {
        return false;
    }
    return opts?.ids?.includes(focusedId) ?? false;
}

import { useBoolean } from '@termuijs/jsx';

export function useToggle(initialValue = false) {
  const [value, { toggle, setTrue, setFalse }] = useBoolean(initialValue);

  return [value, {
    toggle,
    on: setTrue,
    off: setFalse,
  }];
}

// ─────────────────────────────────────────────────────
// @termuijs/jsx — useTypeahead hook
// ─────────────────────────────────────────────────────
import { useState, useInput, useEffect, useRef } from '@termuijs/jsx';
import { timerPoolSubscribe } from '@termuijs/motion';

/**
 * Accumulates printable character keypresses to navigate lists by typing.
 *
 * @param items List of options to search through.
 * @param getItemLabel Mapping function to retrieve a string label from each item.
 * @param delayMs Timeout in milliseconds before the search buffer resets (default: 500).
 * @returns The index of the first matched item, or -1 if no search has run or matches were found.
 */
export function useTypeahead<T>(
    items: T[],
    getItemLabel: (item: T) => string,
    delayMs = 500
): number {
    const [matchIndex, setMatchIndex] = useState(-1);
    const prefixRef = useRef('');
    const unsubscribeRef = useRef<(() => void) | null>(null);

    // Clean up timer on unmount
    useEffect(() => {
        return () => {
            if (unsubscribeRef.current !== null) {
                unsubscribeRef.current();
            }
        };
    }, []);

    useInput((key, event) => {
        // Only handle printable characters: length 1, no ctrl/alt modifiers
        if (key.length !== 1 || event.ctrl || event.alt) return;

        // Reset previous timer
        if (unsubscribeRef.current !== null) {
            unsubscribeRef.current();
            unsubscribeRef.current = null;
        }

        const typedChar = key.toLowerCase();
        const proposedPrefix = prefixRef.current + typedChar;

        // Find the index of the first item whose label starts with the proposed prefix
        const foundIndex = items.findIndex((item) =>
            getItemLabel(item).toLowerCase().startsWith(proposedPrefix)
        );

        if (foundIndex !== -1) {
            prefixRef.current = proposedPrefix;
            setMatchIndex(foundIndex);
        } else if (prefixRef.current === '') {
            // No match at all even for the first character, do not match or update state.
        } else {
            // proposedPrefix has no match. Ignore the mismatching character,
            // but keep the previous valid matching prefix active.
        }

        // Reset search string after inactivity delayMs
        unsubscribeRef.current = timerPoolSubscribe(delayMs, () => {
            prefixRef.current = '';
            if (unsubscribeRef.current !== null) {
                unsubscribeRef.current();
                unsubscribeRef.current = null;
            }
        });
    });

    return matchIndex;
}

// ─────────────────────────────────────────────────────
// @termuijs/jsx — useKeyboardNavigation
//
// Standard list-style keyboard navigation with arrow
// keys, Home/End, PageUp/PageDown, and Enter to select.
//
// Usage:
//   function Menu({ items }: { items: string[] }) {
//       const { selectedIndex } = useKeyboardNavigation({
//           itemCount: items.length,
//           onSelect: (i) => { /* handle selection */ },
//       });
//       return <List items={items} selectedIndex={selectedIndex} />;
//   }
// ─────────────────────────────────────────────────────

import { useState, useInput } from '@termuijs/jsx';
import { normalizeNavigationKey } from '@termuijs/core';

export interface KeyboardNavigationOptions {
    /** Total number of items in the list */
    itemCount: number;
    /**
     * When true (default), navigation wraps from last item back to first
     * and vice versa. When false, navigation clamps at the boundaries.
     */
    loop?: boolean;
    /**
     * Number of items to skip on PageUp/PageDown (default: 10).
     */
    pageSize?: number;
    /**
     * Called when the user presses Enter on a selected item.
     */
    onSelect?: (index: number) => void;
}

export interface KeyboardNavigationResult {
    /** Index of the currently selected item */
    selectedIndex: number;
    /** Programmatically set the selected index */
    setSelectedIndex: (index: number | ((prev: number) => number)) => void;
}

/**
 * useKeyboardNavigation — arrow-key list navigation with wrap/clamp support.
 *
 * Binds the following keys:
 * - `up` / `down` — move selection by 1
 * - `home` — jump to first item
 * - `end` — jump to last item
 * - `pageup` / `pagedown` — move by `pageSize` items (default 10)
 * - `enter` — call `onSelect` with the current index
 *
 * Key names match the values emitted by `@termuijs/core`'s InputParser.
 *
 * ```tsx
 * function FileList({ files }: { files: string[] }) {
 *     const { selectedIndex } = useKeyboardNavigation({
 *         itemCount: files.length,
 *         loop: false,
 *         onSelect: (i) => openFile(files[i]!),
 *     });
 *     return <List items={files} selectedIndex={selectedIndex} />;
 * }
 * ```
 */
export function useKeyboardNavigation({
    itemCount,
    loop = true,
    pageSize = 10,
    onSelect,
}: KeyboardNavigationOptions): KeyboardNavigationResult {
    const [selectedIndex, setSelectedIndex] = useState(0);

    useInput((key) => {
        if (itemCount === 0) return;

        const move = (delta: number) => {
            setSelectedIndex((prev) => {
                const next = prev + delta;
                if (loop) {
                    // Modular wrap — handles large negative deltas correctly
                    return ((next % itemCount) + itemCount) % itemCount;
                }
                return Math.max(0, Math.min(itemCount - 1, next));
            });
        };

        switch (normalizeNavigationKey(key)) {
            case 'up':
                move(-1);
                break;
            case 'down':
                move(1);
                break;
            case 'home':
                setSelectedIndex(0);
                break;
            case 'end':
                setSelectedIndex(itemCount - 1);
                break;
            case 'pageup':
                move(-pageSize);
                break;
            case 'pagedown':
                move(pageSize);
                break;
            case 'enter':
                onSelect?.(selectedIndex);
                break;
        }
    });

    return { selectedIndex, setSelectedIndex };
}

import { spawn } from 'node:child_process';
import { getCurrentApp } from '@termuijs/jsx';

export interface UseSubprocessResult {
    run: (cmd: string[]) => Promise<number>;
}

function spawnProcess(cmd: string[]): Promise<number> {
    return new Promise((resolve, reject) => {
        const proc = spawn(cmd[0], cmd.slice(1), {
            stdio: 'inherit',
        });

        proc.on('close', (code: number | null) => {
            resolve(code ?? 0);
        });

        proc.on('error', reject);
    });
}

export function useSubprocess(): UseSubprocessResult {
    async function run(cmd: string[]): Promise<number> {
        if (cmd.length === 0) {
            throw new Error('useSubprocess.run requires a command');
        }

        const app = getCurrentApp();

        app?.terminal.exitRawMode();

        try {
            return await spawnProcess(cmd);
        } finally {
            app?.terminal.enterRawMode();
            app?.screen.invalidate();
            app?.requestRender();
        }
    }

    return { run };
}

// ─────────────────────────────────────────────────────
// @termuijs/jsx — useFocus
// ─────────────────────────────────────────────────────

import { useEffect } from '@termuijs/jsx';
import { useContext } from '@termuijs/jsx';
import { FocusContext } from '@termuijs/jsx';

export interface UseFocusOptions {
    /** Unique identifier for this focusable element */
    id: string;

    /**
     * When true, this element will auto-focus on mount
     * if nothing else is currently focused.
     */
    autoFocus?: boolean;
}

export interface UseFocusResult {
    /** True when this element is currently focused */
    isFocused: boolean;

    /** Request focus for this element */
    focus: () => void;

    /** Remove focus from entire tree */
    blur: () => void;
}

/**
 * useFocus — consume focus state for a focusable element
 */
export function useFocus({ id, autoFocus }: UseFocusOptions): UseFocusResult {
    const ctx = useContext(FocusContext);

    const isFocused = ctx.focused === id;

    // Extract stable references (important for deps safety)
    const { focused, focus, blur } = ctx;

    useEffect(() => {
        if (autoFocus && focused === null) {
            focus(id);
        }
    }, [autoFocus, focused, focus, id]);

    return {
        isFocused,
        focus: () => focus(id),
        blur: () => blur(),
    };
}

import { useState, useEffect, useRef } from '@termuijs/jsx';
/**
 * useThrottle — throttle a changing value.
 *
 * Returns a value that limits updates to at most once per intervalMs.
 *
 * ```tsx
 * const throttledValue = useThrottle(value, 300);
 * ```
 */

export function useThrottle<T>(value: T, intervalMs: number): T {
    const [throttledValue, setThrottledValue] = useState<T>(value);
    const latestValueRef = useRef<T>(value);
    const lastEmittedValueRef = useRef<T>(value);
    const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    latestValueRef.current = value;
    const runTimeout = () => {
        timeoutRef.current = setTimeout(() => {
            if (latestValueRef.current !== lastEmittedValueRef.current) {
                lastEmittedValueRef.current = latestValueRef.current;
                setThrottledValue(latestValueRef.current);
                runTimeout();
            } else {
                timeoutRef.current = null;
            }
        }, intervalMs);
    };
    // Effect to handle value updates and start throttle timer
    useEffect(() => {
        if (!timeoutRef.current) {
            // Emits the initial value change immediately
            lastEmittedValueRef.current = value;
            setThrottledValue(value);
            runTimeout();
        }
    }, [value]);
    // Effect to clean up the timer on unmount or interval changes
    useEffect(() => {
        return () => {
            if (timeoutRef.current !== null) {
                clearTimeout(timeoutRef.current);
                timeoutRef.current = null;
            }
        };
    }, [intervalMs]);
    return throttledValue;
}

// ─────────────────────────────────────────────────────
// @termuijs/jsx — useTimeout hook
// ─────────────────────────────────────────────────────
import { useEffect, useRef } from '@termuijs/jsx';

/**
 * useTimeout — run a callback once after a delay.
 *
 * Auto-cleans up on unmount. Re-runs if callback or delayMs changes.
 *
 * ```tsx
 * useTimeout(() => {
 *   notify('Session expiring soon!')
 * }, 5000)
 * ```
 */
export function useTimeout(callback: () => void, delayMs: number): void {
    const callbackRef = useRef(callback);

    // Always keep ref pointing to latest callback
    useEffect(() => {
        callbackRef.current = callback;
    }, [callback]);

    useEffect(() => {
        const id = setTimeout(() => {
            callbackRef.current();
        }, delayMs);

        return () => {
            clearTimeout(id);
        };
    }, [delayMs]);
}

import { useState } from '@termuijs/jsx';

export interface UseBooleanActions {
  setTrue: () => void;
  setFalse: () => void;
  toggle: () => void;
  set: (value: boolean) => void;
}

export function useBoolean(initialValue = false): [boolean, UseBooleanActions] {
  const [value, setValue] = useState(initialValue);

  return [value, {
    setTrue: () => setValue(true),
    setFalse: () => setValue(false),
    toggle: () => setValue((prev) => !prev),
    set: (value: boolean) => setValue(value),
  }];
}

import { useCallback } from '@termuijs/jsx';
import { ansi } from '@termuijs/core';

/**
 * useBell - A React-like hook for triggering the terminal bell.
 *
 * Returns a stable function that, when called, will emit the BEL
 * control character to the terminal.
 *
 * ```tsx
 * const triggerBell = useBell();
 * 
 * useInput((key) => {
 *     if (key === 'b') triggerBell();
 * });
 * ```
