// @termuijs/jsx — useCountdown hook
// ─────────────────────────────────────────────────────
import { useState, useEffect, useRef } from '@termuijs/jsx';

export interface UseCountdownOptions {
    intervalMs?: number;
}

export interface UseCountdownControls {
    start: () => void;
    pause: () => void;
    reset: () => void;
}

/**
 * useCountdown — counts down from a start value with start, pause, and reset controls.
 *
 * Returns [count, controls] where count decrements each interval until it reaches zero.
 * The countdown does not tick until start() is called.
 *
 * ```tsx
 * const [count, { start, pause, reset }] = useCountdown(10);
 * ```
 */
export function useCountdown(
    startValue: number,
    opts?: UseCountdownOptions,
): [number, UseCountdownControls] {
    const intervalMs = opts?.intervalMs ?? 1000;
    const [count, setCount] = useState(startValue);
    const [isRunning, setIsRunning] = useState(false);
    const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
    const startValueRef = useRef(startValue);

    useEffect(() => {
        if (isRunning) {
            intervalRef.current = setInterval(() => {
                setCount((c) => {
                    if (c <= 0) {
                        clearInterval(intervalRef.current!);
                        intervalRef.current = null;
                        return 0;
                    }
                    return c - 1;
                });
            }, intervalMs);
        } else {
            if (intervalRef.current !== null) {
                clearInterval(intervalRef.current);
                intervalRef.current = null;
            }
        }

        return () => {
            if (intervalRef.current !== null) {
                clearInterval(intervalRef.current);
                intervalRef.current = null;
            }
        };
    }, [isRunning, intervalMs]);

    // Stop the countdown when count reaches zero.
    // This is intentionally a separate effect so that setIsRunning(false)
    // is never called synchronously inside a setCount functional updater,
    // which would trigger scheduleRender re-entrantly.
    useEffect(() => {
        if (count === 0 && isRunning) {
            setIsRunning(false);
        }
    }, [count, isRunning]);

    const start = (): void => {
        if (count > 0) {
            setIsRunning(true);
        }
    };

    const pause = (): void => {
        setIsRunning(false);
    };

    const reset = (): void => {
        setIsRunning(false);
        setCount(startValueRef.current);
    };

    return [count, { start, pause, reset }];
}

// ─────────────────────────────────────────────────────
// @termuijs/jsx — useElementSize
//
// Hook to track the size of a widget element.
// Returns a ref to attach to the widget and the current size.
//
// Usage:
//   function MyComponent() {
//       const [ref, { width, height }] = useElementSize();
//       return <Box ref={ref}>Size: {width}x{height}</Box>;
//   }
// ─────────────────────────────────────────────────────

import { useEffect, useRef, useState } from '@termuijs/jsx';

// Minimal structural shape this hook needs. Avoids importing the Widget
// base from @termuijs/widgets, which would create a jsx -> widgets cycle.
interface SizedWidget {
    rect?: { width: number; height: number };
    on?(event: string, cb: () => void): void;
    off?(event: string, cb: () => void): void;
}
type Widget = SizedWidget;

export interface ElementSize {
    width: number;
    height: number;
}

/**
 * useElementSize — track the size of a widget element.
 *
 * ```tsx
 * function ResizableBox() {
 *     const [ref, { width, height }] = useElementSize();
 *     return <Box ref={ref}>Size: {width}x{height}</Box>;
 * }
 * ```
 */
export function useElementSize(): [{ current: Widget | null }, ElementSize] {
    const widgetRef = useRef<Widget | null>(null);
    const [size, setSize] = useState<ElementSize>({ width: 0, height: 0 });

    useEffect(() => {
        const widget = widgetRef.current;

        if (!widget) {
            setSize({ width: 0, height: 0 });
            return;
        }

        // Get initial size from widget's rect
        const updateSize = () => {
            if (widget && widget.rect) {
                setSize({ width: widget.rect.width, height: widget.rect.height });
            }
        };

        updateSize();

        // Subscribe to resize events if the widget supports them
        const onResize = () => updateSize();
        widget.on?.('resize', onResize);

        return () => {
            widget.off?.('resize', onResize);
        };
    }, []);

    return [widgetRef, size];
}

// ─────────────────────────────────────────────────────
// @termuijs/jsx — useClipboard
//
// Hook that reads from and writes to the system clipboard
// and exposes a copied-state flag for feedback.
// ─────────────────────────────────────────────────────

import { useState, useRef, useEffect } from '@termuijs/jsx';
import { writeClipboard, readClipboard } from '@termuijs/core';

export interface UseClipboardOptions {
    /** Timeout in milliseconds after which copied state is reset to false */
    resetMs?: number;
}

export interface UseClipboardResult {
    /** True if copy was recently called, resets to false after resetMs */
    copied: boolean;
    /** Copy string text to the system clipboard */
    copy: (text: string) => void;
    /** Read current text from the system clipboard */
    read: () => Promise<string>;
}

/**
 * useClipboard — interact with the system clipboard.
 */
export function useClipboard(opts?: UseClipboardOptions): UseClipboardResult {
    const [copied, setCopied] = useState(false);
    const resetMs = opts?.resetMs ?? 2000;
    const timeoutRef = useRef<any>(null);

    // Clear the timeout on unmount
    useEffect(() => {
        return () => {
            if (timeoutRef.current) {
                clearTimeout(timeoutRef.current);
            }
        };
    }, []);

    const copy = (text: string) => {
        writeClipboard(text);
        setCopied(true);

        if (timeoutRef.current) {
            clearTimeout(timeoutRef.current);
        }

        timeoutRef.current = setTimeout(() => {
            setCopied(false);
            timeoutRef.current = null;
        }, resetMs);
    };

    const read = async () => {
        return await readClipboard();
    };

    return { copied, copy, read };
}

// ─────────────────────────────────────────────────────
// @termuijs/jsx — useFocusTrap
//
// Traps Tab / Shift+Tab navigation within a group of
// focusable IDs. Intended for Modals and Dialogs that
// should not let focus escape to the background.
//
// Usage:
//   function Modal({ ids }: { ids: string[] }) {
//       useFocusTrap(ids);
//       return <Box>...</Box>;
//   }
// ─────────────────────────────────────────────────────

import { useInput } from '@termuijs/jsx';
import { useContext } from '@termuijs/jsx';
import { FocusContext } from '@termuijs/jsx';

/**
 * useFocusTrap — cycle Tab / Shift+Tab focus through a fixed list of IDs.
 *
 * When the currently focused element is in the `ids` array, Tab moves
 * forward through the list (wrapping from last to first) and Shift+Tab
 * moves backward (wrapping from first to last).
 *
 * If no element in the list is focused when Tab is first pressed, focus
 * is placed on the first element.
 *
 * @param ids - Ordered array of focusable element IDs to cycle through.
 *
 * ```tsx
 * function Dialog({ children }: { children: VNode }) {
 *     useFocusTrap(['dialog-ok', 'dialog-cancel']);
 *     return (
 *         <Box>
 *             {children}
 *             <Button id="dialog-ok" />
 *             <Button id="dialog-cancel" />
 *         </Box>
 *     );
 * }
 * ```
 */
export function useFocusTrap(ids: string[]): void {
    const ctx = useContext(FocusContext);

    useInput((key, event) => {
        if (key !== 'tab') return;

        if (ids.length === 0) return;

        const currentIndex = ids.indexOf(ctx.focused ?? '');

        if (event.shift) {
            // Shift+Tab — move backward
            const prev = currentIndex <= 0 ? ids.length - 1 : currentIndex - 1;
            ctx.focus(ids[prev]!);
        } else {
            // Tab — move forward
            const next = currentIndex >= ids.length - 1 ? 0 : currentIndex + 1;
            ctx.focus(ids[next]!);
        }
    });
}

import { useState } from '@termuijs/jsx';

export interface UseSetActions<T> {
  add: (item: T) => void;
  remove: (item: T) => void;
  toggle: (item: T) => void;
  has: (item: T) => boolean;
  clear: () => void;
}

export function useSet<T>(
  initialItems?: Iterable<T>,
): [Set<T>, UseSetActions<T>] {
  const [state, setState] = useState(
    initialItems ? new Set(initialItems) : new Set<T>(),
  );

  const actions: UseSetActions<T> = {
    add: (item: T) => {
      setState((prev) => {
        const next = new Set(prev);
        next.add(item);
        return next;
      });
    },
    remove: (item: T) => {
      setState((prev) => {
        const next = new Set(prev);
        next.delete(item);
        return next;
      });
    },
    toggle: (item: T) => {
      setState((prev) => {
        const next = new Set(prev);
        if (next.has(item)) {
          next.delete(item);
        } else {
          next.add(item);
        }
        return next;
      });
    },
    has: (item: T) => state.has(item),
    clear: () => {
      setState(new Set<T>());
    },
  };

  return [state, actions];
}

// SortPrompt — sortable item list
import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, type KeyEvent, mergeStyles, defaultStyle, styleToCellAttrs, caps } from '@termuijs/core';

export interface SortPromptOptions {
    activeColor?: Style['fg'];
    onSubmit?: (items: string[]) => void;
}

export class SortPrompt extends Widget {
    private _items: string[];
    private _cursorIndex = 0;
    private _activeColor: Style['fg'];
    private _onSubmit?: (items: string[]) => void;
    focusable = true;

    constructor(items: string[], options: SortPromptOptions = {}) {
        super(mergeStyles(defaultStyle(), { flexGrow: 1 }));
        this._items = [...items];
        this._activeColor = options.activeColor ?? { type: 'named', name: 'cyan' };
        this._onSubmit = options.onSubmit;
    }

    selectNext(): void {
        if (this._cursorIndex < this._items.length - 1) {
            this._cursorIndex++;
            this.markDirty();
        }
    }

    selectPrev(): void {
        if (this._cursorIndex > 0) {
            this._cursorIndex--;
            this.markDirty();
        }
    }

    moveItemUp(): void {
        if (this._cursorIndex > 0) {
            const temp = this._items[this._cursorIndex];
            this._items[this._cursorIndex] = this._items[this._cursorIndex - 1];
            this._items[this._cursorIndex - 1] = temp;
            this._cursorIndex--;
            this.markDirty();
        }
    }

    moveItemDown(): void {
        if (this._cursorIndex < this._items.length - 1) {
            const temp = this._items[this._cursorIndex];
            this._items[this._cursorIndex] = this._items[this._cursorIndex + 1];
            this._items[this._cursorIndex + 1] = temp;
            this._cursorIndex++;
            this.markDirty();
        }
    }

    submit(): void {
        this._onSubmit?.(this._items);
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'shift+up':
                this.moveItemUp();
                break;

            case 'shift+down':
                this.moveItemDown();
                break;

            case 'enter':
                this.submit();
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this.style);

        for (let i = 0; i < this._items.length && i < height; i++) {
            const active = i === this._cursorIndex;
            const indicator = active ? (caps.unicode ? '◉ ' : '> ') : '  ';
            const line = `${indicator}${this._items[i]}`;

            screen.writeString(
                x,
                y + i,
                line.slice(0, width),
                {
                    ...attrs,
                    fg: active ? this._activeColor : attrs.fg,
                    bold: active,
                },
            );
        }
    }
}

import type { StandardSchemaV1 } from '@standard-schema/spec';

export type InputValidator =
    | StandardSchemaV1
    | ((v: unknown) => string | undefined | null | Promise<string | undefined | null>);

export async function validateInput(
    validator: InputValidator | undefined,
    value: unknown,
): Promise<string | undefined> {
    if (!validator) {
        return undefined;
    }

    if (typeof validator === 'function') {
        const result = validator(value);
        if (result instanceof Promise) {
            return (await result) ?? undefined;
        }
        return result ?? undefined;
    }

    const result = validator['~standard'].validate(value);

    // Resolve the promise if it is async, otherwise use the synchronous result directly
    const resolvedResult = result instanceof Promise ? await result : result;
    const issues = resolvedResult.issues;

    if (!issues?.length) {
        return undefined;
    }

    return issues[0]?.message ?? 'Validation failed';
}

// AppShell — full-screen application layout
import { Widget } from '@termuijs/widgets';
import { type Screen, type Rect, type LayoutNode, type KeyEvent, createLayoutNode, mergeStyles, defaultStyle } from '@termuijs/core';

export interface AppShellOptions {
    header?: Widget;
    footer?: Widget;
    sidebar?: Widget;
    main: Widget;
    sidebarWidth?: number;
}

export class AppShell extends Widget {
    private _header?: Widget;
    private _footer?: Widget;
    private _sidebar?: Widget;
    private _main: Widget;
    private _sidebarWidth: number;
    private _sidebarVisible = true;
    private _mainScrollOffset = 0;

    constructor(options: AppShellOptions) {
        super(mergeStyles(defaultStyle(), { width: '100%', height: '100%', overflow: 'hidden' }));
        this._header = options.header;
        this._footer = options.footer;
        this._sidebar = options.sidebar;
        this._main = options.main;
        this._sidebarWidth = Math.max(0, Math.floor(options.sidebarWidth ?? 20));
    }

    get sidebarVisible(): boolean {
        return this._sidebarVisible;
    }

    override getLayoutNode(): LayoutNode {
        return createLayoutNode(this.id, this.style, []);
    }

    override updateRect(rect: Rect): void {
        const changed =
            rect.x !== this.rect.x ||
            rect.y !== this.rect.y ||
            rect.width !== this.rect.width ||
            rect.height !== this.rect.height;
        super.updateRect(rect);
        if (changed) this.markDirty();
    }

    handleResize(cols: number, rows: number): void {
        this.updateRect({ x: 0, y: 0, width: cols, height: rows });
        this.markDirty();
    }

    scrollUp(lines = 1): void {
        this._mainScrollOffset = Math.max(0, this._mainScrollOffset - lines);
        this.markDirty();
    }

    scrollDown(lines = 1): void {
        this._mainScrollOffset += lines;
        this._clampMainScroll();
        this.markDirty();
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'up':
                this.scrollUp();
                break;
            case 'down':
                this.scrollDown();
                break;
        }
    }

    toggleSidebar(): void {
        this._sidebarVisible = !this._sidebarVisible;
        this._clampMainScroll();
        this.markDirty();
    }

    protected _renderSelf(_screen: Screen): void {
        // Container only
    }

    override render(screen: Screen): void {
        if (this.style.visible === false) return;

        const nextRect = { x: 0, y: 0, width: screen.cols, height: screen.rows };
        if (
            this.rect.x !== nextRect.x ||
            this.rect.y !== nextRect.y ||
            this.rect.width !== nextRect.width ||
            this.rect.height !== nextRect.height
        ) {
            super.updateRect(nextRect);
        }

        const shouldClip = this.style.overflow !== 'visible';
        if (shouldClip) screen.pushClip(this.rect);

        const { x, y, width, height } = this.rect;
        const headerHeight = this._header ? 1 : 0;
        const footerHeight = this._footer ? 1 : 0;
        const bodyY = y + headerHeight;
        const bodyHeight = Math.max(0, height - headerHeight - footerHeight);

        this._renderFixedChild(this._header, screen, { x, y, width, height: headerHeight });
        this._renderFooter(screen, x, y, width, height, footerHeight);

        const sidebarWidth = this._sidebar && this._sidebarVisible
            ? Math.min(this._sidebarWidth, width)
            : 0;
        const mainX = x + sidebarWidth;
        const mainWidth = Math.max(0, width - sidebarWidth);
        const mainContentHeight = Math.max(bodyHeight, this._main.rect.height || 0);
        this._clampMainScroll(bodyHeight, mainContentHeight);

        if (sidebarWidth > 0 && bodyHeight > 0) {
            this._renderFixedChild(this._sidebar, screen, {
                x,
                y: bodyY,
                width: sidebarWidth,
                height: bodyHeight,
            });
        }

        if (mainWidth > 0 && bodyHeight > 0) {
            const originalRect = { ...this._main.rect };
            this._main.updateRect({
                x: mainX,
                y: bodyY - this._mainScrollOffset,
                width: mainWidth,
                height: mainContentHeight,
            });
            screen.pushClip({ x: mainX, y: bodyY, width: mainWidth, height: bodyHeight });
            try {
                this._main.render(screen);
            } finally {
                screen.popClip();
                this._main.updateRect(originalRect);
            }
        }

        if (shouldClip) screen.popClip();
    }

    private _renderFooter(screen: Screen, x: number, y: number, width: number, height: number, footerHeight: number): void {
        if (!this._footer || footerHeight <= 0) return;
        this._renderFixedChild(this._footer, screen, {
            x,
            y: y + height - footerHeight,
            width,
            height: footerHeight,
        });
    }

    private _renderFixedChild(child: Widget | undefined, screen: Screen, rect: Rect): void {
        if (!child || rect.width <= 0 || rect.height <= 0) return;
        const originalRect = { ...child.rect };
        child.updateRect(rect);
        try {
            child.render(screen);
        } finally {
            child.updateRect(originalRect);
        }
    }

    private _clampMainScroll(viewportHeight = this._bodyHeight(), contentHeight = Math.max(this._main.rect.height || 0, viewportHeight)): void {
        const maxOffset = Math.max(0, contentHeight - viewportHeight);
        this._mainScrollOffset = Math.max(0, Math.min(this._mainScrollOffset, maxOffset));
    }

    private _bodyHeight(): number {
        const headerHeight = this._header ? 1 : 0;
        const footerHeight = this._footer ? 1 : 0;
        return Math.max(0, this.rect.height - headerHeight - footerHeight);
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — RadioGroup widget
//
// Renders a list of options where only one is selectable
// at a time. Up/down arrow keys move the cursor; Enter
// confirms the selection and fires onChange.
// ─────────────────────────────────────────────────────

import { Widget } from '@termuijs/widgets';
import {
    type Screen,
    type KeyEvent,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    caps,
} from '@termuijs/core';

export interface RadioGroupOption {
    label: string;
    value: string;
    disabled?: boolean;
}

export interface RadioGroupOptions {
    options: Array<RadioGroupOption>;
    defaultValue?: string;
    onChange?: (value: string) => void;
}

/**
 * RadioGroup — renders a vertical list of mutually exclusive options.
 *
 * Example output (unicode):
 *   (o) Dark
 *   ( ) Light
 *   ( ) System
 */
export class RadioGroup extends Widget {
    private _options: RadioGroupOption[];
    private _selectedValue: string;
    private _focusedIndex: number;

    /** Fires whenever the confirmed selection changes. */
    onChange?: (value: string) => void;

    focusable = true;

    constructor(config: RadioGroupOptions) {
        super(
            mergeStyles(defaultStyle(), {
                height: Math.max(config.options.length, 1),
            })
        );

        this._options = config.options;
        this.onChange = config.onChange;

        // Determine initial selection
        const defaultIndex = config.defaultValue !== undefined
            ? config.options.findIndex((o) => o.value === config.defaultValue)
            : -1;

        // If defaultValue matched a non-disabled option use it; otherwise pick
        // the first enabled option (or index 0 as a safe fallback).
        if (defaultIndex >= 0 && !config.options[defaultIndex]?.disabled) {
            this._selectedValue = config.options[defaultIndex]!.value;
            this._focusedIndex = defaultIndex;
        } else {
            const firstEnabled = config.options.findIndex((o) => !o.disabled);
            this._focusedIndex = firstEnabled >= 0 ? firstEnabled : 0;
            this._selectedValue = config.options[this._focusedIndex]?.value ?? '';
        }
    }

    // ── Accessors ─────────────────────────────────────

    /** The value of the currently confirmed selection. */
    get selectedValue(): string {
        return this._selectedValue;
    }

    /** The index currently under the keyboard cursor. */
    get focusedIndex(): number {
        return this._focusedIndex;
    }

    // ── Navigation ────────────────────────────────────

    /** Move cursor to the next enabled option. */
    selectNext(): void {
        let n = this._focusedIndex + 1;
        while (n < this._options.length && this._options[n]?.disabled) n++;
        if (n < this._options.length) {
            this._focusedIndex = n;
            this.markDirty();
        }
    }

    /** Move cursor to the previous enabled option. */
    selectPrev(): void {
        let n = this._focusedIndex - 1;
        while (n >= 0 && this._options[n]?.disabled) n--;
        if (n >= 0) {
            this._focusedIndex = n;
            this.markDirty();
        }
    }

    /** Confirm the focused option and fire onChange. */
    confirm(): void {
        const option = this._options[this._focusedIndex];
        if (!option || option.disabled) return;
        if (option.value === this._selectedValue) return; // nothing changed
        this._selectedValue = option.value;
        this.markDirty();
        this.onChange?.(this._selectedValue);
    }

    // ── Key handling ──────────────────────────────────

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'up':
                this.selectPrev();
                break;
            case 'down':
                this.selectNext();
                break;
            case 'home': {
                // Move focus to first enabled option (no-op if already there)
                let n = 0;
                while (n < this._options.length && this._options[n]?.disabled) n++;
                if (n < this._options.length && n !== this._focusedIndex) {
                    this._focusedIndex = n;
                    this.markDirty();
                }
                break;
            }
            case 'end': {
                // Move focus to last enabled option (no-op if already there)
                let m = this._options.length - 1;
                while (m >= 0 && this._options[m]?.disabled) m--;
                if (m >= 0 && m !== this._focusedIndex) {
                    this._focusedIndex = m;
                    this.markDirty();
                }
                break;
            }
            case 'enter':
                this.confirm();
                break;
            case 'space':
                this.confirm();
                break;
        }
    }

    // ── Rendering ─────────────────────────────────────

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this.style);

        for (let i = 0; i < this._options.length && i < height; i++) {
            const option = this._options[i]!;
            const isFocused = i === this._focusedIndex;
            const isSelected = option.value === this._selectedValue;

            // "(o) Label"  — selected
            // "( ) Label"  — unselected
            // ASCII fallbacks for NO_UNICODE environments
            const radio = isSelected
                ? (caps.unicode ? '(o)' : '(*)')
                : (caps.unicode ? '( )' : '( )');

            const cursor = isFocused
                ? (caps.unicode ? '❯ ' : '> ')
                : '  ';

            const text = `${cursor}${radio} ${option.label}`;

            screen.writeString(
                x,
                y + i,
                text.slice(0, width),
                {
                    ...attrs,
                    bold: isFocused,
                    dim: option.disabled === true,
                    fg: option.disabled
                        ? { type: 'named' as const, name: 'brightBlack' as const }
                        : attrs.fg,
                }
            );
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — WelcomeScreen
// Splash/welcome screen composing BigText + subtitle + keymap
// ─────────────────────────────────────────────────────

import {
    type Screen,
    type Style,
    styleToCellAttrs,
    truncate,
    stringWidth,
    mergeStyles,
    defaultStyle,
} from '@termuijs/core';
import { BigText, Widget } from '@termuijs/widgets';

export interface KeymapHint {
    key: string;
    action: string;
}

export interface WelcomeScreenOptions {
    title: string;
    subtitle?: string;
    tagline?: string;
    keymap?: KeymapHint[];
    style?: Partial<Style>;
}

export class WelcomeScreen extends Widget {
    private _subtitle: string;
    private _tagline: string;
    private _keymap: KeymapHint[];
    private _bigText: BigText;

    constructor(options: WelcomeScreenOptions) {
        super(mergeStyles(defaultStyle(), { flexGrow: 1, ...options.style }));
        this._subtitle = options.subtitle ?? '';
        this._tagline  = options.tagline  ?? '';
        this._keymap   = options.keymap   ?? [];
        this._bigText  = new BigText(options.title);
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        let row = y;

        // ── BigText title ──────────────────────────────
        const bigHeight = Math.min(5, height - 2);
        this._bigText.updateRect({ x, y: row, width, height: bigHeight });
        this._bigText.render(screen);
        row += bigHeight + 1;

        if (row >= y + height) return;

        // ── Subtitle ───────────────────────────────────
        if (this._subtitle) {
            const sub = truncate(this._subtitle, width);
            const subX = x + Math.max(0, Math.floor((width - stringWidth(sub)) / 2));
            screen.writeString(subX, row, sub, { ...attrs, bold: true });
            row++;
        }

        // ── Tagline ────────────────────────────────────
        if (this._tagline && row < y + height) {
            const tag = truncate(this._tagline, width);
            const tagX = x + Math.max(0, Math.floor((width - stringWidth(tag)) / 2));
            screen.writeString(tagX, row, tag, { ...attrs, dim: true });
            row++;
        }

        // ── Keymap at bottom ───────────────────────────
        if (this._keymap.length > 0) {
            const keymapRow = y + height - 1;
            if (keymapRow > row) {
                const parts = this._keymap.map(({ key, action }) => `[${key}] ${action}`);
                const hint = parts.join('  ');
                const hintX = x + Math.max(0, Math.floor((width - stringWidth(hint)) / 2));
                screen.writeString(hintX, keymapRow, hint, { ...attrs, dim: true });
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — Autocomplete widget
// ─────────────────────────────────────────────────────

import {
    type Style,
    type Screen,
    type KeyEvent,
    type Color,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    caps,
    truncate,
    stringWidth
} from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface AutocompleteOptions {
    /** List of search suggestions / candidates */
    items: string[];
    /** Callback when an item is selected or submitted */
    onSelect?: (value: string) => void;
    /** Callback when the query text changes */
    onChange?: (value: string) => void;
    /** Custom filter function to override default lowercase startsWith matching */
    filter?: (query: string, item: string) => boolean;
    /** Maximum number of suggestions to display in dropdown. Default: 5 */
    maxSuggestions?: number;
    /** Placeholder text when query is empty */
    placeholder?: string;
    /** Highlight color for the selected suggestion */
    highlightColor?: Color;
}

const defaultFilter = (query: string, item: string) => {
    if (!query) return true;
    const q = query.toLowerCase();
    const t = item.toLowerCase();
    let qIdx = 0;
    for (let i = 0; i < t.length; i++) {
        if (t[i] === q[qIdx]) qIdx++;
        if (qIdx === q.length) return true;
    }
    return false;
};

export class Autocomplete extends Widget {
    private _items: string[] = [];
    private _query = '';
    private _isOpen = false;
    private _selectedIndex = -1;
    private _onSelect?: (value: string) => void;
    private _onChange?: (value: string) => void;
    private _filter: (query: string, item: string) => boolean;
    private _maxSuggestions: number;
    private _placeholder: string;
    private _highlightColor: Color;

    constructor(style: Partial<Style> = {}, options: AutocompleteOptions = { items: [] }) {
        super(mergeStyles(defaultStyle(), { height: 6, focusRingStyle: 'none', ...style }));
        this._items = options.items ?? [];
        this._onSelect = options.onSelect;
        this._onChange = options.onChange;
        this._filter = options.filter ?? defaultFilter;
        this._maxSuggestions = options.maxSuggestions ?? 5;
        this._placeholder = options.placeholder ?? '';
        this._highlightColor = options.highlightColor ?? { type: 'named', name: 'cyan' };
        this.focusable = true;
    }

    get query(): string {
        return this._query;
    }

    set query(value: string) {
        this._query = value;
        this._selectedIndex = -1;
        this.markDirty();
    }

    get items(): string[] {
        return this._items;
    }

    setItems(items: string[]): void {
        this._items = items;
        this._selectedIndex = -1;
        this.markDirty();
    }

    private get _filteredItems(): string[] {
        return this._items.filter(item => this._filter(this._query, item));
    }

    public handleKey(event: KeyEvent): void {
        const filtered = this._filteredItems;
        const key = event.key;

        if (key === 'down' || key === 'tab') {
            this._isOpen = true;
            if (filtered.length > 0) {
                this._selectedIndex = (this._selectedIndex + 1) % filtered.length;
            }
            this.markDirty();
            return;
        }

        if (key === 'up') {
            this._isOpen = true;
            if (filtered.length > 0) {
                if (this._selectedIndex <= 0) {
                    this._selectedIndex = filtered.length - 1;
                } else {
                    this._selectedIndex--;
                }
            }
            this.markDirty();
            return;
        }

        if (key === 'escape') {
            this._isOpen = false;
            this._selectedIndex = -1;
            this.markDirty();
            return;
        }

        if (key === 'enter') {
            if (this._isOpen && this._selectedIndex >= 0 && this._selectedIndex < filtered.length) {
                const selected = filtered[this._selectedIndex];
                this._query = selected;
                this._onChange?.(this._query);
                this._onSelect?.(selected);
                this._isOpen = false;
                this._selectedIndex = -1;
            } else {
                this._onSelect?.(this._query);
            }
            this.markDirty();
            return;
        }

        if (key === 'backspace') {
            if (this._query.length > 0) {
                this._query = this._query.slice(0, -1);
                this._isOpen = true;
                this._selectedIndex = -1;
                this._onChange?.(this._query);
            }
            this.markDirty();
            return;
        }

        if (key.length === 1 && !event.ctrl && !event.alt) {
            this._query += key;
            this._isOpen = true;
            this._selectedIndex = -1;
            this._onChange?.(this._query);
            this.markDirty();
            return;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const pointer = caps.unicode ? '➔' : '>';
        const pointerStr = pointer + ' ';
        const prefixWidth = stringWidth(pointerStr);

        if (this._query.length === 0 && !this.isFocused) {
            const displayPlaceholder = truncate(this._placeholder, width - prefixWidth);
            screen.writeString(x, y, pointerStr + displayPlaceholder, { ...attrs, dim: true });
        } else {
            const displayQuery = truncate(this._query, width - prefixWidth);
            screen.writeString(x, y, pointerStr + displayQuery, attrs);

            if (this.isFocused) {
                const cursorX = x + prefixWidth + stringWidth(displayQuery);
                if (cursorX < x + width) {
                    screen.setCell(cursorX, y, {
                        char: ' ',
                        ...attrs,
                        inverse: true,
                    });
                }
            }
        }

        const filtered = this._filteredItems;
        if (this._isOpen && this.isFocused && filtered.length > 0) {
            const renderCount = Math.min(filtered.length, height - 1, this._maxSuggestions);
            for (let i = 0; i < renderCount; i++) {
                const item = filtered[i];
                const isSelected = i === this._selectedIndex;
                const rowY = y + 1 + i;
                if (rowY >= y + height) break;

                const itemText = truncate(item, width - 2);
                const prefix = isSelected ? (caps.unicode ? '● ' : '* ') : '  ';
                const itemAttrs = isSelected
                    ? { ...attrs, fg: this._highlightColor, bold: true }
                    : attrs;

                screen.writeString(x, rowY, prefix + itemText, itemAttrs);
            }
        }
    }
}

