        return this._outputTokens;
    }

    setUsage(input: number, output: number): void {
        this._inputTokens = input;
        this._outputTokens = output;
        this.markDirty();
    }

    setInputTokens(input: number): void {
        this._inputTokens = input;
        this.markDirty();
    }

