import { Widget } from '@termuijs/widgets';
import {
    type Style,
    type Screen,
    type KeyEvent,
    caps,
    styleToCellAttrs
} from '@termuijs/core';

export type PopoverPlacement = 'top' | 'bottom' | 'left' | 'right';

export interface PopoverOptions {
    /** The placement of the popover relative to the anchor. Default: 'bottom'. */
    placement?: PopoverPlacement;
    /** Title shown in the panel border. */
    title?: string;
    /** Border color. */
    borderColor?: Style['fg'];
    /** * The specific terminal coordinates (row/col) to anchor this popover to.
     * If omitted, it will attempt to use its own rect as the anchor bounds.
     */
    anchor?: { x: number; y: number };
}

export class Popover extends Widget {
    private _isOpen = false;
    private content: Widget;
    private opts: PopoverOptions;

    constructor(content: Widget, style?: Partial<Style>, opts?: PopoverOptions) {
        super(style);
        this.content = content;
        this.opts = { placement: 'bottom', ...opts };
    }

    get isOpen(): boolean {
        return this._isOpen;
    }

    open(): void {
        if (!this._isOpen) {
            this._isOpen = true;
            this.markDirty();
        }
    }

    close(): void {
        if (this._isOpen) {
            this._isOpen = false;
            this.markDirty();
        }
    }

    toggle(): void {
        this._isOpen ? this.close() : this.open();
    }

    /** Update the anchor coordinates dynamically */
    setAnchor(x: number, y: number): void {
        this.opts.anchor = { x, y };
        this.markDirty();
    }

    handleKey(event: KeyEvent): void {
        if (!this._isOpen) return;

        if (event.key === 'escape') {
            this.close();
            return;
        }

        // `Widget` does not declare `handleKey`; only some concrete widgets implement it.
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const focusable = this.content as any;
        if (typeof focusable.handleKey === 'function') {
            focusable.handleKey(event);
        }
    }

    private getBorderChars() {
        if (caps.unicode) {
            return {
                topLeft: '┌', topRight: '┐', bottomLeft: '└', bottomRight: '┘',
                top: '─', bottom: '─', left: '│', right: '│'
            };
        }
        return {
            topLeft: '+', topRight: '+', bottomLeft: '+', bottomRight: '+',
            top: '-', bottom: '-', left: '|', right: '|'
        };
    }

    protected _renderSelf(screen: Screen): void {
        if (!this._isOpen) return;

        // Use the explicit anchor if provided, otherwise fallback to the rect's origin
        const anchorX = this.opts.anchor?.x ?? this._rect.x;
        const anchorY = this.opts.anchor?.y ?? this._rect.y;

        const contentRect = this.content.rect;
        const width = Math.max(10, contentRect.width + 2); 
        const height = Math.max(3, contentRect.height + 2);

        let px = anchorX;
        let py = anchorY;

        switch (this.opts.placement) {
            case 'top': py = anchorY - height; break;
            case 'bottom': py = anchorY + 1; break;
            case 'left': px = anchorX - width; break;
            case 'right': px = anchorX + 1; break;
        }

        const attrs = styleToCellAttrs(this.style);
        const bAttrs = { ...attrs, fg: this.opts.borderColor || attrs.fg };
        const border = this.getBorderChars();

        // ── 1. Draw Sides & Clear Background ──
        for (let r = 1; r < height - 1; r++) {
            screen.writeString(px, py + r, border.left, bAttrs);
            // This space clears whatever was drawn beneath it on the base layer
            screen.writeString(px + 1, py + r, ' '.repeat(Math.max(0, width - 2)), attrs);
            screen.writeString(px + width - 1, py + r, border.right, bAttrs);
        }

        // ── 2. Top Border with Title ──
        const titleStr = this.opts.title ? ` ${this.opts.title} ` : '';
        const innerWidth = Math.max(0, width - 2);
        const fill = Math.max(0, innerWidth - titleStr.length);
        const leftFill = Math.floor(fill / 2);
        const rightFill = fill - leftFill;

        screen.writeString(
            px, py,
            border.topLeft + border.top.repeat(leftFill) + titleStr + border.top.repeat(rightFill) + border.topRight,
            bAttrs
        );

        // ── 3. Bottom Border ──
        if (height >= 2) {
            screen.writeString(
                px, py + height - 1,
                border.bottomLeft + border.bottom.repeat(innerWidth) + border.bottomRight,
                bAttrs
            );
        }

        // ── 4. Render Child Content ──
        const contentX = px + 1;
        const contentY = py + 1;
        const contentW = innerWidth;
        const contentH = Math.max(0, height - 2);

        if (contentW > 0 && contentH > 0) {
            const originalRect = { ...this.content.rect };

            this.content.updateRect({
                x: contentX, y: contentY, width: contentW, height: contentH
            });

            screen.pushClip({ x: contentX, y: contentY, width: contentW, height: contentH });
            try {
                this.content.render(screen);
            } finally {
                screen.popClip();
                this.content.updateRect(originalRect);
            }
        }
    }
}

// Select — single-item dropdown selector
import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, mergeStyles, defaultStyle, styleToCellAttrs, caps } from '@termuijs/core';

export interface SelectOption { label: string; value: string; disabled?: boolean; }
export interface SelectOptions {
    placeholder?: string;
    activeColor?: Style['fg'];
    onSelect?: (option: SelectOption, index: number) => void;
}

export class Select extends Widget {
    private _options: SelectOption[];
    private _selectedIndex = 0;
    private _isOpen = false;
    private _placeholder: string;
    private _activeColor: Style['fg'];
    private _onSelect?: (option: SelectOption, index: number) => void;
    private _closedHeight: number;
    focusable = true;

    constructor(options: SelectOption[], config: SelectOptions = {}, style?: Partial<Style>) {
        super(mergeStyles(mergeStyles(defaultStyle(), { height: 1 }), style ?? {}));
        this._closedHeight = typeof this._style.height === 'number' ? this._style.height : 1;
        this._options = options;
        this._placeholder = config.placeholder ?? 'Select...';
        this._activeColor = config.activeColor ?? { type: 'named', name: 'cyan' };
        this._onSelect = config.onSelect;
    }

    get selectedOption(): SelectOption | undefined { return this._options[this._selectedIndex]; }
    get selectedIndex(): number { return this._selectedIndex; }
    get isOpen(): boolean { return this._isOpen; }
    open(): void { this._isOpen = true; this._expandHeight(); this.markDirty(); }
    close(): void { this._isOpen = false; this._restoreHeight(); this.markDirty(); }
    toggle(): void {
        this._isOpen = !this._isOpen;
        if (this._isOpen) { this._expandHeight(); } else { this._restoreHeight(); }
        this.markDirty();
    }

    private _expandHeight(): void {
        this.updateRect({ ...this._rect, height: this._closedHeight + this._options.length });
    }
    private _restoreHeight(): void {
        this.updateRect({ ...this._rect, height: this._closedHeight });
    }

    selectNext(): void {
        let n = this._selectedIndex + 1;
        while (n < this._options.length && this._options[n].disabled) n++;
        if (n < this._options.length) { this._selectedIndex = n; this.markDirty(); }
    }
    selectPrev(): void {
        let n = this._selectedIndex - 1;
        while (n >= 0 && this._options[n].disabled) n--;
        if (n >= 0) { this._selectedIndex = n; this.markDirty(); }
    }
    confirm(): void {
        const opt = this._options[this._selectedIndex];
        if (opt && !opt.disabled) { this._onSelect?.(opt, this._selectedIndex); this._isOpen = false; this._restoreHeight(); this.markDirty(); }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width } = this._rect;
        if (width <= 0) return;
        const attrs = styleToCellAttrs(this.style);
        const sel = this._options[this._selectedIndex];
        const label = sel ? sel.label : this._placeholder;
        const prefix = this._isOpen ? (caps.unicode ? '▼ ' : 'v ') : (caps.unicode ? '▶ ' : '> ');
        screen.writeString(x, y, prefix + label.slice(0, width - 2), { ...attrs, fg: this._activeColor });
        if (this._isOpen) {
            for (let i = 0; i < this._options.length; i++) {
                const o = this._options[i];
                const isSel = i === this._selectedIndex;
                const m = isSel ? (caps.unicode ? '● ' : '* ') : '  ';
                screen.writeString(x, y + 1 + i, m + o.label.slice(0, width - 2), {
                    ...attrs,
                    fg: o.disabled ? { type: 'named' as const, name: 'brightBlack' as const } : isSel ? this._activeColor : attrs.fg,
                    bold: isSel, dim: o.disabled,
                });
            }
        }
    }
}

// Pagination — simple page navigator
import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, type KeyEvent, mergeStyles, defaultStyle, styleToCellAttrs } from '@termuijs/core';

export interface PaginationOptions {
    onChange?: (page: number) => void;
}

export class Pagination extends Widget {
    private _page: number;
    private _totalPages: number;
    private _onChange?: (page: number) => void;
    focusable = true;

    constructor(page: number, totalPages: number, options: PaginationOptions = {}) {
        super(mergeStyles(defaultStyle(), { height: 1 }));
        this._totalPages = Math.max(1, Math.floor(totalPages));
        this._page = this._clamp(Math.floor(page));
        this._onChange = options.onChange;
    }

    get page(): number { return this._page; }
    get totalPages(): number { return this._totalPages; }

    private _clamp(n: number): number {
        if (isNaN(n) || !isFinite(n)) return 1;
        return Math.min(this._totalPages, Math.max(1, n));
    }

    setPage(n: number): void {
        const next = this._clamp(Math.floor(n));
        if (next === this._page) return;
        this._page = next;
        this._onChange?.(this._page);
        this.markDirty();
    }

    next(): void {
        this.setPage(this._page + 1);
    }

    prev(): void {
        this.setPage(this._page - 1);
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'left': this.prev(); break;
            case 'h': if (!event.ctrl && !event.alt) this.prev(); break;
            case 'right': this.next(); break;
            case 'l': if (!event.ctrl && !event.alt) this.next(); break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width } = this._rect;
        if (width <= 0) return;
        const attrs = styleToCellAttrs(this.style);
        const text = `< ${this._page} / ${this._totalPages} >`;
        screen.writeString(x, y, text.slice(0, width), attrs);
    }
}

import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, type KeyEvent, styleToCellAttrs, truncate, caps, splitGraphemes, stringWidth } from '@termuijs/core';
import type { VimMode } from '@termuijs/widgets';

export interface PasswordInputOptions {
    placeholder?: string;
    maxLength?: number;
    onChange?: (value: string) => void;
    onSubmit?: (value: string) => void;
}

export class PasswordInput extends Widget {
    private _value = '';
    private _cursorPos = 0;
    private _placeholder: string;
    private _maxLength: number;
    private _showText = false;
    private _onChange?: (value: string) => void;
    private _onSubmit?: (value: string) => void;
    private _vimMode: VimMode = process.env.TERMUI_KEYBINDINGS === 'vim' ? 'normal' : 'insert';
    focusable = true;

    // '●' in unicode terminals, '*' in ASCII fallback
    private get _maskChar(): string {
        return caps.unicode ? '●' : '*';
    }

    constructor(
        style: Partial<Style> = {},
        options: PasswordInputOptions = {},
    ) {
        super({ border: 'single', height: 3, ...style });
        this._placeholder = options.placeholder ?? '';
        this._maxLength = options.maxLength ?? Infinity;
        this._onChange = options.onChange;
        this._onSubmit = options.onSubmit;

        this.events.on('key', (event: KeyEvent) => this.handleKey(event));
    }

    /** The actual (unmasked) value. */
    get value(): string { return this._value; }

    set value(v: string) {
        const graphemes = splitGraphemes(v);
        if (graphemes.length > this._maxLength) {
            this._value = graphemes.slice(0, this._maxLength).join('');
        } else {
            this._value = v;
        }
        this._cursorPos = Math.min(this._cursorPos, splitGraphemes(this._value).length);
        this.markDirty();
    }

    get vimMode(): VimMode {
        return this._vimMode;
    }

    set vimMode(mode: VimMode) {
        this._vimMode = mode;
        this.markDirty();
    }

    /** Whether the text is currently visible (unmaksed). */
    get showText(): boolean { return this._showText; }

    /** Toggle visibility of the actual text (Alt+V). */
    toggleVisibility(): void {
        this._showText = !this._showText;
        this.markDirty();
    }

    insertChar(char: string): void {
        const graphemes = splitGraphemes(this._value);
        if (graphemes.length >= this._maxLength) return;
        graphemes.splice(this._cursorPos, 0, char);
        this._value = graphemes.join('');
        this._cursorPos++;
        this._onChange?.(this._value);
        this.markDirty();
    }

    deleteBack(): void {
        if (this._cursorPos > 0) {
            const graphemes = splitGraphemes(this._value);
            graphemes.splice(this._cursorPos - 1, 1);
            this._value = graphemes.join('');
            this._cursorPos--;
            this._onChange?.(this._value);
            this.markDirty();
        }
    }

    deleteForward(): void {
        const graphemes = splitGraphemes(this._value);
        if (this._cursorPos < graphemes.length) {
            graphemes.splice(this._cursorPos, 1);
            this._value = graphemes.join('');
            this._onChange?.(this._value);
            this.markDirty();
        }
    }

    moveCursorLeft(): void { this._cursorPos = Math.max(0, this._cursorPos - 1); this.markDirty(); }
    moveCursorRight(): void {
        const graphemes = splitGraphemes(this._value);
        this._cursorPos = Math.min(graphemes.length, this._cursorPos + 1);
        this.markDirty();
    }
    moveCursorHome(): void { this._cursorPos = 0; this.markDirty(); }
    moveCursorEnd(): void {
        const graphemes = splitGraphemes(this._value);
        this._cursorPos = graphemes.length;
        this.markDirty();
    }
    submit(): void { this._onSubmit?.(this._value); }
    clear(): void { this._value = ''; this._cursorPos = 0; this._onChange?.(''); this.markDirty(); }

    /**
     * Handle key events. Call this from your input loop.
     *  Alt+V  — toggle visibility
     *  Other  — standard text editing
     */
    handleKey(event: KeyEvent): void {
        if (event.alt && event.key === 'v') {
            this.toggleVisibility();
            event.preventDefault();
            event.stopPropagation();
            return;
        }

        const isVim = process.env.TERMUI_KEYBINDINGS === 'vim';

        if (isVim) {
            if (this._vimMode === 'normal') {
                switch (event.key) {
                    case 'i':
                        this._vimMode = 'insert';
                        this.markDirty();
                        event.preventDefault();
                        event.stopPropagation();
                        break;
                    case 'a':
                        this._vimMode = 'insert';
                        this.moveCursorRight();
                        this.markDirty();
                        event.preventDefault();
                        event.stopPropagation();
                        break;
                    case 'v':
                        this._vimMode = 'visual';
                        this.markDirty();
                        event.preventDefault();
                        event.stopPropagation();
                        break;
                    case 'h':
                        this.moveCursorLeft();
                        event.preventDefault();
                        event.stopPropagation();
                        break;
                    case 'l':
                        this.moveCursorRight();
                        event.preventDefault();
                        event.stopPropagation();
                        break;
                    case 'x': {
                        const graphemes = splitGraphemes(this._value);
                        if (this._cursorPos < graphemes.length) {
                            graphemes.splice(this._cursorPos, 1);
                            this._value = graphemes.join('');
                            this._cursorPos = Math.min(this._cursorPos, graphemes.length - 1);
                            this._cursorPos = Math.max(0, this._cursorPos);
                            this._onChange?.(this._value);
                            this.markDirty();
                        }
                        event.preventDefault();
                        event.stopPropagation();
                        break;
                    }
                    case 'j':
                        event.key = 'tab';
                        event.shift = false;
                        break;
                    case 'k':
                        event.key = 'tab';
                        event.shift = true;
                        break;
                    case 'enter':
                    case 'return':
                        this.submit();
                        event.preventDefault();
                        event.stopPropagation();
                        break;
                    default:
                        event.preventDefault();
                        event.stopPropagation();
                        break;
                }
                return;
            } else if (this._vimMode === 'visual') {
                if (event.key === 'escape') {
                    this._vimMode = 'normal';
                    this.markDirty();
                    event.preventDefault();
                    event.stopPropagation();
                } else {
                    event.preventDefault();
                    event.stopPropagation();
                }
                return;
            } else if (this._vimMode === 'insert') {
                if (event.key === 'escape') {
                    this._vimMode = 'normal';
                    this.moveCursorLeft();
                    this.markDirty();
                    event.preventDefault();
                    event.stopPropagation();
                    return;
                }
            }
        }

        switch (event.key) {
            case 'backspace':
                this.deleteBack();
                event.preventDefault();
                event.stopPropagation();
                break;
            case 'delete':
                this.deleteForward();
                event.preventDefault();
                event.stopPropagation();
                break;
            case 'left':
                this.moveCursorLeft();
                event.preventDefault();
                event.stopPropagation();
                break;
            case 'right':
                this.moveCursorRight();
                event.preventDefault();
                event.stopPropagation();
                break;
            case 'home':
                this.moveCursorHome();
                event.preventDefault();
                event.stopPropagation();
                break;
            case 'end':
                this.moveCursorEnd();
                event.preventDefault();
                event.stopPropagation();
                break;
            case 'return':
            case 'enter':
                this.submit();
                event.preventDefault();
                event.stopPropagation();
                break;
            default:
                if (event.key && splitGraphemes(event.key).length === 1 && !event.ctrl && !event.alt) {
                    this.insertChar(event.key);
                    event.preventDefault();
                    event.stopPropagation();
                }
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        if (this._value.length === 0 && !this.isFocused) {
            screen.writeString(x, y, truncate(this._placeholder, width), { ...attrs, dim: true });
            return;
        }

        const graphemes = splitGraphemes(this._value);
        const displayGraphemes = this._showText
            ? graphemes
            : Array(graphemes.length).fill(this._maskChar);

        let rightReserved = 0;
        let modeIndicator = '';
        let showTextIndicator = '';
        if (process.env.TERMUI_KEYBINDINGS === 'vim' && this.isFocused && width > 15) {
            modeIndicator = ` -- ${this._vimMode.toUpperCase()} -- `;
            rightReserved = modeIndicator.length;
        } else if (this._showText && width > 4) {
            showTextIndicator = caps.unicode ? ' 👁' : '[v]';
            rightReserved = showTextIndicator.length;
        }

        const maxVisibleWidth = width - rightReserved;
        if (maxVisibleWidth <= 0) return;

        // Calculate visual width prefix sums
        const prefixWidths: number[] = [0];
        for (let i = 0; i < displayGraphemes.length; i++) {
            prefixWidths.push(prefixWidths[i] + stringWidth(displayGraphemes[i]));
        }

        let scrollGraphemeIndex = 0;
        const targetVisualEnd = this._cursorPos < displayGraphemes.length
            ? prefixWidths[this._cursorPos + 1]
            : prefixWidths[this._cursorPos];

        while (scrollGraphemeIndex < this._cursorPos && targetVisualEnd - prefixWidths[scrollGraphemeIndex] > maxVisibleWidth) {
            scrollGraphemeIndex++;
        }

        let endGraphemeIndex = scrollGraphemeIndex;
        while (endGraphemeIndex < displayGraphemes.length && prefixWidths[endGraphemeIndex + 1] - prefixWidths[scrollGraphemeIndex] <= maxVisibleWidth) {
            endGraphemeIndex++;
        }

        const visibleGraphemes = displayGraphemes.slice(scrollGraphemeIndex, endGraphemeIndex);
        const visibleText = visibleGraphemes.join('');
        screen.writeString(x, y, visibleText, attrs);

        if (this.isFocused) {
            const cursorOffset = prefixWidths[this._cursorPos] - prefixWidths[scrollGraphemeIndex];
            const cursorScreenPos = x + cursorOffset;
            if (cursorScreenPos >= x && cursorScreenPos < x + maxVisibleWidth) {
                const cursorChar = this._cursorPos < displayGraphemes.length
                    ? displayGraphemes[this._cursorPos]
                    : ' ';
                const isBlock = this._vimMode === 'normal' || this._vimMode === 'visual';
                screen.setCell(cursorScreenPos, y, {
                    char: cursorChar[0] || ' ',
                    ...attrs,
                    inverse: isBlock,
                    underline: !isBlock,
                });
            }
        }

        if (modeIndicator) {
            screen.writeString(x + width - modeIndicator.length, y, modeIndicator, { ...attrs, dim: true });
        } else if (showTextIndicator) {
            screen.writeString(x + width - showTextIndicator.length, y, showTextIndicator, { ...attrs, dim: true });
        }
    }
}

// ContentSwitcher — show a single active child widget
import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, mergeStyles, defaultStyle } from '@termuijs/core';

export class ContentSwitcher extends Widget {
    private _activeId?: string;

    constructor(style: Partial<Style> = {}) {
        super(mergeStyles(defaultStyle(), style));
    }

    get activeId(): string | undefined {
        return this._activeId;
    }

    override addChild(child: Widget): void {
        super.addChild(child);
        if (this._activeId === undefined) {
            this._activeId = child.id;
        }
        this._updateChildVisibility();
    }

    setActive(id: string): void {
        if (id === this._activeId) return;
        const child = this._children.find((c) => c.id === id);
        if (!child) return;
        this._activeId = id;
        this._updateChildVisibility();
        this.markDirty();
    }

    protected _renderSelf(_screen: Screen): void {
        // Container only
    }

    private _updateChildVisibility(): void {
        for (const child of this._children) {
            child.setStyle({ visible: child.id === this._activeId });
        }
    }
}

// Modal — overlay dialog with backdrop
import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, mergeStyles, defaultStyle, styleToCellAttrs, getBorderChars, caps } from '@termuijs/core';

export interface ModalOptions {
    title?: string;
    width?: number;
    height?: number;
    borderColor?: Style['fg'];
    backdropChar?: string;
}

export class Modal extends Widget {
    private _title: string;
    private _modalWidth: number;
    private _modalHeight: number;
    private _borderColor: Style['fg'];
    private _backdropChar: string;
    private _visible = false;
    private _content: Widget | null = null;

    constructor(options: ModalOptions = {}, style?: Partial<Style>) {
        super(mergeStyles(defaultStyle(), style ?? {}));
        this._title = options.title ?? '';
        this._modalWidth = options.width ?? 50;
        this._modalHeight = options.height ?? 15;
        this._borderColor = options.borderColor ?? { type: 'named', name: 'cyan' };
        this._backdropChar = options.backdropChar ?? (caps.unicode ? '░' : ' ');
    }

    get visible(): boolean { return this._visible; }
    show(): void { this._visible = true; this.markDirty(); }
    hide(): void { this._visible = false; this.markDirty(); }
    toggle(): void { this._visible = !this._visible; this.markDirty(); }
    setContent(content: Widget): void { this._content = content; this.markDirty(); }

    protected _renderSelf(screen: Screen): void {
        if (!this._visible) return;
        const { x, y, width, height } = this._rect;
        const attrs = styleToCellAttrs(this.style);
        // Backdrop
        for (let r = 0; r < height; r++) {
            screen.writeString(x, y + r, this._backdropChar.repeat(width), { ...attrs, dim: true });
        }
        // Centered modal
        const mw = Math.min(this._modalWidth, width - 4);
        const mh = Math.min(this._modalHeight, height - 2);
        const mx = x + Math.floor((width - mw) / 2);
        const my = y + Math.floor((height - mh) / 2);
        const border = getBorderChars('single');
        if (!border) return;
        const bAttrs = { ...attrs, fg: this._borderColor };
        // Title bar
        const titleStr = this._title ? ` ${this._title} ` : '';
        const topFill = mw - 2 - titleStr.length;
        const tl = Math.floor(topFill / 2);
        const tr = topFill - tl;
        screen.writeString(mx, my, border.topLeft + border.top.repeat(tl) + titleStr + border.top.repeat(Math.max(0, tr)) + border.topRight, bAttrs);
        // Sides
        const clr = styleToCellAttrs(this.style);
        for (let r = 1; r < mh - 1; r++) {
            screen.writeString(mx, my + r, border.left, bAttrs);
            screen.writeString(mx + 1, my + r, ' '.repeat(mw - 2), clr);
            screen.writeString(mx + mw - 1, my + r, border.right, bAttrs);
        }
        // Bottom
        screen.writeString(mx, my + mh - 1, border.bottomLeft + border.bottom.repeat(mw - 2) + border.bottomRight, bAttrs);
        // Content
        if (this._content) {
            const cr = { x: mx + 2, y: my + 1, width: mw - 4, height: mh - 2 };
            this._content.updateRect(cr);
            this._content.render(screen);
        }
    }
}

import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, type KeyEvent, mergeStyles, defaultStyle, styleToCellAttrs, caps } from '@termuijs/core';

export interface QuizQuestion {
    question: string;
    options: string[];
    correctIndex: number;
}

export interface QuizResult {
    total: number;
    correct: number;
    answers: number[];
}

export interface QuizPromptOptions {
    correctColor?: Style['fg'];
    wrongColor?: Style['fg'];
    onComplete?: (result: QuizResult) => void;
}

export class QuizPrompt extends Widget {
    private _questions: QuizQuestion[];
    private _currentIndex: number = 0;
    private _selectedIndex: number = -1;
    private _answers: number[] = [];
    private _feedback: 'correct' | 'wrong' | null = null;
    private _feedbackTimeout: ReturnType<typeof setTimeout> | null = null;
    private _correctColor: Style['fg'];
    private _wrongColor: Style['fg'];
    private _onComplete?: (result: QuizResult) => void;
    focusable = true;

    constructor(questions: QuizQuestion[], style?: Partial<Style>, opts?: QuizPromptOptions) {
        super(mergeStyles(defaultStyle(), style ?? {}));
        this._questions = questions;
        this._correctColor = opts?.correctColor ?? { type: 'named', name: 'green' };
        this._wrongColor = opts?.wrongColor ?? { type: 'named', name: 'red' };
        this._onComplete = opts?.onComplete;
    }

    getResult(): QuizResult {
        let correct = 0;
        for (let i = 0; i < this._answers.length; i++) {
            if (this._answers[i] === this._questions[i].correctIndex) {
                correct++;
            }
        }
        return {
            total: this._answers.length,
            correct,
            answers: [...this._answers],
        };
    }

    handleKey(event: KeyEvent): void {
        if (this._currentIndex >= this._questions.length) return;

        const currentQuestion = this._questions[this._currentIndex];
        const optionsCount = currentQuestion.options.length;

        switch (event.key) {
            case 'up':
                if (this._selectedIndex > 0) {
                    this._selectedIndex--;
                    this.markDirty();
                }
                break;
            case 'down':
                if (this._selectedIndex < optionsCount - 1) {
                    this._selectedIndex++;
                    this.markDirty();
                }
                break;
            case 'enter':
                if (this._selectedIndex >= 0 && this._feedback === null) {
                    this.submitAnswer();
                }
                break;
        }
    }

    private submitAnswer(): void {
        const isCorrect = this._selectedIndex === this._questions[this._currentIndex].correctIndex;
        this._answers[this._currentIndex] = this._selectedIndex;

        // Show feedback
        this._feedback = isCorrect ? 'correct' : 'wrong';
        this.markDirty();

        // Clear feedback after a short delay and advance
        if (this._feedbackTimeout) clearTimeout(this._feedbackTimeout);
        this._feedbackTimeout = setTimeout(() => {
            this._feedback = null;
            this._selectedIndex = -1;
            this._currentIndex++;
            this.markDirty();

            if (this._currentIndex >= this._questions.length) {
                this._onComplete?.(this.getResult());
            }

            this._feedbackTimeout = null;
        }, 800);
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this.style);

        if (this._currentIndex >= this._questions.length) {
            // Show completion screen
            const result = this.getResult();
            const scoreText = `Quiz Complete! Score: ${result.correct}/${result.total}`;
            screen.writeString(x, y, scoreText.slice(0, width), attrs);
            return;
        }

        const currentQuestion = this._questions[this._currentIndex];
        let row = 0;

        // Render question
        const questionText = `${this._currentIndex + 1}. ${currentQuestion.question}`;
        screen.writeString(x, y + row, questionText.slice(0, width), { ...attrs, bold: true });
        row += 2;

        // Render options
        for (let i = 0; i < currentQuestion.options.length && row < height; i++) {
            const option = currentQuestion.options[i];
            const isSelected = this._selectedIndex === i;
            const cursor = isSelected ? (caps.unicode ? '❯ ' : '> ') : '  ';
            const indicator = this._feedback !== null && i === currentQuestion.correctIndex && this._feedback === 'correct' ? ' ✓' : '';
            const feedbackColor = this._feedback === 'correct' && i === currentQuestion.correctIndex ? this._correctColor :
                                 this._feedback === 'wrong' && i === this._selectedIndex ? this._wrongColor : attrs.fg;

            const line = `${cursor}${i + 1}. ${option}${indicator}`;
            screen.writeString(x, y + row, line.slice(0, width), {
                ...attrs,
                fg: feedbackColor,
                bold: isSelected,
            });
            row++;
        }

        // Render feedback message
        if (this._feedback === 'correct') {
            screen.writeString(x, y + row, '✓ Correct!'.slice(0, width), { ...attrs, fg: this._correctColor });
        } else if (this._feedback === 'wrong') {
            const correctIndex = currentQuestion.correctIndex;
            const correctText = `✗ Wrong. Correct answer: ${correctIndex + 1}. ${currentQuestion.options[correctIndex]}`;
            screen.writeString(x, y + row, correctText.slice(0, width), { ...attrs, fg: this._wrongColor });
        }
    }
}

// Toast — auto-dismiss notification
import { Widget } from '@termuijs/widgets';
import { type Screen, mergeStyles, defaultStyle, styleToCellAttrs, caps } from '@termuijs/core';

export type ToastType = 'info' | 'success' | 'warning' | 'error';
export interface ToastMessage { text: string; type: ToastType; expireAt: number; }
export interface ToastOptions {
    position?: 'top-right' | 'bottom-right' | 'top-left' | 'bottom-left';
    durationMs?: number;
    maxVisible?: number;
    /** Enable screen reader announcements (default: true) */
    announce?: boolean;
}

const ICONS_UNICODE: Record<ToastType, string> = { info: 'ℹ', success: '✓', warning: '⚠', error: '✗' };
const ICONS_ASCII: Record<ToastType, string> = { info: 'i', success: '+', warning: '!', error: 'x' };
const COLORS: Record<ToastType, string> = { info: 'cyan', success: 'green', warning: 'yellow', error: 'red' };

export class Toast extends Widget {
    private _messages: ToastMessage[] = [];
    private _position: string;
    private _durationMs: number;
    private _maxVisible: number;
    private _announce: boolean;

    constructor(options: ToastOptions = {}) {
        super(mergeStyles(defaultStyle(), {}));
        this._position = options.position ?? 'top-right';
        this._durationMs = options.durationMs ?? 3000;
        this._maxVisible = options.maxVisible ?? 5;
        this._announce = options.announce ?? true;
    }

        push(text: string, type: ToastType = 'info'): void {
        this._messages.push({ text, type, expireAt: Date.now() + this._durationMs });
        this.markDirty();
        if (this._announce) {
            this._announceToScreenReader(text, type);
        }
    }
    info(text: string): void { this.push(text, 'info'); }
    success(text: string): void { this.push(text, 'success'); }
    warning(text: string): void { this.push(text, 'warning'); }
    error(text: string): void { this.push(text, 'error'); }

    private _announceToScreenReader(text: string, _type: ToastType): void {
        try {
            const announcement = `[${text}]`;
            const oscSequence = `\x1b]777;notify;TermUI;${announcement}\x07`;
            process.stderr.write(oscSequence);
        } catch {
            // Silently fail if stderr is not writable
        }
    }
    protected _renderSelf(screen: Screen): void {
        const now = Date.now();
        this._messages = this._messages.filter(m => m.expireAt > now);
        if (this._messages.length === 0) return;
        const { x, y, width, height } = this._rect;
        const visible = this._messages.slice(-this._maxVisible);
        const tw = Math.min(40, width - 2);
        const isRight = this._position.includes('right');
        const isBottom = this._position.includes('bottom');
        const sx = isRight ? x + width - tw - 1 : x + 1;
        const sy = isBottom ? y + height - visible.length - 1 : y + 1;
        const icons = caps.unicode ? ICONS_UNICODE : ICONS_ASCII;
        const attrs = styleToCellAttrs(this.style);
        for (let i = 0; i < visible.length; i++) {
            const m = visible[i];
            const label = ` ${icons[m.type]} ${m.text} `.slice(0, tw).padEnd(tw);
            screen.writeString(sx, sy + i, label, { ...attrs, fg: { type: 'named', name: COLORS[m.type] as any }, bold: true }); // as any: COLORS values are string but Style.name expects NamedColor; types need aligning
        }
    }
}

