        this._appName   = options.appName;
        this._steps     = options.steps;
        this._onComplete = options.onComplete;
        this._onCancel   = options.onCancel;
        this._stepWidgets = options.steps.map(s => s.render());
    }

    get currentStepIndex(): number { return this._currentIndex; }
    get isComplete(): boolean { return this._complete; }

    next(): void {
        if (this._complete) return;
        if (this._currentIndex >= this._steps.length - 1) {
            this._complete = true;
            this._onComplete();
        } else {
            this._currentIndex++;
        }
        this.markDirty();
    }

    prev(): void {
        if (this._currentIndex <= 0) return;
        this._currentIndex--;
        this.markDirty();
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'return': this.next(); break;
            case 'escape': this._onCancel?.(); break;
            case 'left':   this.prev(); break;
            case 'right':  this.next(); break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        let row = y;

        // ── Header ────────────────────────────────────
        const header = ` Setup: ${this._appName} `;
        const headerX = x + Math.max(0, Math.floor((width - stringWidth(header)) / 2));
        screen.writeString(headerX, row, header, { ...attrs, bold: true });
        row++;

        // ── Step progress indicator ────────────────────
        if (row < y + height && this._steps.length > 0) {
            const done = caps.unicode ? '✓' : 'v';
            const curr = caps.unicode ? '►' : '>';
            const sep  = caps.unicode ? '│' : '|';
            const parts = this._steps.map((s, i) => {
                if (i < this._currentIndex) return `${done} ${s.title}`;
                if (i === this._currentIndex) return `${curr} ${s.title}`;
                return `  ${s.title}`;
            });
            const progress = parts.join(`  ${sep}  `);
            screen.writeString(x, row, truncate(progress, width), {
                ...attrs,
                dim: false,
                bold: false,
            });
            row += 2;
        }

        // ── Divider ───────────────────────────────────
        if (row < y + height) {
            screen.writeString(x, row, (caps.unicode ? '─' : '-').repeat(width), { ...attrs, dim: true });
            row++;
        }

        // ── Current step widget ───────────────────────
        if (!this._complete && row < y + height) {
            const stepWidget = this._stepWidgets[this._currentIndex];
            if (stepWidget) {
                const stepHeight = height - (row - y) - 2;
                if (stepHeight > 0) {
                    stepWidget.updateRect({ x, y: row, width, height: stepHeight });
                    stepWidget.render(screen);
                }
            }
        } else if (this._complete) {
            const msg = `${caps.unicode ? '✓' : 'v'} Setup complete!`;
            const msgX = x + Math.max(0, Math.floor((width - stringWidth(msg)) / 2));
            screen.writeString(msgX, row + 2, msg, { ...attrs, bold: true });
        }

        // ── Key hints at bottom ───────────────────────
        const hintRow = y + height - 1;
        if (hintRow > row) {
            const hint = this._complete
                ? '[Enter] Continue'
                : `[Enter] Next  [Esc] Cancel  [${caps.unicode ? '←' : '<'}] Back`;
            screen.writeString(x, hintRow, truncate(hint, width), { ...attrs, dim: true });
        }
    }
}

// DatePicker — calendar date selector widget
import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, type KeyEvent, mergeStyles, defaultStyle, styleToCellAttrs, caps } from '@termuijs/core';

export interface DatePickerOptions {
    value?: Date;
    onChange?: (date: Date) => void;
}

const MONTH_NAMES = [
    'January', 'February', 'March', 'April', 'May', 'June',
    'July', 'August', 'September', 'October', 'November', 'December'
];

export class DatePicker extends Widget {
    private _selectedDate: Date;
    private _currentMonth: Date;
    private _onChange?: (date: Date) => void;
    focusable = true;

    constructor(options: DatePickerOptions = {}) {
        super(mergeStyles(defaultStyle(), { border: 'single', height: 10 }));
        this._selectedDate = options.value ? new Date(options.value) : new Date();
        this._selectedDate.setHours(0, 0, 0, 0);

        this._currentMonth = new Date(this._selectedDate.getFullYear(), this._selectedDate.getMonth(), 1);
        this._onChange = options.onChange;
    }

    get value(): Date {
        return this._selectedDate;
    }

    set value(date: Date) {
        this._selectedDate = new Date(date);
        this._selectedDate.setHours(0, 0, 0, 0);
        this._currentMonth = new Date(this._selectedDate.getFullYear(), this._selectedDate.getMonth(), 1);
        this.markDirty();
    }

    moveSelection(days: number): void {
        const newDate = new Date(this._selectedDate);
        newDate.setDate(newDate.getDate() + days);
        this._selectedDate = newDate;

        if (newDate.getMonth() !== this._currentMonth.getMonth() || newDate.getFullYear() !== this._currentMonth.getFullYear()) {
            this._currentMonth = new Date(newDate.getFullYear(), newDate.getMonth(), 1);
        }
        this.markDirty();
    }

    changeMonth(months: number): void {
        const targetMonth = this._selectedDate.getMonth() + months;
        const targetYear = this._selectedDate.getFullYear();
        const lastDayOfTarget = new Date(targetYear, targetMonth + 1, 0).getDate();
        const clampedDay = Math.min(this._selectedDate.getDate(), lastDayOfTarget);
        const newDate = new Date(targetYear, targetMonth, clampedDay);
        this._selectedDate = newDate;
        this._currentMonth = new Date(newDate.getFullYear(), newDate.getMonth(), 1);
        this.markDirty();
    }

    confirm(): void {
        this._onChange?.(this._selectedDate);
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'left':
            case 'h':
                if (event.key === 'left' || (!event.ctrl && !event.alt)) {
                    this.moveSelection(-1);
                }
                break;
            case 'right':
            case 'l':
                if (event.key === 'right' || (!event.ctrl && !event.alt)) {
                    this.moveSelection(1);
                }
                break;
            case 'up':
            case 'k':
                if (event.key === 'up' || (!event.ctrl && !event.alt)) {
                    this.moveSelection(-7);
                }
                break;
            case 'down':
            case 'j':
                if (event.key === 'down' || (!event.ctrl && !event.alt)) {
                    this.moveSelection(7);
                }
                break;
            case 'pageup':
                this.changeMonth(-1);
                break;
            case 'pagedown':
                this.changeMonth(1);
                break;
            case 'enter':
            case 'return':
                this.confirm();
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        // 1. Render Month Header (◀ Month Year ▶)
        const prevArrow = caps.unicode ? '◀' : '<';
        const nextArrow = caps.unicode ? '▶' : '>';
        const monthName = MONTH_NAMES[this._currentMonth.getMonth()];
        const year = this._currentMonth.getFullYear();
        const title = `${prevArrow} ${monthName} ${year} ${nextArrow}`;
        const titleX = x + Math.floor((width - title.length) / 2);
        screen.writeString(Math.max(x, titleX), y, title, { ...attrs, bold: true });

        if (height < 2) return;

        // 2. Render Weekdays Header
        const weekdays = 'Su Mo Tu We Th Fr Sa';
        const weekdayX = x + Math.floor((width - weekdays.length) / 2);
        screen.writeString(Math.max(x, weekdayX), y + 1, weekdays, { ...attrs, dim: true });

        // 3. Render Calendar Grid (Days)
        const daysInMonth = new Date(year, this._currentMonth.getMonth() + 1, 0).getDate();
        const firstDay = new Date(year, this._currentMonth.getMonth(), 1).getDay();

        const gridStartY = y + 2;
        const maxWeeks = 6;

        for (let w = 0; w < maxWeeks; w++) {
            const rowY = gridStartY + w;
            if (rowY >= y + height) break;

            for (let d = 0; d < 7; d++) {
                const colX = Math.max(x, weekdayX) + d * 3;
                if (colX >= x + width) continue;

                const dayVal = w * 7 + d - firstDay + 1;

                if (dayVal >= 1 && dayVal <= daysInMonth) {
                    const label = String(dayVal).padStart(2, ' ');
                    const isSelected = this._selectedDate.getDate() === dayVal &&
                        this._selectedDate.getMonth() === this._currentMonth.getMonth() &&
                        this._selectedDate.getFullYear() === this._currentMonth.getFullYear();

                    if (isSelected) {
                        screen.writeString(colX, rowY, label, {
                            ...attrs,
                            bold: true,
                            inverse: this.isFocused,
                            underline: !this.isFocused
                        });
                    } else {
                        screen.writeString(colX, rowY, label, attrs);
                    }
                } else {
                    // Blank spacer for out-of-bounds days
                    screen.writeString(colX, rowY, '  ', attrs);
                }
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — TagInput widget
//
// A text input that tokenizes typed entries into removable
// chips (tags).
// - Typing characters appends to the pending draft text
// - enter commits the draft as a chip and clears the draft
// - backspace on an empty draft removes the last chip
// - Committed chips render as bracketed tokens before the
//   draft text
// ─────────────────────────────────────────────────────

import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, type KeyEvent, mergeStyles, defaultStyle, styleToCellAttrs, stringWidth, truncate, caps } from '@termuijs/core';

export interface TagInputOptions {
    placeholder?: string;
    defaultTags?: string[];
    onChange?: (tags: string[]) => void;
}

export class TagInput extends Widget {
    private _tags: string[] = [];
    private _draft = '';
    private _placeholder: string;
    private _onChange?: (tags: string[]) => void;

    focusable = true;

    constructor(
        style: Partial<Style> = {},
        options: TagInputOptions = {},
    ) {
        super(mergeStyles(defaultStyle(), { border: 'single', height: 3, ...style }));
        this._placeholder = options.placeholder ?? '';
        if (options.defaultTags) {
            this._tags = [...options.defaultTags];
        }
        this._onChange = options.onChange;
    }

    /** The current list of committed tags. */
    get tags(): string[] {
        return [...this._tags];
    }

    /** Add a tag to the list. Empty/whitespace-only strings are ignored. */
    addTag(tag: string): void {
        const trimmed = tag.trim();
        if (trimmed.length === 0) return;
        this._tags.push(trimmed);
        this._onChange?.(this.tags);
        this.markDirty();
    }

    /** Remove the last tag from the list. No-op if the list is empty. */
    removeLast(): void {
        if (this._tags.length === 0) return;
        this._tags.pop();
        this._onChange?.(this.tags);
        this.markDirty();
    }

    /**
     * Handle key events. Call this from your input loop.
     */
    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'return':
            case 'enter':
                if (this._draft.trim().length > 0) {
                    this.addTag(this._draft);
                    this._draft = '';
                    this.markDirty();
                }
                break;

            case 'backspace':
                if (this._draft.length > 0) {
                    this._draft = this._draft.slice(0, -1);
                    this.markDirty();
                } else {
                    this.removeLast();
                }
                break;

            default:
                if (event.key && event.key.length === 1 && !event.ctrl && !event.alt) {
                    this._draft += event.key;
                    this.markDirty();
                }
        }
    }

    /** Format a single chip token using caps.unicode for glyph choice. */
    private _formatChip(tag: string): string {
        if (caps.unicode) {
            return ` \u2039${tag}\u203a `;
        }
        return ` [${tag}] `;
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        // Show placeholder when empty
        if (this._tags.length === 0 && this._draft.length === 0) {
            screen.writeString(x, y, truncate(this._placeholder, width), { ...attrs, dim: true });
            return;
        }

        // Build the display string: chips followed by draft
        let display = '';
        for (const tag of this._tags) {
            display += this._formatChip(tag);
        }
        display += this._draft;

        // Handle horizontal scrolling if content exceeds width
        const displayWidth = stringWidth(display);
        const visibleWidth = width;
        let scrollCols = 0;
        if (displayWidth > visibleWidth) {
            scrollCols = displayWidth - visibleWidth;
        }

        // Width-aware slice: iterate graphemes and accumulate until
        // we have skipped scrollCols columns and collected visibleWidth columns.
        const segmenter = new Intl.Segmenter(undefined, { granularity: 'grapheme' });
        let skipped = 0;
        let accumulated = 0;
        let visibleText = '';
        for (const { segment } of segmenter.segment(display)) {
            const w = stringWidth(segment);
            if (skipped < scrollCols) {
                skipped += w;
                continue;
            }
            if (accumulated + w > visibleWidth) break;
            visibleText += segment;
            accumulated += w;
        }

        screen.writeString(x, y, visibleText, attrs);

        // Show cursor at draft position when focused
        if (this.isFocused) {
            const cursorPos = x + displayWidth - scrollCols;
            if (cursorPos >= x && cursorPos < x + width) {
                screen.setCell(cursorPos, y, {
                    char: ' ',
                    ...attrs,
                    inverse: true,
                });
            }
        }
    }
}

// TreeSelect — expandable tree with single or multi selection
import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, type KeyEvent, mergeStyles, defaultStyle, styleToCellAttrs, caps } from '@termuijs/core';

export interface TreeSelectNode {
    label: string;
    value: string;
    children?: TreeSelectNode[];
    expanded?: boolean;
}

export interface TreeSelectOptions {
    multiple?: boolean;
    activeColor?: Style['fg'];
    onChange?: (values: string[]) => void;
}

export class TreeSelect extends Widget {
    private _roots: TreeSelectNode[];
    private _cursorIndex = 0;
    private _selected = new Set<string>();
    private _multiple: boolean;
    private _activeColor: Style['fg'];
    private _onChange?: (values: string[]) => void;
    focusable = true;

    constructor(roots: TreeSelectNode[], options: TreeSelectOptions = {}) {
        super(mergeStyles(defaultStyle(), { flexGrow: 1 }));
        this._roots = roots;
        this._multiple = options.multiple ?? false;
        this._activeColor = options.activeColor ?? { type: 'named', name: 'cyan' };
        this._onChange = options.onChange;
    }

    get selectedValues(): string[] {
        return [...this._selected];
    }

    private _flatten(): { node: TreeSelectNode; depth: number; path: number[]; hasChildren: boolean }[] {
        const result: { node: TreeSelectNode; depth: number; path: number[]; hasChildren: boolean }[] = [];
        const walk = (nodes: TreeSelectNode[], depth: number, path: number[]) => {
            for (let i = 0; i < nodes.length; i++) {
                const node = nodes[i];
                const hasChildren = (node.children?.length ?? 0) > 0;
                result.push({ node, depth, path: [...path, i], hasChildren });
                if (hasChildren && node.expanded) walk(node.children!, depth + 1, [...path, i]);
            }
        };
        walk(this._roots, 0, []);
        return result;
    }

    selectNext(): void {
        const f = this._flatten();
        if (this._cursorIndex < f.length - 1) {
            this._cursorIndex++;
            this.markDirty();
        }
    }

    selectPrev(): void {
        if (this._cursorIndex > 0) {
            this._cursorIndex--;
            this.markDirty();
        }
    }

    expand(): void {
        const f = this._flatten();
        const it = f[this._cursorIndex];
        if (it?.hasChildren && !it.node.expanded) {
            it.node.expanded = true;
            this.markDirty();
        }
    }

    collapse(): void {
        const f = this._flatten();
        const it = f[this._cursorIndex];
        if (!it) return;

        if (it.hasChildren && it.node.expanded) {
            it.node.expanded = false;
            this.markDirty();
            return;
        }

        if (it.depth > 0) {
            const parentPath = it.path.slice(0, -1);
            const parentIdx = f.findIndex(entry => _pathsEqual(entry.path, parentPath));
            if (parentIdx >= 0) {
                this._cursorIndex = parentIdx;
                this.markDirty();
            }
        }
    }

    toggleSelection(): void {
        const f = this._flatten();
        const it = f[this._cursorIndex];
        if (!it) return;

        const value = it.node.value;
        const previous = this.selectedValues;

        if (this._multiple) {
            if (this._selected.has(value)) {
                this._selected.delete(value);
            } else {
                this._selected.add(value);
            }
        } else if (this._selected.has(value)) {
            this._selected.clear();
        } else {
            this._selected.clear();
            this._selected.add(value);
        }

        this.markDirty();
        const next = this.selectedValues;
        if (!_valuesEqual(previous, next)) {
            this._onChange?.(next);
        }
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'down':
                this.selectNext();
                break;
            case 'up':
                this.selectPrev();
                break;
            case 'right':
                this.expand();
                break;
            case 'left':
                this.collapse();
                break;
            case 'space':
                this.toggleSelection();
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this.style);
        const flat = this._flatten();
        const expandCollapsed = caps.unicode ? '▶ ' : '> ';
        const expandExpanded = caps.unicode ? '▼ ' : 'v ';
        const selectedMarker = caps.unicode ? '● ' : '* ';
        const unselectedMarker = caps.unicode ? '○ ' : 'o ';

        for (let i = 0; i < flat.length && i < height; i++) {
            const it = flat[i];
            const active = i === this._cursorIndex;
            const indent = '  '.repeat(it.depth);
            const expandIcon = it.hasChildren
                ? (it.node.expanded ? expandExpanded : expandCollapsed)
                : '  ';
            const selectIcon = this._selected.has(it.node.value) ? selectedMarker : unselectedMarker;
            const line = `${indent}${expandIcon}${selectIcon}${it.node.label}`;
            screen.writeString(x, y + i, line.slice(0, width), {
                ...attrs,
                fg: active ? this._activeColor : attrs.fg,
                bold: active,
            });
        }
    }
}

function _pathsEqual(a: number[], b: number[]): boolean {
    if (a.length !== b.length) return false;
    for (let i = 0; i < a.length; i++) {
        if (a[i] !== b[i]) return false;
    }
    return true;
}

function _valuesEqual(a: string[], b: string[]): boolean {
    if (a.length !== b.length) return false;
    const sortedA = [...a].sort();
    const sortedB = [...b].sort();
    for (let i = 0; i < sortedA.length; i++) {
        if (sortedA[i] !== sortedB[i]) return false;
    }
    return true;
}

// Pages — named page container with optional overlay behavior
import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, mergeStyles, defaultStyle } from '@termuijs/core';

export interface Page {
    name: string;
    content: Widget;
    overlay?: boolean;
}

export interface PagesOptions {
    style?: Partial<Style>;
}

export class Pages extends Widget {
    private _pages: Page[];
    private _activePageName?: string;

    constructor(pages: Page[], options: PagesOptions = {}) {
        super(mergeStyles(defaultStyle(), options.style ?? { flexGrow: 1 }));
        this._pages = pages;
        for (const page of pages) {
            this.addChild(page.content);
        }
        this._activePageName = pages[0]?.name;
        this._updatePageVisibility();
    }

    get activePage(): string | undefined {
        return this._activePageName;
    }

    switchTo(name: string): void {
        const page = this._pages.find((item) => item.name === name);
        if (!page || page.name === this._activePageName) return;
        this._activePageName = page.name;
        this._updatePageVisibility();
        this.markDirty();
    }

    protected _renderSelf(_screen: Screen): void {
        // Container only
    }

    private _updatePageVisibility(): void {
        const active = this._pages.find((item) => item.name === this._activePageName) ?? this._pages[0];
        const base = this._pages[0];

        for (const page of this._pages) {
            const shouldShow = page === active || (active?.overlay === true && page === base && page !== active);
            page.content.setStyle({ visible: shouldShow });
        }
    }
}

// Form — compound input container with validation
import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, type KeyEvent, mergeStyles, defaultStyle, styleToCellAttrs } from '@termuijs/core';
import { validateInput, type InputValidator } from '@termuijs/ui';

export interface FormField {
    name: string; label: string; type: 'text' | 'select' | 'checkbox';
    placeholder?: string; required?: boolean; options?: string[];
    validate?: InputValidator;
}
export interface FormOptions {
    labelColor?: Style['fg']; errorColor?: Style['fg']; activeColor?: Style['fg'];
    onSubmit?: (values: Record<string, string>) => void;
}

export class Form extends Widget {
    private _fields: FormField[];
    private _values: Map<string, string> = new Map();
    private _errors: Map<string, string> = new Map();
    private _activeField = 0;
    private _cursorPos = 0;
    private _labelColor: Style['fg'];
    private _errorColor: Style['fg'];
    private _activeColor: Style['fg'];
    private _onSubmit?: (values: Record<string, string>) => void;
    private _isValidating = false;
    focusable = true;

    constructor(fields: FormField[], options: FormOptions = {}) {
        super(mergeStyles(defaultStyle(), { height: fields.length * 2 + 1, flexGrow: 1 }));
        this._fields = fields;
        this._labelColor = options.labelColor ?? { type: 'named', name: 'cyan' };
        this._errorColor = options.errorColor ?? { type: 'named', name: 'red' };
        this._activeColor = options.activeColor ?? { type: 'named', name: 'cyan' };
        this._onSubmit = options.onSubmit;
        for (const f of fields) this._values.set(f.name, '');
        // Wire key events from the App/event system into this widget's handlers.
        // Minimal: only route printable chars and backspace to existing methods.
        this.events.on('key', (event: KeyEvent) => this.handleKey(event));
    }

    get values(): Record<string, string> { const r: Record<string, string> = {}; for (const [k, v] of this._values) r[k] = v; return r; }
    nextField(): void { if (this._activeField < this._fields.length) { this._activeField++; this._cursorPos = 0; this.markDirty(); } }
    prevField(): void { if (this._activeField > 0) { this._activeField--; this._cursorPos = (this._values.get(this._fields[this._activeField].name) ?? '').length; this.markDirty(); } }
    insertChar(ch: string): void {
        if (this._activeField >= this._fields.length) return;
        const f = this._fields[this._activeField]; const cur = this._values.get(f.name) ?? '';
        this._values.set(f.name, cur.slice(0, this._cursorPos) + ch + cur.slice(this._cursorPos));
        this._cursorPos++; this._errors.delete(f.name); this.markDirty();
    }
    deleteBack(): void {
        if (this._activeField >= this._fields.length) return;
        const f = this._fields[this._activeField]; const cur = this._values.get(f.name) ?? '';
        if (this._cursorPos > 0) { this._values.set(f.name, cur.slice(0, this._cursorPos - 1) + cur.slice(this._cursorPos)); this._cursorPos--; this.markDirty(); }
    }
    async submit(): Promise<void> {
        this._errors.clear();
        this._isValidating = true;
        this.markDirty();

        let hasErr = false;

        const validationPromises = this._fields.map(async (f) => {
            const v = this._values.get(f.name) ?? '';
            if (f.required && !v.trim()) {
                return { name: f.name, err: `${f.label} is required` };
            }
            const e = await validateInput(f.validate, v);
            return { name: f.name, err: e };
        });

        const results = await Promise.all(validationPromises);

        for (const { name, err } of results) {
            if (err) {
                this._errors.set(name, err);
                hasErr = true;
            }
        }

        this._isValidating = false;
        if (!hasErr) this._onSubmit?.(this.values);
        this.markDirty();
    }

    /** Minimal key router — printable chars -> insertChar, backspace -> deleteBack */
    handleKey(event: KeyEvent): void {
        if (event.key === 'backspace') {
            this.deleteBack();
            return;
        }

        if (event.key && event.key.length === 1 && !event.ctrl && !event.alt) {
            this.insertChar(event.key);
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;
        const attrs = styleToCellAttrs(this.style);
        let row = 0;
        for (let i = 0; i < this._fields.length && row < height - 1; i++) {
            const f = this._fields[i]; const active = i === this._activeField;
            const val = this._values.get(f.name) ?? ''; const err = this._errors.get(f.name);
            screen.writeString(x, y + row, `${f.label}${f.required ? ' *' : ''}:`.slice(0, width), { ...attrs, fg: err ? this._errorColor : this._labelColor, bold: active }); row++;
            if (row >= height) break;
            const display = val || (f.placeholder ?? '');
            const msg = err ? `  - ${err}` : '';
            const displayText = `${active ? '❯ ' : '  '}${display}${msg}`;
            screen.writeString(x, y + row, displayText.slice(0, width), { ...attrs, fg: active ? this._activeColor : attrs.fg, dim: !val && !!f.placeholder }); row++;
        }
        if (row < height) {
            const isSub = this._activeField >= this._fields.length;
            if (this._isValidating) {
                screen.writeString(x, y + row, '  [ Validating... ]', { ...attrs, fg: { type: 'named', name: 'yellow' } });
            } else {
                screen.writeString(x, y + row, isSub ? '  [ Submit ]' : '    Submit  ', { ...attrs, fg: isSub ? { type: 'named', name: 'green' } : attrs.fg, bold: isSub });
            }
        }
    }
}

import { Widget } from '@termuijs/widgets';
import {
    type Style,
    type Screen,
    type KeyEvent,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    stringWidth,
    truncate,
} from '@termuijs/core';

export interface MenuItem {
    label: string;
    shortcut?: string;
    disabled?: boolean;
    onSelect?: () => void;
}

export interface MenuOptions {
    items: MenuItem[];
    onClose?: () => void;
    style?: Partial<Style>;
}

/**
 * Menu — a vertical list of interactive items supporting keyboard navigation,
 * shortcuts, and disabled states.
 */
export class Menu extends Widget {
    private _items: MenuItem[];
    private _selectedIndex = 0;
    private _onClose?: () => void;

    constructor(options: MenuOptions) {
        super(mergeStyles(defaultStyle(), {
            padding: 0,
            ...options.style
        }));
        this._items = options.items;
        this._onClose = options.onClose;
        this.focusable = true;

        // Initialize selection to the first enabled item
        this._initSelection();
    }

    private _initSelection(): void {
        for (let i = 0; i < this._items.length; i++) {
            if (!this._items[i].disabled) {
                this._selectedIndex = i;
                break;
            }
        }
    }

    private _selectNext(): void {
        const start = this._selectedIndex;
        let next = (this._selectedIndex + 1) % this._items.length;

        while (next !== start && this._items[next].disabled) {
            next = (next + 1) % this._items.length;
        }

        if (next !== start && !this._items[next].disabled) {
            this._selectedIndex = next;
            this.markDirty();
        }
    }

    private _selectPrev(): void {
        const start = this._selectedIndex;
        let next = (this._selectedIndex - 1 + this._items.length) % this._items.length;

        while (next !== start && this._items[next].disabled) {
            next = (next - 1 + this._items.length) % this._items.length;
        }

        if (next !== start && !this._items[next].disabled) {
            this._selectedIndex = next;
            this.markDirty();
        }
    }

    private _confirm(): void {
        const item = this._items[this._selectedIndex];
        if (item && !item.disabled) {
            item.onSelect?.();
            // No markDirty — selection did not change
        }
    }

    handleKey(event: KeyEvent): boolean {
        switch (event.key) {
            case 'up':
                this._selectPrev();
                return true;
            case 'down':
                this._selectNext();
                return true;
            case 'home': {
                const first = this._items.findIndex(i => !i.disabled);
                if (first >= 0 && first !== this._selectedIndex) {
                    this._selectedIndex = first;
                    this.markDirty();
                }
                return true;
            }
            case 'end': {
                let last = -1;
                for (let i = this._items.length - 1; i >= 0; i--) {
                    if (!this._items[i].disabled) { last = i; break; }
                }
                if (last >= 0 && last !== this._selectedIndex) {
                    this._selectedIndex = last;
                    this.markDirty();
                }
                return true;
            }
            case 'enter':
            case 'space':
                this._confirm();
                return true;
            case 'escape':
                this._onClose?.();
                // No markDirty — widget is being closed
                return true;
        }
        return false;
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const baseAttrs = styleToCellAttrs(this.style);

        for (let i = 0; i < this._items.length; i++) {
            if (i >= height) break;

            const item = this._items[i];
            const isSelected = i === this._selectedIndex;

            // Highlight selected row
            const rowStyle = {
                ...baseAttrs,
                fg: item.disabled ? { type: 'named' as const, name: 'brightBlack' as const } : baseAttrs.fg,
                bg: isSelected ? { type: 'named' as const, name: 'cyan' as const } : baseAttrs.bg,
                bold: isSelected,
                dim: item.disabled,
            };

            // Clear row
            screen.writeString(x, y + i, ' '.repeat(width), rowStyle);

            // Render label
            const label = truncate(item.label, width - 2);
            screen.writeString(x + 1, y + i, label, rowStyle);

            // Render shortcut if space allows
            if (item.shortcut) {
                const shortcut = item.shortcut;
                const shortcutWidth = stringWidth(shortcut);
                if (width > stringWidth(label) + shortcutWidth + 4) {
                    screen.writeString(x + width - shortcutWidth - 1, y + i, shortcut, {
                        ...rowStyle,
                        fg: isSelected ? rowStyle.fg : { type: 'named', name: 'brightBlack' }
                    });
                }
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — SearchInput component
//
// A text input with a search-icon prefix, debounced
// onSearch, and Escape-to-clear.
// ─────────────────────────────────────────────────────

import { Widget } from '@termuijs/widgets';
import {
    type Screen,
    type KeyEvent,
    type Style,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    truncate,
    caps,
    stringWidth,
} from '@termuijs/core';

export interface SearchInputOptions {
    placeholder?: string;
    debounce?: number;
    onSearch?: (value: string) => void;
}

export class SearchInput extends Widget {
    private _value = '';
    private _placeholder: string;
    private _debounce: number;
    onSearch?: (value: string) => void;

    private _debounceTimer: ReturnType<typeof setTimeout> | null = null;

    focusable = true;

    constructor(options: SearchInputOptions = {}) {
        super(mergeStyles(defaultStyle(), { height: 1 }));
        this._placeholder = options.placeholder ?? '';
        this._debounce = options.debounce ?? 300;
        this.onSearch = options.onSearch;
    }

    get value(): string { return this._value; }

    setValue(value: string): void {
        if (this._value === value) return;
        this._value = value;
        this.markDirty();
        this._scheduleSearch();
    }

    clear(): void {
        if (this._value === '' && this._debounceTimer === null) return;
        this._value = '';
        this._cancelDebounce();
        this.markDirty();
        this.onSearch?.('');
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'escape':
                this.clear();
                break;
            case 'backspace':
                if (this._value.length > 0) {
                    this._value = this._value.slice(0, -1);
                    this.markDirty();
                    this._scheduleSearch();
                }
                break;
            default:
                // Single printable character, no modifier keys held
                if (
                    event.key.length === 1
                    && !event.ctrl
                    && !event.alt
                ) {
                    this._value += event.key;
                    this.markDirty();
                    this._scheduleSearch();
                }
                break;
        }
    }

    private _scheduleSearch(): void {
        this._cancelDebounce();
        const value = this._value;
        this._debounceTimer = setTimeout(() => {
            this._debounceTimer = null;
            this.onSearch?.(value);
        }, this._debounce);
    }

    private _cancelDebounce(): void {
        if (this._debounceTimer !== null) {
            clearTimeout(this._debounceTimer);
            this._debounceTimer = null;
        }
    }

    override destroy(): void {
        this._cancelDebounce();
        super.destroy();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this.style);
        const icon = caps.unicode ? '🔍' : '/';
        const prefix = `${icon} `;
        const prefixWidth = stringWidth(prefix);

        const valueOrPlaceholder = this._value.length > 0
            ? this._value
            : this._placeholder;

        const valueAttrs = this._value.length > 0
            ? attrs
            : { ...attrs, dim: true };

        const available = Math.max(0, width - prefixWidth);
        const valueText = truncate(valueOrPlaceholder, available);

        screen.writeString(x, y, prefix, attrs);
        if (valueText.length > 0) {
            screen.writeString(x + prefixWidth, y, valueText, valueAttrs);
        }
    }
}

import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, type KeyEvent, mergeStyles, defaultStyle, styleToCellAttrs } from '@termuijs/core';

export interface TimePickerOptions {
    value?: Date;
    onChange?: (date: Date) => void;
    use24Hour?: boolean;
}

export class TimePicker extends Widget {
    private _date: Date;
    private _use24Hour: boolean;
    private _activeSegment: number = 0; // 0: Hours, 1: Minutes, 2: AM/PM
    private _onChange?: (date: Date) => void;
    focusable = true;

    constructor(options: TimePickerOptions = {}) {
        super(mergeStyles(defaultStyle(), { border: 'single', height: 3 }));
        this._date = options.value ? new Date(options.value) : new Date();
        this._use24Hour = options.use24Hour ?? false;
        this._onChange = options.onChange;
    }

    get value(): Date {
        return this._date;
    }

    set value(val: Date) {
        this._date = new Date(val);
        this.markDirty();
    }

    private _updateSegment(delta: number): void {
        const d = new Date(this._date);
        if (this._activeSegment === 0) {
            d.setHours(d.getHours() + delta);
        } else if (this._activeSegment === 1) {
            d.setMinutes(d.getMinutes() + delta);
        } else if (this._activeSegment === 2) {
            const h = d.getHours();
            if (h >= 12) {
                d.setHours(h - 12);
            } else {
                d.setHours(h + 12);
            }
        }
        this._date = d;
        this.markDirty();
        this._onChange?.(this._date);
    }

    private _nextSegment(delta: number): void {
        this._activeSegment += delta;
        const max = this._use24Hour ? 1 : 2;
        if (this._activeSegment < 0) this._activeSegment = 0;
        if (this._activeSegment > max) this._activeSegment = max;
        this.markDirty();
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'left':
            case 'h':
                this._nextSegment(-1);
                break;
            case 'right':
            case 'l':
                this._nextSegment(1);
                break;
            case 'up':
            case 'k':
                this._updateSegment(1);
                break;
            case 'down':
            case 'j':
                this._updateSegment(-1);
                break;
            case 'enter':
            case 'return':
                this._onChange?.(this._date);
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        let h = this._date.getHours();
        const m = this._date.getMinutes();
        const isPM = h >= 12;

        let ampmStr = "";
        if (!this._use24Hour) {
            if (h === 0) h = 12;
            else if (h > 12) h -= 12;
            ampmStr = isPM ? " PM" : " AM";
        }

        const hStr = String(h).padStart(2, '0');
        const mStr = String(m).padStart(2, '0');

        const totalWidth = 2 + 1 + 2 + (this._use24Hour ? 0 : 3);
        const startX = x + Math.max(0, Math.floor((width - totalWidth) / 2));
        const centerY = y + Math.floor(height / 2);

        screen.writeString(startX, centerY, hStr, {
            ...attrs,
            inverse: this.isFocused && this._activeSegment === 0
        });

        screen.writeString(startX + 2, centerY, ":", attrs);

        screen.writeString(startX + 3, centerY, mStr, {
            ...attrs,
            inverse: this.isFocused && this._activeSegment === 1
        });

        if (!this._use24Hour) {
            screen.writeString(startX + 5, centerY, ampmStr, {
                ...attrs,
                inverse: this.isFocused && this._activeSegment === 2
            });
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — Wizard widget
//
// A multi-step form flow wizard.
// ─────────────────────────────────────────────────────

import { Widget } from '@termuijs/widgets';
import {
    type Style,
    type Screen,
    type KeyEvent,
    mergeStyles,
    defaultStyle,
    normalizeEdges,
    styleToCellAttrs,
    truncate,
} from '@termuijs/core';

export interface WizardStep {
    title: string;
    render: () => Widget;
    validate?: () => boolean | string;
}

export interface WizardOptions {
    style?: Partial<Style>;
    onComplete?: (stepData: unknown[]) => void;
}

export class Wizard extends Widget {
    private _steps: WizardStep[];
    private _stepWidgets: Widget[];
    private _currentStepIndex = 0;
    private _error = '';
    private _onComplete?: (stepData: unknown[]) => void;
    focusable = true;

    constructor(steps: WizardStep[], options: WizardOptions = {}) {
        const topPadding = 2;
        const userPadding = normalizeEdges(options.style?.padding);
        const style = mergeStyles(defaultStyle(), {
            flexDirection: 'column',
            flexGrow: 1,
            ...options.style,
            padding: {
                top: topPadding,
                right: userPadding.right,
                bottom: userPadding.bottom,
                left: userPadding.left,
            },
        });
        super(style);
        this._steps = steps;
        this._onComplete = options.onComplete;

        // Instantiate all step widgets so widget state persists while navigating
        this._stepWidgets = steps.map((s) => s.render());

        // Keep only the active widget attached as a child
        if (this._stepWidgets[0]) {
            this.addChild(this._stepWidgets[0]);
        }

        // Register default key listener
        this.events.on('key', (event) => this.handleKey(event));
    }

    get currentStepIndex(): number {
        return this._currentStepIndex;
    }

    get error(): string {
        return this._error;
    }

    get stepWidgets(): ReadonlyArray<Widget> {
        return this._stepWidgets;
    }

    nextStep(): void {
        const step = this._steps[this._currentStepIndex];
        if (step && step.validate) {
            const validationResult = step.validate();
            if (typeof validationResult === 'string') {
                this._error = validationResult;
                this.markDirty();
                return;
            } else if (validationResult === false) {
                // block silently
                this.markDirty();
                return;
            }
        }

        // Validation passed
        this._error = '';
        if (this._currentStepIndex < this._steps.length - 1) {
            this._showStep(this._currentStepIndex + 1);
        }
    }

    prevStep(): void {
        this._error = '';
        if (this._currentStepIndex > 0) {
            this._showStep(this._currentStepIndex - 1);
        }
    }

    complete(): void {
        this._onComplete?.(this._getStepData());
    }

    private _showStep(index: number): void {
        const currentWidget = this._stepWidgets[this._currentStepIndex];
        if (currentWidget) {
            this.removeChild(currentWidget);
        }
        this._currentStepIndex = index;
        const nextWidget = this._stepWidgets[index];
        if (nextWidget) {
            this.addChild(nextWidget);
        }
        this.markDirty();
    }

    private _getStepData(): unknown[] {
        return this._stepWidgets.map((widget) => {
            if ('value' in widget) {
                return (widget as { value: unknown }).value;
            }
            if ('values' in widget) {
                return (widget as { values: unknown }).values;
            }
            if ('numericValue' in widget) {
                return (widget as { numericValue: unknown }).numericValue;
            }
            if ('selectedOption' in widget) {
                return (widget as { selectedOption: unknown }).selectedOption;
            }
            if ('selectedOptions' in widget) {
                return (widget as { selectedOptions: unknown }).selectedOptions;
            }
            return undefined;
        });
    }

    handleKey(event: KeyEvent): void {
        if (event._propagationStopped || event._defaultPrevented) return;

        // Bypassing letters if an input widget is focused within the active step
        const isFocusInInput = (widget: Widget): boolean => {
            if (widget.isFocused && ('insertChar' in widget || 'value' in widget)) {
                return true;
            }
            for (const child of widget.children) {
                if (isFocusInInput(child)) return true;
            }
            return false;
        };

        const activeWidget = this._stepWidgets[this._currentStepIndex];
        const inputFocused = activeWidget ? isFocusInInput(activeWidget) : false;

        switch (event.key) {
            case 'right':
                if (!inputFocused) {
                    this.nextStep();
                    event.stopPropagation?.();
                }
                break;
            case 'n':
                if (!event.ctrl && !event.alt && !inputFocused) {
                    this.nextStep();
                    event.stopPropagation?.();
                }
                break;
            case 'left':
                if (!inputFocused) {
                    this.prevStep();
                    event.stopPropagation?.();
                }
                break;
            case 'b':
                if (!event.ctrl && !event.alt && !inputFocused) {
                    this.prevStep();
                    event.stopPropagation?.();
                }
                break;
            case 'enter':
            case 'return':
                if (this._currentStepIndex === this._steps.length - 1) {
                    this.complete();
                    event.stopPropagation?.();
                }
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this.style);
        const border = this._style.border && this._style.border !== 'none' ? 1 : 0;

        const step = this._steps[this._currentStepIndex];
        if (!step) return;

        const stepNum = this._currentStepIndex + 1;
        const total = this._steps.length;
        const indicatorText = `Step ${stepNum} of ${total}: ${step.title}`;
        const contentWidth = Math.max(0, width - border * 2);

        // Write the step indicator on row 0 of the content area
        screen.writeString(
            x + border,
            y + border,
            truncate(indicatorText, contentWidth),
            { ...attrs, bold: true }
        );

        // Write validation error if present on row 1 of the content area
        if (this._error) {
            screen.writeString(
                x + border,
                y + border + 1,
                truncate(this._error, contentWidth),
                { ...attrs, fg: { type: 'named', name: 'red' } }
            );
        } else {
            // Write blank line to clear any old error
            screen.writeString(
                x + border,
                y + border + 1,
                ' '.repeat(contentWidth),
                attrs
            );
        }
    }
}

// Transfer — dual-list shuttle selector widget
import { Widget } from '@termuijs/widgets';
import {
    type Style,
    type Screen,
    type KeyEvent,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    caps,
} from '@termuijs/core';

export interface TransferItem {
    label: string;
    value: string;
    disabled?: boolean;
}

export interface TransferOptions {
    activeColor?: Style['fg'];
    onChange?: (targetValues: string[]) => void;
}

export class Transfer extends Widget {
    private _sourceItems: TransferItem[];
    private _targetItems: TransferItem[] = [];
    private _sourceCursorIndex = 0;
    private _targetCursorIndex = 0;
    private _activePane: 'source' | 'target' = 'source';
    private _activeColor: Style['fg'];
    private _onChange?: (targetValues: string[]) => void;
    focusable = true;

    constructor(items: TransferItem[], config: TransferOptions = {}) {
        super(mergeStyles(defaultStyle(), { height: Math.max(items.length, 1) }));
        this._sourceItems = [...items];
        this._activeColor = config.activeColor ?? { type: 'named', name: 'cyan' };
        this._onChange = config.onChange;
        this._clampCursors();
    }

    get targetValues(): string[] {
        return this._targetItems.map(item => item.value);
    }

    get sourceValues(): string[] {
        return this._sourceItems.map(item => item.value);
    }

    get targetItems(): TransferItem[] {
        return [...this._targetItems];
    }

    get sourceItems(): TransferItem[] {
        return [...this._sourceItems];
    }

    get activePane(): 'source' | 'target' {
        return this._activePane;
    }

    get sourceCursorIndex(): number {
        return this._sourceCursorIndex;
    }

    get targetCursorIndex(): number {
        return this._targetCursorIndex;
    }

    toggleActivePane(): void {
        this._activePane = this._activePane === 'source' ? 'target' : 'source';
        this.markDirty();
    }

    private _clampCursors(): void {
        if (this._sourceItems.length === 0) {
            this._sourceCursorIndex = 0;
        } else {
            this._sourceCursorIndex = Math.max(0, Math.min(this._sourceCursorIndex, this._sourceItems.length - 1));
        }

        if (this._targetItems.length === 0) {
            this._targetCursorIndex = 0;
        } else {
            this._targetCursorIndex = Math.max(0, Math.min(this._targetCursorIndex, this._targetItems.length - 1));
        }
    }

    selectNext(): void {
        if (this._activePane === 'source') {
            let n = this._sourceCursorIndex + 1;
            while (n < this._sourceItems.length && this._sourceItems[n].disabled) n++;
            if (n < this._sourceItems.length) {
                this._sourceCursorIndex = n;
                this.markDirty();
            }
        } else {
            let n = this._targetCursorIndex + 1;
            while (n < this._targetItems.length && this._targetItems[n].disabled) n++;
            if (n < this._targetItems.length) {
                this._targetCursorIndex = n;
                this.markDirty();
            }
        }
    }

    selectPrev(): void {
        if (this._activePane === 'source') {
            let n = this._sourceCursorIndex - 1;
            while (n >= 0 && this._sourceItems[n].disabled) n--;
            if (n >= 0) {
                this._sourceCursorIndex = n;
                this.markDirty();
            }
        } else {
            let n = this._targetCursorIndex - 1;
            while (n >= 0 && this._targetItems[n].disabled) n--;
            if (n >= 0) {
                this._targetCursorIndex = n;
                this.markDirty();
            }
        }
    }

    transferToTarget(): void {
        if (this._sourceItems.length === 0) return;
        const item = this._sourceItems[this._sourceCursorIndex];
        if (item.disabled) return;

        this._sourceItems.splice(this._sourceCursorIndex, 1);
        this._targetItems.push(item);

        this._clampCursors();
        this.markDirty();
        this._onChange?.(this.targetValues);
    }

    transferToSource(): void {
        if (this._targetItems.length === 0) return;
        const item = this._targetItems[this._targetCursorIndex];
        if (item.disabled) return;

        this._targetItems.splice(this._targetCursorIndex, 1);
        this._sourceItems.push(item);

        this._clampCursors();
        this.markDirty();
        this._onChange?.(this.targetValues);
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'up':
                this.selectPrev();
                break;
            case 'down':
                this.selectNext();
                break;
            case 'tab':
                this.toggleActivePane();
                break;
            case 'right':
                if (this._activePane === 'source') {
                    this.transferToTarget();
                }
                break;
            case 'left':
                if (this._activePane === 'target') {
                    this.transferToSource();
                }
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this.style);

        const leftPaneWidth = Math.floor((width - 1) / 2);
        const rightPaneWidth = width - 1 - leftPaneWidth;
        if (leftPaneWidth < 0 || rightPaneWidth < 0) return;

        const dividerX = x + leftPaneWidth;
        const dividerChar = caps.unicode ? '│' : '|';
        const indicator = caps.unicode ? '❯ ' : '> ';
        const noIndicator = ' '.repeat(indicator.length);

        for (let i = 0; i < height; i++) {
            // 1. Left pane (source)
            if (i < this._sourceItems.length) {
                const o = this._sourceItems[i];
                const active = this._activePane === 'source' && i === this._sourceCursorIndex;
                const text = (active ? indicator : noIndicator) + o.label;
                const truncatedText = text.slice(0, leftPaneWidth).padEnd(leftPaneWidth, ' ');
                screen.writeString(x, y + i, truncatedText, {
                    ...attrs,
                    fg: o.disabled ? { type: 'named' as const, name: 'brightBlack' as const } : active ? this._activeColor : attrs.fg,
                    bold: active,
                    dim: o.disabled,
                });
            } else {
                screen.writeString(x, y + i, ' '.repeat(leftPaneWidth), attrs);
            }

            // 2. Divider
            screen.setCell(dividerX, y + i, {
                char: dividerChar,
                ...attrs,
            });

            // 3. Right pane (target)
            if (i < this._targetItems.length) {
                const o = this._targetItems[i];
                const active = this._activePane === 'target' && i === this._targetCursorIndex;
                const text = (active ? indicator : noIndicator) + o.label;
                const truncatedText = text.slice(0, rightPaneWidth).padEnd(rightPaneWidth, ' ');
                screen.writeString(dividerX + 1, y + i, truncatedText, {
                    ...attrs,
                    fg: o.disabled ? { type: 'named' as const, name: 'brightBlack' as const } : active ? this._activeColor : attrs.fg,
                    bold: active,
                    dim: o.disabled,
                });
            } else {
                screen.writeString(dividerX + 1, y + i, ' '.repeat(rightPaneWidth), attrs);
            }
        }
    }
}

// SnippetPrompt — parse template placeholders and manage prompt values
import { Widget } from '@termuijs/widgets';
import { type Screen, mergeStyles, defaultStyle } from '@termuijs/core';

export interface SnippetPromptOptions {
    validate?: Record<string, (value: string) => string | null>;
}

export class SnippetPrompt extends Widget {
    private _placeholders: string[];
    private _values: Map<string, string>;
    private _errors: Map<string, string> = new Map();
    private _validators: Map<string, (value: string) => string | null>;
    private _activeIndex = 0;

    constructor(template: string, options: SnippetPromptOptions = {}) {
        super(mergeStyles(defaultStyle(), { height: 1 }));
        this._placeholders = this._parsePlaceholders(template);
        this._values = new Map(this._placeholders.map((key) => [key, '']));
        this._validators = new Map(Object.entries(options.validate ?? {}));
        this.template = template;
    }

    readonly template: string;

    get placeholders(): string[] {
        return [...this._placeholders];
    }

    get activeField(): string | undefined {
        return this._placeholders[this._activeIndex];
    }

    get values(): Record<string, string> {
        const record: Record<string, string> = {};
        for (const [key, value] of this._values) record[key] = value;
        return record;
    }

    get errors(): Record<string, string> {
        const record: Record<string, string> = {};
        for (const [key, value] of this._errors) record[key] = value;
        return record;
    }

    setValue(field: string, value: string): void {
        if (!this._values.has(field)) return;
        this._values.set(field, value);
        this._errors.delete(field);
        this.markDirty();
    }

    nextField(): void {
        if (this._activeIndex < this._placeholders.length - 1) {
            this._activeIndex++;
            this.markDirty();
        }
    }

    prevField(): void {
        if (this._activeIndex > 0) {
            this._activeIndex--;
            this.markDirty();
        }
    }

    validate(): boolean {
        this._errors.clear();

        for (const field of this._placeholders) {
            const validator = this._validators.get(field);
            if (!validator) continue;
            const value = this._values.get(field) ?? '';
            const error = validator(value);
            if (error) {
                this._errors.set(field, error);
            }
        }

        this.markDirty();
        return this._errors.size === 0;
    }

    buildResult(): string {
        return this.template.replace(/{{\s*([^}]+?)\s*}}/g, (_match, name) => {
            return this._values.get(name) ?? '';
        });
    }

    protected _renderSelf(_screen: Screen): void {
        // Container only
    }

    private _parsePlaceholders(template: string): string[] {
        const placeholders: string[] = [];
        const seen = new Set<string>();
        const matcher = /{{\s*([^}]+?)\s*}}/g;
        let match: RegExpExecArray | null;

        while ((match = matcher.exec(template)) !== null) {
            const key = match[1].trim();
            if (!seen.has(key)) {
                seen.add(key);
                placeholders.push(key);
            }
        }

        return placeholders;
    }
}

// ConfirmDialog — yes/no prompt overlay
import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, type KeyEvent, mergeStyles, defaultStyle, styleToCellAttrs, getBorderChars } from '@termuijs/core';

export interface ConfirmDialogOptions {
    message: string;
    confirmLabel?: string;
    cancelLabel?: string;
    borderColor?: Style['fg'];
    onConfirm?: () => void;
    onCancel?: () => void;
}

export class ConfirmDialog extends Widget {
    private _message: string;
    private _confirmLabel: string;
    private _cancelLabel: string;
    private _borderColor: Style['fg'];
    private _selected: 'confirm' | 'cancel' = 'confirm';
    private _visible = false;
    private _onConfirm?: () => void;
    private _onCancel?: () => void;
    focusable = true;

    constructor(options: ConfirmDialogOptions) {
        super(mergeStyles(defaultStyle(), {}));
        this._message = options.message;
        this._confirmLabel = options.confirmLabel ?? 'Yes';
        this._cancelLabel = options.cancelLabel ?? 'No';
        this._borderColor = options.borderColor ?? { type: 'named', name: 'yellow' };
        this._onConfirm = options.onConfirm;
        this._onCancel = options.onCancel;
        this.events.on('key', (event) => this.handleKey(event));
    }

    get visible(): boolean { return this._visible; }
    show(): void { this._visible = true; this._selected = 'confirm'; this.markDirty(); }
    hide(): void { this._visible = false; this.markDirty(); }
    selectConfirm(): void { this._selected = 'confirm'; this.markDirty(); }
    selectCancel(): void { this._selected = 'cancel'; this.markDirty(); }
    toggleSelection(): void { this._selected = this._selected === 'confirm' ? 'cancel' : 'confirm'; this.markDirty(); }
    confirm(): void {
        (this._selected === 'confirm' ? this._onConfirm : this._onCancel)?.();
        this._visible = false;
        this.markDirty();
    }

    private handleKey(event: KeyEvent): void {
        if (!this._visible) return;
        if (event.key === 'escape') {
            this.selectCancel();
            this.confirm();
            event.preventDefault();
            event.stopPropagation();
        }
    }

    protected _renderSelf(screen: Screen): void {
        if (!this._visible) return;
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;
        const attrs = styleToCellAttrs(this.style);
        for (let r = 0; r < height; r++) screen.writeString(x, y + r, '░'.repeat(width), { ...attrs, dim: true });
        const bw = Math.min(40, width - 4);
        const bh = 5;
        if (bw < 2 || height < bh) return;
        const bx = x + Math.floor((width - bw) / 2);
        const by = y + Math.floor((height - bh) / 2);
        const border = getBorderChars('single');
        if (!border) return;
        const ba = { ...attrs, fg: this._borderColor };
        screen.writeString(bx, by, border.topLeft + border.top.repeat(bw - 2) + border.topRight, ba);
        for (let r = 1; r < bh - 1; r++) {
            screen.writeString(bx, by + r, border.left, ba);
            screen.writeString(bx + 1, by + r, ' '.repeat(bw - 2), attrs);
            screen.writeString(bx + bw - 1, by + r, border.right, ba);
        }
        screen.writeString(bx, by + bh - 1, border.bottomLeft + border.bottom.repeat(bw - 2) + border.bottomRight, ba);
        screen.writeString(bx + 2, by + 1, this._message.slice(0, bw - 4), { ...attrs, bold: true });
        const yesStr = this._selected === 'confirm' ? ` [${this._confirmLabel}] ` : `  ${this._confirmLabel}  `;
        const noStr = this._selected === 'cancel' ? ` [${this._cancelLabel}] ` : `  ${this._cancelLabel}  `;
        screen.writeString(bx + 2, by + 3, yesStr, { ...attrs, fg: this._selected === 'confirm' ? { type: 'named', name: 'green' } : attrs.fg, bold: this._selected === 'confirm' });
        screen.writeString(bx + 2 + yesStr.length + 2, by + 3, noStr, { ...attrs, fg: this._selected === 'cancel' ? { type: 'named', name: 'red' } : attrs.fg, bold: this._selected === 'cancel' });
    }
}

import { Widget } from '@termuijs/widgets';
import {
    type Screen,
    type KeyEvent,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    caps,
} from '@termuijs/core';

export interface SwitchOptions {
    defaultValue?: boolean;
    label?: string;
    onChange?: (value: boolean) => void;
}

export class Switch extends Widget {
    private _value: boolean;
    private _label?: string;
    onChange?: (value: boolean) => void;

    focusable = true;

    constructor(options: SwitchOptions = {}) {
        super(mergeStyles(defaultStyle(), { height: 1 }));

        this._value = options.defaultValue ?? false;
        this._label = options.label;
        this.onChange = options.onChange;
    }

    get value(): boolean {
        return this._value;
    }

    setValue(value: boolean): void {
        if (this._value === value) return;

        this._value = value;
        this.onChange?.(value);
        this.markDirty();
    }

    toggle(): void {
        this.setValue(!this._value);
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'space':
                this.toggle();
                break;

            case 'right':
                this.setValue(true);
                break;

            case 'left':
                this.setValue(false);
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width } = this._rect;

        if (width <= 0) return;

        const attrs = styleToCellAttrs(this.style);

        const track = caps.unicode
            ? (this._value ? '──●' : '●──')
            : (this._value ? '--O' : 'O--');

        const text = this._label
            ? `${this._label} ${track}`
            : track;

        screen.writeString(
            x,
            y,
            text.slice(0, width),
            attrs
        );
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — Imperative Prompts
//
// Pure Node.js readline-based prompts for CLI scripts
// that don't need a full TUI app. Zero dependency on
// @termuijs/core, @termuijs/widgets, or @termuijs/jsx.
// ─────────────────────────────────────────────────────

import * as readline from 'readline';

export class NonInteractiveError extends Error {
    constructor() {
        super('Prompts require an interactive TTY. stdin is not a TTY.');
        this.name = 'NonInteractiveError';
    }
}

export interface TextPromptOptions {
    message: string;
    placeholder?: string;
    validate?: (value: string) => string | null;
    default?: string;
}

export interface ConfirmPromptOptions {
    message: string;
    default?: boolean;
}

export interface SelectPromptOptions<T = string> {
    message: string;
    options: Array<{ label: string; value: T }>;
    default?: T;
}

async function promptText(options: TextPromptOptions): Promise<string> {
    if (!process.stdin.isTTY) throw new NonInteractiveError();

    const defaultHint = options.default ? ` (${options.default})` : '';
    const placeholder = options.placeholder ? ` [${options.placeholder}]` : '';

    return new Promise((resolve) => {
        const rl = readline.createInterface({
            input: process.stdin,
            output: process.stdout,
        });

        const ask = () => {
            rl.question(`${options.message}${defaultHint}${placeholder}: `, (answer) => {
                const value = answer.trim() || options.default || '';
                if (options.validate) {
                    const error = options.validate(value);
                    if (error) {
                        process.stdout.write(`  ${error}\n`);
                        ask();
                        return;
                    }
                }
                rl.close();
                resolve(value);
            });
        };

        ask();
    });
}

async function promptConfirm(options: ConfirmPromptOptions): Promise<boolean> {
    if (!process.stdin.isTTY) throw new NonInteractiveError();

    const hint = options.default === true ? 'Y/n' : options.default === false ? 'y/N' : 'y/n';

    return new Promise((resolve) => {
        const rl = readline.createInterface({
            input: process.stdin,
            output: process.stdout,
        });

        rl.question(`${options.message} [${hint}]: `, (answer) => {
            rl.close();
            const a = answer.trim().toLowerCase();
            if (a === 'y' || a === 'yes') { resolve(true); return; }
            if (a === 'n' || a === 'no') { resolve(false); return; }
            if (a === '' && options.default !== undefined) { resolve(options.default); return; }
            resolve(false);
        });
    });
}

async function promptSelect<T = string>(options: SelectPromptOptions<T>): Promise<T> {
    if (!process.stdin.isTTY) throw new NonInteractiveError();

    const { options: choices, default: defaultValue } = options;
    process.stdout.write(`${options.message}\n`);
    choices.forEach((opt, i) => {
        const isDefault = opt.value === defaultValue;
        process.stdout.write(`  ${i + 1}. ${opt.label}${isDefault ? ' (default)' : ''}\n`);
    });

    return new Promise((resolve) => {
        const rl = readline.createInterface({
            input: process.stdin,
            output: process.stdout,
        });

        const ask = () => {
            rl.question(`Enter number (1-${choices.length}): `, (answer) => {
                const trimmed = answer.trim();
                if (trimmed === '' && defaultValue !== undefined) {
                    rl.close();
                    resolve(defaultValue);
                    return;
                }
                const n = parseInt(trimmed, 10);
                if (!isNaN(n) && n >= 1 && n <= choices.length) {
                    rl.close();
                    resolve(choices[n - 1].value);
                    return;
                }
                process.stdout.write(`  Invalid choice. Enter a number 1-${choices.length}.\n`);
                ask();
            });
        };

        ask();
    });
}

/**
 * Imperative prompts for CLI scripts — no widget stack required.
 *
 * ```ts
 * const name = await prompt.text({ message: 'Project name:', default: 'my-app' });
 * const ok = await prompt.confirm({ message: 'Continue?', default: true });
 * const pkg = await prompt.select({ message: 'Package manager:', options: [
 *     { label: 'pnpm', value: 'pnpm' },
 *     { label: 'npm', value: 'npm' },
 * ]});
 * ```
 *
 * Throws `NonInteractiveError` when stdin is not a TTY.
 */
export const prompt = {
    text: promptText,
    confirm: promptConfirm,
    select: promptSelect,
} as const;

