// SegmentedControl — single-selection segmented control

import { Widget } from '@termuijs/widgets';
import {
    type Style,
    type Screen,
    type KeyEvent,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    caps,
} from '@termuijs/core';

export interface SegmentedControlOptions {
    options: string[];
    value?: string;
    activeColor?: Style['fg'];
    onChange?: (value: string) => void;
}

export class SegmentedControl extends Widget {
    private _options: string[];
    private _selectedIndex = 0;
    private _activeColor: Style['fg'];
    private _onChange?: (value: string) => void;

    focusable = true;

    constructor(config: SegmentedControlOptions) {
        super(mergeStyles(defaultStyle(), { height: 1 }));

        this._options = config.options;

        const index = this._options.indexOf(
            config.value ?? this._options[0]
        );

        this._selectedIndex = index >= 0 ? index : 0;

        this._activeColor =
            config.activeColor ??
            { type: 'named', name: 'cyan' };

        this._onChange = config.onChange;
    }

    get value(): string {
        return this._options[this._selectedIndex];
    }

    private _setIndex(index: number): void {
        if (
            index < 0 ||
            index >= this._options.length ||
            index === this._selectedIndex
        ) {
            return;
        }

        this._selectedIndex = index;
        this._onChange?.(this.value);
        this.markDirty();
    }

    next(): void {
        this._setIndex(this._selectedIndex + 1);
    }

    prev(): void {
        this._setIndex(this._selectedIndex - 1);
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'left':
                this.prev();
                break;

            case 'right':
                this.next();
                break;
            case 'home':
                this._setIndex(0);
                break;
            case 'end':
                this._setIndex(this._options.length - 1);
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y } = this._rect;

        const attrs = styleToCellAttrs(this.style);

        const separator = caps.unicode ? ' │ ' : ' | ';

        let col = x;

        screen.writeString(col, y, '[ ', attrs);
        col += 2;

        for (let i = 0; i < this._options.length; i++) {
            const active = i === this._selectedIndex;

            screen.writeString(
                col,
                y,
                this._options[i],
                {
                    ...attrs,
                    fg: active ? this._activeColor : attrs.fg,
                    bold: active,
                }
            );

            col += this._options[i].length;

            if (i < this._options.length - 1) {
                screen.writeString(col, y, separator, attrs);
                col += separator.length;
            }
        }

        screen.writeString(col, y, ' ]', attrs);
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — FilePicker widget
//
// Interactive file browser:
//   ↑ / ↓    Move selection
//   Enter     Open directory | fire onSelect for file
//   Backspace Navigate to parent directory
//   Escape    Fire onCancel
// ─────────────────────────────────────────────────────

import * as fs from 'node:fs';
import * as nodePath from 'node:path';
import { Widget } from '@termuijs/widgets';
import {
    type Style,
    type Screen,
    type KeyEvent,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    caps,
    truncate,
} from '@termuijs/core';

// ── Types ────────────────────────────────────────────

/** A single entry shown in the file picker list. */
export interface FileEntry {
    /** Basename only (never a full path). */
    name: string;
    /** True when the entry is a directory. */
    isDir: boolean;
    /** Resolved absolute path. */
    fullPath: string;
}

export interface FilePickerOptions {
    /** Initial directory. Defaults to `process.cwd()`. */
    startPath?: string;
    /**
     * Extension filter (e.g. `['.ts', '.tsx']`).
     * When provided, only files whose extension matches are shown.
     * Directories are always shown regardless of this filter.
     */
    filter?: string[];
    /** Show dot-files / dot-directories. Default: `false`. */
    showHidden?: boolean;
    /** Foreground colour for directory entries. Default: cyan. */
    dirColor?: Style['fg'];
    /** Foreground colour for file entries. Default: white. */
    fileColor?: Style['fg'];
    /** Foreground colour for the highlighted (active) row. Default: yellow. */
    activeColor?: Style['fg'];
    /** Called with the absolute path when the user selects a file. */
    onSelect?: (path: string) => void;
    /** Called when the user presses Escape. */
    onCancel?: () => void;
}

// ── Widget ───────────────────────────────────────────

/**
 * FilePicker — an interactive file browser widget.
 *
 * Wire keyboard events via `handleKey(event)`.
 * The widget is self-contained: it reads the filesystem on construction
 * and every time the directory changes.
 */
export class FilePicker extends Widget {
    private _cwd: string;
    private _filter: string[];
    private _showHidden: boolean;
    private _entries: FileEntry[] = [];
    private _cursor = 0;
    private _scrollTop = 0;

    private _dirColor: Style['fg'];
    private _fileColor: Style['fg'];
    private _activeColor: Style['fg'];

    private _onSelect?: (path: string) => void;
    private _onCancel?: () => void;

    focusable = true;

    constructor(options: FilePickerOptions = {}) {
        super(mergeStyles(defaultStyle(), { flexGrow: 1 }));
        this._cwd = nodePath.resolve(options.startPath ?? process.cwd());
        this._filter = options.filter ?? [];
        this._showHidden = options.showHidden ?? false;
        this._dirColor = options.dirColor ?? { type: 'named', name: 'cyan' };
        this._fileColor = options.fileColor ?? { type: 'named', name: 'white' };
        this._activeColor = options.activeColor ?? { type: 'named', name: 'yellow' };
        this._onSelect = options.onSelect;
        this._onCancel = options.onCancel;

        this._loadEntries();
    }

    // ── Public accessors ─────────────────────────────

    /** The absolute path of the directory currently being displayed. */
    get currentPath(): string { return this._cwd; }

    /** The `FileEntry` the cursor is currently on, or `undefined` if the list is empty. */
    get selectedEntry(): FileEntry | undefined { return this._entries[this._cursor]; }

    /** Read-only snapshot of the currently visible entries. */
    get entries(): readonly FileEntry[] { return this._entries; }

    /** Current cursor index within `entries`. */
    get cursorIndex(): number { return this._cursor; }

    // ── Navigation ───────────────────────────────────

    /** Move the cursor one row down. Clamps at the last entry. */
    selectNext(): void {
        if (this._cursor < this._entries.length - 1) {
            this._cursor++;
            this.markDirty();
        }
    }

    /** Move the cursor one row up. Clamps at the first entry. */
    selectPrev(): void {
        if (this._cursor > 0) {
            this._cursor--;
            this.markDirty();
        }
    }

    /**
     * Confirm the current selection:
     * - If the entry is a directory (including `..`), navigate into it.
     * - If the entry is a file, fire `onSelect(fullPath)`.
     */
    confirm(): void {
        const entry = this._entries[this._cursor];
        if (!entry) return;

        if (entry.isDir) {
            this._navigateTo(entry.fullPath);
        } else {
            this._onSelect?.(entry.fullPath);
        }
    }

    /**
     * Navigate to the parent directory.
     * No-ops when already at the filesystem root.
     */
    goUp(): void {
        const parent = nodePath.dirname(this._cwd);
        if (parent !== this._cwd) {          // at root dirname(root) === root
            this._navigateTo(parent);
        }
    }

    /** Fire `onCancel`. */
    cancel(): void {
        this._onCancel?.();
    }

    /**
     * Convenience key handler. Wire this to your app's input loop.
     *
     * | Key               | Action         |
     * |-------------------|----------------|
     * | `up` / `k`        | `selectPrev()` |
     * | `down` / `j`      | `selectNext()` |
     * | `enter`/`return`  | `confirm()`    |
     * | `backspace`       | `goUp()`       |
     * | `escape`          | `cancel()`     |
     */
    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'up':        this.selectPrev(); break;
            case 'k':         if (!event.ctrl && !event.alt) this.selectPrev(); break;
            case 'down':      this.selectNext(); break;
            case 'j':         if (!event.ctrl && !event.alt) this.selectNext(); break;
            case 'enter':
            case 'return':    this.confirm(); break;
            case 'backspace': this.goUp(); break;
            case 'escape':    this.cancel(); break;
        }
    }

    // ── Filesystem ───────────────────────────────────

    /**
     * Navigate to an absolute directory path.
     * Reloads the entry list and resets cursor / scroll.
     */
    private _navigateTo(absPath: string): void {
        this._cwd = absPath;
        this._loadEntries();
        // _loadEntries resets cursor and calls markDirty
    }

    /**
     * Read `this._cwd` and populate `this._entries`.
     *
     * Layout:
     *  1. `..` parent entry (omitted at root)
     *  2. Directories — alpha-sorted
     *  3. Files       — alpha-sorted, filtered by `this._filter`
     */
    private _loadEntries(): void {
        const entries: FileEntry[] = [];

        // Parent entry (unless at root)
        const parent = nodePath.dirname(this._cwd);
        if (parent !== this._cwd) {
            entries.push({ name: '..', isDir: true, fullPath: parent });
        }

        try {
            const dirents = fs.readdirSync(this._cwd, { withFileTypes: true });

            const dirs: FileEntry[] = [];
            const files: FileEntry[] = [];

            for (const dirent of dirents) {
                // Skip hidden entries unless explicitly shown
                if (!this._showHidden && dirent.name.startsWith('.')) continue;

                const fullPath = nodePath.join(this._cwd, dirent.name);
                const isDir = dirent.isDirectory() || dirent.isSymbolicLink() && this._isDir(fullPath);

                if (isDir) {
                    dirs.push({ name: dirent.name, isDir: true, fullPath });
                } else {
                    // Apply extension filter to files only
                    if (this._filter.length > 0) {
                        const ext = nodePath.extname(dirent.name);
                        if (!this._filter.includes(ext)) continue;
                    }
                    files.push({ name: dirent.name, isDir: false, fullPath });
                }
            }

            // Sort each group alphabetically (case-insensitive)
            const alpha = (a: FileEntry, b: FileEntry) =>
                a.name.toLowerCase().localeCompare(b.name.toLowerCase());

            dirs.sort(alpha);
            files.sort(alpha);

            entries.push(...dirs, ...files);
        } catch {
            // Permission denied or directory removed — show only the `..` entry
        }

        this._entries = entries;
        this._cursor = 0;
        this._scrollTop = 0;
        this.markDirty();
    }

    /** Safe stat to check if a symlink target is a directory. Never throws. */
    private _isDir(p: string): boolean {
        try { return fs.statSync(p).isDirectory(); } catch { return false; }
    }

    // ── Rendering ────────────────────────────────────

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        // ── Row 0: path header ────────────────────────
        const headerIcon = caps.unicode ? '📁 ' : '> ';
        const headerText = truncate(headerIcon + this._cwd, width);
        screen.writeString(x, y, headerText, {
            ...attrs,
            fg: this._dirColor,
            bold: true,
        });

        if (height < 2) return;

        // ── Row 1: separator ─────────────────────────
        const sep = caps.unicode ? '─'.repeat(width) : '-'.repeat(width);
        screen.writeString(x, y + 1, sep, { ...attrs, dim: true });

        // ── Rows 2+: entries ─────────────────────────
        const listTop = y + 2;
        const listHeight = height - 2;
        if (listHeight <= 0) return;

        // Scroll the viewport so the cursor stays visible
        if (this._cursor < this._scrollTop) {
            this._scrollTop = this._cursor;
        } else if (this._cursor >= this._scrollTop + listHeight) {
            this._scrollTop = this._cursor - listHeight + 1;
        }

        for (let i = 0; i < listHeight; i++) {
            const entryIdx = this._scrollTop + i;
            const entry = this._entries[entryIdx];
            const row = listTop + i;

            if (!entry) {
                // Blank the row so stale characters don't linger
                screen.writeString(x, row, ' '.repeat(width), attrs);
                continue;
            }

            const isActive = entryIdx === this._cursor;

            const icon = entry.isDir
                ? (caps.unicode ? (entry.name === '..' ? '↩ ' : '📂 ') : (entry.name === '..' ? '.. ' : 'd  '))
                : (caps.unicode ? '   ' : '   ');

            const label = truncate(icon + entry.name, width);

            const fg = isActive
                ? this._activeColor
                : entry.isDir
                    ? this._dirColor
                    : this._fileColor;

            screen.writeString(x, row, label.padEnd(width), {
                ...attrs,
                fg,
                bold: isActive,
                inverse: isActive,
            });
        }
    }
}

// LinearPrompt — screen-reader-friendly linear prompt rendering
import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, type KeyEvent, mergeStyles, defaultStyle, styleToCellAttrs } from '@termuijs/core';

export interface LinearPromptOption {
    label: string;
    value: string;
    disabled?: boolean;
}

export interface LinearPromptOptions {
    question: string;
    activeColor?: Style['fg'];
    onSelect?: (option: LinearPromptOption, index: number) => void;
}

export class LinearPrompt extends Widget {
    private _options: LinearPromptOption[];
    private _selectedIndex = 0;
    private _question: string;
    private _activeColor: Style['fg'];
    private _onSelect?: (option: LinearPromptOption, index: number) => void;
    focusable = true;

    constructor(options: LinearPromptOption[], config: LinearPromptOptions) {
        super(mergeStyles(defaultStyle(), { height: options.length + 2 }));
        this._options = options;
        this._question = config.question;
        this._activeColor = config.activeColor ?? { type: 'named', name: 'cyan' };
        this._onSelect = config.onSelect;
    }

    get selectedOption(): LinearPromptOption | undefined {
        return this._options[this._selectedIndex];
    }

    get selectedIndex(): number {
        return this._selectedIndex;
    }

    selectNext(): void {
        let n = this._selectedIndex + 1;
        while (n < this._options.length && this._options[n]?.disabled) n++;
        if (n < this._options.length) {
            this._selectedIndex = n;
            this.markDirty();
        }
    }

    selectPrev(): void {
        let n = this._selectedIndex - 1;
        while (n >= 0 && this._options[n]?.disabled) n--;
        if (n >= 0) {
            this._selectedIndex = n;
            this.markDirty();
        }
    }

    confirm(): void {
        const opt = this._options[this._selectedIndex];
        if (opt && !opt.disabled) {
            this._onSelect?.(opt, this._selectedIndex);
            this.markDirty();
        }
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'down':
                this.selectNext();
                break;

            case 'up':
                this.selectPrev();
                break;

            case 'enter':
                this.confirm();
                break;

            case 'tab':
                this.selectNext();
                break;

            case 'shift+tab':
                // Note: shift+tab is not directly supported in most terminals,
                // but we handle it for completeness if the platform provides it
                this.selectPrev();
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width } = this._rect;
        if (width <= 0) return;

        const attrs = styleToCellAttrs(this.style);
        let currentY = y;

        // Render question
        screen.writeString(x, currentY, this._question.slice(0, width), attrs);
        currentY++;

        // Render options sequentially without positioning codes
        for (let i = 0; i < this._options.length; i++) {
            const opt = this._options[i];
            const isSel = i === this._selectedIndex;
            const marker = isSel ? '> ' : '  ';
            const label = opt.label.slice(0, width - 2);

            screen.writeString(
                x,
                currentY,
                marker + label,
                {
                    ...attrs,
                    fg: opt.disabled
                        ? { type: 'named', name: 'brightBlack' }
                        : isSel
                        ? this._activeColor
                        : attrs.fg,
                    bold: isSel,
                    dim: opt.disabled,
                }
            );

            currentY++;
        }
    }
}

// MultiSelect — checkbox-style multi-item selector
import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, mergeStyles, defaultStyle, styleToCellAttrs, caps } from '@termuijs/core';

export interface MultiSelectOption { label: string; value: string; disabled?: boolean; }
export interface MultiSelectOptions {
    activeColor?: Style['fg'];
    checkChar?: string;
    uncheckChar?: string;
    onSubmit?: (selected: MultiSelectOption[]) => void;
}

export class MultiSelect extends Widget {
    private _options: MultiSelectOption[];
    private _cursorIndex = 0;
    private _checked: Set<number> = new Set();
    private _activeColor: Style['fg'];
    private _checkChar: string;
    private _uncheckChar: string;
    private _onSubmit?: (selected: MultiSelectOption[]) => void;
    focusable = true;

    constructor(options: MultiSelectOption[], config: MultiSelectOptions = {}) {
        super(mergeStyles(defaultStyle(), { height: Math.max(options.length, 1) }));
        this._options = options;
        this._activeColor = config.activeColor ?? { type: 'named', name: 'cyan' };
        this._checkChar = config.checkChar ?? (caps.unicode ? '◼' : '[x]');
        this._uncheckChar = config.uncheckChar ?? (caps.unicode ? '◻' : '[ ]');
        this._onSubmit = config.onSubmit;
    }

    get selectedOptions(): MultiSelectOption[] {
        return [...this._checked].sort().map(i => this._options[i]);
    }
    selectNext(): void { if (this._options.length === 0) return; let n = this._cursorIndex + 1; while (n < this._options.length && this._options[n].disabled) n++; if (n < this._options.length) { this._cursorIndex = n; this.markDirty(); } }
    selectPrev(): void { if (this._options.length === 0) return; let n = this._cursorIndex - 1; while (n >= 0 && this._options[n].disabled) n--; if (n >= 0) { this._cursorIndex = n; this.markDirty(); } }
    toggleCurrent(): void {
        const o = this._options[this._cursorIndex];
        if (o && !o.disabled) { this._checked.has(this._cursorIndex) ? this._checked.delete(this._cursorIndex) : this._checked.add(this._cursorIndex); this.markDirty(); }
    }
    submit(): void { this._onSubmit?.(this.selectedOptions); }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;
        const attrs = styleToCellAttrs(this.style);
        for (let i = 0; i < this._options.length && i < height; i++) {
            const o = this._options[i];
            const active = i === this._cursorIndex;
            const checked = this._checked.has(i);
            const label = `${active ? (caps.unicode ? '❯ ' : '> ') : '  '}${checked ? this._checkChar : this._uncheckChar} ${o.label}`;
            screen.writeString(x, y + i, label.slice(0, width), {
                ...attrs,
                fg: o.disabled ? { type: 'named' as const, name: 'brightBlack' as const } : active ? this._activeColor : attrs.fg,
                bold: active, dim: o.disabled,
            });
        }
    }
}

// SearchableSelect — searchable dropdown selector with filtering
import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, type KeyEvent, mergeStyles, defaultStyle, styleToCellAttrs, caps, truncate } from '@termuijs/core';

export interface SearchableSelectOption {
    label: string;
    value: string;
}

export interface SearchableSelectOptions {
    placeholder?: string;
    activeColor?: Style['fg'];
    onSelect?: (option: SearchableSelectOption, index: number) => void;
}

export class SearchableSelect extends Widget {
    private _allOptions: SearchableSelectOption[] = [];
    private _filteredOptions: SearchableSelectOption[] = [];
    private _searchQuery: string = '';
    private _selectedIndex: number = 0;
    private _placeholder: string;
    private _activeColor: Style['fg'];
    private _onSelect?: (option: SearchableSelectOption, index: number) => void;
    focusable = true;

    constructor(options: SearchableSelectOption[] = [], config: SearchableSelectOptions = {}) {
        super(mergeStyles(defaultStyle(), { height: 5 }));
        this._allOptions = options;
        this._filteredOptions = [...options];
        this._placeholder = config.placeholder ?? 'Search...';
        this._activeColor = config.activeColor ?? { type: 'named', name: 'cyan' };
        this._onSelect = config.onSelect;
    }

    get searchQuery(): string { return this._searchQuery; }
    get filteredOptions(): ReadonlyArray<SearchableSelectOption> { return this._filteredOptions; }
    get selectedIndex(): number { return this._selectedIndex; }

    get selectedOption(): string {
        const opt = this._filteredOptions[this._selectedIndex];
        return opt ? opt.value : '';
    }

    setOptions(options: SearchableSelectOption[]): void {
        this._allOptions = options;
        this._filterOptions();
        this._selectedIndex = 0;
        this.markDirty();
    }

    handleKey(event: KeyEvent): void {
        if (event._propagationStopped || event._defaultPrevented) return;
        const char = event.key;

        if (char.length === 1 && !event.ctrl && !event.alt) {
            this._searchQuery += char;
            this._filterOptions();
            this._selectedIndex = 0;
            this.markDirty();
            return;
        }

        if (event.key === 'backspace') {
            this._searchQuery = this._searchQuery.slice(0, -1);
            this._filterOptions();
            this._selectedIndex = 0;
            this.markDirty();
            return;
        }

        if (event.key === 'down') {
            this.selectNext();
            return;
        }

        if (event.key === 'up') {
            this.selectPrev();
            return;
        }

        if (event.key === 'enter' || event.key === 'return') {
            this.confirm();
            return;
        }
    }

    selectNext(): void {
        if (this._selectedIndex < this._filteredOptions.length - 1) {
            this._selectedIndex++;
            this.markDirty();
        }
    }

    selectPrev(): void {
        if (this._selectedIndex > 0) {
            this._selectedIndex--;
            this.markDirty();
        }
    }

    confirm(): void {
        const opt = this._filteredOptions[this._selectedIndex];
        if (opt) {
            this._onSelect?.(opt, this._selectedIndex);
        }
    }

    private _filterOptions(): void {
        if (this._searchQuery === '') {
            this._filteredOptions = [...this._allOptions];
            return;
        }
        const q = this._searchQuery.toLowerCase();
        this._filteredOptions = this._allOptions.filter(
            o => o.label.toLowerCase().includes(q) || o.value.toLowerCase().includes(q)
        );
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;
        const attrs = styleToCellAttrs(this.style);

        const displayText = this._searchQuery.length > 0 ? this._searchQuery : this._placeholder;
        const pointer = caps.unicode ? '➔' : '>';
        const searchLine = pointer + ' ' + displayText;
        const searchStyle = this._searchQuery.length > 0 ? attrs : { ...attrs, dim: true };
        screen.writeString(x, y, truncate(searchLine, width), searchStyle);

        const maxVisible = height - 1;
        const visibleCount = Math.min(this._filteredOptions.length, maxVisible);
        for (let i = 0; i < visibleCount; i++) {
            const opt = this._filteredOptions[i];
            const isSelected = i === this._selectedIndex;
            const prefix = isSelected ? (caps.unicode ? '● ' : '* ') : '  ';
            const line = prefix + opt.label;
            screen.writeString(x, y + 1 + i, truncate(line, width), {
                ...attrs,
                fg: isSelected ? this._activeColor : attrs.fg,
                bold: isSelected,
            });
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — ThemeSwitcher widget
//
// A list-based widget to display and switch between different themes.
// - Keyboard navigable (Up/Down or K/J)
// - Emits onChange(themeName) when a theme is confirmed via Enter/Space
// ─────────────────────────────────────────────────────

import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, type KeyEvent, mergeStyles, defaultStyle, styleToCellAttrs, caps } from '@termuijs/core';

export interface ThemeSwitcherOptions {
    themes?: string[];
    activeTheme?: string;
    onChange?: (theme: string) => void;
    activeColor?: Style['fg'];
}

export class ThemeSwitcher extends Widget {
    private _themes: string[];
    private _activeTheme: string;
    private _selectedIndex: number;
    private _onChange?: (theme: string) => void;
    private _activeColor: Style['fg'];
    focusable = true;

    constructor(options: ThemeSwitcherOptions = {}) {
        const themes = options.themes ?? [
            'default',
            'cyberpunk',
            'nord',
            'dracula',
            'gruvbox',
            'catppuccin',
            'solarized',
            'tokyo-night',
            'highContrast'
        ];

        super(mergeStyles(defaultStyle(), { border: 'single', height: themes.length + 2 }));

        this._themes = themes;
        this._activeTheme = options.activeTheme ?? 'default';
        this._selectedIndex = this._themes.indexOf(this._activeTheme);
        if (this._selectedIndex === -1) {
            this._activeTheme = this._themes[0] ?? '';
            this._selectedIndex = 0;
        }
        this._onChange = options.onChange;
        this._activeColor = options.activeColor ?? { type: 'named', name: 'cyan' };
    }

    get activeTheme(): string {
        return this._activeTheme;
    }

    set activeTheme(theme: string) {
        if (this._activeTheme === theme) return;
        this._activeTheme = theme;
        const idx = this._themes.indexOf(theme);
        if (idx !== -1) {
            this._selectedIndex = idx;
        }
        this.markDirty();
    }

    get themes(): string[] {
        return this._themes;
    }

    get selectedIndex(): number {
        return this._selectedIndex;
    }

    selectNext(): void {
        if (this._selectedIndex < this._themes.length - 1) {
            this._selectedIndex++;
            this.markDirty();
        }
    }

    selectPrev(): void {
        if (this._selectedIndex > 0) {
            this._selectedIndex--;
            this.markDirty();
        }
    }

    confirm(): void {
        const theme = this._themes[this._selectedIndex];
        if (theme) {
            this._activeTheme = theme;
            this._onChange?.(theme);
            this.markDirty();
        }
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'up':
            case 'k':
                this.selectPrev();
                break;
            case 'down':
            case 'j':
                this.selectNext();
                break;
            case 'enter':
            case 'space':
                this.confirm();
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        for (let i = 0; i < this._themes.length; i++) {
            if (i >= height) break;

            const themeName = this._themes[i];
            const isSelected = i === this._selectedIndex;
            const isActive = themeName === this._activeTheme;

            let prefix = '  ';
            if (isActive && isSelected) {
                prefix = caps.unicode ? '●▸' : '*>';
            } else if (isActive) {
                prefix = caps.unicode ? '● ' : '* ';
            } else if (isSelected) {
                prefix = caps.unicode ? ' ▸' : ' >';
            }

            const formattedName = themeName.charAt(0).toUpperCase() + themeName.slice(1);
            const lineText = `${prefix} ${formattedName}`;

            screen.writeString(x, y + i, lineText.slice(0, width), {
                ...attrs,
                fg: isSelected ? this._activeColor : attrs.fg,
                bold: isSelected || isActive,
            });
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — EmailInput widget
//
// A TextInput restricted to email addresses.
// - Validates email format
// - Shows inline error for invalid emails
// - Supports tab autocomplete for domains
// ─────────────────────────────────────────────────────

import { Widget } from '@termuijs/widgets';
import { type Style, type Color, type Screen, type KeyEvent, styleToCellAttrs, truncate, mergeStyles, defaultStyle } from '@termuijs/core';

export interface EmailInputOptions {
    placeholder?: string;
    /** Common domains to suggest after '@'. Default: ['gmail.com','outlook.com','yahoo.com'] */
    domains?: string[];
    onSubmit?: (value: string) => void;
    onChange?: (value: string, valid: boolean) => void;
    errorColor?: Color;
}

export class EmailInput extends Widget {
    private _raw = '';
    private _cursorPos = 0;
    private _placeholder: string;
    private _domains: string[];
    private _onSubmit?: (value: string) => void;
    private _onChange?: (value: string, valid: boolean) => void;
    private _errorColor: Color;

    focusable = true;

    constructor(
        style: Partial<Style> = {},
        opts: EmailInputOptions = {},
    ) {
        super(mergeStyles(defaultStyle(), { border: 'single', height: 3, ...style }));
        this._placeholder = opts.placeholder ?? '';
        this._domains = opts.domains ?? ['gmail.com', 'outlook.com', 'yahoo.com'];
        this._onSubmit = opts.onSubmit;
        this._onChange = opts.onChange;
        this._errorColor = opts.errorColor ?? { type: 'named', name: 'red' };
    }

    getValue(): string {
        return this._raw;
    }

    isValid(): boolean {
        return /^[^@]+@[^@]+\.[^@]+$/.test(this._raw);
    }

    private _notify(): void {
        this._onChange?.(this._raw, this.isValid());
        this.markDirty();
    }

    insertChar(char: string): void {
        this._raw =
            this._raw.slice(0, this._cursorPos) +
            char +
            this._raw.slice(this._cursorPos);
        this._cursorPos++;
        this._notify();
    }

    deleteBack(): void {
        if (this._cursorPos > 0) {
            this._raw =
                this._raw.slice(0, this._cursorPos - 1) +
                this._raw.slice(this._cursorPos);
            this._cursorPos--;
            this._notify();
        }
    }

    deleteForward(): void {
        if (this._cursorPos < this._raw.length) {
            this._raw =
                this._raw.slice(0, this._cursorPos) +
                this._raw.slice(this._cursorPos + 1);
            this._notify();
        }
    }

    moveCursorLeft(): void { 
        this._cursorPos = Math.max(0, this._cursorPos - 1); 
        this.markDirty(); 
    }

    moveCursorRight(): void { 
        this._cursorPos = Math.min(this._raw.length, this._cursorPos + 1); 
        this.markDirty(); 
    }

    moveCursorHome(): void { 
        this._cursorPos = 0; 
        this.markDirty(); 
    }

    moveCursorEnd(): void { 
        this._cursorPos = this._raw.length; 
        this.markDirty(); 
    }

    autocompleteDomain(): void {
        const atIndex = this._raw.lastIndexOf('@');
        if (atIndex === -1) return;

        const typedDomain = this._raw.slice(atIndex + 1);
        const match = this._domains.find(d => d.startsWith(typedDomain));

        if (match) {
            this._raw = this._raw.slice(0, atIndex + 1) + match;
            this._cursorPos = this._raw.length;
            this._notify();
        }
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'backspace': this.deleteBack(); break;
            case 'delete': this.deleteForward(); break;
            case 'left': this.moveCursorLeft(); break;
            case 'right': this.moveCursorRight(); break;
            case 'home': this.moveCursorHome(); break;
            case 'end': this.moveCursorEnd(); break;
            case 'tab': this.autocompleteDomain(); break;
            case 'return':
            case 'enter':
                if (this.isValid()) {
                    this._onSubmit?.(this._raw);
                }
                break;
            default:
                if (event.key && event.key.length === 1 && !event.ctrl && !event.alt) {
                    this.insertChar(event.key);
                }
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        if (this._raw.length === 0 && !this.isFocused) {
            screen.writeString(x, y, truncate(this._placeholder, width), { ...attrs, dim: true });
            return;
        }

        const display = this._raw;
        const visibleWidth = width - 1;
        let scrollX = 0;
        if (this._cursorPos > visibleWidth) {
            scrollX = this._cursorPos - visibleWidth;
        }

        const visibleText = display.slice(scrollX, scrollX + visibleWidth);

        // Show error indicator if invalid and not empty
        const isError = this._raw.length > 0 && !this.isValid();
        const renderAttrs = isError ? { ...attrs, fg: this._errorColor } : attrs;

        screen.writeString(x, y, visibleText, renderAttrs);

        if (this.isFocused) {
            const cursorScreenPos = x + this._cursorPos - scrollX;
            if (cursorScreenPos >= x && cursorScreenPos < x + width) {
                const cursorChar = this._cursorPos < display.length
                    ? display[this._cursorPos]
                    : ' ';
                screen.setCell(cursorScreenPos, y, {
                    char: cursorChar,
                    ...renderAttrs,
                    inverse: true,
                });
            }
        }

        // Inline error indicator if error
        if (isError && width > 4) {
            const hint = `[!]`;
            screen.writeString(x + width - hint.length, y, hint, { ...renderAttrs, fg: this._errorColor });
        }
    }
}

import {
    type Screen,
    type KeyEvent,
    type Style,
    caps,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    truncate,
} from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface DisclosureOptions {
    summary: string;
    defaultOpen?: boolean;
    onToggle?: (open: boolean) => void;
}

export class Disclosure extends Widget {
    private _isOpen: boolean;
    private summary: string;
    private onToggleCallback?: (open: boolean) => void;
    private content: Widget;
    private _customStyle: Style;

    constructor(content: Widget, options: DisclosureOptions, style?: Partial<Style>) {
        super();

        this.content = content;
        this.summary = options.summary;
        this._isOpen = options.defaultOpen ?? false;
        this.onToggleCallback = options.onToggle;

        this._customStyle = mergeStyles(defaultStyle(), style ?? {}) as Style;

        this.focusable = true;
    }

    get isOpen(): boolean {
        return this._isOpen;
    }

    open(): void {
        if (!this._isOpen) {
            this._isOpen = true;
            this.markDirty();
            this.onToggleCallback?.(true);
        }
    }

    close(): void {
        if (this._isOpen) {
            this._isOpen = false;
            this.markDirty();
            this.onToggleCallback?.(false);
        }
    }

    toggle(): void {
        this._isOpen = !this._isOpen;
        this.markDirty();
        this.onToggleCallback?.(this._isOpen);
    }

    handleKey(event: KeyEvent): void {
        const key = event.key.toLowerCase();
        if (key === 'enter' || key === ' ' || key === 'space') {
            this.toggle();
        }
    }

    protected _renderSelf(screen: Screen): void {
        if (!this.rect || this.rect.width <= 0) return;

        const { x, y, width, height } = this.rect;

        const marker = caps.unicode
            ? (this._isOpen ? '▾' : '▸')
            : (this._isOpen ? 'v' : '>');

        const headerText = `${marker} ${this.summary}`;
        const truncatedHeader = truncate(headerText, width);

        screen.writeString(x, y, truncatedHeader, styleToCellAttrs(this._customStyle));

        if (this._isOpen && this.content) {
            const childRect = {
                x,
                y: y + 1,
                width,
                height: Math.max(0, height - 1),
            };

            this.content.updateRect(childRect);
            this.content.render(screen);
        }
    }
}

import { Widget } from '@termuijs/widgets';
import {
    type Style,
    type Color,
    type Screen,
    type KeyEvent,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
} from '@termuijs/core';

export interface ButtonGroupItem {
    label: string;
    value: string;
    disabled?: boolean;
}

export interface ButtonGroupOptions {
    activeColor?: Color;
    inactiveColor?: Color;
    onSelect?: (value: string) => void;
}

export class ButtonGroup extends Widget {
    private _items: ButtonGroupItem[];
    private _activeIndex = -1;
    private _activeColor: Color;
    private _inactiveColor: Color;
    private _onSelect?: (value: string) => void;

    focusable = true;

    constructor(
        items: ButtonGroupItem[],
        style: Partial<Style> = {},
        opts: ButtonGroupOptions = {}
    ) {
        super(mergeStyles(mergeStyles(defaultStyle(), { height: 1 }), style as Style));

        this._items = items;
        this._activeColor = opts.activeColor ?? { type: 'named', name: 'cyan' };
        this._inactiveColor = opts.inactiveColor ?? { type: 'named', name: 'brightBlack' };
        this._onSelect = opts.onSelect;
        this._activeIndex = this._firstEnabledIndex();
    }

    setItems(items: ButtonGroupItem[]): void {
        this._items = items;

        const activeValue = this.getActiveValue();
        const activeIndex = this._items.findIndex(
            (item) => !item.disabled && item.value === activeValue
        );

        this._activeIndex = activeIndex >= 0
            ? activeIndex
            : this._firstEnabledIndex();

        this.markDirty();
    }

    setActiveValue(value: string): void {
        const index = this._items.findIndex(
            (item) => !item.disabled && item.value === value
        );

        if (index < 0 || index === this._activeIndex) return;

        this._activeIndex = index;
        this.markDirty();
    }

    getActiveValue(): string {
        return this._items[this._activeIndex]?.value ?? '';
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'left':
                this._move(-1);
                break;

            case 'right':
                this._move(1);
                break;

            case 'enter':
                this._onSelect?.(this.getActiveValue());
                break;
        }
    }

    private _firstEnabledIndex(): number {
        return this._items.findIndex((item) => !item.disabled);
    }

    private _move(direction: -1 | 1): void {
        if (this._items.length === 0) return;

        let index = this._activeIndex;

        for (let i = 0; i < this._items.length; i++) {
            index = (index + direction + this._items.length) % this._items.length;

            if (!this._items[index].disabled) {
                this._activeIndex = index;
                this.markDirty();
                return;
            }
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width } = this._rect;

        if (width <= 0) return;

        const attrs = styleToCellAttrs(this.style);
        let col = x;

        for (let i = 0; i < this._items.length; i++) {
            const item = this._items[i];
            const label = `[${item.label}]`;
            const active = i === this._activeIndex;
            const remaining = x + width - col;

            if (remaining <= 0) return;

            screen.writeString(
                col,
                y,
                label.slice(0, remaining),
                {
                    ...attrs,
                    fg: active ? this._activeColor : this._inactiveColor,
                    bold: active,
                    dim: item.disabled || !active,
                }
            );

            col += label.length;

            if (i < this._items.length - 1) {
                const spacerRemaining = x + width - col;

                if (spacerRemaining <= 0) return;

                screen.writeString(col, y, ' '.slice(0, spacerRemaining), attrs);
                col++;
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — MaskedInput widget
//
// Text input constrained to a mask template.
// '_' = editable slot. Other chars are fixed.
// Examples: date '__/__/____', phone '(___) ___-____'
// ─────────────────────────────────────────────────────

import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, type KeyEvent, type Color, styleToCellAttrs, truncate } from '@termuijs/core';

export interface MaskedInputOptions {
    /** Mask template. '_' = editable slot. Other chars are fixed. Example: '__/__/____' */
    mask: string;
    /** Character shown in empty slots. Default: '_' */
    placeholder?: string;
    /** Callback when all slots are filled */
    onComplete?: (value: string) => void;
    /** Callback on every change */
    onChange?: (value: string) => void;
    /** Color for the text */
    color?: Color;
}

export class MaskedInput extends Widget {
    private _mask: string;
    private _slots: (string | null)[] = []; // null = empty slot, string = filled
    private _cursorSlotIndex = 0; // index into _slots array
    private _placeholder: string;
    private _onComplete?: (value: string) => void;
    private _onChange?: (value: string) => void;
    private _color?: Color;
    focusable = true;

    constructor(
        style: Partial<Style> = {},
        options: MaskedInputOptions,
    ) {
        super({ border: 'single', height: 3, ...style });
        this._mask = options.mask;
        this._placeholder = options.placeholder ?? '_';
        this._onComplete = options.onComplete;
        this._onChange = options.onChange;
        this._color = options.color;

        // Initialize slots array with one entry per '_' in mask
        const slots: (string | null)[] = [];
        for (const char of this._mask) {
            if (char === '_') {
                slots.push(null);
            }
        }
        this._slots = slots;
    }

    /** Get the complete masked string with current values filled in. */
    getValue(): string {
        let result = '';
        let slotIndex = 0;

        for (const char of this._mask) {
            if (char === '_') {
                const val = this._slots[slotIndex];
                result += val ?? this._placeholder;
                slotIndex++;
            } else {
                result += char;
            }
        }

        return result;
    }

    /** Reset all slots to empty and position cursor at first slot. */
    reset(): void {
        this._slots = this._slots.map(() => null);
        this._cursorSlotIndex = 0;
        this._onChange?.(this.getValue());
        this.markDirty();
    }

    /** Check if all slots are filled. */
    private _isComplete(): boolean {
        return this._slots.every((slot) => slot !== null);
    }

    /** Move cursor to the next empty slot, skipping filled ones. Auto-advance on input. */
    private _advanceToNextEmpty(): void {
        while (this._cursorSlotIndex < this._slots.length && this._slots[this._cursorSlotIndex] !== null) {
            this._cursorSlotIndex++;
        }
    }

    /** Move cursor right to the next slot. */
    private _moveCursorRight(): void {
        if (this._cursorSlotIndex < this._slots.length - 1) {
            this._cursorSlotIndex++;
        }
    }

    /** Move cursor to the previous slot. */
    private _moveCursorLeft(): void {
        if (this._cursorSlotIndex > 0) {
            this._cursorSlotIndex--;
        }
    }

    /** Insert a digit character at the current slot. Auto-advance past filled chars. */
    private _insertDigit(char: string): void {
        if (!/^\d$/.test(char)) return; // Only accept digits
        if (this._cursorSlotIndex >= this._slots.length) return; // Already at end

        this._slots[this._cursorSlotIndex] = char;
        this._advanceToNextEmpty();
        this._onChange?.(this.getValue());

        if (this._isComplete()) {
            this._onComplete?.(this.getValue());
        }

        this.markDirty();
    }

    /** Clear the previous slot and move cursor back. */
    private _deleteBack(): void {
        if (this._cursorSlotIndex > 0) {
            this._cursorSlotIndex--;
            this._slots[this._cursorSlotIndex] = null;
            this._onChange?.(this.getValue());
            this.markDirty();
        }
    }

    /**
     * Handle key events. Call this from your input loop.
     */
    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'backspace':
                this._deleteBack();
                break;

            case 'left':
                this._moveCursorLeft();
                this.markDirty();
                break;

            case 'right':
                this._moveCursorRight();
                this.markDirty();
                break;

            case 'home':
                this._cursorSlotIndex = 0;
                this.markDirty();
                break;

            case 'end':
                this._cursorSlotIndex = this._slots.length - 1;
                this.markDirty();
                break;

            default:
                // Single character input (digits)
                if (event.key?.length === 1) {
                    this._insertDigit(event.key);
                }
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width } = rect;
        if (width <= 0) return;

        const attrs = styleToCellAttrs(this.style);
        if (this._color) {
            attrs.fg = this._color;
        }
        const value = this.getValue();
        const display = truncate(value, width);

        screen.writeString(x, y, display, attrs);

        // Render cursor at current slot position if focused
        if (this.isFocused) {
            const cursorX = x + this._getCursorDisplayPos();
            if (cursorX >= x && cursorX < x + width) {
                const cellIndex = cursorX - x;
                if (cellIndex >= 0 && cellIndex < display.length) {
                    const cell = screen.back[y]?.[cursorX];
                    if (cell) {
                        cell.inverse = true;
                    }
                }
            }
        }
    }

    /** Calculate the display position of the cursor (account for fixed chars before it). */
    private _getCursorDisplayPos(): number {
        let displayPos = 0;
        let slotCount = 0;

        for (const char of this._mask) {
            if (char === '_') {
                if (slotCount === this._cursorSlotIndex) {
                    return displayPos;
                }
                slotCount++;
            }
            displayPos++;
        }

        return displayPos;
    }
}

// Announcer — screen reader announcer live region
import { Widget } from '@termuijs/widgets';
import { type Screen, mergeStyles, defaultStyle, styleToCellAttrs, truncate } from '@termuijs/core';

export type Politeness = 'polite' | 'assertive';

export interface AnnouncerOptions {
    /** Max messages kept in the visible log. Default 1. */
    history?: number;
}

export class Announcer extends Widget {
    private _history: number;
    private _log: string[] = [];
    private _queue: { text: string; politeness: Politeness }[] = [];

    constructor(options: AnnouncerOptions = {}) {
        super(mergeStyles(defaultStyle(), {}));
        const history = options.history ?? 1;
        if (!Number.isInteger(history) || history < 1) {
            throw new RangeError('AnnouncerOptions.history must be a positive integer');
        }
        this._history = history;
    }

    /** Queue a message. Assertive messages replace any pending polite ones. */
    announce(text: string, politeness: Politeness = 'polite'): void {
        if (politeness === 'assertive') {
            this._queue = this._queue.filter(msg => msg.politeness !== 'polite');
        }
        this._queue.push({ text, politeness });
        this.markDirty();
    }

    /** The current visible announcement text (most recent). */
    get current(): string {
        if (this._queue.length > 0) {
            return this._queue[this._queue.length - 1].text;
        }
        return this._log[this._log.length - 1] ?? '';
    }

    /** Clear the live region. */
    clear(): void {
        this._queue = [];
        this._log = [];
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        // Flush queue to log
        if (this._queue.length > 0) {
            for (const item of this._queue) {
                this._log.push(item.text);
            }
            this._queue = [];
        }

        // Limit log to history size
        if (this._log.length > this._history) {
            this._log = this._log.slice(-this._history);
        }

        const visible = this._log.slice(-height);
        const attrs = styleToCellAttrs(this.style);

        for (let i = 0; i < visible.length; i++) {
            const msg = visible[i];
            // Truncate render output to the display width (handles multi-byte/emoji)
            const text = truncate(msg, width);
            screen.writeString(x, y + i, text, attrs);
        }
    }
}

/** Shared singleton announcer for app-wide use. */
export const announcer = new Announcer();

import { Widget } from '@termuijs/widgets';
import {
    type Screen,
    type KeyEvent,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    caps,
} from '@termuijs/core';

export interface CheckboxGroupOption {
    label: string;
    value: string;
}

export interface CheckboxGroupOptions {
    options: CheckboxGroupOption[];
    defaultValues?: string[];
    onChange?: (selectedValues: string[]) => void;
}

export class CheckboxGroup extends Widget {
    private _options: CheckboxGroupOption[];
    private _selected: Set<string>;
    private _focusedIndex = 0;

    onChange?: (selectedValues: string[]) => void;

    focusable = true;

    constructor(options: CheckboxGroupOptions) {
        super(
            mergeStyles(defaultStyle(), {
                height: Math.max(options.options.length, 1),
            })
        );

        this._options = options.options;
        const knownValues = new Set(options.options.map(o => o.value));
        this._selected = new Set(
            (options.defaultValues ?? []).filter(v => knownValues.has(v)),
        );
        this.onChange = options.onChange;
    }

    get selectedValues(): string[] {
        return Array.from(this._selected);
    }

    private emitChange(): void {
        this.onChange?.(this.selectedValues);
    }

    selectNext(): void {
        if (this._focusedIndex < this._options.length - 1) {
            this._focusedIndex++;
            this.markDirty();
        }
    }

    selectPrev(): void {
        if (this._focusedIndex > 0) {
            this._focusedIndex--;
            this.markDirty();
        }
    }

    toggleCurrent(): void {
        const option = this._options[this._focusedIndex];

        if (!option) return;

        if (this._selected.has(option.value)) {
            this._selected.delete(option.value);
        } else {
            this._selected.add(option.value);
        }

        this.emitChange();
        this.markDirty();
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'up':
                this.selectPrev();
                break;

            case 'down':
                this.selectNext();
                break;

            case 'space':
                this.toggleCurrent();
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;

        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this.style);

        for (let i = 0; i < this._options.length && i < height; i++) {
            const option = this._options[i];

            const focused = i === this._focusedIndex;
            const checked = this._selected.has(option.value);

            const prefix = focused
                ? (caps.unicode ? '❯ ' : '> ')
                : '  ';

            const checkbox = checked ? '[x]' : '[ ]';

            const text = `${prefix}${checkbox} ${option.label}`;

            screen.writeString(
                x,
                y + i,
                text.slice(0, width),
                {
                    ...attrs,
                    bold: focused,
                }
            );
        }
    }
}

import { Widget } from '@termuijs/widgets';
import { type Style, type Color, type KeyEvent, type Screen, mergeStyles, defaultStyle, styleToCellAttrs } from '@termuijs/core';

export interface ListbarItem {
    label: string;
    key?: string;
    action?: () => void;
    disabled?: boolean;
}

export interface ListbarOptions {
    activeColor?: Color;
    keyColor?: Color;
    separator?: string;
}

export class Listbar extends Widget {
    private _items: ListbarItem[] = [];
    private _activeIndex = 0;
    private _activeColor: Color;
    private _keyColor: Color;
    private _separator: string;

    focusable = true;

    constructor(items: ListbarItem[], style?: Partial<Style>, opts?: ListbarOptions) {
        super(mergeStyles(defaultStyle(), { height: 1, ...style }));
        this._items = items;
        this._activeColor = opts?.activeColor ?? { type: 'named', name: 'cyan' };
        this._keyColor = opts?.keyColor ?? { type: 'named', name: 'yellow' };
        this._separator = opts?.separator ?? ' | ';
        this._initActiveIndex();
    }

    get activeItem(): number {
        return this._activeIndex;
    }

    setItems(items: ListbarItem[]): void {
        this._items = items;
        this._initActiveIndex();
        this.markDirty();
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'left':
                this._activeIndex = this._nextEnabled(this._activeIndex, -1);
                this.markDirty();
                break;

            case 'right':
                this._activeIndex = this._nextEnabled(this._activeIndex, 1);
                this.markDirty();
                break;

            case 'enter':
                const item = this._items[this._activeIndex];
                if (item && !item.disabled && item.action) {
                    item.action();
                }
                break;
        }
    }

    private _initActiveIndex(): void {
        this._activeIndex = 0;
        for (let i = 0; i < this._items.length; i++) {
            if (!this._items[i].disabled) {
                this._activeIndex = i;
                return;
            }
        }
    }

    private _nextEnabled(from: number, direction: number): number {
        if (this._items.length === 0) return from;

        let i = from;
        do {
            i = (i + direction + this._items.length) % this._items.length;
            if (!this._items[i].disabled) return i;
        } while (i !== from);

        return from;
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width } = this._rect;
        if (width <= 0) return;

        const baseAttrs = styleToCellAttrs(this.style);
        let col = x;

        for (let i = 0; i < this._items.length; i++) {
            if (col >= x + width) break;

            const item = this._items[i];
            const isActive = i === this._activeIndex;

            if (item.key) {
                const keyText = `${item.key} `;
                const keyColor = item.disabled
                    ? { type: 'named', name: 'brightBlack' } as Color
                    : isActive
                        ? this._activeColor
                        : this._keyColor;

                const keyVisible = keyText.slice(0, x + width - col);
                screen.writeString(col, y, keyVisible, {
                    ...baseAttrs,
                    fg: keyColor,
                    dim: item.disabled,
                    bold: isActive,
                });
                col += keyText.length;
                if (col >= x + width) break;
            }

            const labelVisible = item.label.slice(0, x + width - col);
            screen.writeString(col, y, labelVisible, {
                ...baseAttrs,
                fg: item.disabled
                    ? { type: 'named', name: 'brightBlack' }
                    : isActive
                        ? this._activeColor
                        : baseAttrs.fg,
                dim: item.disabled,
                bold: isActive,
            });
            col += item.label.length;

            if (i < this._items.length - 1 && col < x + width) {
                const sepVisible = this._separator.slice(0, x + width - col);
                screen.writeString(col, y, sepVisible, baseAttrs);
                col += this._separator.length;
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — Rating widget
//
// Renders a star rating selector controlled by arrow keys.
// Right/left arrows adjust the value; enter confirms and
// fires onSelect.
// ─────────────────────────────────────────────────────

import { Widget } from '@termuijs/widgets';
import {
    type Screen,
    type Style,
    type Color,
    type KeyEvent,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    caps,
} from '@termuijs/core';

export interface RatingOptions {
    /** Total number of stars. Default: 5 */
    max?: number;
    /** Initial rating. Default: 0 */
    value?: number;
    /** Filled star character. Default: '★' with ASCII fallback '*' */
    filledChar?: string;
    /** Empty star character. Default: '☆' with ASCII fallback '-' */
    emptyChar?: string;
    /** Color for filled stars */
    filledColor?: Color;
    /** Callback when the user confirms a rating via enter */
    onSelect?: (value: number) => void;
}

/**
 * Rating — renders a row of star glyphs for a 1-to-N rating.
 *
 * Example output (unicode, max=5, value=3):
 *   ★★★☆☆
 *
 * ASCII fallback:
 *   ***--
 */
export class Rating extends Widget {
    private _value: number;
    private _max: number;
    private _filledChar?: string;
    private _emptyChar?: string;
    private _filledColor?: Color;

    /** Callback when the user confirms a rating via enter. */
    onSelect?: (value: number) => void;

    focusable = true;

    constructor(style: Partial<Style> = {}, opts: RatingOptions = {}) {
        const max = Math.max(opts.max ?? 5, 1);

        super(mergeStyles(defaultStyle(), { ...style, height: 1 }));

        this._max = max;
        this._value = Math.max(0, Math.min(opts.value ?? 0, max));
        this._filledChar = opts.filledChar;
        this._emptyChar = opts.emptyChar;
        this._filledColor = opts.filledColor;
        this.onSelect = opts.onSelect;
    }

    // ── Accessors ─────────────────────────────────────

    /** The current rating value (0 to max). */
    get value(): number {
        return this._value;
    }

    /** The maximum number of stars. */
    get max(): number {
        return this._max;
    }

    // ── Public methods ────────────────────────────────

    /** Set the rating value (clamped to 0..max). Calls markDirty(). */
    setValue(value: number): void {
        const clamped = Math.max(0, Math.min(value, this._max));
        if (clamped === this._value) return;
        this._value = clamped;
        this.markDirty();
    }

    /** Get the current rating value. */
    getValue(): number {
        return this._value;
    }

    // ── Key handling ──────────────────────────────────

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'right':
                this.setValue(this._value + 1);
                break;
            case 'left':
                this.setValue(this._value - 1);
                break;
            case 'home':
                this.setValue(0);
                break;
            case 'end':
                this.setValue(this._max);
                break;
            case 'enter':
                this.onSelect?.(this._value);
                break;
        }
    }

    // ── Rendering ─────────────────────────────────────

    protected _renderSelf(screen: Screen): void {
        const { x, y, width } = this._rect;
        if (width <= 0) return;

        const attrs = styleToCellAttrs(this.style);

        const filled = this._filledChar ?? (caps.unicode ? '★' : '*');
        const empty = this._emptyChar ?? (caps.unicode ? '☆' : '-');

        let text = '';
        for (let i = 0; i < this._max; i++) {
            text += i < this._value ? filled : empty;
        }

        screen.writeString(x, y, text.slice(0, width), attrs);
    }
}

// DateRangePicker — calendar date range selector widget
import { Widget } from '@termuijs/widgets';
import {
    type Style,
    type Screen,
    type KeyEvent,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    caps,
} from '@termuijs/core';

export interface DateRange {
    start: Date;
    end: Date;
}

export interface DateRangePickerOptions {
    value?: Partial<DateRange>;
    onChange?: (range: Partial<DateRange>) => void;
}

const MONTH_NAMES = [
    'January', 'February', 'March', 'April', 'May', 'June',
    'July', 'August', 'September', 'October', 'November', 'December'
];

export class DateRangePicker extends Widget {
    private _cursorDate: Date;
    private _currentMonth: Date;
    private _rangeStart: Date | null = null;
    private _rangeEnd: Date | null = null;
    private _selectionState: 'none' | 'start-set' | 'end-set' = 'none';
    private _onChange?: (range: Partial<DateRange>) => void;
    focusable = true;

    constructor(options: DateRangePickerOptions = {}) {
        super(mergeStyles(defaultStyle(), { border: 'single', height: 10 }));

        this._rangeStart = options.value?.start ? this._zeroTime(options.value.start) : null;
        this._rangeEnd = options.value?.end ? this._zeroTime(options.value.end) : null;

        if (this._rangeStart && this._rangeEnd) {
            this._selectionState = 'end-set';
        } else if (this._rangeStart) {
            this._selectionState = 'start-set';
        } else {
            this._selectionState = 'none';
        }

        const baseDate = this._rangeStart || this._rangeEnd || new Date();
        this._cursorDate = this._zeroTime(baseDate);

        this._currentMonth = new Date(this._cursorDate.getFullYear(), this._cursorDate.getMonth(), 1);
        this._onChange = options.onChange;
    }

    private _zeroTime(d: Date): Date {
        const res = new Date(d);
        res.setHours(0, 0, 0, 0);
        return res;
    }

    get range(): Partial<DateRange> {
        const res: Partial<DateRange> = {};
        if (this._rangeStart) res.start = new Date(this._rangeStart);
        if (this._rangeEnd) res.end = new Date(this._rangeEnd);
        return res;
    }

    moveSelection(days: number): void {
        const newDate = new Date(this._cursorDate);
        newDate.setDate(newDate.getDate() + days);
        this._cursorDate = newDate;

        if (newDate.getMonth() !== this._currentMonth.getMonth() || newDate.getFullYear() !== this._currentMonth.getFullYear()) {
            this._currentMonth = new Date(newDate.getFullYear(), newDate.getMonth(), 1);
        }
        this.markDirty();
    }

    changeMonth(months: number): void {
        const targetMonth = this._cursorDate.getMonth() + months;
        const targetYear = this._cursorDate.getFullYear();
        const lastDayOfTarget = new Date(targetYear, targetMonth + 1, 0).getDate();
        const clampedDay = Math.min(this._cursorDate.getDate(), lastDayOfTarget);
        const newDate = new Date(targetYear, targetMonth, clampedDay);
        this._cursorDate = newDate;
        this._currentMonth = new Date(newDate.getFullYear(), newDate.getMonth(), 1);
        this.markDirty();
    }

    confirm(): void {
        const cur = new Date(this._cursorDate);
        if (this._selectionState === 'none' || this._selectionState === 'end-set') {
            this._rangeStart = cur;
            this._rangeEnd = null;
            this._selectionState = 'start-set';
        } else if (this._selectionState === 'start-set') {
            const start = this._rangeStart!;
            if (cur < start) {
                // Swap start and end
                this._rangeEnd = start;
                this._rangeStart = cur;
            } else {
                this._rangeEnd = cur;
            }
            this._selectionState = 'end-set';
        }
        this.markDirty();
        this._onChange?.(this.range);
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'left':
            case 'h':
                if (event.key === 'left' || (!event.ctrl && !event.alt)) {
                    this.moveSelection(-1);
                }
                break;
            case 'right':
            case 'l':
                if (event.key === 'right' || (!event.ctrl && !event.alt)) {
                    this.moveSelection(1);
                }
                break;
            case 'up':
            case 'k':
                if (event.key === 'up' || (!event.ctrl && !event.alt)) {
                    this.moveSelection(-7);
                }
                break;
            case 'down':
            case 'j':
                if (event.key === 'down' || (!event.ctrl && !event.alt)) {
                    this.moveSelection(7);
                }
                break;
            case 'pageup':
                this.changeMonth(-1);
                break;
            case 'pagedown':
                this.changeMonth(1);
                break;
            case 'enter':
            case 'return':
                this.confirm();
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        // 1. Render Month Header (◀ Month Year ▶)
        const prevArrow = caps.unicode ? '◀' : '<';
        const nextArrow = caps.unicode ? '▶' : '>';
        const monthName = MONTH_NAMES[this._currentMonth.getMonth()];
        const year = this._currentMonth.getFullYear();
        const title = `${prevArrow} ${monthName} ${year} ${nextArrow}`;
        const titleX = x + Math.floor((width - title.length) / 2);
        screen.writeString(Math.max(x, titleX), y, title, { ...attrs, bold: true });

        if (height < 2) return;

        // 2. Render Weekdays Header
        const weekdays = 'Su Mo Tu We Th Fr Sa';
        const weekdayX = x + Math.floor((width - weekdays.length) / 2);
        screen.writeString(Math.max(x, weekdayX), y + 1, weekdays, { ...attrs, dim: true });

        // 3. Render Calendar Grid (Days)
        const daysInMonth = new Date(year, this._currentMonth.getMonth() + 1, 0).getDate();
        const firstDay = new Date(year, this._currentMonth.getMonth(), 1).getDay();

        const gridStartY = y + 2;
        const maxWeeks = 6;

        for (let w = 0; w < maxWeeks; w++) {
            const rowY = gridStartY + w;
            if (rowY >= y + height) break;

            for (let d = 0; d < 7; d++) {
                const colX = Math.max(x, weekdayX) + d * 3;
                if (colX >= x + width) continue;

                const dayVal = w * 7 + d - firstDay + 1;

                if (dayVal >= 1 && dayVal <= daysInMonth) {
                    const label = String(dayVal).padStart(2, ' ');
                    const dayDate = new Date(year, this._currentMonth.getMonth(), dayVal);
                    dayDate.setHours(0, 0, 0, 0);
                    const dayTime = dayDate.getTime();

                    const isCursor = this._cursorDate.getTime() === dayTime;
                    const isStart = this._rangeStart !== null && this._rangeStart.getTime() === dayTime;
                    const isEnd = this._rangeEnd !== null && this._rangeEnd.getTime() === dayTime;
                    const isBetween = this._rangeStart !== null && this._rangeEnd !== null &&
                        dayTime > this._rangeStart.getTime() && dayTime < this._rangeEnd.getTime();

                    if (isCursor) {
                        screen.writeString(colX, rowY, label, {
                            ...attrs,
                            bold: true,
                            inverse: this.isFocused,
                            underline: !this.isFocused
                        });
                    } else if (isStart || isEnd) {
                        screen.writeString(colX, rowY, label, {
                            ...attrs,
                            bold: true,
                            fg: { type: 'named', name: 'cyan' },
                            underline: true
                        });
                    } else if (isBetween) {
                        screen.writeString(colX, rowY, label, {
                            ...attrs,
                            fg: { type: 'named', name: 'black' },
                            bg: { type: 'named', name: 'cyan' }
                        });
                    } else {
                        screen.writeString(colX, rowY, label, attrs);
                    }
                } else {
                    // Blank spacer for out-of-bounds days
                    screen.writeString(colX, rowY, '  ', attrs);
                }
            }
        }
    }
}

// Spacer — flexible empty space
import { Widget } from '@termuijs/widgets';
import { type Screen, mergeStyles, defaultStyle } from '@termuijs/core';

export class Spacer extends Widget {
    constructor(grow: number = 1) {
        super(mergeStyles(defaultStyle(), { flexGrow: grow }));
    }
    protected _renderSelf(_screen: Screen): void { /* empty */ }
}

import { Widget } from "@termuijs/widgets";
import { type Style, type KeyEvent, Screen, caps } from "@termuijs/core";

export interface BasicAuthCredentials {
    username: string;
    password: string;
}

export interface BasicAuthPromptOptions {
    usernameLabel?: string; // default: 'Username:'
    passwordLabel?: string; // default: 'Password:'
    onSubmit?: (credentials: BasicAuthCredentials) => void;
}

export class BasicAuthPrompt extends Widget {
    private _username = "";
    private _password = "";
    private _activeField: "username" | "password" = "username";
    private _opts: BasicAuthPromptOptions;
    private get _maskChar(): string {
        return caps.unicode ? "●" : "*";
    }
    constructor(style?: Partial<Style>, opts?: BasicAuthPromptOptions) {
        super(style);

        this._opts = {
            usernameLabel: "Username:",
            passwordLabel: "Password:",
            ...opts,
        };
    }
    getCredentials(): BasicAuthCredentials {
        return {
            username: this._username,
            password: this._password,
        };
    }
    private onSubmit(): void {
        if (this._activeField === "username") {
            this._activeField = "password";
        } else if (this._activeField === "password") {
            this._opts.onSubmit?.(this.getCredentials());
        }
        this.markDirty();
    }
    private deleteBackward(): void {
        if (this._activeField === "username") {
            this._username = this._username.slice(0, -1);
        } else {
            this._password = this._password.slice(0, -1);
        }
        this.markDirty();
    }
    private insertChar(key: string): void {
        if (this._activeField === "username") {
            this._username += key;
        } else {
            this._password += key;
        }
        this.markDirty();
    }
    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case "enter":
                this.onSubmit();
                break;
            case "backspace":
                this.deleteBackward();
                break;
            default:
                if (event.key.length === 1 && !event.ctrl && !event.alt) {
                    this.insertChar(event.key);
                }
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;
        const username = `${this._opts.usernameLabel} ${this._username}`;
        const masked = this._maskChar.repeat(this._password.length);
        const password = `${this._opts.passwordLabel} ${masked}`;
        screen.writeString(x, y, username);
        if (height > 1) {
            screen.writeString(x, y + 1, password);
        }
    }
}

import { Widget } from "@termuijs/widgets";
import {
    type Style,
    type Screen,
    type KeyEvent,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    caps,
} from "@termuijs/core";

export interface SurveyQuestion {
    id: string;
    question: string;
    type: "text" | "choice";
    options?: string[];
}

export interface SurveyPromptOptions {
    onComplete?: (answers: Record<string, string>) => void;
}

export class SurveyPrompt extends Widget {
    private _questions: SurveyQuestion[];
    private _currentIndex = 0;
    private _answers: Record<string, string> = {};

    private _textBuffer = "";
    private _choiceIndex = 0;

    private _onComplete?: (answers: Record<string, string>) => void;

    focusable = true;

    constructor(
        questions: SurveyQuestion[],
        style?: Partial<Style>,
        opts?: SurveyPromptOptions,
    ) {
        super(mergeStyles(defaultStyle(), style ?? {}));

        this._questions = questions;
        this._onComplete = opts?.onComplete;
    }

    getAnswers(): Record<string, string> {
        return { ...this._answers };
    }

    getCurrentIndex(): number {
        return this._currentIndex;
    }
    private _advance(): void {
        this._currentIndex++;

        this._textBuffer = "";
        this._choiceIndex = 0;

        if (this._currentIndex >= this._questions.length) {
            this._onComplete?.({ ...this._answers });
        }

        this.markDirty();
    }

    handleKey(event: KeyEvent): void {
        if (this._currentIndex >= this._questions.length) return;

        const question = this._questions[this._currentIndex];

        if (question.type === "text") {
            switch (event.key) {
                case "backspace":
                    this._textBuffer = this._textBuffer.slice(0, -1);
                    this.markDirty();
                    break;

                case "enter":
                    this._answers[question.id] = this._textBuffer;
                    this._advance();
                    break;

                default:
                    if (
                        event.key &&
                        event.key.length === 1 &&
                        !event.ctrl &&
                        !event.alt
                    ) {
                        this._textBuffer += event.key;
                        this.markDirty();
                    }
            }

            return;
        }

        switch (event.key) {
            case "up":
                if (this._choiceIndex > 0) {
                    this._choiceIndex--;
                    this.markDirty();
                }
                break;

            case "down":
                if (
                    question.options &&
                    this._choiceIndex < question.options.length - 1
                ) {
                    this._choiceIndex++;
                    this.markDirty();
                }
                break;

            case "enter":
                if (question.options?.length) {
                    this._answers[question.id] =
                        question.options[this._choiceIndex];
                    this._advance();
                }
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;

        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this.style);

        if (this._currentIndex >= this._questions.length) {
            screen.writeString(x, y, "Survey Complete".slice(0, width), attrs);
            return;
        }

        const question = this._questions[this._currentIndex];

        let row = 0;

        screen.writeString(
            x,
            y + row,
            `${this._currentIndex + 1} / ${this._questions.length}`.slice(
                0,
                width,
            ),
            attrs,
        );
        row += 2;

        screen.writeString(x, y + row, question.question.slice(0, width), {
            ...attrs,
            bold: true,
        });
        row += 2;

        if (question.type === "text") {
            screen.writeString(
                x,
                y + row,
                this._textBuffer.slice(0, width),
                attrs,
            );
            return;
        }

        const options = question.options ?? [];

        for (let i = 0; i < options.length && row < height; i++) {
            const active = i === this._choiceIndex;

            const prefix = active ? (caps.unicode ? "❯ " : "> ") : "  ";

            screen.writeString(
                x,
                y + row,
                `${prefix}${options[i]}`.slice(0, width),
                {
                    ...attrs,
                    bold: active,
                },
            );

            row++;
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — MultilineTextInput widget
//
// A multi-line text editor widget for terminal UIs.
// - Arrow keys move the cursor across lines and columns
// - Enter inserts a newline
// - Text soft-wraps at the widget width so long lines stay visible
// - Fires onChange(value) when the text changes
// - Calls this.markDirty() on state changes that affect rendering
// - Checks caps.unicode and provides an ASCII fallback where it draws symbols
// ─────────────────────────────────────────────────────

import { Widget } from '@termuijs/widgets';
import {
    type Style,
    type Screen,
    type KeyEvent,
    styleToCellAttrs,
    caps,
    stringWidth,
} from '@termuijs/core';

export interface MultilineTextInputOptions {
    placeholder?: string;
    onChange?: (value: string) => void;
    onSubmit?: (value: string) => void;
}

export class MultilineTextInput extends Widget {
    /** Each element is one logical line (no '\n' inside). */
    private _lines: string[] = [''];
    /** Cursor position: line index. */
    private _cursorLine = 0;
    /** Cursor position: column index within the logical line. */
    private _cursorCol = 0;
    private _placeholder: string;
    private _onChange?: (value: string) => void;
    private _onSubmit?: (value: string) => void;
    focusable = true;

    constructor(style: Partial<Style> = {}, options: MultilineTextInputOptions = {}) {
        super({ border: 'single', height: 6, ...style });
        this._placeholder = options.placeholder ?? '';
        this._onChange = options.onChange;
        this._onSubmit = options.onSubmit;
    }

    // ── Public API ─────────────────────────────────────

    /** Full text value with newlines. */
    get value(): string {
        return this._lines.join('\n');
    }

    /** Set text programmatically. */
    set value(v: string) {
        this._lines = v.split('\n');
        if (this._lines.length === 0) this._lines = [''];
        this._cursorLine = Math.min(this._cursorLine, this._lines.length - 1);
        this._cursorCol = Math.min(this._cursorCol, this._lines[this._cursorLine].length);
        this.markDirty();
    }

    /** Clear all content. */
    clear(): void {
        this._lines = [''];
        this._cursorLine = 0;
        this._cursorCol = 0;
        this._onChange?.('');
        this.markDirty();
    }

    // ── Editing operations ──────────────────────────────

    /** Insert a single printable character at the cursor position. */
    insertChar(char: string): void {
        const line = this._lines[this._cursorLine];
        this._lines[this._cursorLine] =
            line.slice(0, this._cursorCol) + char + line.slice(this._cursorCol);
        this._cursorCol++;
        this._notify();
    }

    /** Insert a newline — splits the current line at cursor. */
    insertNewline(): void {
        const line = this._lines[this._cursorLine];
        const before = line.slice(0, this._cursorCol);
        const after = line.slice(this._cursorCol);
        this._lines[this._cursorLine] = before;
        this._lines.splice(this._cursorLine + 1, 0, after);
        this._cursorLine++;
        this._cursorCol = 0;
        this._notify();
    }

    /** Delete the character before the cursor (Backspace). */
    deleteBack(): void {
        if (this._cursorCol > 0) {
            const line = this._lines[this._cursorLine];
            this._lines[this._cursorLine] =
                line.slice(0, this._cursorCol - 1) + line.slice(this._cursorCol);
            this._cursorCol--;
            this._notify();
        } else if (this._cursorLine > 0) {
            // Merge with previous line
            const prevLine = this._lines[this._cursorLine - 1];
            const curLine = this._lines[this._cursorLine];
            this._lines.splice(this._cursorLine, 1);
            this._cursorLine--;
            this._cursorCol = prevLine.length;
            this._lines[this._cursorLine] = prevLine + curLine;
            this._notify();
        }
    }

    /** Delete the character after the cursor (Delete). */
    deleteForward(): void {
        const line = this._lines[this._cursorLine];
        if (this._cursorCol < line.length) {
            this._lines[this._cursorLine] =
                line.slice(0, this._cursorCol) + line.slice(this._cursorCol + 1);
            this._notify();
        } else if (this._cursorLine < this._lines.length - 1) {
            // Merge next line into current
            const nextLine = this._lines[this._cursorLine + 1];
            this._lines.splice(this._cursorLine + 1, 1);
            this._lines[this._cursorLine] = line + nextLine;
            this._notify();
        }
    }

    // ── Cursor movement ─────────────────────────────────

    moveCursorLeft(): void {
        if (this._cursorCol > 0) {
            this._cursorCol--;
        } else if (this._cursorLine > 0) {
            this._cursorLine--;
            this._cursorCol = this._lines[this._cursorLine].length;
        }
        this.markDirty();
    }

    moveCursorRight(): void {
        const line = this._lines[this._cursorLine];
        if (this._cursorCol < line.length) {
            this._cursorCol++;
        } else if (this._cursorLine < this._lines.length - 1) {
            this._cursorLine++;
            this._cursorCol = 0;
        }
        this.markDirty();
    }

    moveCursorUp(): void {
        if (this._cursorLine > 0) {
            this._cursorLine--;
            this._cursorCol = Math.min(this._cursorCol, this._lines[this._cursorLine].length);
            this.markDirty();
        }
    }

    moveCursorDown(): void {
        if (this._cursorLine < this._lines.length - 1) {
            this._cursorLine++;
            this._cursorCol = Math.min(this._cursorCol, this._lines[this._cursorLine].length);
            this.markDirty();
        }
    }

    moveCursorHome(): void {
        this._cursorCol = 0;
        this.markDirty();
    }

    moveCursorEnd(): void {
        this._cursorCol = this._lines[this._cursorLine].length;
        this.markDirty();
    }

    submit(): void {
        this._onSubmit?.(this.value);
    }

    // ── Key handler ─────────────────────────────────────

    /**
     * Handle key events. Call this from your application input loop.
     * Returns true if the event was consumed.
     */
    handleKey(event: KeyEvent): boolean {
        switch (event.key) {
            case 'up':    this.moveCursorUp();    return true;
            case 'down':  this.moveCursorDown();  return true;
            case 'left':  this.moveCursorLeft();  return true;
            case 'right': this.moveCursorRight(); return true;
            case 'home':  this.moveCursorHome();  return true;
            case 'end':   this.moveCursorEnd();   return true;
            case 'backspace': this.deleteBack();  return true;
            case 'delete':    this.deleteForward(); return true;
            case 'return':
            case 'enter': this.insertNewline();   return true;
            default:
                if (
                    event.key &&
                    event.key.length === 1 &&
                    !event.ctrl &&
                    !event.alt
                ) {
                    this.insertChar(event.key);
                    return true;
                }
                return false;
        }
    }

    // ── Rendering ───────────────────────────────────────

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        // Show placeholder when empty and not focused
        const isEmpty = this._lines.length === 1 && this._lines[0] === '';
        if (isEmpty && !this.isFocused && this._placeholder) {
            screen.writeString(x, y, this._placeholder.slice(0, width), { ...attrs, dim: true });
            return;
        }

        // Soft-wrap each logical line into display rows
        const displayRows = this._softWrap(width);

        // Find the display row + col of the cursor
        const { displayRow: cursorDisplayRow, displayCol: cursorDisplayCol } =
            this._cursorDisplayPos(width);

        // Scroll vertically so cursor is always visible
        const scrollY = this._calcScrollY(cursorDisplayRow, height);

        // Render visible rows
        for (let row = 0; row < height; row++) {
            const dRow = row + scrollY;
            if (dRow >= displayRows.length) break;
            const { text } = displayRows[dRow];
            screen.writeString(x, y + row, text.padEnd(width, ' ').slice(0, width), attrs);
        }

        // Render cursor
        if (this.isFocused) {
            const screenRow = cursorDisplayRow - scrollY;
            if (screenRow >= 0 && screenRow < height) {
                const cursorDisplayRow2 = cursorDisplayRow;
                const rowText = displayRows[cursorDisplayRow2]?.text ?? '';

                let cursorChar = ' ';
                const segmenter = new Intl.Segmenter();
                const segments = Array.from(segmenter.segment(rowText));
                let w = 0;
                for (const seg of segments) {
                    const segWidth = stringWidth(seg.segment);
                    if (cursorDisplayCol >= w && cursorDisplayCol < w + segWidth) {
                        cursorChar = seg.segment;
                        break;
                    }
                    w += segWidth;
                }

                // Unicode block cursor vs ASCII '|'
                const cursorGlyph = caps.unicode ? cursorChar : cursorChar;
                screen.setCell(x + cursorDisplayCol, y + screenRow, {
                    char: cursorGlyph,
                    ...attrs,
                    inverse: true,
                });
            }
        }
    }

    // ── Private helpers ─────────────────────────────────

    private _notify(): void {
        this._onChange?.(this.value);
        this.markDirty();
    }

    private _softWrap(width: number): Array<{ text: string; lineIdx: number; lineOffset: number }> {
        const rows: Array<{ text: string; lineIdx: number; lineOffset: number }> = [];
        const segmenter = new Intl.Segmenter();

        for (let li = 0; li < this._lines.length; li++) {
            const line = this._lines[li];
            if (line.length === 0) {
                rows.push({ text: '', lineIdx: li, lineOffset: 0 });
                continue;
            }

            const segments = Array.from(segmenter.segment(line));
            let currentWidth = 0;
            let currentStart = 0;
            let currentText = '';
            let charOffset = 0;

            for (let i = 0; i < segments.length; i++) {
                const seg = segments[i];
                const w = stringWidth(seg.segment);

                if (currentWidth + w > width && currentText.length > 0) {
                    rows.push({
                        text: currentText,
                        lineIdx: li,
                        lineOffset: currentStart,
                    });
                    currentStart = charOffset;
                    currentText = seg.segment;
                    currentWidth = w;
                } else {
                    currentText += seg.segment;
                    currentWidth += w;
                }
                charOffset += seg.segment.length;
            }
            if (currentText.length > 0) {
                rows.push({
                    text: currentText,
                    lineIdx: li,
                    lineOffset: currentStart,
                });
            }
        }
        return rows;
    }

    /**
     * Compute the display row and column for the current cursor position,
     * given the content area width.
     */
    private _cursorDisplayPos(width: number): { displayRow: number; displayCol: number } {
        const rows = this._softWrap(width);
        // Walk rows to find the one that contains the cursor
        let best = { displayRow: 0, displayCol: 0 };
        for (let ri = 0; ri < rows.length; ri++) {
            const row = rows[ri];
            if (row.lineIdx !== this._cursorLine) continue;
            const rowEndOffset = row.lineOffset + row.text.length;
            if (
                this._cursorCol >= row.lineOffset &&
                (this._cursorCol < rowEndOffset || ri === rows.length - 1 || rows[ri + 1]?.lineIdx !== this._cursorLine)
            ) {
                const targetCharOffset = this._cursorCol - row.lineOffset;
                const segmenter = new Intl.Segmenter();
                const segments = Array.from(segmenter.segment(row.text));
                let charCount = 0;
                let displayWidth = 0;
                for (const seg of segments) {
                    if (charCount >= targetCharOffset) break;
                    charCount += seg.segment.length;
                    displayWidth += stringWidth(seg.segment);
                }
                best = {
                    displayRow: ri,
                    displayCol: displayWidth,
                };
            }
        }
        return best;
    }

    /**
     * Calculate a scroll offset so the cursor row is always visible.
     */
    private _calcScrollY(cursorDisplayRow: number, height: number): number {
        // Simple strategy: keep cursor in view, bias towards showing as much
        // content from the top as possible.
        let scrollY = 0;
        if (cursorDisplayRow >= height) {
            scrollY = cursorDisplayRow - height + 1;
        }
        return scrollY;
    }
}

// Tabs — tabbed container with keyboard switching
import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, mergeStyles, defaultStyle, styleToCellAttrs, caps } from '@termuijs/core';

export interface Tab { label: string; content: Widget; }
export interface TabsOptions {
    activeColor?: Style['fg'];
    inactiveColor?: Style['fg'];
    border?: Style['border'];
}

export class Tabs extends Widget {
    private _tabs: Tab[] = [];
    private _activeIndex = 0;
    private _activeColor: Style['fg'];
    private _inactiveColor: Style['fg'];
    focusable = true;

    constructor(tabs: Tab[], options: TabsOptions = {}) {
        super(mergeStyles(defaultStyle(), { flexGrow: 1, border: options.border ?? 'single' }));
        this._tabs = tabs;
        this._activeColor = options.activeColor ?? { type: 'named', name: 'cyan' };
        this._inactiveColor = options.inactiveColor ?? { type: 'named', name: 'brightBlack' };
    }

    get activeIndex(): number { return this._activeIndex; }
    selectTab(i: number): void {
        if (i >= 0 && i < this._tabs.length) { this._activeIndex = i; this.markDirty(); }
    }
    nextTab(): void {
        if (this._tabs.length === 0) return;
        this._activeIndex = (this._activeIndex + 1) % this._tabs.length;
        this.markDirty();
    }
    prevTab(): void {
        if (this._tabs.length === 0) return;
        this._activeIndex = (this._activeIndex - 1 + this._tabs.length) % this._tabs.length;
        this.markDirty();
    }
    get activeContent(): Widget | undefined { return this._tabs[this._activeIndex]?.content; }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;
        const attrs = styleToCellAttrs(this.style);
        let col = x;
        for (let i = 0; i < this._tabs.length; i++) {
            const tab = this._tabs[i];
            const isActive = i === this._activeIndex;
            const label = isActive ? ` ${caps.unicode ? '●' : '*'} ${tab.label} ` : `   ${tab.label} `;
            screen.writeString(col, y, label, {
                ...attrs,
                fg: isActive ? this._activeColor : this._inactiveColor,
                bold: isActive, dim: !isActive,
            });
            col += label.length;
            if (i < this._tabs.length - 1) { screen.writeString(col, y, caps.unicode ? '│' : '|', { ...attrs, dim: true }); col++; }
        }
        if (height > 1) screen.writeString(x, y + 1, '─'.repeat(width), { ...attrs, dim: true });

        // Render active tab content below the separator
        if (height > 2) {
            const content = this.activeContent;
            if (content) {
                content.updateRect({ x, y: y + 2, width, height: height - 2 });
                content.render(screen);
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — PathInput widget
//
// A TextInput with Tab-completion for filesystem paths.
// - Tab triggers completion: reads dir entries via readdirSync
// - Shows completion options below the input
// - Tab cycles through completions
// - Enter accepts current value
// - Handles relative and absolute paths gracefully
// ─────────────────────────────────────────────────────

import * as fs from 'node:fs';
import * as path from 'node:path';
import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, type KeyEvent, styleToCellAttrs, truncate, caps } from '@termuijs/core';

export interface PathInputOptions {
    placeholder?: string;
    maxLength?: number;
    cwd?: string;               // base directory for relative paths
    maxCompletions?: number;    // max completions shown (default 5)
    onChange?: (value: string) => void;
    onSubmit?: (value: string) => void;
}

/**
 * PathInput — filesystem path input with Tab-completion.
 *
 * @note height must be at least (maxCompletions + 2) to show completions.
 * Default height of 3 shows up to 1 completion. If height is insufficient,
 * the input line is still rendered but completions are hidden.
 */
export class PathInput extends Widget {
    private _value = '';
    private _cursorPos = 0;
    private _placeholder: string;
    private _maxLength: number;
    private _cwd: string;
    private _maxCompletions: number;
    private _completions: string[] = [];
    private _completionIndex = -1;       // -1 = original value, 0..n = cycling
    private _preCompletionValue = '';    // value before Tab was pressed
    private _showCompletions = false;
    private _onChange?: (value: string) => void;
    private _onSubmit?: (value: string) => void;
    focusable = true;

    constructor(
        style: Partial<Style> = {},
        options: PathInputOptions = {},
    ) {
        super({ border: 'single', height: 3, ...style });
        this._placeholder = options.placeholder ?? '';
        this._maxLength = options.maxLength ?? 4096;
        this._cwd = options.cwd ?? process.cwd();
        this._maxCompletions = options.maxCompletions ?? 5;
        this._onChange = options.onChange;
        this._onSubmit = options.onSubmit;
    }

    get value(): string { return this._value; }

    set value(v: string) {
        this._value = v.slice(0, this._maxLength);
        this._cursorPos = Math.min(this._cursorPos, this._value.length);
        this._dismissCompletions();
    }

    get completions(): string[] { return this._completions; }
    get isShowingCompletions(): boolean { return this._showCompletions && this._completions.length > 0; }

    private _dismissCompletions(): void {
        this._completions = [];
        this._completionIndex = -1;
        this._showCompletions = false;
    }

    /** Compute completions for the current value. Does NOT throw. */
    private _computeCompletions(): string[] {
        try {
            const raw = this._value;
            const isAbs = path.isAbsolute(raw);
            const base = isAbs ? raw : path.join(this._cwd, raw);

            // Determine the directory to list and the prefix to filter by
            let dir: string;
            let prefix: string;

            // If raw ends with separator or is empty, list the dir itself
            if (raw === '' || raw.endsWith('/') || raw.endsWith(path.sep)) {
                dir = isAbs ? raw || '/' : path.join(this._cwd, raw || '.');
                prefix = '';
            } else {
                dir = path.dirname(base);
                prefix = path.basename(base).toLowerCase();
            }

            const entries = fs.readdirSync(dir, { withFileTypes: true });
            const matches = entries
                .filter((e) => e.name.toLowerCase().startsWith(prefix))
                .slice(0, this._maxCompletions)
                .map((e) => {
                    const full = path.join(dir, e.name);
                    // Return path relative to cwd or absolute depending on input style
                    const candidate = isAbs
                        ? full + (e.isDirectory() ? path.sep : '')
                        : path.relative(this._cwd, full) + (e.isDirectory() ? path.sep : '');
                    return candidate;
                });

            return matches;
        } catch {
            return [];
        }
    }

    /** Trigger tab-completion. */
    triggerCompletion(): void {
        if (!this._showCompletions || this._completions.length === 0) {
            // First Tab press — compute completions
            this._preCompletionValue = this._value;
            this._completions = this._computeCompletions();
            if (this._completions.length === 0) {
                this._showCompletions = false;
                return;
            }
            this._showCompletions = true;
            this._completionIndex = 0;
        } else {
            // Subsequent Tab presses — cycle
            this._completionIndex = (this._completionIndex + 1) % this._completions.length;
        }

        this._value = this._completions[this._completionIndex];
        this._cursorPos = this._value.length;
        this._onChange?.(this._value);
        this.markDirty();
    }

    insertChar(char: string): void {
        if (this._value.length >= this._maxLength) return;
        this._value =
            this._value.slice(0, this._cursorPos) +
            char +
            this._value.slice(this._cursorPos);
        this._cursorPos++;
        this._dismissCompletions();
        this._onChange?.(this._value);
        this.markDirty();
    }

    deleteBack(): void {
        if (this._cursorPos > 0) {
            this._value =
                this._value.slice(0, this._cursorPos - 1) +
                this._value.slice(this._cursorPos);
            this._cursorPos--;
            this._dismissCompletions();
            this._onChange?.(this._value);
            this.markDirty();
        }
    }

    deleteForward(): void {
        if (this._cursorPos < this._value.length) {
            this._value =
                this._value.slice(0, this._cursorPos) +
                this._value.slice(this._cursorPos + 1);
            this._dismissCompletions();
            this._onChange?.(this._value);
            this.markDirty();
        }
    }

    moveCursorLeft(): void { this._cursorPos = Math.max(0, this._cursorPos - 1); this.markDirty(); }
    moveCursorRight(): void { this._cursorPos = Math.min(this._value.length, this._cursorPos + 1); this.markDirty(); }
    moveCursorHome(): void { this._cursorPos = 0; this.markDirty(); }
    moveCursorEnd(): void { this._cursorPos = this._value.length; this.markDirty(); }
    submit(): void { this._dismissCompletions(); this._onSubmit?.(this._value); }
    clear(): void { this._value = ''; this._cursorPos = 0; this._dismissCompletions(); this._onChange?.(''); this.markDirty(); }

    /**
     * Handle key events. Call this from your input loop.
     *  Tab   — trigger/cycle completions
     *  Esc   — dismiss completions
     *  Enter — submit current value
     */
    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'tab':
                this.triggerCompletion();
                event.preventDefault();
                event.stopPropagation();
                break;
            case 'escape': this._dismissCompletions(); this.markDirty(); break;
            case 'backspace': this.deleteBack(); break;
            case 'delete': this.deleteForward(); break;
            case 'left': this.moveCursorLeft(); break;
            case 'right': this.moveCursorRight(); break;
            case 'home': this.moveCursorHome(); break;
            case 'end': this.moveCursorEnd(); break;
            case 'return':
            case 'enter': this.submit(); break;
            default:
                if (event.key && event.key.length === 1 && !event.ctrl && !event.alt) {
                    this.insertChar(event.key);
                }
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        // ── Defensive: if height insufficient for completions, hide them ──
        if (height <= 1 && this._showCompletions) {
            this._showCompletions = false;
        }

        // ── Input line ──
        if (this._value.length === 0 && !this.isFocused) {
            screen.writeString(x, y, truncate(this._placeholder, width), { ...attrs, dim: true });
        } else {
            const visibleWidth = width - 1;
            let scrollX = 0;
            if (this._cursorPos > visibleWidth) {
                scrollX = this._cursorPos - visibleWidth;
            }
            const visibleText = this._value.slice(scrollX, scrollX + visibleWidth);
            screen.writeString(x, y, visibleText, attrs);

            if (this.isFocused) {
                const cursorScreenPos = x + this._cursorPos - scrollX;
                if (cursorScreenPos >= x && cursorScreenPos < x + width) {
                    const cursorChar = this._cursorPos < this._value.length
                        ? this._value[this._cursorPos]
                        : ' ';
                    screen.setCell(cursorScreenPos, y, {
                        char: cursorChar,
                        ...attrs,
                        inverse: true,
                    });
                }
            }
        }

        // ── Completion list (rendered below the input line) ──
        // Requires height >= maxCompletions + 2 (input line + separator).
        // Default height=3 shows up to 1 completion.
        if (this._showCompletions && this._completions.length > 0 && height > 1) {
            const maxRows = Math.min(this._completions.length, height - 1);
            for (let i = 0; i < maxRows; i++) {
                const row = y + 1 + i;
                const isSelected = i === this._completionIndex;
                const prefix = isSelected ? (caps.unicode ? '▶ ' : '> ') : '  ';
                const entry = this._completions[i];
                screen.writeString(x, row, truncate(prefix + entry, width), {
                    ...attrs,
                    bold: isSelected,
                    inverse: isSelected,
                });
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — ColorPicker widget
//
// A keyboard-navigable and text-editable ColorPicker.
// - Arrow keys (or hjkl) navigate a 16-color preset grid palette
// - Alphanumeric entry directly edits the hex value input
// - Shows a live swatch preview of the current color
// - Fires onChange(color) when the selection changes
// ─────────────────────────────────────────────────────

import { Widget } from '@termuijs/widgets';
import {
    type Style,
    type Screen,
    type KeyEvent,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    caps,
    parseColor,
    colorToRgb,
    Color,
    NamedColor
} from '@termuijs/core';

export interface ColorPickerOptions {
    value?: string | Color;
    onChange?: (color: Color) => void;
}

const DEFAULT_PALETTE: NamedColor[] = [
    'black', 'red', 'green', 'yellow', 'blue', 'magenta', 'cyan', 'white',
    'brightBlack', 'brightRed', 'brightGreen', 'brightYellow', 'brightBlue', 'brightMagenta', 'brightCyan', 'brightWhite'
];

const PALETTE_COLORS: Color[] = DEFAULT_PALETTE.map(name => parseColor(name));

export class ColorPicker extends Widget {
    private _selectedColor: Color;
    private _hexValue = 'ffffff'; // hex digits without '#'
    private _paletteIndex: number | null = null;
    private _onChange?: (color: Color) => void;
    focusable = true;

    constructor(options: ColorPickerOptions = {}) {
        super(mergeStyles(defaultStyle(), { border: 'single', height: 7 }));

        const initialValue = options.value ?? '#ffffff';
        if (typeof initialValue === 'string') {
            const parsed = parseColor(initialValue);
            this._selectedColor = parsed.type !== 'none' ? parsed : parseColor('#ffffff');
        } else {
            this._selectedColor = initialValue.type !== 'none' ? initialValue : parseColor('#ffffff');
        }

        this._hexValue = this._colorToHexStr(this._selectedColor);
        this._onChange = options.onChange;

        // Determine if initial color is in the palette
        const matchIdx = PALETTE_COLORS.findIndex(c => this._colorsEqual(c, this._selectedColor));
        this._paletteIndex = matchIdx !== -1 ? matchIdx : null;
    }

    get value(): Color {
        return this._selectedColor;
    }

    set value(val: string | Color) {
        let newColor: Color;
        if (typeof val === 'string') {
            const parsed = parseColor(val);
            newColor = parsed.type !== 'none' ? parsed : parseColor('#ffffff');
        } else {
            newColor = val.type !== 'none' ? val : parseColor('#ffffff');
        }

        this._selectedColor = newColor;
        this._hexValue = this._colorToHexStr(newColor);

        const matchIdx = PALETTE_COLORS.findIndex(c => this._colorsEqual(c, newColor));
        this._paletteIndex = matchIdx !== -1 ? matchIdx : null;

        this.markDirty();
    }

    private _colorToHexStr(color: Color): string {
        const [r, g, b] = colorToRgb(color);
        return ((r << 16) | (g << 8) | b).toString(16).padStart(6, '0');
    }

    private _colorsEqual(c1: Color, c2: Color): boolean {
        const rgb1 = colorToRgb(c1);
        const rgb2 = colorToRgb(c2);
        return rgb1[0] === rgb2[0] && rgb1[1] === rgb2[1] && rgb1[2] === rgb2[2];
    }

    private _updateFromHexInput(): void {
        const fullHex = '#' + this._hexValue;
        const parsed = parseColor(fullHex);
        if (parsed.type !== 'none') {
            this._selectedColor = parsed;
            const matchIdx = PALETTE_COLORS.findIndex(c => this._colorsEqual(c, parsed));
            this._paletteIndex = matchIdx !== -1 ? matchIdx : null;
            this._onChange?.(parsed);
        }
        this.markDirty();
    }

    handleKey(event: KeyEvent): void {
        let index = this._paletteIndex ?? 0;
        let paletteChanged = false;

        switch (event.key) {
            case 'left':
            case 'h':
                if (event.key === 'left' || (!event.ctrl && !event.alt)) {
                    if (index > 0) {
                        index--;
                        paletteChanged = true;
                    }
                }
                break;

            case 'right':
            case 'l':
                if (event.key === 'right' || (!event.ctrl && !event.alt)) {
                    if (index < 15) {
                        index++;
                        paletteChanged = true;
                    }
                }
                break;

            case 'up':
            case 'k':
                if (event.key === 'up' || (!event.ctrl && !event.alt)) {
                    if (index >= 8) {
                        index -= 8;
                        paletteChanged = true;
                    }
                }
                break;

            case 'down':
            case 'j':
                if (event.key === 'down' || (!event.ctrl && !event.alt)) {
                    if (index < 8) {
                        index += 8;
                        paletteChanged = true;
                    }
                }
                break;

            case 'backspace':
                if (this._hexValue.length > 0) {
                    this._hexValue = this._hexValue.slice(0, -1);
                    this._updateFromHexInput();
                }
                break;

            default:
                if (event.key && event.key.length === 1 && !event.ctrl && !event.alt) {
                    const char = event.key.toLowerCase();
                    if (/^[0-9a-f]$/.test(char) && this._hexValue.length < 6) {
                        this._hexValue += char;
                        this._updateFromHexInput();
                    }
                }
                break;
        }

        if (paletteChanged) {
            this._paletteIndex = index;
            const newColor = PALETTE_COLORS[index];
            this._selectedColor = newColor;
            this._hexValue = this._colorToHexStr(newColor);
            this._onChange?.(newColor);
            this.markDirty();
        }
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        // 1. Render Palette Grid (Row 0 and 1)
        const symbol = caps.unicode ? '■' : 'o';

        for (let r = 0; r < 2; r++) {
            const rowY = y + r;
            if (rowY >= y + height) break;

            for (let c = 0; c < 8; c++) {
                const index = r * 8 + c;
                const cellX = x + c * 4;
                if (cellX >= x + width) continue;

                const color = PALETTE_COLORS[index];
                const isSelected = this._paletteIndex === index;

                if (isSelected) {
                    screen.writeString(cellX, rowY, '[', attrs);
                    screen.writeString(cellX + 1, rowY, symbol, { ...attrs, fg: color, bold: true });
                    screen.writeString(cellX + 2, rowY, ']', attrs);
                } else {
                    screen.writeString(cellX + 1, rowY, symbol, { ...attrs, fg: color });
                }
            }
        }

        if (height < 4) return;

        // 2. Render Hex Input & Live Swatch Line (Row 3)
        const hexPrefix = 'Hex: #';
        const hexFull = hexPrefix + this._hexValue;
        screen.writeString(x, y + 3, hexFull, attrs);

        // Render input cursor if focused
        if (this.isFocused) {
            const cursorX = x + hexFull.length;
            if (cursorX < x + width) {
                screen.setCell(cursorX, y + 3, {
                    char: ' ',
                    ...attrs,
                    inverse: true
                });
            }
        }

        // Render Swatch next to it (starting at col 20 to give plenty of space for "Hex: #ffffff ")
        const swatchX = x + 20;
        if (swatchX < x + width) {
            const swatchLabel = 'Swatch: ';
            screen.writeString(swatchX, y + 3, swatchLabel, attrs);

            const swatchTextX = swatchX + swatchLabel.length;
            if (swatchTextX < x + width) {
                const swatchBlocks = caps.unicode ? '████' : '####';
                screen.writeString(swatchTextX, y + 3, swatchBlocks, {
                    ...attrs,
                    fg: this._selectedColor,
                    bg: this._selectedColor
                });
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — Drawer widget
//
// A side panel that slides in from an edge of the terminal.
// It overlays existing content when open and dims the rest
// of the screen behind it.
//
// Keyboard behaviour:
//   Escape   Fire onClose
//   Tab      Cycle focus forward through focusable children
//   Shift+Tab  Cycle focus backward through focusable children
// ─────────────────────────────────────────────────────

import { Widget } from '@termuijs/widgets';
import {
    type Style,
    type Screen,
    type KeyEvent,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    getBorderChars,
    caps,
} from '@termuijs/core';

// ── Types ────────────────────────────────────────────

/** The edge from which the drawer slides into view. */
export type DrawerPosition = 'left' | 'right' | 'top' | 'bottom';

export interface DrawerOptions {
    /** Edge the drawer appears from. */
    position: DrawerPosition;
    /**
     * Panel width in columns.
     * Applies to 'left' and 'right' positions only.
     * Defaults to 30.
     */
    width?: number;
    /**
     * Panel height in rows.
     * Applies to 'top' and 'bottom' positions only.
     * Defaults to 10.
     */
    height?: number;
    /** Optional title shown in the drawer's top border. */
    title?: string;
    /** Called when the user presses Escape or explicitly closes the drawer. */
    onClose: () => void;
    /** Character used for the dimmed backdrop. Defaults to '░' (unicode) or ' '. */
    backdropChar?: string;
    /** Border colour. Defaults to cyan. */
    borderColor?: Style['fg'];
}

// ── Widget ───────────────────────────────────────────

/**
 * Drawer — a side panel that slides in from any edge.
 *
 * Usage:
 * ```ts
 * const drawer = new Drawer({
 *   position: 'right',
 *   width: 30,
 *   title: 'Settings',
 *   onClose: () => closeDrawer(),
 * });
 * drawer.addChild(new Form({ fields: settingsFields }));
 * drawer.open();
 * ```
 *
 * Wire keyboard events via `handleKey(event)`.
 */
export class Drawer extends Widget {
    private _position: DrawerPosition;
    private _panelWidth: number;
    private _panelHeight: number;
    private _title: string;
    private _onClose: () => void;
    private _backdropChar: string;
    private _borderColor: Style['fg'];
    private _open = false;

    /**
     * Index into the flat list of focusable children that currently
     * holds the "focused" slot inside the focus trap.
     * Starts at -1 so the first Tab press naturally lands on index 0.
     */
    private _focusIndex = -1;

    focusable = true;

    constructor(options: DrawerOptions) {
        super(mergeStyles(defaultStyle(), {}));
        this._position = options.position;
        this._panelWidth = options.width ?? 30;
        this._panelHeight = options.height ?? 10;
        this._title = options.title ?? '';
        this._onClose = options.onClose;
        this._backdropChar = options.backdropChar ?? (caps.unicode ? '░' : ' ');
        this._borderColor = options.borderColor ?? { type: 'named', name: 'cyan' };
    }

    // ── Public API ───────────────────────────────────

    /** Whether the drawer is currently open. */
    get isOpen(): boolean {
        return this._open;
    }

    /** Open the drawer and mark dirty. */
    open(): void {
        this._open = true;
        this._focusIndex = -1;
        this.markDirty();
    }

    /** Close the drawer and mark dirty. */
    close(): void {
        this._open = false;
        this.markDirty();
    }

    /** Toggle open/close state. */
    toggle(): void {
        this._open ? this.close() : this.open();
    }

    /**
     * Handle keyboard input.
     *
     * | Key          | Action                          |
     * |--------------|---------------------------------|
     * | `Escape`     | Fire `onClose`                  |
     * | `Tab`        | Move focus to next child        |
     * | `Shift+Tab`  | Move focus to previous child    |
     */
    handleKey(event: KeyEvent): void {
        if (!this._open) return;

        switch (event.key) {
            case 'escape':
                this._onClose();
                break;
            case 'tab':
                if (event.shift) {
                    this._focusPrev();
                } else {
                    this._focusNext();
                }
                event.preventDefault?.();
                event.stopPropagation?.();
                break;
        }
    }

    // ── Focus trap ───────────────────────────────────

    /**
     * Return a flat list of all focusable descendants in tree order.
     * Used to implement the focus trap.
     */
    private _focusableChildren(): Widget[] {
        const result: Widget[] = [];
        const collect = (widget: Widget): void => {
            for (const child of widget.children) {
                if (child.focusable) result.push(child);
                collect(child);
            }
        };
        collect(this);
        return result;
    }

    private _focusNext(): void {
        const focusable = this._focusableChildren();
        if (focusable.length === 0) return;
        // _focusIndex starts at -1 so the first +1 lands on index 0.
        this._focusIndex = (this._focusIndex + 1) % focusable.length;
        this._applyFocus(focusable);
        this.markDirty();
    }

    private _focusPrev(): void {
        const focusable = this._focusableChildren();
        if (focusable.length === 0) return;
        // When _focusIndex is -1 (no prior Tab), wrap to the last child.
        const base = this._focusIndex < 0 ? 0 : this._focusIndex;
        this._focusIndex = (base - 1 + focusable.length) % focusable.length;
        this._applyFocus(focusable);
        this.markDirty();
    }

    private _applyFocus(focusable: Widget[]): void {
        for (let i = 0; i < focusable.length; i++) {
            focusable[i].isFocused = i === this._focusIndex;
        }
    }

    // ── Geometry helpers ─────────────────────────────

    /**
     * Compute the panel rect (position + dimensions) relative to the
     * full widget rect.
     */
    private _panelRect(
        x: number,
        y: number,
        totalWidth: number,
        totalHeight: number,
    ): { px: number; py: number; pw: number; ph: number } {
        const pw =
            this._position === 'left' || this._position === 'right'
                ? Math.min(this._panelWidth, totalWidth)
                : totalWidth;

        const ph =
            this._position === 'top' || this._position === 'bottom'
                ? Math.min(this._panelHeight, totalHeight)
                : totalHeight;

        let px: number;
        let py: number;

        switch (this._position) {
            case 'left':
                px = x;
                py = y;
                break;
            case 'right':
                px = x + totalWidth - pw;
                py = y;
                break;
            case 'top':
                px = x;
                py = y;
                break;
            case 'bottom':
                px = x;
                py = y + totalHeight - ph;
                break;
        }

        return { px, py, pw, ph };
    }

    // ── Rendering ────────────────────────────────────

    protected _renderSelf(screen: Screen): void {
        if (!this._open) return;

        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this.style);

        // ── 1. Backdrop (dim the whole area) ─────────
        for (let r = 0; r < height; r++) {
            screen.writeString(
                x,
                y + r,
                this._backdropChar.repeat(width),
                { ...attrs, dim: true },
            );
        }

        // ── 2. Panel ─────────────────────────────────
        const { px, py, pw, ph } = this._panelRect(x, y, width, height);

        const border = getBorderChars('single');
        if (!border) return;

        const bAttrs = { ...attrs, fg: this._borderColor };

        // Clear panel interior (overwrite backdrop characters)
        for (let r = 1; r < ph - 1; r++) {
            screen.writeString(px, py + r, border.left, bAttrs);
            screen.writeString(px + 1, py + r, ' '.repeat(Math.max(0, pw - 2)), attrs);
            screen.writeString(px + pw - 1, py + r, border.right, bAttrs);
        }

        // ── Top border with optional title ────────────
        const titleStr = this._title ? ` ${this._title} ` : '';
        const innerWidth = Math.max(0, pw - 2);
        const fill = Math.max(0, innerWidth - titleStr.length);
        const leftFill = Math.floor(fill / 2);
        const rightFill = fill - leftFill;

        screen.writeString(
            px,
            py,
            border.topLeft
            + border.top.repeat(leftFill)
            + titleStr
            + border.top.repeat(rightFill)
            + border.topRight,
            bAttrs,
        );

        // ── Bottom border ─────────────────────────────
        if (ph >= 2) {
            screen.writeString(
                px,
                py + ph - 1,
                border.bottomLeft + border.bottom.repeat(Math.max(0, pw - 2)) + border.bottomRight,
                bAttrs,
            );
        }

        // ── 3. Render children inside the content area ──
        const contentX = px + 1;
        const contentY = py + 1;
        const contentW = Math.max(0, pw - 2);
        const contentH = Math.max(0, ph - 2);

        if (contentW > 0 && contentH > 0) {
            for (const child of this._children) {
                const originalRect = { ...child.rect };
                child.updateRect({
                    x: contentX,
                    y: contentY,
                    width: contentW,
                    height: contentH,
                });
                screen.pushClip({ x: contentX, y: contentY, width: contentW, height: contentH });
                try {
                    child.render(screen);
                } finally {
                    screen.popClip();
                    child.updateRect(originalRect);
                }
            }
        }
    }
}

import { type Screen, type Style, type KeyEvent, styleToCellAttrs, caps, truncate, mergeStyles, defaultStyle } from '@termuijs/core';
import { Widget } from '@termuijs/widgets';

export interface TextAreaOptions {
    /** Number of visible rows (default: 4) */
    rows?: number;
    placeholder?: string;
    onChange?: (value: string) => void;
    onSubmit?: (value: string) => void;
}

/**
 * TextArea - a multi-line text input field.
 *
 * Supports:
 * - Multi-line editing (Enter for newline)
 * - Cursor movement (up/down/left/right)
 * - Ctrl+Enter to submit
 * - Horizontal/Vertical scrolling when content overflows
 */
export class TextArea extends Widget {
    private _lines: string[] = [''];
    private _cursor = { row: 0, col: 0 };
    private _placeholder: string;
    private _onChange?: (value: string) => void;
    private _onSubmit?: (value: string) => void;

    constructor(style: Partial<Style> = {}, options: TextAreaOptions = {}) {
        // default rows = 4, add 2 for top/bottom single borders
        super(mergeStyles(defaultStyle(), { border: 'single', height: (options.rows ?? 4) + 2, ...style }));
        this._placeholder = options.placeholder ?? '';
        this._onChange = options.onChange;
        this._onSubmit = options.onSubmit;
        this.focusable = true;
    }

    get value(): string {
        return this._lines.join('\n');
    }

    set value(v: string) {
        this._lines = v.split('\n');
        if (this._lines.length === 0) this._lines = [''];
        this._cursor.row = Math.min(this._cursor.row, this._lines.length - 1);
        this._cursor.col = Math.min(this._cursor.col, this._lines[this._cursor.row].length);
        this.markDirty();
    }

    insertChar(char: string): void {
        const line = this._lines[this._cursor.row];
        this._lines[this._cursor.row] = line.slice(0, this._cursor.col) + char + line.slice(this._cursor.col);
        this._cursor.col++;
        this._notify();
    }

    insertNewline(): void {
        const line = this._lines[this._cursor.row];
        const before = line.slice(0, this._cursor.col);
        const after = line.slice(this._cursor.col);
        this._lines[this._cursor.row] = before;
        this._lines.splice(this._cursor.row + 1, 0, after);
        this._cursor.row++;
        this._cursor.col = 0;
        this._notify();
    }

    deleteBack(): void {
        if (this._cursor.col > 0) {
            const line = this._lines[this._cursor.row];
            this._lines[this._cursor.row] = line.slice(0, this._cursor.col - 1) + line.slice(this._cursor.col);
            this._cursor.col--;
            this._notify();
        } else if (this._cursor.row > 0) {
            const prevLine = this._lines[this._cursor.row - 1];
            const curLine = this._lines[this._cursor.row];
            this._lines.splice(this._cursor.row, 1);
            this._cursor.row--;
            this._cursor.col = prevLine.length;
            this._lines[this._cursor.row] = prevLine + curLine;
            this._notify();
        }
    }

    moveCursorLeft(): void {
        if (this._cursor.col > 0) {
            this._cursor.col--;
            this.markDirty();
        } else if (this._cursor.row > 0) {
            this._cursor.row--;
            this._cursor.col = this._lines[this._cursor.row].length;
            this.markDirty();
        }
    }

    moveCursorRight(): void {
        const line = this._lines[this._cursor.row];
        if (this._cursor.col < line.length) {
            this._cursor.col++;
            this.markDirty();
        } else if (this._cursor.row < this._lines.length - 1) {
            this._cursor.row++;
            this._cursor.col = 0;
            this.markDirty();
        }
    }

    moveCursorUp(): void {
        if (this._cursor.row > 0) {
            this._cursor.row--;
            this._cursor.col = Math.min(this._cursor.col, this._lines[this._cursor.row].length);
            this.markDirty();
        }
    }

    moveCursorDown(): void {
        if (this._cursor.row < this._lines.length - 1) {
            this._cursor.row++;
            this._cursor.col = Math.min(this._cursor.col, this._lines[this._cursor.row].length);
            this.markDirty();
        }
    }

    handleKey(event: KeyEvent): void {
        this.markDirty();
        const isEnter = event.key === 'enter' || event.key === 'return' || event.key === '\r' || event.key === '\n';

        if (isEnter && (event.ctrl || event.alt)) {
            this._onSubmit?.(this.value);
            return;
        }
        if (event.key === 's' && (event.ctrl || event.alt)) {
            this._onSubmit?.(this.value);
            return;
        }
        if (isEnter) {
            this.insertNewline();
            return;
        }

        switch (event.key) {
            case 'up':    this.moveCursorUp();    break;
            case 'down':  this.moveCursorDown();  break;
            case 'left':  this.moveCursorLeft();  break;
            case 'right': this.moveCursorRight(); break;
            case 'backspace': this.deleteBack();  break;
            case 'space': this.insertChar(' ');   break;
            default:
                if (event.key && event.key.length === 1 && !event.ctrl && !event.alt) {
                    this.insertChar(event.key);
                }
                break;
        }
    }

    private _notify(): void {
        this._onChange?.(this.value);
        this.markDirty();
    }

    protected _renderSelf(screen: Screen): void {
        const rect = this._getContentRect();
        const { x, y, width, height } = rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);

        const isEmpty = this._lines.length === 1 && this._lines[0] === '';
        if (isEmpty && !this.isFocused && this._placeholder) {
            screen.writeString(x, y, truncate(this._placeholder, width), { ...attrs, dim: true });
            return;
        }

        // Scroll Y to keep cursor visible
        let scrollY = 0;
        if (this._cursor.row >= height) {
            scrollY = this._cursor.row - height + 1;
        }

        // Scroll X to keep cursor visible
        let scrollX = 0;
        if (this._cursor.col >= width) {
            scrollX = this._cursor.col - width + 1;
        }

        // Render visible lines
        for (let r = 0; r < height; r++) {
            const lineIdx = r + scrollY;
            if (lineIdx >= this._lines.length) break;
            const lineStr = this._lines[lineIdx];
            const visibleText = lineStr.slice(scrollX, scrollX + width).padEnd(width, ' ').slice(0, width);
            screen.writeString(x, y + r, visibleText, attrs);
        }

        // Draw cursor
        if (this.isFocused) {
            const screenRow = this._cursor.row - scrollY;
            const screenCol = this._cursor.col - scrollX;
            if (screenRow >= 0 && screenRow < height && screenCol >= 0 && screenCol < width) {
                const lineStr = this._lines[this._cursor.row] || '';
                const cursorChar = this._cursor.col < lineStr.length ? lineStr[this._cursor.col] : ' ';
                const asciiFallback = cursorChar === ' ' ? '_' : cursorChar;
                const cursorGlyph = caps.unicode ? cursorChar : asciiFallback;
                screen.setCell(x + screenCol, y + screenRow, {
                    char: cursorGlyph,
                    ...attrs,
                    inverse: true,
                });
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — Breadcrumb component
//
// A horizontal path navigator. Left/right arrows move
// focus; Enter fires the focused item's onSelect.
// ─────────────────────────────────────────────────────

import { Widget } from '@termuijs/widgets';
import {
    type Screen,
    type KeyEvent,
    type Style,
    type Color,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    caps,
    stringWidth,
    truncate,
} from '@termuijs/core';

export interface BreadcrumbItem {
    label: string;
    onSelect?: () => void;
}

export interface BreadcrumbOptions {
    items: BreadcrumbItem[];
    currentColor?: Color;
    inactiveColor?: Color;
    separatorColor?: Color;
}

export class Breadcrumb extends Widget {
    private _items: BreadcrumbItem[];
    private _focusedIndex = 0;
    private _currentColor: Color;
    private _inactiveColor: Color;
    private _separatorColor: Color;

    focusable = true;

    constructor(options: BreadcrumbOptions) {
        super(mergeStyles(defaultStyle(), { height: 1 }));
        this._items = options.items;
        this._currentColor = options.currentColor ?? { type: 'named', name: 'cyan' };
        this._inactiveColor = options.inactiveColor ?? { type: 'named', name: 'brightBlack' };
        this._separatorColor = options.separatorColor ?? { type: 'named', name: 'brightBlack' };
    }

    get items(): ReadonlyArray<BreadcrumbItem> { return this._items; }
    get focusedIndex(): number { return this._focusedIndex; }

    setItems(items: BreadcrumbItem[]): void {
        this._items = items;
        this._focusedIndex = Math.min(this._focusedIndex, Math.max(0, items.length - 1));
        this.markDirty();
    }

    handleKey(event: KeyEvent): void {
        if (this._items.length === 0) return;
        switch (event.key) {
            case 'right':
                this._focusedIndex = (this._focusedIndex + 1) % this._items.length;
                this.markDirty();
                break;
            case 'left':
                this._focusedIndex = (this._focusedIndex - 1 + this._items.length) % this._items.length;
                this.markDirty();
                break;
            case 'enter':
            case 'return':
                this._items[this._focusedIndex]?.onSelect?.();
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width } = this._getContentRect();
        if (width <= 0) return;

        const attrs = styleToCellAttrs(this.style);
        const sep = caps.unicode ? '›' : '>';
        const sepWithSpaces = ` ${sep} `;

        let cx = x;
        for (let i = 0; i < this._items.length; i++) {
            const item = this._items[i];
            if (!item) continue;
            const isLast = i === this._items.length - 1;
            const isFocused = i === this._focusedIndex;

            const itemWidth = stringWidth(item.label);
            if (cx + itemWidth > x + width) {
                const remaining = x + width - cx;
                screen.writeString(cx, y, truncate(item.label, remaining), attrs);
                return;
            }

            const itemAttrs = isLast
                ? { ...attrs, fg: this._currentColor, bold: true }
                : isFocused
                    ? { ...attrs, fg: this._currentColor, underline: true }
                    : { ...attrs, fg: this._inactiveColor };

            screen.writeString(cx, y, item.label, itemAttrs);
            cx += itemWidth;

            if (!isLast) {
                const sepWidth = stringWidth(sepWithSpaces);
                if (cx + sepWidth > x + width) return;
                screen.writeString(cx, y, sepWithSpaces, { ...attrs, fg: this._separatorColor, dim: true });
                cx += sepWidth;
            }
        }
    }
}

// Combobox — text input with inline filtered dropdown
import { Widget } from '@termuijs/widgets';
import {
    type Style,
    type Screen,
    type KeyEvent,
    mergeStyles,
    defaultStyle,
    styleToCellAttrs,
    caps,
    stringWidth,
    truncate
} from '@termuijs/core';

export interface ComboboxOption {
    label: string;
    value: string;
}

export interface ComboboxOptions {
    placeholder?: string;
    activeColor?: Style['fg'];
    onSelect?: (value: string) => void;
}

export class Combobox extends Widget {
    private _options: ComboboxOption[];
    private _placeholder: string;
    private _activeColor: Style['fg'];
    private _onSelect?: (value: string) => void;

    private _inputValue = '';
    private _committedValue = '';
    private _isOpen = false;
    private _selectedIndex = -1;
    focusable = true;

    constructor(options: ComboboxOption[], config?: ComboboxOptions) {
        super(mergeStyles(defaultStyle(), { height: 6, focusRingStyle: 'none' }));
        this._options = options;
        this._placeholder = config?.placeholder ?? '';
        this._activeColor = config?.activeColor ?? { type: 'named', name: 'cyan' };
        this._onSelect = config?.onSelect;
    }

    get value(): string {
        return this._committedValue;
    }

    get filtered(): ComboboxOption[] {
        const query = this._inputValue.toLowerCase();
        return this._options.filter(option =>
            option.label.toLowerCase().includes(query)
        );
    }

    handleKey(event: KeyEvent): void {
        const key = event.key;
        const filtered = this.filtered;

        if (key === 'down') {
            this._isOpen = true;
            if (filtered.length > 0) {
                this._selectedIndex = (this._selectedIndex + 1) % filtered.length;
            }
            this.markDirty();
            return;
        }

        if (key === 'up') {
            this._isOpen = true;
            if (filtered.length > 0) {
                if (this._selectedIndex <= 0) {
                    this._selectedIndex = filtered.length - 1;
                } else {
                    this._selectedIndex--;
                }
            }
            this.markDirty();
            return;
        }

        if (key === 'escape') {
            if (!this._isOpen && this._selectedIndex === -1) {
                return;
            }

            this._isOpen = false;
            this._selectedIndex = -1;
            this.markDirty();
            return;
        }

        if (key === 'enter') {
            if (this._isOpen && this._selectedIndex >= 0 && this._selectedIndex < filtered.length) {
                const selected = filtered[this._selectedIndex];
                this._committedValue = selected.value;
                this._inputValue = selected.label;
                this._onSelect?.(selected.value);
            } else {
                this._committedValue = this._inputValue;
                this._onSelect?.(this._inputValue);
            }
            this._isOpen = false;
            this._selectedIndex = -1;
            this.markDirty();
            return;
        }

        if (key === 'backspace') {
            if (this._inputValue.length === 0) {
                return;
            }

            this._inputValue = this._inputValue.slice(0, -1);
            this._isOpen = true;
            this._selectedIndex = -1;
            this.markDirty();
            return;
        }

        if (key.length === 1 && !event.ctrl && !event.alt) {
            this._inputValue += key;
            this._isOpen = true;
            this._selectedIndex = -1;
            this.markDirty();
            return;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._getContentRect();
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this.style);
        const prefix = this._isOpen ? (caps.unicode ? '▼ ' : 'v ') : (caps.unicode ? '▶ ' : '> ');
        const prefixWidth = stringWidth(prefix);

        const isPlaceholder = this._inputValue === '' && !this.isFocused;
        const displayText = this._inputValue !== '' ? this._inputValue : (this.isFocused ? '' : this._placeholder);

        screen.writeString(x, y, prefix + truncate(displayText, width - prefixWidth), {
            ...attrs,
            fg: isPlaceholder ? { type: 'named', name: 'brightBlack' } : attrs.fg,
        });

        if (this.isFocused) {
            const cursorX = x + prefixWidth + stringWidth(truncate(this._inputValue, width - prefixWidth));
            if (cursorX < x + width) {
                screen.setCell(cursorX, y, {
                    char: ' ',
                    ...attrs,
                    inverse: true,
                });
            }
        }

        const filtered = this.filtered;
        if (this._isOpen && this.isFocused && filtered.length > 0) {
            const renderCount = Math.min(filtered.length, height - 1);
            for (let i = 0; i < renderCount; i++) {
                const option = filtered[i];
                const isSelected = i === this._selectedIndex;
                const rowY = y + 1 + i;
                if (rowY >= y + height) break;

                const marker = isSelected ? (caps.unicode ? '● ' : '* ') : '  ';
                const itemText = truncate(option.label, width - stringWidth(marker));

                screen.writeString(x, rowY, marker + itemText, {
                    ...attrs,
                    fg: isSelected ? this._activeColor : attrs.fg,
                    bold: isSelected,
                });
            }
        }
    }
}

// MenuBar — horizontal menu bar with dropdown menus
import { Widget } from '@termuijs/widgets';
import { type Style, type Color, type KeyEvent, type Screen, mergeStyles, defaultStyle, styleToCellAttrs, caps } from '@termuijs/core';

export interface MenuItem {
    label: string;
    action?: () => void;
    disabled?: boolean;
}

export interface MenuBarItem {
    label: string;
    items: MenuItem[];
}

export interface MenuBarOptions {
    activeColor?: Color;
}

export class MenuBar extends Widget {
    private _menus: MenuBarItem[] = [];
    private _activeMenu = 0;
    private _isOpen = false;
    private _activeItem = -1;
    private _activeColor: Color;
    focusable = true;

    constructor(menus: MenuBarItem[], style?: Partial<Style>, opts?: MenuBarOptions) {
        super(mergeStyles(defaultStyle(), { height: 1, ...style }));
        this._menus = menus;
        this._activeColor = opts?.activeColor ?? { type: 'named', name: 'cyan' };
    }

    get activeMenu(): number {
        return this._activeMenu;
    }

    get isOpen(): boolean {
        return this._isOpen;
    }

    get activeItem(): number {
        return this._activeItem;
    }

    get menus(): MenuBarItem[] {
        return this._menus;
    }

    setMenus(menus: MenuBarItem[]): void {
        this._menus = menus;
        this._activeMenu = 0;
        this._isOpen = false;
        this._activeItem = -1;
        this.markDirty();
    }

    private _initActiveItem(): void {
        const items = this._menus[this._activeMenu]?.items ?? [];
        let firstEnabled = -1;
        for (let i = 0; i < items.length; i++) {
            if (!items[i].disabled) {
                firstEnabled = i;
                break;
            }
        }
        this._activeItem = firstEnabled;
    }

    private _selectNextItem(): void {
        const items = this._menus[this._activeMenu]?.items ?? [];
        if (items.length === 0 || items.every(i => i.disabled)) return;
        let n = this._activeItem;
        const start = n;
        do {
            n = (n + 1) % items.length;
            if (!items[n].disabled) {
                this._activeItem = n;
                this.markDirty();
                return;
            }
        } while (n !== start);
    }

    private _selectPrevItem(): void {
        const items = this._menus[this._activeMenu]?.items ?? [];
        if (items.length === 0 || items.every(i => i.disabled)) return;
        let n = this._activeItem;
        const start = n;
        do {
            n = (n - 1 + items.length) % items.length;
            if (!items[n].disabled) {
                this._activeItem = n;
                this.markDirty();
                return;
            }
        } while (n !== start);
    }

    private _openMenu(): void {
        this._initActiveItem();
        this._isOpen = true;
        this.markDirty();
    }

    private _closeMenu(): void {
        this._isOpen = false;
        this.markDirty();
    }

    selectNextMenu(): void {
        if (this._menus.length === 0) return;
        this._activeMenu = (this._activeMenu + 1) % this._menus.length;
        if (this._isOpen) {
            this._initActiveItem();
        }
        this.markDirty();
    }

    selectPrevMenu(): void {
        if (this._menus.length === 0) return;
        this._activeMenu = (this._activeMenu - 1 + this._menus.length) % this._menus.length;
        if (this._isOpen) {
            this._initActiveItem();
        }
        this.markDirty();
    }

    handleKey(event: KeyEvent): void {
        const key = event.key.toLowerCase();

        if (this._isOpen) {
            if (key === 'escape') {
                this._closeMenu();
            } else if (key === 'up') {
                this._selectPrevItem();
            } else if (key === 'down') {
                this._selectNextItem();
            } else if (key === 'enter') {
                const items = this._menus[this._activeMenu]?.items ?? [];
                const activeItem = items[this._activeItem];
                if (activeItem && !activeItem.disabled) {
                    if (activeItem.action) {
                        activeItem.action();
                    }
                    this._closeMenu();
                }
            } else if (key === 'left') {
                this.selectPrevMenu();
            } else if (key === 'right') {
                this.selectNextMenu();
            }
        } else {
            if (key === 'left') {
                this.selectPrevMenu();
            } else if (key === 'right') {
                this.selectNextMenu();
            } else if (key === 'enter') {
                this._openMenu();
            }
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this.style);
        let col = x;
        const menuPositions: number[] = [];

        for (let i = 0; i < this._menus.length; i++) {
            const menu = this._menus[i];
            const isActive = i === this._activeMenu;
            const label = `  ${menu.label}  `;
            menuPositions.push(col);

            if (col < x + width) {
                const visibleLabel = label.slice(0, x + width - col);
                screen.writeString(col, y, visibleLabel, {
                    ...attrs,
                    fg: isActive ? this._activeColor : attrs.fg,
                    bold: isActive,
                });
            }
            col += label.length;
        }

        if (this._isOpen) {
            const menu = this._menus[this._activeMenu];
            if (menu) {
                const items = menu.items;
                const menuX = menuPositions[this._activeMenu];
                const maxItemLabelLength = items.reduce((max, item) => Math.max(max, item.label.length), 0);
                const dropdownWidth = Math.max(
                    `  ${menu.label}  `.length,
                    maxItemLabelLength + 4
                );

                for (let k = 0; k < items.length; k++) {
                    const item = items[k];
                    const isSel = k === this._activeItem;
                    const prefix = isSel ? (caps.unicode ? '● ' : '* ') : '  ';
                    const itemText = prefix + item.label;
                    const paddedText = itemText.padEnd(dropdownWidth);

                    if (menuX < x + width) {
                        const visibleText = paddedText.slice(0, x + width - menuX);
                        screen.writeString(menuX, y + 1 + k, visibleText, {
                            ...attrs,
                            fg: item.disabled
                                ? { type: 'named', name: 'brightBlack' }
                                : isSel
                                    ? this._activeColor
                                    : attrs.fg,
                            bold: isSel,
                            dim: item.disabled,
                        });
                    }
                }
            }
        }
    }
}

// ─────────────────────────────────────────────────────
// @termuijs/ui — KeyboardShortcuts display widget
//
// Renders a grid of keyboard shortcut bindings.
// Groups by category if provided.
//
// Layout (2-column):
//   [key]  description       [key]  description
// ─────────────────────────────────────────────────────

import { Widget } from '@termuijs/widgets';
import { type Style, type Screen, styleToCellAttrs, caps } from '@termuijs/core';

export interface ShortcutBinding {
    key: string;
    description: string;
    category?: string;
}

export interface KeyboardShortcutsOptions {
    /** Color for the key label boxes */
    keyColor?: Style['fg'];
    /** Color for category headings */
    categoryColor?: Style['fg'];
    /** Number of columns (default 2) */
    columns?: number;
    /** Show category headings (default true) */
    showCategories?: boolean;
}

/** A group of bindings belonging to the same category. */
interface BindingGroup {
    category: string | undefined;
    bindings: ShortcutBinding[];
}

export class KeyboardShortcuts extends Widget {
    private _bindings: ShortcutBinding[];
    private _keyColor: Style['fg'];
    private _categoryColor: Style['fg'];
    private _columns: number;
    private _showCategories: boolean;

    constructor(bindings: ShortcutBinding[], options: KeyboardShortcutsOptions = {}) {
        super({});
        this._bindings = bindings;
        this._keyColor = options.keyColor ?? { type: 'named', name: 'cyan' };
        this._categoryColor = options.categoryColor ?? { type: 'named', name: 'yellow' };
        this._columns = Math.max(1, options.columns ?? 2);
        this._showCategories = options.showCategories ?? true;
    }

    /** Replace all bindings and trigger a re-render. */
    setBindings(bindings: ShortcutBinding[]): void {
        this._bindings = bindings;
        this.markDirty();
    }

    /** Group bindings by category, preserving insertion order. */
    private _groupBindings(): BindingGroup[] {
        const groups: BindingGroup[] = [];
        const indexMap = new Map<string, number>();

        for (const b of this._bindings) {
            const cat = b.category ?? '';
            const key = cat;
            if (!indexMap.has(key)) {
                indexMap.set(key, groups.length);
                groups.push({ category: b.category, bindings: [] });
            }
            groups[indexMap.get(key)!].bindings.push(b);
        }
        return groups;
    }

    /**
     * Render a key label in a bordered box style:
     *   ┌─────┐
     *   │ key │
     *   └─────┘
     *
     * We fit it on one line: [ key ] — box drawing characters or ASCII fallback.
     */
    private _renderKeyLabel(screen: Screen, kx: number, ky: number, key: string, attrs: ReturnType<typeof styleToCellAttrs>): number {
        const label = `[${key}]`;
        screen.writeString(kx, ky, label, { ...attrs, fg: this._keyColor, bold: true });
        return label.length;
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;
        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this._style);
        const groups = this._groupBindings();

        let row = y;
        const colWidth = Math.floor(width / this._columns);

        for (const group of groups) {
            if (row >= y + height) break;

            // Category heading
            if (this._showCategories && group.category) {
                const heading = group.category.toUpperCase();
                const divider = caps.unicode ? '─' : '-';
                const line = heading + ' ' + divider.repeat(Math.max(0, width - heading.length - 1));
                screen.writeString(x, row, line.slice(0, width), {
                    ...attrs,
                    fg: this._categoryColor,
                    bold: true,
                });
                row++;
                if (row >= y + height) break;
            }

            // Render bindings in a grid of _columns
            for (let i = 0; i < group.bindings.length; i += this._columns) {
                if (row >= y + height) break;

                for (let col = 0; col < this._columns; col++) {
                    const binding = group.bindings[i + col];
                    if (!binding) continue;

                    const cx = x + col * colWidth;
                    const availWidth = colWidth - 1; // 1 char gap between columns

                    if (availWidth <= 0) continue;

                    // Render key label
                    const labelLen = this._renderKeyLabel(screen, cx, row, binding.key, attrs);

                    // Render description after the label (with a space gap)
                    const descX = cx + labelLen + 1;
                    const descWidth = availWidth - labelLen - 1;
                    if (descWidth > 0) {
                        const desc = binding.description.slice(0, descWidth);
                        screen.writeString(descX, row, desc, attrs);
                    }
                }
                row++;
            }

            // Blank line between groups
            if (this._showCategories && group.category) {
                row++;
            }
        }
    }
}

import { Widget } from '@termuijs/widgets';
import { type Color, type Style, type Screen, type KeyEvent, mergeStyles, defaultStyle, styleToCellAttrs } from '@termuijs/core';

export interface ScalePromptOptions {
    max?: number;
    question?: string;
    endLabels?: [string, string];
    activeColor?: Color;
    onSelect?: (value: number) => void;
}

export class ScalePrompt extends Widget {
    private _max: number;
    private _value: number;
    private _question?: string;
    private _endLabels?: [string, string];
    private _activeColor: Color;
    private _onSelect?: (value: number) => void;

    focusable = true;

    constructor(style?: Partial<Style>, opts: ScalePromptOptions = {}) {
        super(mergeStyles(defaultStyle(), { height: 3, flexGrow: 1, ...style }));

        this._max = Math.max(1, Math.floor(opts.max ?? 5));
        this._value = 1;
        this._question = opts.question;
        this._endLabels = opts.endLabels;
        this._activeColor = opts.activeColor ?? { type: 'named', name: 'cyan' };
        this._onSelect = opts.onSelect;
    }

    getValue(): number {
        return this._value;
    }

    private _setValue(value: number): void {
        const nextValue = Math.max(1, Math.min(this._max, value));

        if (nextValue === this._value) return;

        this._value = nextValue;
        this.markDirty();
    }

    handleKey(event: KeyEvent): void {
        switch (event.key) {
            case 'left':
                this._setValue(this._value - 1);
                break;

            case 'right':
                this._setValue(this._value + 1);
                break;

            case 'enter':
                this._onSelect?.(this._value);
                break;
        }
    }

    protected _renderSelf(screen: Screen): void {
        const { x, y, width, height } = this._rect;

        if (width <= 0 || height <= 0) return;

        const attrs = styleToCellAttrs(this.style);
        let row = 0;

        if (this._question) {
            screen.writeString(x, y + row, this._question.slice(0, width), attrs);
            row++;
        }

        if (row < height) {
            const numbers: string[] = [];

            for (let i = 1; i <= this._max; i++) {
                numbers.push(i === this._value ? `[${i}]` : String(i));
            }

            screen.writeString(
                x,
                y + row,
                numbers.join(' ').slice(0, width),
                { ...attrs, fg: this._activeColor }
            );
            row++;
        }

        if (row < height && this._endLabels) {
            const [leftLabel, rightLabel] = this._endLabels;
            const leftText = leftLabel.slice(0, width);
            const rightText = rightLabel.slice(0, width);
            const rightX = x + Math.max(0, width - rightText.length);

            screen.writeString(x, y + row, leftText, attrs);
            screen.writeString(rightX, y + row, rightText, attrs);
        }
    }
}
